public class PlayZone : BasePlayZone, ISystemHelpPart
{
	private PlayZone()
	{
		int[] array = new int[9];
		array[3] = 1;
		array[4] = 1;
		array[5] = 1;
		this.ts_patterns = array;
		this.skillids = "206,206";
		this.skillids2 = "206";
		this.skillAttackIdList = new ArrayList();
		this.ActionDict = new Dictionary<string, Action<string[]>>();
		base..ctor();
	}

	protected override void InitializeComponent()
	{
		if (null == PlayZone.GlobalPlayZone)
		{
			SystemHelpMgr.RegisterPart(this);
			PlayZone.GlobalPlayZone = this;
		}
		base.InitializeComponent();
		this.UserControl_Loaded(this);
	}

	protected void UserControl_Loaded(UserControl sender)
	{
		Super.GData.GlobalPlayZone = this;
		Super.GData.PlayZoneRoot = this;
		if (null != Global.Joystick)
		{
			Global.Joystick.gameObject.SetActive(true);
		}
		this.InitCookies();
		base.InitializeGameArguments();
		this.EnterGame();
	}

	private void InitCookies()
	{
		Global.LoadSystemSettings();
		Global.LoadAutoFightSettings();
		Global.LoadZhuanShengPromptingSettings();
	}

	public void StartPlayGame()
	{
		GameInstance.Game.StartPlayGame();
	}

	protected void InitializeGameScene()
	{
		this.scene = new GScene();
		this.scene.MapConversion = new MapConversionEventHandler(base.MapConversion);
		this.scene.LeftButtonClickOnSprite = new SpriteNotifyEventHandler(this.LeftButtonClickOnSprite);
		this.scene.SpriteDeadNotify = new SpriteNotifyEventHandler(this.SpriteDeadNotify);
		this.scene.KillSpriteNotify = new SpriteNotifyEventHandler(this.KillSpriteNotify);
		this.scene.GoodsPackNotify = new GoodsPackNotifyEventHandler(this.GoodsPackNotify);
		this.scene.BackgroundHeartNotfiy = new EventHandler(this.BackgroundHeartNotfiy);
		this.scene.SpriteStallNotify = new SpriteNotifyEventHandler(this.SpriteStallNotify);
		this.scene.EndAutoFightNotifiy = new EventHandler(this.EndAutoFightNotifiy);
		this.scene.AutoFightingNoDrugNotfiy = new EventHandler(this.AutoFightingNoDrugNotfiy);
		this.scene.SafeRegionNotfiy = new SafeRegionNotfiyEventHandler(this.SafeRegionNotfiy);
		this.scene.AutoFindRoadDecoNotify = new StateNotifyEventHandler(this.AutoFindRoadDecoNotify);
		this.scene.AutoFightDecoNotify = new StateNotifyEventHandler(this.AutoFightDecoNotify);
		this.scene.m_DisableInputEvent = new DisableInputEvent(this.DisableInputEventProc);
		Global.Data.GameScene = this.scene;
	}

	protected void EnterGame()
	{
		this.InitializeGameInterface();
		this.InitializeGameScene();
		this.InitRadarMap();
		this.InitGongnengYugaoMgr();
		this.InitNetwork();
		this.LoadScene(Global.Data.roleData.MapCode, Global.Data.roleData.PosX, Global.Data.roleData.PosY, (double)Global.Data.roleData.RoleDirection, true);
		this.InitFirstEnterGame();
		SystemHelpMgr.ShowSystemHelp(SystemHelpModes.ToMap, Global.Data.roleData.MapCode);
		Global.NotifyStatURL("entergame");
	}

	private void CalcArchorForIphoneX()
	{
	}

	private void InitFirstEnterGame()
	{
		this.StartPlayGame();
	}

	protected override void ClearScene()
	{
		base.ClearScene();
		if (null != this.RadarMap)
		{
		}
	}

	public override void LoadScene(int mapCode, int leaderX, int leaderY, double direction, bool newLifeDeco)
	{
		int timer = U3DUtils.GetTimer();
		base.LoadScene(mapCode, leaderX, leaderY, direction, newLifeDeco);
		this.LoadRadarMap();
	}

	public int onRenderScene()
	{
		if (this.scene != null)
		{
			return this.scene.onRenderScene();
		}
		return 0;
	}

	public int onUIRenderFrame()
	{
		if (Input.GetKeyDown(27) || Input.GetKeyDown(278))
		{
			this.CloseNetwork();
			if (PlatSDKMgr.PlatName == "QH360")
			{
				PlatSDKMgr.LoginOut(string.Empty);
			}
			else
			{
				Application.Quit();
			}
			return 0;
		}
		this.RefreshRoleFace();
		return 0;
	}

	public UICtrlBar GetGameCtrlBar
	{
		get
		{
			return this.GameCtrlBar;
		}
	}

	public GRadarMap GetRadarMap()
	{
		return this.RadarMap;
	}

	protected void AddAllEventListener()
	{
		Global.GlobalEventDispatcher.addEventListener("EventPrivateChat", new Global.GlobalEventDispatcher.PlayGameContolEventHandler(this.OnPrivateChat));
		Global.GlobalEventDispatcher.addEventListener("EventShowParcel", new Global.GlobalEventDispatcher.PlayGameContolEventHandler(this.OnShowParcel));
		Global.GlobalEventDispatcher.addEventListener("EventSendMail", new Global.GlobalEventDispatcher.PlayGameContolEventHandler(this.OnSendMail));
		Global.GlobalEventDispatcher.addEventListener("EventOpenBaoDian", new Global.GlobalEventDispatcher.PlayGameContolEventHandler(this.OnOpenBaoDian));
		Global.GlobalEventDispatcher.addEventListener("EventOpenNPCSale", new Global.GlobalEventDispatcher.PlayGameContolEventHandler(this.OnOpenNPCSale));
		Global.GlobalEventDispatcher.addEventListener("EventOpenMallBuyGoodsID", new Global.GlobalEventDispatcher.PlayGameContolEventHandler(this.OnOpenMallBuyGoodsID));
		Global.GlobalEventDispatcher.addEventListener("EventMergeWin", new Global.GlobalEventDispatcher.PlayGameContolEventHandler(this.OnOpenMergeWin));
		Global.GlobalEventDispatcher.addEventListener("EventFuBen", new Global.GlobalEventDispatcher.PlayGameContolEventHandler(this.OnFuBenEvent));
		Global.GlobalEventDispatcher.addEventListener("EventSystemWizard", new Global.GlobalEventDispatcher.PlayGameContolEventHandler(this.OnSystemWizardEvent));
		Global.GlobalEventDispatcher.addEventListener("EventWindowOperation", new Global.GlobalEventDispatcher.PlayGameContolEventHandler(this.OnEventWindowOperation));
		Global.GlobalEventDispatcher.addEventListener("EventMenuIconBoxAddIcon", new Global.GlobalEventDispatcher.PlayGameContolEventHandler(this.GongNengIconAddAnim));
		Global.GlobalEventDispatcher.addEventListener("EventAddHintIcon", new Global.GlobalEventDispatcher.PlayGameContolEventHandler(this.OnAddHintIconEvent));
	}

	private void ReleaseEvent()
	{
		Global.GlobalEventDispatcher.ClearEventListener();
	}

	public void AddWinTouchPos(string key, int x, int y)
	{
		if (!this.WinTouchPosDict.ContainsKey(key))
		{
			this.WinTouchPosDict[key] = new Point(x, y);
		}
	}

	protected void InitializeAttackObjecgInfo()
	{
		this.AttackObjectInfo = new HSTextField(string.Empty, -1, -1, -1, -1, 0);
		Canvas.SetTop(this.AttackObjectInfo, (int)Global.GlobalMainWindow.ActualHeight - 330 - 20 + 13 - 20);
		this.Root.Children.Add(this.AttackObjectInfo);
	}

	protected void InitializePingText()
	{
		this.PingText = new HSTextField("0", 65280, -1, -1, -1, -1);
		this.PingText.text = TCPPing.GetPingTicks().ToString() + "ms";
		Canvas.SetLeft(this.PingText, 235);
		Canvas.SetTop(this.PingText, 0);
		this.Root.Children.Add(this.PingText);
	}

