	protected void InitializeObjectRoleFace()
	{
		this.ObjectRoleFace = U3DUtils.NEW<ObjectRoleFacePart>();
		this.ObjectRoleFace.Visibility = false;
		this.ObjectRoleFace.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
		{
			if (!Global.Data.DisableRoleInfo && this.ObjectRoleFace.ObjectFaceType == GSpriteTypes.Other)
			{
				if (e.ID == 0)
				{
					GameInstance.Game.SpriteGetOtherAttrib(this.objectFaceID);
				}
				else if (e.ID == 1)
				{
					if (0 < this.ObjectRoleFace.ShowName.Length)
					{
						if (Global.IsKuaFuHuoDongMapSceneUIClass(Global.GetMapSceneUIClass()))
						{
							Super.HintMainText(Global.GetLang("当前不能进行此操作"), 10, 3);
						}
						else
						{
							this.ShowGameChatBoxWindow(4, this.ObjectRoleFace.ShowName);
						}
					}
				}
				else if (e.ID == 2)
				{
					if (this.ObjectRoleFace != null && this.ObjectRoleFace != null)
					{
						if (Global.IsKuaFuHuoDongMapSceneUIClass(Global.GetMapSceneUIClass()) || SceneUIClasses.RebornMap.IsTheScene())
						{
							Super.HintMainText(Global.GetLang("当前不能进行此操作"), 10, 3);
						}
						else if (!Global.IsOperateUnPermitInKuaFuMapCheck(true, false))
						{
							GameInstance.Game.SpriteGoodsExchange(this.ObjectRoleFace.RoleID, 1, -1);
						}
					}
				}
				else if (e.ID == 3)
				{
					if (Global.IsInShiLiZhengBaMap() || SceneUIClasses.RebornMap.IsTheScene())
					{
						Super.HintMainText(Global.GetLang("当前不能进行此操作"), 10, 3);
					}
					else
					{
						GameInstance.Game.SpriteTeam(4, this.ObjectRoleFace.RoleID, 0);
					}
				}
				else if (e.ID == 4)
				{
					RoleData roleData = null;
					if (Global.Data.OtherRoles.ContainsKey(this.ObjectRoleFace.RoleID))
					{
						roleData = Global.Data.OtherRoles[this.ObjectRoleFace.RoleID];
					}
					if (Global.IsKuaFuHuoDongMapSceneUIClass(Global.GetMapSceneUIClass()) && Global.Data.roleData.BattleWhichSide != roleData.BattleWhichSide)
					{
						Super.HintMainText(Global.GetLang("当前不能进行此操作"), 10, 3);
					}
					else if (Global.IsInShiLiZhengBaMap() || SceneUIClasses.RebornMap.IsTheScene())
					{
						Super.HintMainText(Global.GetLang("当前不能进行此操作"), 10, 3);
					}
					else
					{
						if (Global.Data.CurrentTeamData == null)
						{
							GameInstance.Game.SpriteTeam(1, e.GetThingOpt, 0);
						}
						GameInstance.Game.SpriteTeam(3, this.ObjectRoleFace.RoleID, 0);
					}
				}
				else if (e.ID == 5)
				{
					if (Global.IsOperateUnPermitInKuaFuMapCheck(true, false))
					{
						return;
					}
					if (SceneUIClasses.RebornMap.IsTheScene())
					{
						Super.HintMainText(Global.GetLang("当前不能进行此操作"), 10, 3);
						return;
					}
					RoleData roleData2 = null;
					if (Global.Data.OtherRoles.ContainsKey(this.ObjectRoleFace.RoleID))
					{
						Global.Data.OtherRoles.TryGetValue(this.objectFaceID, ref roleData2);
						if (Global.Data.roleData.OccupationList != null && Global.Data.roleData.Occupation != Global.Data.roleData.OccupationList[0])
						{
							string lang = Global.GetLang("求婚必须使用主职业");
							Super.HintMainText(lang, 10, 3);
							return;
						}
						if (roleData2.OccupationList != null && roleData2.Occupation != roleData2.OccupationList[0])
						{
							string lang2 = Global.GetLang("对方必须使用主职业");
							Super.HintMainText(lang2, 10, 3);
							return;
						}
						if (roleData2.ChangeLifeCount >= 3 && Global.Data.roleData.ChangeLifeCount >= 3)
						{
							if (roleData2.OccupationList != null)
							{
								List<int> occupationList = roleData2.OccupationList;
								if (occupationList[0] != Global.CalcOriginalOccupationID(roleData2.Occupation))
								{
									Super.HintMainText("对方必须使用主职业", 10, 3);
									return;
								}
							}
							if (roleData2.RoleSex != Global.Data.roleData.RoleSex)
							{
								if (GameInstance.Game.CurrentSession != null && GameInstance.Game.CurrentSession.MarriageData != null && (int)GameInstance.Game.CurrentSession.MarriageData.byMarrytype != -1)
								{
									Super.HintMainText(Global.GetLang("您当前为已结婚状态，无法再次求婚"), 10, 3);
								}
								else
								{
									int num = 58;
									SystemOpenVO systemOpenVOByID = ConfigSystemOpen.GetSystemOpenVOByID(num);
									if (systemOpenVOByID == null)
									{
										MUDebug.LogError<string>(new string[]
										{
											"SystemOpen中没找到 结婚功能开启ID" + num
										});
										return;
									}
									int timeParameters = systemOpenVOByID.TimeParameters;
									if (timeParameters == -1)
									{
										MUDebug.LogError<string>(new string[]
										{
											"SystemOpen中没找到 结婚功能开启的任务ID" + num
										});
										return;
									}
									if (Global.Data.roleData.CompletedMainTaskID < timeParameters)
									{
										Super.HintMainText(Global.GetLang("需要完成主线任务") + string.Format(Global.GetLang("【{0}】"), Global.GetTaskTitleByID(timeParameters)), 10, 3);
										return;
									}
									this.OpenRequestMarryPart(0, roleData2.RoleID, roleData2.RoleName);
								}
							}
							else
							{
								Super.HintMainText(Global.GetLang("结婚双方性别必须不同"), 10, 3);
							}
						}
						else
						{
							Super.HintMainText(Global.GetLang("结婚双方角色等级必须达到3转"), 10, 3);
						}
					}
				}
				else if (e.ID == 7)
				{
					if (SceneUIClasses.RebornMap.IsTheScene())
					{
						Super.HintMainText(Global.GetLang("当前不能进行此操作"), 10, 3);
						return;
					}
					Global.Data.otherPlayerTalentData = null;
					GameInstance.Game.OtherObjectFaceID(this.objectFaceID);
					GameInstance.Game.GetOtherTianFuInfoFromServer();
				}
				else if (e.ID == 6)
				{
					if (SceneUIClasses.RebornMap.IsTheScene())
					{
						Super.HintMainText(Global.GetLang("当前不能进行此操作"), 10, 3);
						return;
					}
					PlayZone.GlobalPlayZone.OpenLoversWishPartSendWishWindow(false, this.ObjectRoleFace.VSName, null, 0);
				}
				else if (e.ID == 8)
				{
					RoleData roleData3 = null;
					if (Global.Data.OtherRoles.ContainsKey(this.ObjectRoleFace.RoleID))
					{
						Global.Data.OtherRoles.TryGetValue(this.objectFaceID, ref roleData3);
					}
					bool active = roleData3 != null && roleData3.SpouseId > 0;
					if (Global.IsKuaFuHuoDongMapSceneUIClass(Global.GetMapSceneUIClass()) || Global.GetMapSceneUIClass() == SceneUIClasses.LangHunLingYu || Global.GetMapSceneUIClass() == SceneUIClasses.KuaFuMap || Global.GetMapSceneUIClass() == SceneUIClasses.Comp || Global.GetMapSceneUIClass() == SceneUIClasses.CompBattle || SceneUIClasses.RebornMap.IsTheScene())
					{
						active = false;
					}
					this.ObjectRoleFace.wishBtn.gameObject.SetActive(active);
				}
				else if (e.ID == 9)
				{
					if (SceneUIClasses.RebornMap.IsTheScene())
					{
						Super.HintMainText(Global.GetLang("当前不能进行此操作"), 10, 3);
						return;
					}
					TeamCompeteDataManager.SendInviteTeanMemberMsg(this.ObjectRoleFace.RoleID);
				}
			}
			else if (this.ObjectRoleFace.ObjectFaceType == GSpriteTypes.FakeRole && e.ID == 100)
			{
				FakeRoleData fakeRoleData = null;
				if (Global.Data.FakeRoles.TryGetValue(this.objectFaceID, ref fakeRoleData) && fakeRoleData.FakeRoleType == 1)
				{
					this.OpenOtherStallPart(fakeRoleData.MyRoleDataMini.RoleID);
				}
			}
		};
		this.Root.Children.Add(this.ObjectRoleFace);
	}

