	protected void InitSystemHintWindow()
	{
		SystemErrorText.InitSystemErrorPart(this.Root);
		SystemHintWindow.Root = this.Root;
		GGameInfocs.ClearEvents();
		GGameInfocs.NotifyGameInfoMessage += new EventHandler(this.NotifyGameInfoMessage);
		if (Global.Data.roleData.LoginNum <= 0)
		{
			GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Normal, ShowGameInfoTypes.OnlyBox, Global.GetLang("欢迎来到怒斩的世界!"), 0, -1, -1, 0);
		}
		else
		{
			GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Normal, ShowGameInfoTypes.OnlyBox, Global.GetLang("欢迎回到怒斩的世界!"), 0, -1, -1, 0);
		}
		DateTime dateTime;
		dateTime..ctor(Global.GetCorrectLocalTime() * 10000L);
		GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Normal, ShowGameInfoTypes.OnlyBox, StringUtil.substitute(Global.GetLang("游戏经过服务器校准的时间是: {0}"), new object[]
		{
			dateTime.ToString("yyyy-MM-dd HH:mm:ss")
		}), 0, -1, -1, 0);
	}

