	public void InitBufferBox()
	{
		if (null != this.BufferBox)
		{
			if (this.BufferBox.Visibility)
			{
				this.BufferBox.Hide();
			}
			else
			{
				this.BufferBox.Show();
				this.BufferBox.RefreshDataList();
			}
			return;
		}
		this.BufferBox = DBBufferBox.GGetInstance();
		if (null != this.BufferBox)
		{
			this.BufferBox.Visibility = true;
			this.Root.Children.Add(this.BufferBox);
			this.BufferBox.Z = 90.0;
			this.BufferBox._Close.MouseLeftButtonUp = delegate(object s, MouseEvent e)
			{
				this.BufferBox.Visibility = false;
			};
			this.BufferBox.RefreshDataList();
		}
	}

