	private IEnumerator GetGongGaoAddress(string NoticeContent)
	{
		string url = Global.WebPath("GongGaoAdd.xml");
		WWW www = new WWW(url);
		yield return www;
		if (!string.IsNullOrEmpty(www.error))
		{
			GError.AddErrMsg(string.Format("{0}", Global.GetLang("因为网络原因下载公告配置文件失败...")));
			yield break;
		}
		string content = Global.GetUTF8StringFromBytes(www.bytes);
		XElement xml = XElement.Parse(content);
		List<XElement> xmlList = Global.GetXElementList(xml, "GongGaoAdd");
		for (int i = 0; i < xmlList.Count; i++)
		{
			if ("GongGaoAdd_Android" == Global.GetXElementAttributeStr(xmlList[i], "PingTai"))
			{
				this.gongGaoAddress = Global.GetXElementAttributeStr(xmlList[i], "Add");
			}
		}
		if (!string.IsNullOrEmpty(NoticeContent))
		{
			this.gongGaoAddress = NoticeContent;
			MUDebug.LogError<string>(new string[]
			{
				"111内部调用公告 " + this.gongGaoAddress
			});
		}
		MUDebug.LogError<string>(new string[]
		{
			"222内部调用公告 " + this.gongGaoAddress
		});
		if (null != this.m_GonggaoWindow)
		{
			if (this.m_GonggaoWindow.Visibility)
			{
				this.CloseGonggaoWindow();
			}
			yield break;
		}
		this.m_GonggaoWindow = U3DUtils.NEW<GChildWindow>();
		this.InitChildWindow(this.m_GonggaoWindow, "GonggaoWindow");
		this.Root.Children.Add(this.m_GonggaoWindow);
		this.m_GonggaoWindow.ModalType = ChildWindowModalType.TransBak;
		this.m_GonggaoWindow.ChildWindowClose = delegate(object s, EventArgs e)
		{
			this.CloseGonggaoWindow();
			return true;
		};
		this.m_GonggaoPart = U3DUtils.NEW<WebGongGao>();
		this.m_GonggaoPart.InitGongGaoAddress(this.gongGaoAddress);
		this.m_GonggaoPart.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
		{
			if (e.IDType == -10)
			{
				this.CloseGonggaoWindow();
			}
		};
		this.m_GonggaoWindow.SetContent(this.m_GonggaoWindow.BodyPresenter, this.m_GonggaoPart, 0.0, 0.0, true);
		yield break;
	}

	public void ShowGonggaoWindow(string NoticeContent)
	{
		base.StartCoroutine<bool>(this.GetGongGaoAddress(NoticeContent));
	}

	public void CloseGonggaoWindow()
	{
		if (null != this.m_GonggaoWindow)
		{
			this.m_GonggaoWindow.Visibility = false;
			this.CloseChildWindow(this.m_GonggaoWindow);
			this.m_GonggaoWindow = null;
			this.m_GonggaoPart = null;
		}
		if (this.showPages.charAt(1) == '1')
		{
			this.OPenHuoDongWindow(5, 0);
			this.showPages = "000";
		}
		else if (this.showPages.charAt(2) == '1')
		{
			this.OPenHuoDongWindow(6, 0);
			this.showPages = "000";
		}
		else
		{
			this.showPages = "000";
		}
	}

