	public GChildWindow ShowBaodianGuideWindow(BaodianGuidePart.GuideType winType, DPSelectedItemEventHandler callback, string customLinkIDs = "", string customTitle = "", bool IsShowModel = false)
	{
		if (null != this.m_BaodianGuideWindow)
		{
			if (this.m_BaodianGuideWindow.Visibility)
			{
				this.CloseBaodianGuideWindow();
			}
			return null;
		}
		this.m_BaodianGuideWindow = U3DUtils.NEW<GChildWindow>();
		this.m_BaodianGuideWindow.ModalBak.transform.localPosition = new Vector3(-2000f, -2000f, -2000f);
		base.StartCoroutine<bool>(this.WaitForEndOfFrameEX(delegate(object m, DPSelectedItemEventArgs n)
		{
			this.m_BaodianGuideWindow.ModalBak.transform.localPosition = new Vector3(0f, 0f, 0.1f);
		}));
		this.InitChildWindow(this.m_BaodianGuideWindow, "BaodianGuideWindow");
		this.m_BaodianGuideWindow.ChildWindowClose = delegate(object s, EventArgs e)
		{
			this.CloseBaodianGuideWindow();
			return true;
		};
		this.Root.Children.Add(this.m_BaodianGuideWindow);
		this.m_BaodianGuideWindow.ModalType = ChildWindowModalType.Translucent;
		this.m_BaodianGuidePart = U3DUtils.NEW<BaodianGuidePart>();
		this.m_BaodianGuidePart.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
		{
			if (e.IDType == -10)
			{
				this.CloseBaodianGuideWindow();
			}
			else
			{
				this.CloseBaodianGuideWindow();
				if (callback != null)
				{
					callback(s, e);
				}
				Super.CloseAllUIWindow();
				this.StartCoroutine<bool>(this.WaitForEndOfFrameEX(delegate(object m, DPSelectedItemEventArgs n)
				{
					this.ProcessGuideRequest(e);
				}));
			}
		};
		this.m_BaodianGuideWindow.SetContent(this.m_BaodianGuideWindow.BodyPresenter, this.m_BaodianGuidePart, 0.0, 0.0, true);
		if (IsShowModel)
		{
			ModelShowHide modelShowHide = this.m_BaodianGuidePart.gameObject.AddComponent<ModelShowHide>();
			if (callback != null)
			{
				modelShowHide.goShowHide = (callback.Target as MonoBehaviour).gameObject;
			}
		}
		this.m_BaodianGuidePart.SetWindowType(winType, customLinkIDs, customTitle);
		return this.m_BaodianGuideWindow;
	}

	private IEnumerator WaitForEndOfFrameEX(DPSelectedItemEventHandler Hander)
	{
		yield return new WaitForEndOfFrame();
		if (Hander != null)
		{
			Hander(null, null);
		}
		yield break;
	}

