	public void ProcessGuideRequest(DPSelectedItemEventArgs e)
	{
		if (e.IDType == 0)
		{
			int id = e.ID;
			switch (id)
			{
			case 1450:
				this.ShowFamilyWindow(Global.Data.roleData.Faction, false);
				break;
			default:
				switch (id)
				{
				case 200:
					this.ShowLianluWindow(0, 0);
					break;
				case 201:
					this.ShowLianluWindow(1, 0);
					break;
				case 202:
					this.ShowLianluWindow(5, 0);
					break;
				case 203:
					this.ShowSyntesizeWindow(false, 201);
					break;
				case 204:
					if (Global.g_bIsYaoQingCeShi)
					{
						this.OPenHuoDongWindow(1, 0);
					}
					else
					{
						this.OPenHuoDongWindow(2, 0);
					}
					break;
				case 205:
					this.ShowArenaWindow();
					if (this.m_ArenaPart != null)
					{
						this.m_ArenaPart.ShowJunXianPart();
					}
					break;
				case 206:
					this.ProcessFactionEvent();
					if (this.familyPart != null)
					{
						this.familyPart.ShowSubWindow(0);
					}
					break;
				case 207:
					this.ShowArenaWindow();
					break;
				case 208:
					if (Global.Data.roleData.BHName.Equals(string.Empty))
					{
						Super.HintMainText(Global.GetLang("该活动需要加入战盟才能参加"), 10, 3);
						return;
					}
					this.ProcessFactionEvent();
					if (this.familyPart != null)
					{
						this.familyPart.ShowActivityWindow();
						if (null != this.familyPart.m_familyActivity)
						{
							FamilyActivityBtnitem familyActivityBtnitem = new FamilyActivityBtnitem();
							familyActivityBtnitem.Id = 2;
							this.familyPart.m_familyActivity.ListTabBtn.SelectedIndex = 1;
						}
					}
					break;
				case 209:
					if (Global.Data.roleData.BHName.Equals(string.Empty))
					{
						Super.HintMainText(Global.GetLang("该活动需要加入战盟才能参加"), 10, 3);
						return;
					}
					this.ProcessFactionEvent();
					if (this.familyPart != null)
					{
						this.familyPart.ShowActivityWindow();
						if (null != this.familyPart.m_familyActivity)
						{
							FamilyActivityBtnitem familyActivityBtnitem2 = new FamilyActivityBtnitem();
							familyActivityBtnitem2.Id = 3;
							this.familyPart.m_familyActivity.ListTabBtn.SelectedIndex = 2;
						}
					}
					break;
				case 210:
					this.ShowLianluWindow(7, 0);
					break;
				case 211:
					this.ShowSyntesizeWindow(false, 301);
					break;
				case 212:
					if (Global.Data.roleData.BHName.Equals(string.Empty))
					{
						Super.HintMainText(Global.GetLang("该活动需要加入战盟才能参加"), 10, 3);
						return;
					}
					this.ProcessFactionEvent();
					if (this.familyPart != null)
					{
						this.familyPart.ShowActivityWindow();
						if (null != this.familyPart.m_familyActivity)
						{
							FamilyActivityBtnitem familyActivityBtnitem3 = new FamilyActivityBtnitem();
							familyActivityBtnitem3.Id = 4;
							this.familyPart.m_familyActivity.ListTabBtn.SelectedIndex = 3;
						}
					}
					break;
				case 213:
					this.ShowActivityWindow(false, 1200, -1);
					if (null != PlayZone.GlobalPlayZone._ActivityPart && null != this._ActivityPart._KuafuActivityPart)
					{
						this._ActivityPart._KuafuActivityPart.activityList.SelectedIndex = 4;
					}
					break;
				case 214:
					this.ShowActivityWindow(false, 1200, -1);
					if (null != this._ActivityPart && null != this._ActivityPart._KuafuActivityPart)
					{
						this._ActivityPart._KuafuActivityPart.activityList.SelectedIndex = 0;
					}
					break;
				case 215:
					this.ShowActivityWindow(false, 1200, -1);
					if (null != this._ActivityPart && null != this._ActivityPart._KuafuActivityPart)
					{
						this._ActivityPart._KuafuActivityPart.activityList.SelectedIndex = 2;
					}
					break;
				case 216:
					this.ShowActivityWindow(false, 1200, -1);
					if (null != this._ActivityPart && null != this._ActivityPart._KuafuActivityPart)
					{
						this._ActivityPart._KuafuActivityPart.activityList.SelectedIndex = 6;
					}
					break;
				case 217:
					this.ShowActivityWindow(false, 1200, -1);
					if (null != this._ActivityPart && null != this._ActivityPart._KuafuActivityPart)
					{
						this._ActivityPart._KuafuActivityPart.activityList.SelectedIndex = 5;
					}
					break;
				default:
					switch (id)
					{
					case 100:
						this.ShowActivityWindow(false, 101, -1);
						break;
					default:
						switch (id)
						{
						case 300:
							this.ShowActivityWindow(false, 0, -1);
							break;
						case 301:
							this.ShowActivityWindow(false, 600 + Global.HuoDongPageById(RiChangHuoDongTypes.BloodCastle), -1);
							break;
						case 302:
							this.ShowActivityWindow(false, 600 + Global.HuoDongPageById(RiChangHuoDongTypes.Demon), -1);
							break;
						case 303:
							this.ShowMallWindow(false, 0, 0);
							break;
						case 304:
							this.ShowGamePayerRoleWindow(GamePayerRolePart_PartID.GamePayerRolePart_ChuShou);
							break;
						case 305:
							this.ShowMuDuiHuanWindow(0, 0);
							break;
						case 306:
							if (null != this.JingLingPart.jingling)
							{
								this.JingLingPart.jingling.DPSelectedItem(this, new DPSelectedItemEventArgs
								{
									ID = -10
								});
							}
							this.ShowGamePayerRoleWindow(GamePayerRolePart_PartID.GamePayerRolePart_JingLIngHuiShou);
							break;
						default:
							switch (id)
							{
							case 400:
							{
								int trigger = 0;
								int param = 0;
								int param2 = 0;
								if (!GongnengYugaoMgr.IsGongNengOpened(GongNengIDs.QiFu, ref trigger, ref param, ref param2))
								{
									UIHelper.HintGongNengOpenCondition(GongNengIDs.QiFu, trigger, param, param2, true);
									return;
								}
								this.ShowZaDanWindow(false);
								break;
							}
							default:
								switch (id)
								{
								case 1000:
									this.ShowActivityWindow(false, 900 + Global.HuoDongPageById(RiChangHuoDongTypes.GuZhanChang), -1);
									break;
								case 1001:
									this.ShowActivityWindow(false, 600 + Global.HuoDongPageById(RiChangHuoDongTypes.Battle), -1);
									break;
								case 1002:
									this.ShowActivityWindow(false, 600 + Global.HuoDongPageById(RiChangHuoDongTypes.AngelTemple), -1);
									break;
								default:
									switch (id)
									{
									case 700:
										PlayZone.GlobalPlayZone.ShowGamePayerRoleWindow(GamePayerRolePart_PartID.GamePayerRolePart_JiNeng);
										break;
									case 701:
										PlayZone.GlobalPlayZone.ShowGamePayerRoleWindow(GamePayerRolePart_PartID.GamePayerRolePart_ChiBang);
										break;
									case 702:
										PlayZone.GlobalPlayZone.ShowGamePayerRoleWindow(GamePayerRolePart_PartID.GamePayerRolePart_XingHun);
										break;
									case 703:
										this.CloseRelatedToParcelPart();
										PlayZone.GlobalPlayZone.ShowGamePayerRoleWindow(GamePayerRolePart_PartID.GamePayerRolePart_BeiBao);
										break;
									default:
										switch (id)
										{
										case 601:
											this.ShowChongZhiWindow();
											break;
										case 602:
											this.ShowMallWindow(false, 0, 0);
