	protected Point GetErrTextPoint(GameInfoTextItem gameInfoTextItem)
	{
		if (gameInfoTextItem.ToX != -1 && gameInfoTextItem.ToY != -1)
		{
			return this.Root.globalToLocal(new Point(gameInfoTextItem.ToX, gameInfoTextItem.ToY));
		}
		if (gameInfoTextItem.ShowGameInfoType != ShowGameInfoTypes.OnlyErr && gameInfoTextItem.ShowGameInfoType != ShowGameInfoTypes.ErrAndBox)
		{
			return new Point(-1, -1);
		}
		if (gameInfoTextItem.GameInfoTypeIndex != GameInfoTypeIndexes.Error)
		{
			return new Point(-1, -1);
		}
		return this.CurrentMousePos;
	}

	protected void NotifyGameInfoMessage(object sender, object e)
	{
		try
		{
			if (GGameInfocs.GameInfoTextList.Count > 0)
			{
				if (GGameInfocs.GameInfoTextList[GGameInfocs.GameInfoTextList.Count - 1].ShowGameInfoType == ShowGameInfoTypes.OnlySysHint || GGameInfocs.GameInfoTextList[GGameInfocs.GameInfoTextList.Count - 1].ShowGameInfoType == ShowGameInfoTypes.SysHintAndChatBox)
				{
					SystemHintWindow.AddHintText(GGameInfocs.GameInfoTextList[GGameInfocs.GameInfoTextList.Count - 1], (double)FontSizeMgr.SystemHintTextBigFontSize, 3000);
				}
				else if (GGameInfocs.GameInfoTextList[GGameInfocs.GameInfoTextList.Count - 1].ShowGameInfoType == ShowGameInfoTypes.HintAndBox)
				{
					SystemHintWindow.AddHintText(GGameInfocs.GameInfoTextList[GGameInfocs.GameInfoTextList.Count - 1], (double)FontSizeMgr.SystemHintTextBigFontSize, 3000);
					if (null != this.GameInfobox)
					{
						this.GameInfobox.AddHintText(GGameInfocs.GameInfoTextList[GGameInfocs.GameInfoTextList.Count - 1]);
					}
					Super.AddPersonalHintText(GGameInfocs.GameInfoTextList[GGameInfocs.GameInfoTextList.Count - 1]);
				}
				else if (GGameInfocs.GameInfoTextList[GGameInfocs.GameInfoTextList.Count - 1].ShowGameInfoType == ShowGameInfoTypes.OnlyBox)
				{
					if (null != this.GameInfobox)
					{
						this.GameInfobox.AddHintText(GGameInfocs.GameInfoTextList[GGameInfocs.GameInfoTextList.Count - 1]);
					}
					Super.AddPersonalHintText(GGameInfocs.GameInfoTextList[GGameInfocs.GameInfoTextList.Count - 1]);
				}
				else if (GGameInfocs.GameInfoTextList[GGameInfocs.GameInfoTextList.Count - 1].ShowGameInfoType == ShowGameInfoTypes.OnlyErr)
				{
					GameInfoTextItem gameInfoTextItem = GGameInfocs.GameInfoTextList[GGameInfocs.GameInfoTextList.Count - 1];
					Point errTextPoint = this.GetErrTextPoint(gameInfoTextItem);
					SystemErrorText.ShowErrorText(this.Root, errTextPoint.X, errTextPoint.Y, Super.GetGameInfoTextItemColor(gameInfoTextItem), gameInfoTextItem.TextMsg, ShowGameInfoTypes.OnlyErr);
				}
				else if (GGameInfocs.GameInfoTextList[GGameInfocs.GameInfoTextList.Count - 1].ShowGameInfoType == ShowGameInfoTypes.ErrAndBox)
				{
					GameInfoTextItem gameInfoTextItem2 = GGameInfocs.GameInfoTextList[GGameInfocs.GameInfoTextList.Count - 1];
					Point errTextPoint2 = this.GetErrTextPoint(gameInfoTextItem2);
					SystemErrorText.ShowErrorText(this.Root, errTextPoint2.X, errTextPoint2.Y, Super.GetGameInfoTextItemColor(gameInfoTextItem2), gameInfoTextItem2.TextMsg, ShowGameInfoTypes.OnlyErr);
					if (null != this.GameInfobox)
					{
						this.GameInfobox.AddHintText(GGameInfocs.GameInfoTextList[GGameInfocs.GameInfoTextList.Count - 1]);
					}
					Super.AddPersonalHintText(GGameInfocs.GameInfoTextList[GGameInfocs.GameInfoTextList.Count - 1]);
				}
				else if (GGameInfocs.GameInfoTextList[GGameInfocs.GameInfoTextList.Count - 1].ShowGameInfoType == ShowGameInfoTypes.LittleSysHint)
				{
					SystemHintWindow.AddHintText(GGameInfocs.GameInfoTextList[GGameInfocs.GameInfoTextList.Count - 1], (double)FontSizeMgr.SystemHintTextSmallFontSize, 3000);
				}
				else if (GGameInfocs.GameInfoTextList[GGameInfocs.GameInfoTextList.Count - 1].ShowGameInfoType == ShowGameInfoTypes.PiaoFuZi)
				{
					GameInfoTextItem gameInfoTextItem3 = GGameInfocs.GameInfoTextList[GGameInfocs.GameInfoTextList.Count - 1];
					Super.HintMainText(gameInfoTextItem3.TextMsg, 10, 3);
				}
				this.ProcessGameInfoTextErrCode(GGameInfocs.GameInfoTextList[GGameInfocs.GameInfoTextList.Count - 1].ErrCode, GGameInfocs.GameInfoTextList[GGameInfocs.GameInfoTextList.Count - 1].TextMsg, GGameInfocs.GameInfoTextList[GGameInfocs.GameInfoTextList.Count - 1].ToBuyGoodsID);
			}
		}
		catch (Exception ex)
		{
			MUDebug.LogException(ex);
		}
	}

