	protected void InitCaijiBar()
	{
		this.caijiBar = U3DUtils.NEW<CaiJiBar>();
		this.Root.Children.Add(this.caijiBar);
		this.caijiBar.Visibility = false;
		this.caijiBar.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
		{
			if (e.IDType == 1)
			{
				if (e.ID == 0)
				{
					GameInstance.Game.SpriteCaiJi(this.caijiBar.CaiJiRoleID);
				}
				else if (e.ID == 1)
				{
					if (this.isNPCCaiJi)
					{
						this.isNPCCaiJi = false;
						this.ClickNPC(this.caijiBar.CaiJiRoleID, 1);
					}
					else
					{
						GameInstance.Game.SpriteFinishCaiji(this.caijiBar.CaiJiRoleID);
					}
				}
			}
			else if (e.IDType == -1)
			{
				this.StopCaiji(false);
			}
		};
	}

	protected void StartCaiji(int roleID, int value, CaijiTypes type, bool isNPC = false)
	{
		if (!this.caijiBar.Visibility || roleID != this.caijiBar.CaiJiRoleID)
		{
			this.isNPCCaiJi = isNPC;
			this.caijiBar.gameObject.SetActive(true);
			this.caijiBar.Visibility = true;
			this.caijiBar.StartCaiJi(roleID, value, type);
			this.scene.DoAction(GActions.Collect);
		}
	}

	public void StopCaiji(bool isRecoverAction = false)
	{
		if (this.caijiBar == null)
		{
			return;
		}
		if (!this.caijiBar.Visibility)
		{
			return;
		}
		this.caijiBar.Visibility = false;
		this.caijiBar.StopCaiJi();
		if (isRecoverAction)
		{
			this.scene.DoAction(GActions.Stand);
		}
	}

