	public void InitMaskWin(SystemOpenVO data, bool auto = false)
	{
		if (null == this.maskWin)
		{
			this.maskWin = U3DUtils.NEW<GImgScrollShowWindow>();
			this.maskWin.WinBackgroundURL = new ImageURL(Global.GetGameResImageURL("Images/Plate/gongnenYugaoWin_bak.png"), false, 0);
			this.maskWin.Left = (double)((int)((Global.GlobalMainWindow.ActualWidth - 304.0) / 2.0) + 304);
			this.maskWin.Top = (double)((int)((Global.GlobalMainWindow.ActualHeight - 327.0) / 2.0));
			this.maskWin.BodyLeft = 0.0;
			this.maskWin.BodyTop = 0.0;
			this.maskWin.BodyWidth = 304.0;
			this.maskWin.BodyHeight = 327.0;
			this.maskWin.CloseButtonWidth = 13.0;
			this.maskWin.CloseButtonHeight = 13.0;
			this.maskWin.CloseButtonLeft = 252.0;
			this.maskWin.CloseButtonTop = 28.0;
			this.maskWin.CloseButtonFill = Global.GetGameResImage("Images/Plate/x1.png");
			this.maskWin.CloseButtonTransformFill = Global.GetGameResImage("Images/Plate/x0.png");
			this.maskWin.Angle90 = true;
			this.maskWin.EffectID = 517;
			this.maskWin.EffectPos = new Point(145, 260);
			this.maskWin.ChildWindowClose = delegate(object s, EventArgs e)
			{
				this.CloseMaskWin();
				return true;
			};
			this.Root.Children.Add(this.maskWin);
			this.maskPart = U3DUtils.NEW<MaskPart>();
			this.maskPart.InitPartSize((int)this.maskWin.BodyWidth, (int)this.maskWin.BodyHeight);
			this.maskPart.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
			{
				if (e.IDType == 1)
				{
					this.CloseMaskWin();
					this.ProcessImgAnimation(e.ID);
					this.yugao.SetItemByLevel(false);
				}
			};
			this.maskWin.SetContent(this.maskWin.Body, this.maskPart);
		}
		this.maskWin.CloseButtonVisible = !auto;
		this.maskPart.InitPartData(data);
		this.maskWin.ScrollShowWindow();
	}

	protected void ProcessImgAnimation(int id)
	{
		SystemOpenVO systemOpenVOByID = ConfigSystemOpen.GetSystemOpenVOByID(id);
		if (systemOpenVOByID != null && systemOpenVOByID.DongHua != -1)
		{
			Global.Data.GameScene.CancelAutoFight(0, true);
			Global.Data.GameScene.CancelAutoFindRoad(true);
			Global.Data.GameScene.CancelLockObject(false);
			this.SetFaceVisiable(-1);
			Global.Data.WaitingForSystemHelp = true;
			GongnengYugaoMgr.ReadyFlyingImgAnimation(this.Root, id);
		}
	}

	protected void InitHintIconBar()
	{
		this.SysHintIconBar = U3DUtils.NEW<HintIconBar>();
		this.SysHintIconBar.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
		{
			if (e.IDType != 0)
			{
				if (e.IDType == 1)
				{
					if (!this.IsShowLeaderAttributeWindow())
					{
						this.ProcessUserAttribEvent(1);
					}
				}
				else if (e.IDType == 2)
				{
					if (!this.IsShowParcelWindow())
					{
						this.ProcessParcelEvent();
					}
				}
				else if (e.IDType == 3)
				{
					if (!this.IsShowBiguanWindow())
					{
						this.ProcessBiGuanEvent();
					}
				}
				else if (e.IDType == 5)
				{
					if (!this.IsShowLeaderAttributeWindow())
					{
						this.ProcessUserAttribEvent(2);
					}
				}
				else if (e.IDType == 8)
				{
					if (!this.IsShowGiftBagsWindow())
					{
						this.ShowHuoDongWindow(false, 5);
					}
				}
				else if (e.IDType == 9 && !this.IsShowGiftBagsWindow())
				{
					this.ShowHuoDongWindow(false, 6);
				}
			}
		};
		this.Root.Children.Add(this.SysHintIconBar);
	}

