	public void RefreshRoleArmor(int SpriteID, float value)
	{
		if (!ConfigVersionSystemOpen.IsVersionSystemOpen(100100))
		{
			value = 1f;
		}
		if (SpriteID == Global.Data.RoleID)
		{
			if (null != this.LeaderRoleFace)
			{
				this.LeaderRoleFace.RefreshLeaderArmor(value);
			}
		}
		else if (Global.Data.OtherRoles.ContainsKey(SpriteID))
		{
			if (null != this.ObjectRoleFace && this.ObjectRoleFace.RoleID == SpriteID)
			{
				this.ObjectRoleFace.RefreshLeaderArmor(value);
			}
		}
		else if (Global.Data.FakeRoles.ContainsKey(SpriteID) && null != this.ObjectRoleFace && this.ObjectRoleFace.RoleID == SpriteID)
		{
			this.ObjectRoleFace.RefreshLeaderArmor(value);
		}
	}

	public void InitPlayerSelfInfo()
	{
		this.LeaderRoleFace = U3DUtils.NEW<FacePlate>();
		this.LeaderRoleFace.Left = 0.0;
		this.LeaderRoleFace.Top = 0.0;
		this.LeaderRoleFace.ZIndex = 0;
		this.LeaderRoleFace.VSName = Global.FormatRoleName(Global.Data.roleData);
		if (SceneUIClasses.RebornMap.IsTheScene())
		{
			this.LeaderRoleFace.VLevel = StringUtil.substitute(Global.GetLang("重生{0}"), new object[]
			{
				Global.Data.roleData.RebornLevel.ToString()
			});
		}
		else
		{
			this.LeaderRoleFace.VLevel = StringUtil.substitute(Global.GetLang("{0}[{1}转]"), new object[]
			{
				Global.Data.roleData.Level,
				Global.Data.roleData.ChangeLifeCount
			});
		}
		this.LeaderRoleFace.PKMode_v = Global.Data.roleData.PKMode;
		this.LeaderRoleFace.VipLev = Global.GetVIPLeve();
		this.LeaderRoleFace.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
		{
			if (e.ID == 0)
			{
				if (Global.IsKuaFuHuoDongMapSceneUIClass(Global.GetMapSceneUIClass()) || Global.GetMapSceneUIClass() == SceneUIClasses.LangHunLingYu)
				{
					Super.HintMainText(Global.GetLang("当前不能进行此操作"), 10, 3);
				}
				else if (Global.Data.roleData.MapCode == 70000 || Global.Data.roleData.MapCode == 70100 || Global.Data.roleData.MapCode == 70200 || (Global.Data.roleData.MapCode >= 80000 && Global.Data.roleData.MapCode <= 80010))
				{
					Super.HintMainText(Global.GetLang("当前不能进行此操作"), 10, 3);
				}
				else if (SceneUIClasses.RebornMap.IsTheScene())
				{
					this.ShowRebirthMianWind();
				}
				else
				{
					this.SwitchMainUI(!this.uiVisible);
				}
			}
			else if (e.ID == 1)
			{
				this.ShowPVPMenuWindow(0, 0);
			}
			else if (e.ID == 2)
			{
				if (Global.IsKuaFuHuoDongMapSceneUIClass(Global.GetMapSceneUIClass()) || SceneUIClasses.LangHunLingYu.IsTheScene() || SceneUIClasses.RebornMap.IsTheScene())
				{
					Super.HintMainText(Global.GetLang("当前不能进行此操作"), 10, 3);
				}
				else
				{
					this.ShowMUVipWindow(1);
				}
			}
		};
		string rolePhotoUrl = StringUtil.substitute("NetImages/Face/{0}{1}_0.png", new object[]
		{
			Global.CalcOriginalOccupationID(Global.Data.roleData.Occupation),
			Global.Data.roleData.RoleSex
		});
		this.LeaderRoleFace.RolePhotoUrl = rolePhotoUrl;
		if (Global.Data.roleData.MaxLifeV > 0)
		{
			this.LeaderRoleFace.LifePercent = (double)Global.Data.roleData.LifeV / (double)Global.Data.roleData.MaxLifeV;
		}
		if (Global.Data.roleData.MaxMagicV > 0)
		{
			this.LeaderRoleFace.MagicPercent = (double)Global.Data.roleData.MagicV / (double)Global.Data.roleData.MaxMagicV;
		}
		this.Root.Children.Add(this.LeaderRoleFace);
	}

	private void SwitchMainUI(bool visible)
	{
		if (visible == this.uiVisible || this.GameMenuIconBoxContainer.isStarted)
		{
			return;
		}
		SceneUIClasses mapSceneUIClass = Global.GetMapSceneUIClass();
		if (mapSceneUIClass == SceneUIClasses.JingJiChang && this.uiVisible)
		{
			return;
		}
		if (SystemHelpMgr.ActiveHelpID > 0)
		{
			if (this.uiVisible || SystemHelpMgr.ActiveHelpID == 1000)
			{
				this.LeaderRoleFace.ShowHelpAnim(SystemHelpMgr.ActiveHelpID, 0);
			}
			SystemHelpMgr.OnAction(UIObjIDs.LeaderRoleFace, HelpStateEvents.Clicked, (!this.uiVisible) ? 0 : 1);
		}
		this.uiVisible = visible;
		if (this.uiVisible)
		{
			this.GameMenuIconBoxContainer.BodyVisible = false;
			this.BufferBoxMini.Visibility = true;
			Global.IsShowGongNengYuGaoItemPart(true);
		}
		else
		{
			this.SetUIVisible(this.uiVisible);
			this.GameMenuIconBoxContainer.BodyVisible = true;
			this.BufferBoxMini.Visibility = false;
			this.ObjectRoleFace.Visibility = false;
			this.MonsterFace.Visibility = false;
			this.BossFace.Visibility = false;
			Global.IsShowGongNengYuGaoItemPart(false);
		}
	}

