		{
			if (ev.IDType == 0)
			{
				if (ev.ID == 0)
				{
					this.ShowGameChatBoxWindow(0, string.Empty);
				}
			}
			else if (ev.IDType == 1)
			{
				this.ShowInteractionWindow();
			}
			else if (ev.IDType == 2)
			{
				if (Global.GetMapSceneUIClass() == SceneUIClasses.AKaLunDong || Global.GetMapSceneUIClass() == SceneUIClasses.AKaLunXi)
				{
					Super.HintMainText(Global.GetLang("当前不能进行此操作"), 10, 3);
				}
				else if (Global.GetMapSceneUIClass() == SceneUIClasses.CompBattle)
				{
					Super.HintMainText(Global.GetLang("当前不能进行此操作"), 10, 3);
				}
				else
				{
					this.ProcessQuickFightEvent();
				}
			}
			else if (ev.IDType == 3)
			{
				if (Global.IsKuaFuHuoDongMapSceneUIClass(Global.GetMapSceneUIClass()) || Global.GetMapSceneUIClass() == SceneUIClasses.JingJiChang)
				{
					Super.HintMainText(Global.GetLang("当前不能进行此操作"), 10, 3);
				}
				else if (SceneUIClasses.RebornMap.IsTheScene())
				{
					this.ShowGamePayerRoleWindow(GamePayerRolePart_PartID.GamePayerRolePart_BeiBaoChongSheng);
				}
				else
				{
					this.ShowGamePayerRoleWindow(GamePayerRolePart_PartID.GamePayerRolePart_BeiBao);
				}
			}
			else if (ev.IDType == 4)
			{
				this.ShowArmyTeQuanWindow();
			}
		};
		this.Root.Children.Add(this.GameChatBoxMini);
	}

