	public void InitGameTopIconBox()
	{
		this.GameTopIconBox = U3DUtils.NEW<TopIconBox>();
		this.GameTopIconBox.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
		{
			if (e.ID == 0)
			{
				this.OPenHuoDongWindow(0, 0);
			}
			else if (e.ID == 1)
			{
				if (Global.IsOperateUnPermitInKuaFuMapCheck(true, false))
				{
					return;
				}
				this.ShowActivityWindow(true, 0, -1);
			}
			else if (e.ID == 2)
			{
				if (Global.IsOperateUnPermitInKuaFuMapCheck(true, false))
				{
					return;
				}
				this.ShowActivityWindow(false, 0, -1);
			}
			else if (e.ID == 3)
			{
				this.ShowMingXiangWindow();
			}
			else if (e.ID == 4)
			{
				this.ShowArenaWindow();
			}
			else if (e.ID == 5)
			{
				if (Global.IsOperateUnPermitInKuaFuMapCheck(true, false))
				{
					return;
				}
				if (1 < HuoDongCommonFlag.GetTopIconBoxDownRightIconIsOpen().Count)
				{
					this.OnQiRiKuangHuanActivityIconClicked(e);
				}
				else
				{
					this.OpenServerActiveWindow();
				}
			}
			else if (e.ID == 6)
			{
				this.ShowGongnengIconWindow(e.Tag as Transform);
			}
			else if (e.ID == 7)
			{
				if (Global.IsOperateUnPermitInKuaFuMapCheck(true, false))
				{
					return;
				}
				this.OPenHuoDongWindow(0, 0);
				if (null != this.m_HuoDongPart && null != this.m_HuoDongPart.m_ChongzhiHuikuiPart)
				{
					this.m_HuoDongPart.m_ChongzhiHuikuiPart.initItemPart(0);
				}
			}
			else if (e.ID == 8)
			{
				if (Global.IsOperateUnPermitInKuaFuMapCheck(true, false))
				{
					return;
				}
				this.OPenHuoDongWindow(0, 1);
				if (null != this.m_HuoDongPart && null != this.m_HuoDongPart.m_ChongzhiHuikuiPart)
				{
					this.m_HuoDongPart.m_ChongzhiHuikuiPart.initItemPart(1);
				}
			}
			else if (e.ID == 9)
			{
				this.ShowChongZhiWindow();
			}
			else if (e.ID == 10)
			{
				if (Global.IsOperateUnPermitInKuaFuMapCheck(true, false))
				{
					return;
				}
				if (1 < HuoDongCommonFlag.GetTopIconBoxDownRightIconIsOpen().Count)
				{
					this.OnQiRiKuangHuanActivityIconClicked(e);
				}
				else
				{
					this.OpenHefuhuodongWindow();
				}
			}
			else if (e.ID == 11)
			{
				if (HuoDongCommonFlag.TopIconTreeActivityActivedLst().Count > 1)
				{
					this.OpenMergedActivityWindow(e.Tag as Transform);
				}
				else
				{
					this.OpenJieRihuodongWindow();
				}
			}
			else if (e.ID == 20)
			{
				if (HuoDongCommonFlag.TopIconTreeActivityActivedLst().Count > 1)
				{
					this.OpenMergedActivityWindow(e.Tag as Transform);
				}
				else
				{
					if (Global.IsOperateUnPermitInKuaFuMapCheck(true, false))
					{
