	public void GongNengIconAddAnim(PlayGameContolEvent evt)
	{
		if (evt != null)
		{
			int num = (int)evt.argu;
			if (null != this.GameMenuIconBoxContainer)
			{
				if (num == 0)
				{
					this.GameMenuIconBoxContainer.ReSetIconPos();
				}
				else if ((num >= 2 && num <= 10) || num == 57 || num == 11 || num == 58 || num == 59 || num == 60 || num == 61 || num == 62 || num == 63 || num == 64 || num == 68 || num == 69 || num == 70 || num == 71 || num == 72 || num == 73 || num == 74 || num == 75 || num == 76 || num == 77 || num == 78 || num == 79)
				{
					this.GameMenuIconBoxContainer.PrepareAddIconAnim(num);
				}
			}
		}
	}

