						return;
					}
					this.OpenShenHunPartWindow(ShenHunType.FuTi);
				}
				else if (e.ID == 34)
				{
					byte b = 0;
					if (Global.Data != null && Global.Data.roleData != null && 0 < Global.Data.roleData.RebornCount)
					{
						b = 1;
