					{
						this.OpenTeamCompeteCreatePart();
					}
					else
					{
						this.OpenTeamCompeteMainPart();
					}
				}
			}
			else if (e.IDType == 1)
			{
				if (e.ID == 0)
				{
					this.SetUIVisible(this.uiVisible);
				}
				if (null != GongnengYugaoMgr.img)
				{
					GongnengYugaoMgr.img.OnUIReady();
				}
