	public void OnChangeSceneUI()
	{
		SceneUIClasses mapSceneUIClass = Global.GetMapSceneUIClass();
		if (null != this.GameCtrlBar)
		{
			this.GameCtrlBar.CancelAutoUseSkill();
		}
		if (mapSceneUIClass == SceneUIClasses.MoYu)
		{
			GameInstance.Game.SpriteUpdatePKMode(2);
			this.GameTaskBoxMini.SetMoYuNumber(-1);
		}
		if (mapSceneUIClass == SceneUIClasses.ShiLian)
		{
			GameInstance.Game.SpriteUpdatePKMode(3);
		}
		this.HideFace();
		this.CancelNPCDialogWindows();
		if (mapSceneUIClass == SceneUIClasses.BloodCastle)
		{
			Global.Data.DisableAutoRoad = true;
		}
		else
		{
			Global.Data.DisableAutoRoad = false;
		}
		if (mapSceneUIClass == SceneUIClasses.NewPlayerMap)
		{
			if (null != this.BufferBoxMini)
			{
				this.BufferBoxMini.Visibility = false;
			}
			if (null != this.GameTeamGroupBox)
			{
				this.GameTeamGroupBox.Visibility = false;
			}
		}
		else
		{
			if (null != this.BufferBoxMini)
			{
				this.BufferBoxMini.Visibility = true;
			}
			if (null != this.GameTeamGroupBox)
			{
				this.GameTeamGroupBox.Visibility = true;
			}
		}
		if (null != this._FuBenPassPart && this._FuBenPassPart && this._FuBenPassPart.IsActive && this._FuBenPassPart.DPSelectedItem != null)
		{
			this._FuBenPassPart.DPSelectedItem(null, null);
		}
		if (null != this.loversWishPart_TeXiaoWish)
		{
			this.CloseLoversWishWindow();
		}
		this.HideAngleTempleGuWuIcon();
		this.HideMainAngelTempleGuWuPart();
		this.CloseActivityWindow();
		this.CloseFamilyWindow();
		if (this.mDaTaoShaMainPart != null && this.mDaTaoShaMainPartWind != null)
		{
			this.mDaTaoShaMainPart.CloseAllWindow();
			this.CloseDaTaoShaMainPart();
		}
	}

	public void SetMainUIForScene()
	{
		SceneUIClasses mapSceneUIClass = Global.GetMapSceneUIClass();
		Global.IsShowGongNengYuGaoItemPart(false);
		if (this.GameChatBoxMini != null)
		{
		}
		if (null != this.GameTaskBoxMini)
		{
			this.GameTaskBoxMini.EnterMapScene();
			this.GameTaskBoxMini.RefreshTasks(-1, -1, true);
			if (null != this.GameFubenBoxMini)
			{
				this.GameFubenBoxMini.GameTaskBoxMini = this.GameTaskBoxMini;
				this.GameFubenBoxMini.ReUpdateFuBenStepData(mapSceneUIClass);
			}
		}
		try
		{
			if (Context.IsHaiwai)
			{
				RoleData roleData = Global.Data.roleData;
				if (roleData != null && roleData.GMAuth > 0)
				{
					MUDebug.Log<string>(new string[]
					{
						"GM开关打开"
					});
					Context.IsShowGmMenuInMobile = true;
					this.RadarMap.btnShare.gameObject.SetActive(false);
					this.RadarMap.btnShare2.gameObject.SetActive(true);
				}
				else
				{
					Context.IsShowGmMenuInMobile = false;
					this.RadarMap.btnShare.gameObject.SetActive(false);
					this.RadarMap.btnShare2.gameObject.SetActive(false);
				}
			}
			this.scene.RemoveShengbeiDec(Global.Data.RoleID, 101);
			this.scene.RemoveShengbeiDec(Global.Data.RoleID, 2080001);
			this.scene.RemoveShengbeiDec(Global.Data.RoleID, 2080007);
			this.scene.RemoveShengbeiDec(Global.Data.RoleID, 2080008);
			this.scene.RemoveShengbeiDec(Global.Data.RoleID, 2080009);
			if (mapSceneUIClass == SceneUIClasses.NormalCopy || mapSceneUIClass == SceneUIClasses.FamilyBoss || mapSceneUIClass == SceneUIClasses.BloodCastle || mapSceneUIClass == SceneUIClasses.Demon || mapSceneUIClass == SceneUIClasses.JingYanFuBen || mapSceneUIClass == SceneUIClasses.NewPlayerMap || mapSceneUIClass == SceneUIClasses.PaTa || mapSceneUIClass == SceneUIClasses.JinBiFuBen || mapSceneUIClass == SceneUIClasses.ShuiJingHuanJing || mapSceneUIClass == SceneUIClasses.EMoLaiXiCopy || mapSceneUIClass == SceneUIClasses.LuolanFazhen || mapSceneUIClass == SceneUIClasses.HuanYingSiYuan || mapSceneUIClass == SceneUIClasses.TianTi || mapSceneUIClass == SceneUIClasses.YongZheZhanChang || mapSceneUIClass == SceneUIClasses.ElementWar || mapSceneUIClass == SceneUIClasses.MoRiJudge || mapSceneUIClass == SceneUIClasses.CopyWolf || mapSceneUIClass == SceneUIClasses.KuaFuBoss || mapSceneUIClass == SceneUIClasses.ShiLian || mapSceneUIClass == SceneUIClasses.MoYu || mapSceneUIClass == SceneUIClasses.OnePiece)
			{
				this.GameTopIconBox.Visibility = false;
				this.GameTaskBoxMini.Visibility = true;
				this.GameFubenBoxMini.Visibility = true;
				this.GameFubenBoxMini.InitPartData();
				FubenBoxMini.TrySendLuoLanFaZhenQuest();
				if (mapSceneUIClass == SceneUIClasses.OnePiece)
				{
					this.SwitchMainUI((!this.m_HaveCloseCangBaoMiJing) ? this.uiVisible : (!this.uiVisible));
				}
			}
			else if (mapSceneUIClass == SceneUIClasses.AngelTemple || mapSceneUIClass == SceneUIClasses.Battle || mapSceneUIClass == SceneUIClasses.PKKing || mapSceneUIClass == SceneUIClasses.KaLiMaTemple || mapSceneUIClass == SceneUIClasses.FamilyBoss || mapSceneUIClass == SceneUIClasses.LoveFuBen || mapSceneUIClass == SceneUIClasses.ZhongShenZhengBa || mapSceneUIClass == SceneUIClasses.PKLovers || mapSceneUIClass == SceneUIClasses.ZhengDuoZhiDi || mapSceneUIClass == SceneUIClasses.LingDiCaiJi || mapSceneUIClass == SceneUIClasses.ZhanMengLianSaiBiSai)
			{
				this.GameTopIconBox.Visibility = false;
				this.GameTaskBoxMini.Visibility = false;
				this.GameFubenBoxMini.Visibility = true;
