			Debug.LogError(ex.StackTrace);
			Debug.LogError("__________________________________");
		}
		if (Global.Data.roleData.MapCode == 14000 || Global.Data.roleData.MapCode == 14001 || Global.Data.roleData.MapCode == 14002 || Global.Data.roleData.MapCode == 14003)
		{
