			{
				Object.Destroy(this._BattleScoreBox.gameObject);
			}
			if (this.GameChatBoxMini)
			{
				Object.Destroy(this.GameChatBoxMini.gameObject);
			}
			if (this.GameTaskBoxMini)
			{
