			this.GameHintQueueIcon.gameObject.SetActive(true);
		}
		if (mapSceneUIClass == SceneUIClasses.JingYanFuBen || mapSceneUIClass == SceneUIClasses.PaTa || mapSceneUIClass == SceneUIClasses.JinBiFuBen || mapSceneUIClass == SceneUIClasses.KaLiMaTemple || mapSceneUIClass == SceneUIClasses.NormalCopy || mapSceneUIClass == SceneUIClasses.FamilyBoss || mapSceneUIClass == SceneUIClasses.BloodCastle || mapSceneUIClass == SceneUIClasses.Demon || mapSceneUIClass == SceneUIClasses.AngelTemple || mapSceneUIClass == SceneUIClasses.EMoLaiXiCopy || mapSceneUIClass == SceneUIClasses.FamilyBoss || mapSceneUIClass == SceneUIClasses.LuolanFazhen || mapSceneUIClass == SceneUIClasses.LoveFuBen || mapSceneUIClass == SceneUIClasses.KuaFuWangZhe || mapSceneUIClass == SceneUIClasses.OnePiece || mapSceneUIClass == SceneUIClasses.ZhengDuoZhiDi || mapSceneUIClass == SceneUIClasses.AKaLunDong || mapSceneUIClass == SceneUIClasses.AKaLunXi || mapSceneUIClass == SceneUIClasses.ZhanMengLianSaiBiSai || mapSceneUIClass == SceneUIClasses.WanMoXiaGu || mapSceneUIClass == SceneUIClasses.CompBattle || Global.InKuafuFuben())
		{
			this.ShowAngleTempleGuWuIcon();
		}
		else
		{
			this.HideAngleTempleGuWuIcon();
		}
		if (Global.Data.roleData.MapCode == 70000)
		{
			this.GameTopIconBox.Visibility = false;
			this.GameFubenBoxMini.Visibility = true;
			this.GameTaskBoxMini.Visibility = true;
			this.GameFubenBoxMini.InitPartData();
		}
		if (Global.Data.roleData.MapCode == 70100)
