		}
		if (Global.Data.roleData.MapCode == 70200)
		{
		}
		if (Global.IsInKuafuHuodongYongZheZhanChang())
		{
			this.HideAngleTempleGuWuIcon();
		}
		JingLingMapEvent.ProcessEvent(EmJingMapEvent.SetMainUIForScene);
		KuaFuPlunderEventProcessor.ProcessEvent(EmKuaFuPlunderEvent.EnterPlunderMap);
		if (PlayZone.GlobalPlayZone)
		{
			PlayZone.GlobalPlayZone.CloseActivityWindow();
			PlayZone.GlobalPlayZone.CloseQiRiKuangHuanWindow();
			PlayZone.GlobalPlayZone.CloseGrowFundWindow();
			PlayZone.GlobalPlayZone.CloseAoYunDaTiWindow();
			PlayZone.GlobalPlayZone.CloseLianzhiWindow();
			PlayZone.GlobalPlayZone.CloseSystemSetting();
		}
