	protected void FormatTextItemClick(object sender, EventArgs _e)
	{
		TextSelectionChangedEventArgs textSelectionChangedEventArgs = _e as TextSelectionChangedEventArgs;
		if (textSelectionChangedEventArgs.Text.Length > 3)
		{
			string text = textSelectionChangedEventArgs.Text.Substring(1, textSelectionChangedEventArgs.Text.Length - 2);
			if (text == Global.GetLang("我要充值"))
			{
				Super.OpenChongZhiHtmlWindow();
			}
			else if (text == Global.GetLang("成为VIP"))
			{
				this.ProcessMallEvent((int)ConfigSystemParam.GetSystemParamIntByName("VIPGoodsID"));
			}
			else if (text == Global.GetLang("查看VIP特权"))
			{
				this.ShowMUVipWindow(1);
			}
			else if (text == Global.GetLang("查看BOSS信息"))
			{
				this.ShowActivityWindow(false, 700, -1);
			}
			else if (text == Global.GetLang("我要进阶坐骑"))
			{
				if (!this.IsShowLeaderAttributeWindow())
				{
					this.ProcessUserAttribEvent(1);
				}
			}
			else if (text == Global.GetLang("我要强化装备"))
			{
				this.ShowLianluWindow(0, 0);
			}
			else if (text == Global.GetLang("我要炼化神装"))
			{
				this.ShowLianluWindow(3, 0);
			}
			else if (text == Global.GetLang("我要精炼装备"))
			{
				this.ShowEnhanceWindow();
			}
			else if (text == Global.GetLang("我要精锻装备"))
			{
				this.ShowSubForgeWindow(-1);
			}
			else if (text == Global.GetLang("我要进阶装备"))
			{
				this.ShowEquipUpgradeWindow();
			}
			else if (text == Global.GetLang("我要传承装备"))
			{
				this.ShowLianluWindow(2, 0);
			}
			else if (text == Global.GetLang("我要领取"))
			{
				this.ShowHuoDongWindow(false, 1);
			}
			else if (text == Global.GetLang("我要下注"))
			{
				Global.GotoShengXiaoGuessNPC();
			}
			else if (text == Global.GetLang("我要下载"))
			{
				this.DoIWantDownloadMinyClient();
			}
			else if (text == Global.GetLang("点击加入"))
			{
				this.ShowFamilyListWindow(false);
			}
			else if (text != Global.FormatRoleName(Global.Data.roleData))
			{
				Point position = new global::MousePosition(textSelectionChangedEventArgs.e).GetPosition(this.Root);
				this.ShowFormatedRoleMenuWindow(position.X, position.Y, text);
			}
		}
	}

