	protected void ChatChannelMouseLeftButtonUp(object sender, EventArgs e)
	{
		if (null != this.ChatChannelMenuWindow)
		{
			this.CloseNoBorderWindow(this.ChatChannelMenuWindow);
			this.ChatChannelMenuWindow = null;
			this.menuPart = null;
		}
