	private void InitTestData()
	{
		Global.Data.roleData.RebornExperience = 100000L;
		Global.Data.roleData.MoneyData[148] = Global.Data.roleData.RebornExperience * 3L;
		Global.Data.roleData.MoneyData[149] = Global.Data.roleData.RebornExperience * 2L;
	}

	protected void RefreshLeaderExprienceBar()
	{
		if (SceneUIClasses.RebornMap.IsTheScene())
		{
			if (!this.LeaderExperience.EXPBarEX.Visibility)
			{
				this.LeaderExperience.EXPBarEX.Visibility = true;
			}
			if (Global.Data != null && Global.Data.roleData != null)
			{
				if (Global.Data.roleData.RebornLevel > IConfigbase<ConfigRebirth>.Instance.GetMaxLevel())
				{
					this.LeaderExperience.EXPPercent = 1.0;
					this.LeaderExperience.ExpValue = Global.Data.roleData.RebornExperience.ToString();
				}
				else
				{
					RebornLevelVO rebornLevelVOByID = IConfigbase<ConfigRebirth>.Instance.GetRebornLevelVOByID(Global.Data.roleData.RebornLevel);
					if (rebornLevelVOByID != null && 0 < rebornLevelVOByID.NeedRebornExp)
					{
						this.LeaderExperience.EXPPercent = (double)Global.Data.roleData.RebornExperience / (double)rebornLevelVOByID.NeedRebornExp;
						StringBuilder stringBuilder = new StringBuilder();
						stringBuilder.Append(Global.Data.roleData.RebornExperience).Append(" / ").Append(rebornLevelVOByID.NeedRebornExp);
						this.LeaderExperience.ExpValue = stringBuilder.ToString();
					}
				}
			}
			else
			{
				this.LeaderExperience.EXPPercent = 1.0;
				this.LeaderExperience.ExpValue = Global.Data.roleData.RebornExperience.ToString();
			}
		}
		else
		{
			if (this.LeaderExperience.EXPBarEX.Visibility)
			{
				this.LeaderExperience.EXPBarEX.Visibility = false;
			}
			if (Global.Data.roleData.Level <= Global.Data.LevelUpExperienceList.Length - 1)
			{
				double num = (double)Global.Data.LevelUpExperienceList[Math.Min(Global.Data.roleData.Level, Global.Data.LevelUpExperienceList.Length - 1)];
				double num2 = 0.0;
				if (Global.Data.LevelUpExpProportionList.TryGetValue(Global.Data.roleData.ChangeLifeCount, ref num2))
				{
					num *= num2;
				}
				if (num > 0.0)
				{
					this.LeaderExperience.EXPPercent = (double)Global.Data.roleData.Experience / num;
					StringBuilder stringBuilder2 = new StringBuilder();
					stringBuilder2.Append(Global.Data.roleData.Experience).Append(" / ").Append(num);
					this.LeaderExperience.ExpValue = stringBuilder2.ToString();
				}
				else
				{
					this.LeaderExperience.ExpValue = string.Empty;
					this.LeaderExperience.EXPPercent = 0.0;
				}
			}
			else
			{
				this.LeaderExperience.EXPPercent = 1.0;
				this.LeaderExperience.ExpValue = Global.Data.roleData.Experience.ToString();
			}
		}
	}

	public void RefreshRoleFace()
	{
		if (PlayZone.bRefreshRoleFace)
		{
			if (null != this.LeaderRoleFace)
			{
				if (Global.Data.roleData.MaxLifeV > 0)
				{
					double num = (double)Global.Data.roleData.MaxLifeV;
					this.LeaderRoleFace.LifePercent = (double)Global.Data.roleData.LifeV / num;
					Global.Data.roleData.LifeV = Math.Min(Global.Data.roleData.LifeV, (int)num);
					this.LeaderRoleFace.LifeText = StringUtil.substitute("{0}/{1}", new object[]
					{
						Global.Data.roleData.LifeV,
						num
					});
				}
				if (Global.Data.roleData.MaxMagicV > 0)
				{
					double num = (double)Global.Data.roleData.MaxMagicV;
					Global.Data.roleData.MagicV = Math.Min(Global.Data.roleData.MagicV, (int)num);
					this.LeaderRoleFace.MagicPercent = (double)Global.Data.roleData.MagicV / num;
					this.LeaderRoleFace.MagicText = StringUtil.substitute("{0}/{1}", new object[]
					{
						Global.Data.roleData.MagicV,
						num
					});
				}
				if (SceneUIClasses.RebornMap.IsTheScene())
				{
					this.LeaderRoleFace.VLevel = StringUtil.substitute(Global.GetLang("重生{0}"), new object[]
					{
						Global.Data.roleData.RebornLevel.ToString()
					});
				}
				else
				{
					this.LeaderRoleFace.VLevel = StringUtil.substitute(Global.GetLang("{0}[{1}转]"), new object[]
					{
						Global.Data.roleData.Level.ToString(),
						Global.Data.roleData.ChangeLifeCount.ToString()
					});
				}
				this.LeaderRoleFace.VipLev = Global.GetVIPLeve();
			}
			PlayZone.bRefreshRoleFace = false;
		}
	}

	protected void NotifyLeaderRoleFace(int enemyRoleID, bool refreshLeader = true)
	{
		if (refreshLeader)
		{
			PlayZone.bRefreshRoleFace = true;
		}
		if (null == this.ObjectRoleFace)
		{
			return;
		}
		if (!this.ObjectRoleFace.Visibility && !this.MonsterFace.Visibility)
		{
			return;
		}
		if (this.objectFaceID != enemyRoleID)
		{
			return;
		}
		if (this.ObjectFaceType == GSpriteTypes.Other)
		{
			RoleData roleData = null;
			if (Global.Data.OtherRoles.ContainsKey(this.objectFaceID))
			{
				Global.Data.OtherRoles.TryGetValue(this.objectFaceID, ref roleData);
				this.ObjectRoleFace.VLevel = Global.FormatRoleLevel(roleData);
				this.ObjectRoleFace.RoleID = roleData.RoleID;
				this.ObjectRoleFace.ObjectFaceType = GSpriteTypes.Other;
				this.ObjectRoleFace.StallName = roleData.StallName;
				if (roleData.MaxLifeV > 0)
				{
					this.ObjectRoleFace.LifePercent = (double)roleData.LifeV / (double)roleData.MaxLifeV;
				}
				if (roleData.MaxMagicV > 0)
				{
					this.ObjectRoleFace.MagicPercent = (double)roleData.MagicV / (double)roleData.MaxMagicV;
				}
			}
		}
		else if (this.ObjectFaceType == GSpriteTypes.FakeRole)
		{
			FakeRoleData fakeRoleData = null;
			if (Global.Data.FakeRoles.ContainsKey(this.objectFaceID))
			{
				Global.Data.FakeRoles.TryGetValue(this.objectFaceID, ref fakeRoleData);
				this.ObjectRoleFace.VLevel = Global.FormatRoleLevel(fakeRoleData.MyRoleDataMini);
				this.ObjectRoleFace.RoleID = fakeRoleData.MyRoleDataMini.RoleID;
				this.ObjectRoleFace.ObjectFaceType = GSpriteTypes.FakeRole;
				if (fakeRoleData.MyRoleDataMini.MaxLifeV > 0)
				{
					this.ObjectRoleFace.LifePercent = (double)fakeRoleData.MyRoleDataMini.LifeV / (double)fakeRoleData.MyRoleDataMini.MaxLifeV;
				}
				if (fakeRoleData.MyRoleDataMini.MaxMagicV > 0)
				{
					this.ObjectRoleFace.MagicPercent = (double)fakeRoleData.MyRoleDataMini.MagicV / (double)fakeRoleData.MyRoleDataMini.MaxMagicV;
				}
			}
		}
	}

	protected void NotifyRoleFace(int injuredRoleID, int attackerRoleID, bool refreshLeader = false)
	{
		this.NotifyLeaderRoleFace(attackerRoleID, refreshLeader);
		if (this.OtherFaceType == OtherFaceTypes.None || this.objectFaceID != injuredRoleID)
		{
			return;
		}
		if (this.ObjectFaceType == GSpriteTypes.Monster)
		{
			MonsterData monsterData = null;
			if (Global.Data.SystemMonsters.TryGetValue(this.objectFaceID, ref monsterData))
			{
				this.ObjectRoleFace.ObjectFaceType = GSpriteTypes.Monster;
				if (monsterData.MaxLifeV > 0.0)
				{
					if (this.OtherFaceType == OtherFaceTypes.BOSS)
					{
						this.BossFace.UpdateLife(monsterData.LifeV);
					}
					else if (this.OtherFaceType == OtherFaceTypes.Monster)
					{
						this.MonsterFace.LifePercent = monsterData.LifeV / monsterData.MaxLifeV;
					}
				}
			}
		}
		else if (this.ObjectFaceType == GSpriteTypes.BiaoChe)
		{
			if (Global.Data.BiaoChes.ContainsKey(this.objectFaceID))
			{
			}
		}
		else if (this.ObjectFaceType == GSpriteTypes.JunQi)
		{
			if (Global.Data.JunQis.ContainsKey(this.objectFaceID))
			{
			}
		}
		else if (this.ObjectFaceType == GSpriteTypes.Other)
		{
			RoleData roleData = null;
			if (Global.Data.OtherRoles.ContainsKey(this.objectFaceID))
			{
				Global.Data.OtherRoles.TryGetValue(this.objectFaceID, ref roleData);
				this.ObjectRoleFace.ObjectFaceType = GSpriteTypes.Other;
				this.ObjectRoleFace.VLevel = Global.FormatRoleLevel(roleData);
				this.ObjectRoleFace.RoleID = roleData.RoleID;
				this.ObjectRoleFace.StallName = roleData.StallName;
				if (roleData.MaxLifeV > 0)
				{
					this.ObjectRoleFace.LifePercent = (double)roleData.LifeV / (double)roleData.MaxLifeV;
				}
				if (roleData.MaxMagicV > 0)
				{
					this.ObjectRoleFace.MagicPercent = (double)roleData.MagicV / (double)roleData.MaxMagicV;
				}
			}
		}
		else if (this.ObjectFaceType == GSpriteTypes.FakeRole)
		{
			FakeRoleData fakeRoleData = null;
			if (Global.Data.FakeRoles.ContainsKey(this.objectFaceID))
			{
				Global.Data.FakeRoles.TryGetValue(this.objectFaceID, ref fakeRoleData);
				this.ObjectRoleFace.ObjectFaceType = GSpriteTypes.FakeRole;
				this.ObjectRoleFace.VLevel = Global.FormatRoleLevel(fakeRoleData.MyRoleDataMini);
				this.ObjectRoleFace.RoleID = fakeRoleData.FakeRoleID;
				if (fakeRoleData.MyRoleDataMini.MaxLifeV > 0)
				{
					this.ObjectRoleFace.LifePercent = (double)fakeRoleData.MyRoleDataMini.LifeV / (double)fakeRoleData.MyRoleDataMini.MaxLifeV;
				}
				if (fakeRoleData.MyRoleDataMini.MaxMagicV > 0)
				{
					this.ObjectRoleFace.MagicPercent = (double)fakeRoleData.MyRoleDataMini.MagicV / (double)fakeRoleData.MyRoleDataMini.MaxMagicV;
				}
			}
		}
	}

