	protected bool CloseMostTopChildWindow()
	{
		bool result = false;
		if (this.ChildWindowList.Count <= 0)
		{
			return result;
		}
		int num = 0;
		GChildWindow gchildWindow = null;
		for (int i = 0; i < this.ChildWindowList.Count; i++)
		{
			if (this.ChildWindowList[i].Visibility)
			{
				int num2 = (int)Canvas.GetZIndex(this.ChildWindowList[i]);
				if (num2 > num)
				{
					num = num2;
					gchildWindow = this.ChildWindowList[i];
				}
			}
		}
		if (null != gchildWindow)
		{
			result = true;
			gchildWindow.NotifyClose(-1);
		}
		return result;
	}

	protected GChildWindow GetMostTopChildWindow()
	{
		if (this.ChildWindowList.Count <= 0)
		{
			return null;
		}
		int num = 0;
		GChildWindow result = null;
		for (int i = 0; i < this.ChildWindowList.Count; i++)
		{
			if (this.ChildWindowList[i].Visibility)
			{
				int num2 = (int)Canvas.GetZIndex(this.ChildWindowList[i]);
				if (num2 > num)
				{
					num = num2;
					result = this.ChildWindowList[i];
				}
			}
		}
		return result;
	}

