	private void SetFaceVisiable(int type)
	{
		this.ObjectRoleFace.Visibility = (type == 0);
		this.MonsterFace.Visibility = (type == 1);
		this.BossFace.Visibility = (type == 2);
	}

	protected void ShowObjectRoleFace(SpriteNotifyEventArgs e)
	{
		if (null == this.ObjectRoleFace)
		{
			return;
		}
		this.ObjectFaceType = e.SpriteType;
		this.objectFaceID = e.RoleID;
		if (this.ObjectFaceType == GSpriteTypes.Other)
		{
			this.OtherFaceType = OtherFaceTypes.Other;
			RoleData roleData = null;
			if (Global.Data.OtherRoles.ContainsKey(this.objectFaceID))
			{
				Global.Data.OtherRoles.TryGetValue(this.objectFaceID, ref roleData);
				if (roleData != null && roleData.LifeV <= 0)
				{
					return;
				}
				this.SwitchMainUI(true);
				this.SetFaceVisiable(0);
				this.ObjectRoleFace.VSName = Global.FormatRoleName(roleData);
				this.ObjectRoleFace.ShowName = Global.FormatShowName(roleData, 1);
				this.ObjectRoleFace.VLevel = Global.FormatRoleLevel(roleData);
				this.ObjectRoleFace.RoleID = roleData.RoleID;
				this.ObjectRoleFace.isTeam = (roleData.TeamID > 0);
				this.ObjectRoleFace.ObjectFaceType = GSpriteTypes.Other;
				string rolePhotoUrl = StringUtil.substitute("NetImages/Face/{0}{1}_0.png", new object[]
				{
					Global.CalcOriginalOccupationID(roleData.Occupation),
					roleData.RoleSex
				});
				this.ObjectRoleFace.RolePhotoUrl = rolePhotoUrl;
				this.ObjectRoleFace.Visibility = true;
				this.ObjectRoleFace.StallName = roleData.StallName;
				if (roleData.TeamID <= 0)
				{
					this.ObjectRoleFace.TeamMode = false;
				}
				else
				{
					this.ObjectRoleFace.TeamMode = true;
				}
				if (roleData.MaxLifeV > 0)
				{
					this.ObjectRoleFace.LifePercent = (double)roleData.LifeV / (double)roleData.MaxLifeV;
				}
				if (roleData.MaxMagicV > 0)
				{
					this.ObjectRoleFace.MagicPercent = (double)roleData.MagicV / (double)roleData.MaxMagicV;
				}
			}
		}
		else if (this.ObjectFaceType == GSpriteTypes.FakeRole)
		{
			this.OtherFaceType = OtherFaceTypes.Other;
			FakeRoleData fakeRoleData = null;
			if (Global.Data.FakeRoles.ContainsKey(this.objectFaceID))
			{
				this.SwitchMainUI(true);
				this.SetFaceVisiable(0);
				Global.Data.FakeRoles.TryGetValue(this.objectFaceID, ref fakeRoleData);
				this.ObjectRoleFace.VSName = Global.FormatRoleName(fakeRoleData.MyRoleDataMini);
				this.ObjectRoleFace.ShowName = Global.FormatShowName(fakeRoleData.MyRoleDataMini);
				this.ObjectRoleFace.VLevel = Global.FormatRoleLevel(fakeRoleData.MyRoleDataMini);
				this.ObjectRoleFace.RoleID = fakeRoleData.FakeRoleID;
				this.ObjectRoleFace.ObjectFaceType = GSpriteTypes.FakeRole;
				string rolePhotoUrl2 = StringUtil.substitute("NetImages/Face/{0}{1}_0.png", new object[]
				{
					Global.CalcOriginalOccupationID(fakeRoleData.MyRoleDataMini.Occupation),
					fakeRoleData.MyRoleDataMini.RoleSex
				});
				this.ObjectRoleFace.RolePhotoUrl = rolePhotoUrl2;
				this.ObjectRoleFace.Visibility = true;
				if (fakeRoleData.MyRoleDataMini.TeamID <= 0)
				{
					this.ObjectRoleFace.TeamMode = false;
				}
				else
				{
					this.ObjectRoleFace.TeamMode = true;
				}
			}
		}
		else if (this.ObjectFaceType == GSpriteTypes.Monster)
		{
			MonsterData monsterData = null;
			if (Global.Data.SystemMonsters.ContainsKey(this.objectFaceID))
			{
				this.ObjectRoleFace.ObjectFaceType = GSpriteTypes.Monster;
				Global.Data.SystemMonsters.TryGetValue(this.objectFaceID, ref monsterData);
				this.SwitchMainUI(true);
				if (this.ObjectRoleFace.Visibility)
				{
					this.ObjectRoleFace.Visibility = false;
				}
				if (monsterData == null)
				{
					return;
				}
				if (monsterData.MonsterType == 1101)
				{
					if (!this.caijiBar.Visibility)
					{
						this.caijiBar.Visibility = true;
						this.caijiBar.StartCaiJi(monsterData.MasterRoleID, (int)monsterData.LifeV, CaijiTypes.ByLife);
					}
					this.SetFaceVisiable(3);
					this.OtherFaceType = OtherFaceTypes.CAIJI;
				}
				else
				{
					MonsterVO monsterXmlNodeByID = ConfigMonsters.GetMonsterXmlNodeByID(monsterData.ExtensionID);
					int[] xueTiaoType = monsterXmlNodeByID.XueTiaoType;
					if (xueTiaoType.Length != 2 || xueTiaoType[0] == 1)
					{
						this.OtherFaceType = OtherFaceTypes.Monster;
						this.MonsterFace.RoleID = monsterData.RoleID;
						this.MonsterFace.VLevel = monsterData.MonsterLevel.ToString();
						this.MonsterFace.VSName = monsterData.RoleName;
						if (monsterData.MaxLifeV > 0.0)
						{
							this.MonsterFace.LifePercent = monsterData.LifeV / monsterData.MaxLifeV;
						}
						this.MonsterFace.Visibility = true;
						this.SetFaceVisiable(1);
					}
					else if (xueTiaoType[0] == 2)
					{
						this.OtherFaceType = OtherFaceTypes.BOSS;
						this.SetFaceVisiable(2);
						if (!this.BossFace.Visibility || this.BossFace.MonsterID != monsterData.ExtensionID)
						{
							this.BossFace.RoleID = monsterData.RoleID;
							this.BossFace.MonsterID = monsterData.ExtensionID;
							this.BossFace.VLevel = monsterData.MonsterLevel.ToString();
							this.BossFace.VSName = monsterData.RoleName;
							if (xueTiaoType.Length == 2 && xueTiaoType[0] == 2 && xueTiaoType[1] > 1)
							{
								this.BossFace.SetLifeInfo(monsterData.MaxLifeV, xueTiaoType[1], monsterData.MonsterLevel);
							}
							else
							{
								this.BossFace.SetLifeInfo(monsterData.MaxLifeV, 1, monsterData.MonsterLevel);
							}
						}
						this.BossFace.UpdateLife(monsterData.LifeV);
					}
				}
			}
		}
		else if (this.ObjectFaceType == GSpriteTypes.JunQi)
		{
			JunQiData junQiData = null;
			if (Global.Data.JunQis.ContainsKey(this.objectFaceID))
			{
				this.ObjectRoleFace.ObjectFaceType = GSpriteTypes.JunQi;
				Global.Data.JunQis.TryGetValue(this.objectFaceID, ref junQiData);
				this.SwitchMainUI(true);
				if (this.ObjectRoleFace.Visibility)
				{
					this.ObjectRoleFace.Visibility = false;
				}
				if (junQiData == null)
				{
					return;
				}
				this.OtherFaceType = OtherFaceTypes.Monster;
				this.MonsterFace.RoleID = junQiData.JunQiID;
				this.MonsterFace.VLevel = junQiData.JunQiLevel.ToString();
				this.MonsterFace.VSName = junQiData.QiName;
				if (junQiData.LifeV > 0)
				{
					this.MonsterFace.LifePercent = (double)junQiData.CurrentLifeV / (double)junQiData.LifeV;
				}
				this.MonsterFace.Visibility = true;
				this.SetFaceVisiable(1);
			}
		}
		else
		{
			this.SetFaceVisiable(-1);
		}
	}

	protected void InitRadarMap()
	{
		this.RadarMap = U3DUtils.NEW<GRadarMap>();
		this.RadarMap.Left = 0.0;
		this.RadarMap.Top = 0.0;
		this.RadarMap.ZIndex = 1.0;
		this.RadarMap.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
		{
			if (e.ID == 0)
			{
				this.ShowEmailWindow(true, string.Empty);
			}
			else if (e.ID == 1)
			{
				this.ShowAutoPlayWindow(false);
			}
			else if (e.ID == 2)
			{
				this.ShowWorldNavigationWindow(false);
			}
			else if (e.ID == 3)
			{
				this.ProcessExceptionEvent();
			}
			else if (e.ID == 4)
			{
				MUDebug.Log<string>(new string[]
				{
					string.Concat(new object[]
					{
						"海外指令状态：",
						Context.IsHaiwai,
						"---",
						Context.IsShowGmMenuInMobile
					})
				});
				if (!Context.IsHaiwai || !Context.IsShowGmMenuInMobile)
				{
					string systemParamByName = ConfigSystemParam.GetSystemParamByName("TenAwardInvite", true);
					if (systemParamByName != "-1" && PlatSDKMgr.PlatName == "YYB")
					{
						this.ShowInviteWindow(false);
					}
					else
					{
						this.ShowShareWindow(false);
					}
				}
			}
			else if (e.ID == 5)
			{
				this.ShowVideoWindow();
			}
			else if (e.ID == 6)
			{
				this.ShowInteractionWindow();
			}
			else if (e.ID == 7 && Context.IsHaiwai)
			{
				this.ShowGoogleWindow();
			}
		};
		this.Root.Children.Add(this.RadarMap);
		Global.Data.GameRadarMap = this.RadarMap;
		this.LoadRadarMap();
	}

	protected void LoadRadarMap()
	{
		this.RadarMap.MiniMap.URL = StringUtil.substitute("NetImages/MiniMap/{0}.png", new object[]
		{
			ConfigSettings.GetMapPicCodeByCode(Global.Data.roleData.MapCode)
		});
		this.RadarMap.MapName.text = StringUtil.substitute("{0}", new object[]
		{
			ConfigSettings.GetMapNameByCode(Global.Data.roleData.MapCode, false)
		});
		this.RadarMap.ScalingX = 0f;
		this.RadarMap.ScalingY = 0f;
	}

