		this.dingWeiWindow.BodyTop = 63.0;
		this.dingWeiWindow.BodyWidth = 304.0;
		this.dingWeiWindow.BodyHeight = 370.0;
		this.dingWeiWindow.Left = (double)(Super.GetChildLeft((int)Global.GlobalMainWindow.ActualWidth, 1000) + 550 - 306);
		this.dingWeiWindow.Top = (double)(Super.GetChildTop((int)Global.GlobalMainWindow.ActualHeight, 600) + 35);
