	public void ShowNPCLuaDialogWindow(int npcID, int npcExenstionID, bool caching = false)
	{
		if (this.scene.IsInStalling())
		{
			return;
		}
		if (this.IsShowNPCLuaDialogWindow() && null != this.NpcLuaDialogPart && npcID == this.NpcLuaDialogPart.NpcID && npcExenstionID == this.NpcLuaDialogPart.NpcExtensionID)
		{
			return;
		}
		this.CancelNPCDialogWindows();
		if (npcID > 0)
		{
			GSprite gsprite = this.scene.FindSprite(StringUtil.substitute("Role_{0}", new object[]
			{
				npcID
			}));
		}
		if (null != this.NPCLuaDialogWindow)
		{
			if (this.NPCLuaDialogWindow.Visibility)
			{
				this.CloseNPCLuaDialogWindow();
			}
			this.NpcLuaDialogPart.NpcID = npcID;
			this.NpcLuaDialogPart.NpcExtensionID = npcExenstionID;
			this.NpcLuaDialogPart.GetNewData();
			this.NPCLuaDialogWindow.TitleText = ConfigNPCs.GetNPCNameByID(npcExenstionID);
			this.LimitChildWindowRange(this.NPCLuaDialogWindow);
			Super.SwitchSelfWindowAndMainUI(this.NPCLuaDialogWindow.gameObject, true);
			return;
		}
		this.NPCLuaDialogWindow = U3DUtils.NEW<GChildWindow>();
		this.NPCLuaDialogWindow.ModalType = ChildWindowModalType.TransBak;
		this.InitChildWindow(this.NPCLuaDialogWindow, "NPCDialog");
		this.NPCLuaDialogWindow.ChildWindowClose = delegate(object s, EventArgs e)
		{
			this.CloseNPCLuaDialogWindow();
			return true;
		};
		Global.MainStage.Children.Add(this.NPCLuaDialogWindow);
		this.NpcLuaDialogPart = U3DUtils.NEW<LuaPublicDialogPart>();
		this.NpcLuaDialogPart.InitPartSize((int)this.NPCLuaDialogWindow.BodyWidth - 20, (int)this.NPCLuaDialogWindow.BodyHeight - 20);
		this.NpcLuaDialogPart.InitPartData();
		this.NpcLuaDialogPart.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
		{
			npcID = (s as LuaPublicDialogPart).NpcID;
			npcExenstionID = (s as LuaPublicDialogPart).NpcExtensionID;
			this.CloseNPCLuaDialogWindow();
		};
		this.NpcLuaDialogPart.HandleLuaCmd = new HandleLuaHander(this.HandleLuaCmd);
		if (!caching)
		{
			this.NpcLuaDialogPart.NpcID = npcID;
			this.NpcLuaDialogPart.NpcExtensionID = npcExenstionID;
			this.NpcLuaDialogPart.GetNewData();
		}
		this.NPCLuaDialogWindow.SetContent(this.NPCLuaDialogWindow.BodyPresenter, this.NpcLuaDialogPart, 0.0, 0.0, false);
		this.LimitChildWindowRange(this.NPCLuaDialogWindow);
		Super.SwitchSelfWindowAndMainUI(this.NPCLuaDialogWindow.gameObject, true);
		if (caching)
		{
			this.NPCLuaDialogWindow.Visibility = false;
		}
	}

