	}

	protected bool HandleLuaCmd(object s, string e)
	{
		string text = e.ToString();
		if ("_jingyuanexchange" == text)
		{
			this.ShowDuiHuanWindow();
			return true;
		}
		if ("_huizhangexchange" == text)
		{
			this.ShowHuiZhangSHWindow();
			return true;
		}
		return false;
	}

