	protected bool HookOpenNPCDialogWindow(int npcID, int npcExenstionID)
	{
		if (npcExenstionID == 211)
		{
			this.ShowRepetitionWindow(npcID, false, ActivityCategorys.JuQingFuBen, -1);
			return true;
		}
		if (npcExenstionID == 1000002)
		{
			this.ShowShiLianTaWindow();
			return true;
		}
		return false;
	}

