			{
				npcID
			}));
		}
		if (null != this.NPCDialogWindow)
		{
			if (this.NPCDialogWindow.Visibility)
			{
				this.CloseNPCDialogWindow();
			}
			this.NPCDialogWindow.TitleText = ConfigNPCs.GetNPCNameByID(npcExenstionID);
			this.NPCDialogWindow.Visibility = true;
			this.LimitChildWindowRange(this.NPCDialogWindow);
			if ((double)GChildWindow.ZZ > Canvas.GetZIndex(this.NPCDialogWindow))
			{
				Canvas.SetZIndex(this.NPCDialogWindow, (double)GChildWindow.ZZ);
			}
			this.NpcDialogPart.NpcID = npcID;
			this.NpcDialogPart.NpcExtensionID = npcExenstionID;
			this.NpcDialogPart.GetNewData();
			Super.SwitchSelfWindowAndMainUI(this.NPCDialogWindow.gameObject, true);
			return;
		}
		this.NPCDialogWindow = U3DUtils.NEW<GChildWindow>();
		this.InitChildWindow(this.NPCDialogWindow, "NPCDialog");
		this.NPCDialogWindow.ChildWindowClose = delegate(object s, EventArgs e)
		{
			this.CloseNPCDialogWindow();
			return true;
		};
		Global.MainStage.Children.Add(this.NPCDialogWindow);
		this.NPCDialogWindow.ModalType = ChildWindowModalType.TransBak;
		this.NpcDialogPart = U3DUtils.NEW<NPCDialogPart>();
		this.NpcDialogPart.BodyBackgroundURL = new ImageURL(Global.GetGameResImageString("npc_bak.png"), false, 0);
		this.NpcDialogPart._Close.MouseLeftButtonUp = delegate(object s, MouseEvent e)
		{
			this.CloseNPCDialogWindow();
