	public void LeftButtonClickOnSprite(object sender, SpriteNotifyEventArgs e)
	{
		Global.ViewSprite = null;
		if (e.RoleID == -1)
		{
			return;
		}
		this.ShowObjectRoleFace(e);
		if (e.SpriteType == GSpriteTypes.Other)
		{
			Global.ViewSprite = StringUtil.substitute("Role_{0}", new object[]
			{
				e.RoleID
			});
		}
		else if (e.SpriteType == GSpriteTypes.NPC)
		{
			if (e.ShowDlg)
			{
				if (null != this.NPCSaleWindow)
				{
					this.CloseChildWindow(this.NPCSaleWindow);
					this.NPCSaleWindow = null;
					this.NpcSalePart.Destroy();
					this.NpcSalePart = null;
				}
				this.ProcessNpcClickOnStart(e);
			}
		}
		else if (e.SpriteType == GSpriteTypes.Monster)
		{
			MonsterData monsterData = null;
			Global.Data.SystemMonsters.TryGetValue(e.RoleID, ref monsterData);
			if (monsterData != null)
			{
				if (monsterData.MonsterType == 1101)
				{
					this.StartCaiji(e.RoleID, (int)monsterData.MaxLifeV, CaijiTypes.ByLife, false);
				}
				else if (monsterData.MonsterType == 1601)
				{
					if (Global.IsEnableCaiji())
					{
						this.StopCaiji(false);
						GameInstance.Game.SpriteStartCaiji(monsterData.RoleID);
					}
				}
			}
		}
	}

	public void SpriteDeadNotify(object sender, SpriteNotifyEventArgs e)
	{
		if (e.RoleID == Global.Data.RoleID)
		{
			if (null == this.m_FuhuoPanle)
			{
				Global.Data.MapCodeAtDeath = Global.Data.roleData.MapCode;
				GameInstance.Game.SpriteDead();
			}
		}
		else if (null != this.ObjectRoleFace && this.objectFaceID == e.RoleID)
		{
			if (this.ObjectRoleFace.Visibility)
			{
				this.ObjectRoleFace.Visibility = false;
			}
			if (this.MonsterFace.Visibility)
			{
				this.MonsterFace.Visibility = false;
			}
			if (this.BossFace.Visibility)
			{
				this.BossFace.Visibility = false;
			}
			if (this.caijiBar.Visibility)
			{
				this.StopCaiji(true);
				this.caijiBar.Visibility = false;
			}
		}
		this.scene.RemoveEmblem(e.RoleID, (int)ConfigSystemParam.GetSystemParamIntByName("EmblemProp"), 1, 0);
	}

	public void KillSpriteNotify(object sender, object _e)
	{
		SpriteNotifyEventArgs spriteNotifyEventArgs = _e as SpriteNotifyEventArgs;
		if (spriteNotifyEventArgs != null)
		{
			if (spriteNotifyEventArgs.SpriteType == GSpriteTypes.Monster)
			{
				this.ShowEnterAutoFightWizard();
				Global.Data.GameRadarMap.RemoveRolePoint(spriteNotifyEventArgs.RoleID);
			}
			else if (spriteNotifyEventArgs.SpriteType == GSpriteTypes.Other || spriteNotifyEventArgs.SpriteType == GSpriteTypes.FakeRole)
			{
				this.scene.RemoveEmblem(spriteNotifyEventArgs.RoleID, (int)ConfigSystemParam.GetSystemParamIntByName("EmblemProp"), 1, 0);
			}
		}
	}

	public void AutoFightingNoDrugNotfiy(object sender, object _e)
	{
		AutoFightingNoDrugEventArgs autoFightingNoDrugEventArgs = _e as AutoFightingNoDrugEventArgs;
		if (!autoFightingNoDrugEventArgs.isAutoFight)
		{
			if (Global.Data.roleData.Level < 45)
			{
				return;
			}
			if (!this.FirstHintBuyDrugWizard)
			{
				return;
			}
			this.FirstHintBuyDrugWizard = false;
			if (Global.GetMapType(Global.Data.roleData.MapCode) != MapTypes.Normal)
			{
				this.ShowHintNoGoodsToBuyWizard(20036, 0);
				return;
			}
			if (autoFightingNoDrugEventArgs.DrugType == 0)
			{
				this.ShowBuyLifeDrugsWizard();
			}
			else
			{
				this.ShowBuyMagicDrugsWizard();
			}
			return;
		}
		else
		{
			if (!autoFightingNoDrugEventArgs.autoGoBack)
			{
				return;
			}
			if (Global.GetMapType(Global.Data.roleData.MapCode) != MapTypes.Normal)
			{
				if (!this.FirstAutoFightHintDrugWizard)
				{
					return;
				}
				this.FirstAutoFightHintDrugWizard = false;
				this.ShowHintNoGoodsToBuyWizard(20036, 0);
				return;
			}
			else
			{
				if (null != this.AutoFightingNoDrugDialogBoxWindow)
				{
					return;
				}
				this.AutoFightingNoDrugDialogBoxWindow = Super.ShowDialogBox(this.Root, 1, Global.GetLang("背包中没有药品了，还要继续自动挂机战斗吗？"), (int)Global.GlobalMainWindow.ActualWidth / 2 - 150, 100, 10000, string.Empty, Global.GetLang("继续"), Global.GetLang("回城"));
				this.AutoFightingNoDrugDialogBoxWindow.ChildWindowClose = delegate(object s1, EventArgs e1)
				{
					int dialogBoxReturn = (s1 as NoTitleWindow).DialogBoxReturn;
					Super.CloseNoTitleWindow(this.Root, s1 as NoTitleWindow);
					this.AutoFightingNoDrugDialogBoxWindow = null;
					if (dialogBoxReturn == 0)
					{
						this.scene.SetNoHintNoDrugGoBack();
					}
					else
					{
						this.scene.CancelAutoFight(1, true);
						GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, Global.GetLang("背包中没有药品了，结束自动战斗回城！"), 0, -1, -1, 0);
					}
					return true;
				};
				return;
			}
		}
	}

	public bool BaiTanState()
	{
		if (Global.g_StallStateType != StallStateType.StallNull)
		{
			PlayZone.GlobalPlayZone.DisableInputEventProc(null, null);
			return true;
		}
		return false;
	}

	public void DisableInputEventProc(object obj, EventArgs e)
	{
		if (Global.Data.MeditateState != 0)
		{
			if (!this.IsMeditateMsgBoxShowing)
			{
				this.IsMeditateMsgBoxShowing = true;
				Super.ShowMessageBoxEx("提示", Global.GetLang("冥想状态下无法移动，确定要停止冥想修炼吗？"), delegate(object s, DPSelectedItemEventArgs e1)
				{
					this.IsMeditateMsgBoxShowing = false;
					if (e1.ID == 0)
					{
						Global.Data.MeditateState = 0;
						GameInstance.Game.SpriteStartMeditateCmd(0);
					}
				}, new string[]
				{
					Global.GetLang("确定"),
					Global.GetLang("取消")
				});
			}
		}
		else if (null == Super.m_MessageBoxPart)
		{
			string[] buttons = new string[]
			{
				Global.GetLang("确定"),
				Global.GetLang("取消")
			};
			Super.ShowMessageBoxEx(Global.GetLang("提示"), Global.GetLang("您当前正在摆摊，请先收摊在执行此操作！"), new DPSelectedItemEventHandler(this.MessageHandler), buttons);
		}
		else
		{
			this.IsMeditateMsgBoxShowing = false;
		}
	}

	public void MessageHandler(object sender, DPSelectedItemEventArgs args)
	{
		if (args.ID == 0)
		{
			GameInstance.Game.SpriteOpenMarketCmd(string.Empty, 0);
			this.CloseBaiTan();
		}
		else if (args.ID == 1)
		{
		}
	}

