	public void BackgroundHeartNotfiy(object sender, object e)
	{
		if (this.ChildWindowList.Count > 0)
		{
			Point mapPoint = this.scene.GetMapPoint();
			List<GChildWindow> list = new List<GChildWindow>();
			for (int i = 0; i < this.ChildWindowList.Count; i++)
			{
				GChildWindow gchildWindow = this.ChildWindowList[i];
				if (null != gchildWindow && gchildWindow.Visibility && gchildWindow.IsOutViewRange(mapPoint))
				{
					list.Add(gchildWindow);
				}
			}
			for (int j = 0; j < list.Count; j++)
			{
				list[j].NotifyClose(-1);
			}
		}
		if (this.NoTitleWindowList.Count > 0)
		{
			Point mapPoint2 = this.scene.GetMapPoint();
			List<NoTitleWindow> list2 = new List<NoTitleWindow>();
			for (int k = 0; k < this.NoTitleWindowList.Count; k++)
			{
				NoTitleWindow noTitleWindow = this.NoTitleWindowList[k];
				if (null != noTitleWindow && this.NoTitleWindowList[k].Visibility && noTitleWindow.IsOutViewRange(mapPoint2))
				{
					list2.Add(noTitleWindow);
				}
			}
			for (int l = 0; l < list2.Count; l++)
			{
				list2[l].NotifyClose(-1);
			}
		}
	}

