	protected void ShowNPCNewTaskWindow(int npcID, int taskID, int npcExtensionID, bool caching = false)
	{
		if (!Global.Data.PlayGame)
		{
			return;
		}
		this.CancelNPCDialogWindows();
		if (null != this.NPCNewTaskWindow)
		{
			if (this.NPCNewTaskWindow.Visibility)
			{
				this.CloseNPCNewTaskWindow();
			}
			if (Global.Data.npcData == null)
			{
				return;
			}
			this.NPCNewTaskWindow.TitleText = ConfigNPCs.GetNPCNameByID(npcExtensionID);
			this.NPCNewTaskWindow.Visibility = true;
			this.LimitChildWindowRange(this.NPCNewTaskWindow);
			GChildWindow.ZZ++;
			if ((double)GChildWindow.ZZ > Canvas.GetZIndex(this.NPCNewTaskWindow))
			{
