		{
			showPage
		});
		tc.SelectionChanged = delegate(object sender, object item)
		{
			GTabControl gtabControl = sender as GTabControl;
			string text = (item as BaseEventArgs).Text.toChineseLang();
			if (text != null)
			{
				if (PlayZone.<>f__switch$map7 == null)
				{
					Dictionary<string, int> dictionary = new Dictionary<string, int>(6);
					dictionary.Add("升级礼包", 0);
					dictionary.Add("见面有礼", 1);
					dictionary.Add("登陆有礼", 2);
					dictionary.Add("在线有礼", 3);
					dictionary.Add("充值有礼", 4);
					dictionary.Add("活动送礼", 5);
					PlayZone.<>f__switch$map7 = dictionary;
				}
				int num;
				if (PlayZone.<>f__switch$map7.TryGetValue(text, ref num))
				{
					switch (num)
					{
					case 0:
						tc.Container.BackgroundURL = new ImageURL(Global.GetGameResImageURL("Images/Plate/jmyl_bak.png"), false, 0);
						gtabControl.SetBody(this.giftBagPart);
						this.giftBagPart.InitPartData();
						this.giftBagPart.GetNewData();
						break;
					case 1:
						this.meetGifPart.InitPartData();
						tc.Container.BackgroundURL = new ImageURL(Global.GetGameResImageURL("Images/Plate/jmyl_bak.png"), false, 0);
						gtabControl.SetBody(this.meetGifPart);
						this.meetGifPart.InitPartData();
						this.meetGifPart.GetNewData();
						break;
					case 2:
						tc.Container.BackgroundURL = new ImageURL(Global.GetGameResImageURL("Images/Plate/dlyl_bak.png"), false, 0);
						gtabControl.SetBody(this.loginTimeGiftPart);
						this.loginTimeGiftPart.GetNewData();
						break;
					case 3:
						tc.Container.BackgroundURL = new ImageURL(Global.GetGameResImageURL("Images/Plate/zxyl_bak.png"), false, 0);
						gtabControl.SetBody(this.onlingGiftPart);
						this.onlingGiftPart.InitPartData();
						this.onlingGiftPart.GetNewData();
						break;
					case 4:
						tc.Container.BackgroundURL = new ImageURL(Global.GetGameResImageURL("Images/Plate/djdh_bak.png"), false, 0);
						gtabControl.SetBody(this.campaignFiftPart);
						this.campaignFiftPart.InitPartData();
						this.campaignFiftPart.GetNewData();
						break;
					case 5:
						tc.Container.BackgroundURL = new ImageURL(Global.GetGameResImageURL("Images/Plate/hdsl_bak.png"), false, 0);
						gtabControl.SetBody(this.activitiesGiftPart);
						this.activitiesGiftPart.InitPartData();
						this.activitiesGiftPart.GetNewData();
						break;
					}
				}
			}
		};
		this.GiftBagsWindow.SetContent(this.GiftBagsWindow.BodyPresenter, tc, 9.0, 0.0, true);
		if (caching)
		{
			this.GiftBagsWindow.Visibility = false;
		}
	}

