				this.NpcSalePart.SaleID = saleID;
				this.NpcSalePart.InitPartData(npcID);
				GChildWindow.ZZ++;
				if ((double)GChildWindow.ZZ > Canvas.GetZIndex(this.NPCSaleWindow))
				{
					Canvas.SetZIndex(this.NPCSaleWindow, (double)GChildWindow.ZZ);
				}
			}
			return;
		}
		Global.Data.RoleSalesWindowCount++;
		this.NPCSaleWindow = U3DUtils.NEW<GChildWindow>();
