	protected void ShowParcelWindow(bool caching = false)
	{
		if (null != this.ParcelWindow)
		{
			if (this.ParcelWindow.Visibility)
			{
				this.CloseParcelWindow();
			}
			else
			{
				this.ParcelWindow.Left = (double)Super.GetChildLeft((int)Global.GlobalMainWindow.ActualWidth, 277);
				this.ParcelWindow.Top = (double)Super.GetChildTop((int)Global.GlobalMainWindow.ActualHeight, 446);
				this.ParcelWindow.Visibility = true;
				this.parcelPart.OpenAgain();
				GChildWindow.ZZ++;
				if ((double)GChildWindow.ZZ > Canvas.GetZIndex(this.ParcelWindow))
				{
					Canvas.SetZIndex(this.ParcelWindow, (double)GChildWindow.ZZ);
				}
			}
			return;
		}
		this.ParcelWindow = U3DUtils.NEW<GChildWindow>();
		this.ParcelWindow.Left = (double)Super.GetChildLeft((int)Global.GlobalMainWindow.ActualWidth, 316);
		this.ParcelWindow.Top = (double)Super.GetChildTop((int)Global.GlobalMainWindow.ActualHeight, 481);
		this.ParcelWindow.HeadLeft = 0.0;
		this.ParcelWindow.HeadTop = 0.0;
		this.ParcelWindow.HeadWidth = 316.0;
		this.ParcelWindow.HeadHeight = 39.0;
		this.ParcelWindow.BodyLeft = 0.0;
		this.ParcelWindow.BodyTop = 39.0;
		this.ParcelWindow.BodyWidth = 316.0;
		this.ParcelWindow.BodyHeight = 442.0;
		this.ParcelWindow.ImgTitle = "NetImages/GameRes/Images/WinTitle/Beibao.png";
		this.InitChildWindow(this.ParcelWindow, Global.GetLang("包 裹"));
		this.ParcelWindow.ChildWindowClose = delegate(object s, EventArgs e)
		{
			this.CloseParcelWindow();
			return true;
		};
		this.Root.Children.Add(this.ParcelWindow);
		this.parcelPart = U3DUtils.NEW<ParcelPart>();
		this.parcelPart.BodyBackgroundURL = new ImageURL(Global.GetGameResImageURL("Images/Plate/bg_bak.png"), false, 0);
		this.parcelPart.InitPartSize((int)this.ParcelWindow.BodyWidth - 18, (int)this.ParcelWindow.BodyHeight - 9);
		this.parcelPart.OpenAgain();
		this.parcelPart.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
		{
			if (e.ID == 1)
			{
				this.ProcessMallEvent(0);
			}
			else if (e.ID == 2)
			{
				this.ShowPortableBagWindow(false, e.IDType == 1);
			}
			else if (e.ID == 3)
			{
				this.ProcessMarketEvent(0, 0, string.Empty);
			}
			else if (e.ID != 4)
			{
				if (e.ID != 5)
				{
					if (e.ID == 6)
					{
						GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, Global.GetLang("整理背包功能开发中..."), 0, -1, -1, 0);
					}
					else if (e.ID == 8)
					{
						if (null != this.GameChatBox)
						{
							uint enchanceColor = Global.GetEnchanceColor(e.Quality);
							string str = e.Title;
							if (e.Level != -1 && e.Level > 0)
							{
								str = StringUtil.substitute("{0}+{1}", new object[]
								{
									e.Title,
									e.Level
								});
							}
							this.GameChatBox.ChatTextBox.addText(str, e, enchanceColor, true);
						}
					}
					else if (e.ID == 9)
					{
						if (this.PortableBagWindow == null || !this.PortableBagWindow.Visibility)
						{
							return false;
						}
					}
					else if (e.ID == 10)
					{
						this.ShowYijianChushouWindow(HuiShouType.Equipment);
					}
					else if (e.ID == 11)
					{
						this.ShowYijianChushouWindow(HuiShouType.Pet);
					}
					else if (e.ID == 12)
					{
						this.ShowZaDanCangKuWindow(false, false);
					}
				}
			}
			return true;
		};
		this.parcelPart.GuanLianItem = delegate(object s, DPSelectedItemEventArgs _e)
		{
			int idtype = _e.IDType;
			int id = _e.ID;
			if (idtype == 140)
			{
				this.ShowDigTreasureByYaoShiWindow(false, id);
			}
			else if (idtype == 10)
			{
				this.ShowDigTreasureWindow(false);
			}
			else if (idtype == 20)
			{
				int skillIDByBook = Global.GetSkillIDByBook(Global.Data.roleData.Occupation, id);
				this.ProcessSkillEvent(skillIDByBook, false);
			}
			else if (idtype == 30)
			{
				this.ProcessHorseEvent(true);
			}
			else if (idtype == 40)
			{
				this.ProcessPetEvent(true);
			}
			else if (idtype != 80)
			{
				if (idtype != 90)
				{
					if (idtype != 110)
					{
						if (idtype != 100)
						{
							if (idtype == 160)
							{
								this.ShowSubForgeWindow(id);
							}
							else if (idtype == 120)
							{
								if ((long)id != ConfigSystemParam.GetSystemParamIntByName("JuLingZhuKongGoodsID"))
								{
									if ((long)id == ConfigSystemParam.GetSystemParamIntByName("JuLingZhuManGoodsID"))
									{
									}
								}
							}
							else if (idtype == 190)
							{
								this.ShowLianluWindow(0, 0);
							}
							else if (idtype == 250)
							{
								this.ShowLianluWindow(1, 0);
							}
							else if (idtype == 230)
							{
								this.ShowZaDanWindow(false);
							}
							else if (idtype == 260)
							{
								this.ShowSyntesizeWindow(false, 101);
							}
							else if (idtype == 270)
							{
								this.ShowSyntesizeWindow(false, 1000);
							}
							else if (idtype == 270)
							{
								this.ShowSyntesizeWindow(false, 201);
							}
						}
					}
				}
			}
		};
		this.ParcelWindow.SetContent(this.ParcelWindow.BodyPresenter, this.parcelPart, 9.0, 0.0, true);
		if (caching)
		{
			this.ParcelWindow.Visibility = false;
		}
	}

