	protected void PrivateChat(string targetname)
	{
		if (null != this.GameChatBoxWindow)
		{
			this.GameChatBoxMini.HasNewMessage = false;
			this.GameChatBox.OpenPrivateChat(targetname);
			return;
		}
		this.ShowGameChatBoxWindow(4, targetname);
	}

	protected void ShowGameChatBoxWindow(int nChatMode = 0, string strChatText = "")
	{
		if (null != this.GameChatBoxWindow)
		{
			if (this.GameChatBoxWindow.Visibility)
			{
				this.CloseGameChatBoxWindow();
			}
			else
			{
				if (nChatMode == 0 && null != this.GameChatBoxMini && this.GameChatBoxMini.HasNewMessage)
				{
					this.GameChatBoxMini.HasNewMessage = false;
				}
				else
				{
					this.GameChatBox.InitPartData();
				}
				this.GameChatBoxWindow.Visibility = true;
			}
			return;
		}
		this.GameChatBoxWindow = U3DUtils.NEW<GChildWindow>();
		this.GameChatBoxWindow.ModalType = ChildWindowModalType.TransBak;
		this.InitChildWindow(this.GameChatBoxWindow, Global.GetLang("聊天"));
		this.Root.Children.Add(this.GameChatBoxWindow);
		this.GameChatBoxWindow.ChildWindowClose = delegate(object s, EventArgs e)
		{
			this.CloseGameChatBoxWindow();
			return true;
		};
		this.GameChatBox = U3DUtils.NEW<ChatBox>();
		this.GameChatBox.InitPartSize();
		this.GameChatBoxWindow.Visibility = true;
		if (nChatMode == 0 && null != this.GameChatBoxMini && this.GameChatBoxMini.HasNewMessage)
		{
			this.GameChatBoxMini.HasNewMessage = false;
		}
		else
		{
			this.GameChatBox.InitPartData();
		}
		if (nChatMode == 4 && 0 < strChatText.Length)
		{
			this.GameChatBox.OpenPrivateChat(strChatText);
		}
		this.GameChatBox.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
		{
			if (e.ID == 0)
			{
				this.CloseGameChatBoxWindow();
			}
			else if (e.ID == 1)
			{
				this.ShowChatBoxEmotionContainerWindow();
			}
		};
		this.GameChatBoxWindow.SetContent(this.GameChatBoxWindow.BodyPresenter, this.GameChatBox, 0.0, 0.0, true);
	}

	protected void ShowChatBoxEmotionContainerWindow()
	{
		if (null != this.m_ChatBoxEmotionContainerWindow)
		{
			this.CloseChatEmotionContainerWindow();
			return;
		}
		this.m_ChatBoxEmotionContainerWindow = U3DUtils.NEW<GChildWindow>();
		this.m_ChatBoxEmotionContainerWindow.ModalType = ChildWindowModalType.TransBak;
		this.m_ChatBoxEmotionContainerWindow.Modal = true;
		this.InitChildWindow(this.m_ChatBoxEmotionContainerWindow, Global.GetLang("ChatBoxEmotionContainerWindow"));
		this.Root.Children.Add(this.m_ChatBoxEmotionContainerWindow);
		this.m_ChatBoxEmotionContainer = U3DUtils.NEW<ChatBoxEmotionContainer>();
		this.m_ChatBoxEmotionContainer.DPSelectedEmotionItem = delegate(object s, DPSelectedItemEventArgs e)
		{
			if (e.ID == 1)
			{
				TextBox chatTextBox = this.GameChatBox.ChatTextBox;
				chatTextBox.text += e.Data.ToString();
			}
			else if (e.ID == 2)
			{
				if (null != this.GameChatBox)
				{
					if (0 < this.GameChatBox.ChatTextBox.text.Length)
					{
						if (this.GameChatBox.ChatTextBox.text == Global.GetLang("请输入聊天信息"))
						{
							this.GameChatBox.ChatTextBox.text = string.Format("{0} ", e.Title);
						}
						else
						{
							TextBox chatTextBox2 = this.GameChatBox.ChatTextBox;
							chatTextBox2.text += string.Format("{0} ", e.Title);
						}
						TextBox chatTextBox3 = this.GameChatBox.ChatTextBox;
						chatTextBox3.text += " ";
					}
					else
					{
						this.GameChatBox.ChatTextBox.text = string.Format("{0} ", e.Title);
						TextBox chatTextBox4 = this.GameChatBox.ChatTextBox;
						chatTextBox4.text += " ";
					}
				}
			}
			else if (e.ID == 3)
			{
				if (null == this.GameChatBox)
				{
					this.ShowGameChatBoxWindow(4, e.Title);
				}
				if (null != this.GameChatBox)
				{
					this.GameChatBox.ChatTextBox.text = string.Format("/{0} ", e.Title);
				}
				this.GameChatBox.OpenPrivateChat(e.Title);
				this.CloseChatEmotionContainerWindow();
			}
			else if (e.ID == 0)
			{
				this.CloseChatEmotionContainerWindow();
			}
		};
		this.m_ChatBoxEmotionContainerWindow.SetContent(this.m_ChatBoxEmotionContainerWindow.BodyPresenter, this.m_ChatBoxEmotionContainer, 0.0, 0.0, false);
	}

	protected void CloseChatEmotionContainerWindow()
	{
		if (null != this.m_ChatBoxEmotionContainerWindow)
		{
			this.m_ChatBoxEmotionContainer.Destroy();
			this.m_ChatBoxEmotionContainer = null;
			this.m_ChatBoxEmotionContainerWindow.Visibility = false;
			this.CloseChildWindow(this.m_ChatBoxEmotionContainerWindow);
			this.Root.Children.Remove(this.m_ChatBoxEmotionContainerWindow, true);
			this.m_ChatBoxEmotionContainerWindow = null;
		}
	}

