	public void ShowGongnengIconWindow(Transform trans)
	{
		if (null != this.GongnengIconWindow)
		{
			if (this.GongnengIconWindow.Visibility)
			{
				this.CloseGongnengIconWindow();
			}
			else
			{
				this.GongnengIconWindow.Visibility = true;
			}
			return;
		}
		this.GongnengIconWindow = U3DUtils.NEW<GChildWindow>();
		this.GongnengIconWindow.ModalType = ChildWindowModalType.TransBak;
		Vector3 vector = this.GongnengIconWindow.ModalBak.transform.localScale;
		vector *= 1.5f;
		this.GongnengIconWindow.ModalBak.transform.localScale = vector;
		this.InitChildWindow(this.GongnengIconWindow, Global.GetLang("功能"));
		this.GongnengIconWindow.ChildWindowModalBakClick = delegate(object s, EventArgs e)
		{
			this.CloseGongnengIconWindow();
			return true;
		};
		this.GongnengIconWindow.ChildWindowClose = delegate(object s, EventArgs e)
		{
			this.CloseGongnengIconWindow();
			return true;
		};
		this.Root.Children.Add(this.GongnengIconWindow);
		this.gongnengIconPart = U3DUtils.NEW<GongnengIconPart>();
		this.gongnengIconPart.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
		{
			this.CloseGongnengIconWindow();
			if (e.ID == 0)
			{
				this.ShowMingXiangWindow();
			}
			else if (e.ID == 1)
			{
				this.ShowEmailWindow(true, string.Empty);
			}
			else if (e.ID == 2)
			{
				QMQJJava.Feedback();
			}
			else if (e.ID == 3)
			{
				this.ShowSystemSettingWindow(0);
			}
			else if (e.ID == 4)
			{
				this.ShowAutoPlayWindow(false);
			}
			else if (e.ID == 5)
			{
				this.ShowGonggaoWindow(string.Empty);
			}
			else if (e.ID == 6)
			{
				if (Global.IsOperateUnPermitInKuaFuMapCheck(true, false))
				{
					return;
				}
				if (Global.HasSecondPassword == 0)
				{
					this.ShowSetSecondPasswordWindow();
				}
				else if (Global.HasSecondPassword == 1)
				{
					this.ShowSecondPasswordOptionsWindow();
				}
				else
				{
					MUDebug.LogError<string>(new string[]
					{
						"二级密码的存在状态Global.HasSecondPassword的值异常:" + Global.HasSecondPassword
					});
				}
			}
			else if (e.ID == 7)
			{
				string systemParamByName = ConfigSystemParam.GetSystemParamByName("TenAwardInvite", true);
				if (systemParamByName != "-1" && PlatSDKMgr.PlatName == "YYB")
				{
					this.ShowInviteWindow(false);
				}
				else
				{
					this.ShowShareWindow(false);
				}
			}
		};
		if (null != trans)
		{
			Transform transform = this.GongnengIconWindow.transform;
			transform.position = new Vector3(trans.position.x, trans.position.y, transform.position.z);
			transform.localPosition = new Vector3(transform.localPosition.x, transform.localPosition.y - 120f, transform.localPosition.z);
		}
		this.GongnengIconWindow.SetContent(this.GongnengIconWindow.BodyPresenter, this.gongnengIconPart, 0.0, 0.0, false);
	}

	protected bool IsShowLeaderAttributeWindow()
	{
		return null != this.LeaderAttributeWindow && this.LeaderAttributeWindow.Visibility;
	}

	protected void CloseLeaderAttributeWindow(int index = 0)
	{
		if (null != this.LeaderAttributeWindow)
		{
			if (index == 0)
			{
				this.LeaderAttributeWindow.WinTouchPos = Super.GetObjectCenterPos(this.BottomMenu.FindName("UserAttribBtn"));
			}
			else if (index == 1)
			{
				this.LeaderAttributeWindow.WinTouchPos = Super.GetObjectCenterPos(this.BottomMenu.FindName("HorsesBtn"));
			}
			this.roleAttributePart.PauseAllEffect(true);
