	protected void ReShowLeaderAttributeWindow()
	{
		if (this.HideLeaderAttributeWindowTicks <= 0.0)
		{
			return;
		}
		if (null == this.LeaderAttributeWindow)
		{
			return;
		}
		if (this.LeaderAttributeWindow.Visibility)
		{
			return;
		}
		double num = (double)Global.GetCorrectLocalTime();
		if (num - this.HideLeaderAttributeWindowTicks < this.MaxHideLeaderAttributeWindowTicks)
		{
			return;
		}
		this.HideLeaderAttributeWindowTicks = 0.0;
		this.LeaderAttributeWindow.Visibility = true;
	}

