	protected void ShowOtherAttributeWindow(string[] dataFields, bool caching = false)
	{
		if (Global.IsKuaFuHuoDongMapSceneUIClass(Global.GetMapSceneUIClass()))
		{
			Super.HintMainText(Global.GetLang("当前不能进行此操作"), 10, 3);
			return;
		}
		if (null != this.OtherAttributeWindow)
		{
			if (this.OtherAttributeWindow.Visibility)
			{
				this.CloseOtherAttributeWindow();
			}
			this.OtherAttributeWindow.Visibility = true;
			this.otherAttributePart.DataFields = dataFields;
			this.otherAttributePart.GetNewData();
			return;
		}
		if (null != this.topListPart)
		{
			this.topListPart.m_bIsModalSate = false;
		}
		if (this.NPCMobaiPart != null)
		{
			this.NPCMobaiPart.IsModalVisable = false;
		}
		this.OtherAttributeWindow = U3DUtils.NEW<GChildWindow>();
		this.InitChildWindow(this.OtherAttributeWindow, Global.GetLang(string.Empty));
		this.OtherAttributeWindow.ModalType = ChildWindowModalType.TransBak;
		this.OtherAttributeWindow.ChildWindowClose = delegate(object s, EventArgs e)
		{
			this.CloseOtherAttributeWindow();
			Super.GData.OtherRoleData = null;
			Global.Data.OtherJingMaiDataList = null;
			return true;
		};
		this.Root.Children.Add(this.OtherAttributeWindow);
		this.otherAttributePart = U3DUtils.NEW<OtherAttributePart>();
		this.otherAttributePart.DataFields = dataFields;
		this.otherAttributePart.transform.SetParent(this.OtherAttributeWindow.Body.transform, false);
		this.otherAttributePart.GetNewData();
		this.otherAttributePart.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
		{
			if (e.ID == -1)
			{
				this.CloseOtherAttributeWindow();
			}
			else if (e.ID == 1 && e.Type == 6)
			{
				if (Global.IsKuaFuHuoDongMapSceneUIClass(Global.GetMapSceneUIClass()) || SceneUIClasses.RebornMap.IsTheScene())
				{
					Super.HintMainText(Global.GetLang("当前不能进行此操作"), 10, 3);
				}
				else
				{
					GameInstance.Game.SpriteGoodsExchange(Super.GData.OtherRoleData.RoleID, 1, -1);
					this.CloseOtherAttributeWindow();
				}
			}
			else if (e.ID == 2)
			{
				string text = Global.FormatRoleNameByChat(Super.GData.OtherRoleData);
				if (0 < text.Length)
				{
					this.PrivateChat(text);
				}
				this.CloseOtherAttributeWindow();
			}
			else if (e.ID == 3 && e.Type != -1)
			{
				if (Global.IsKuaFuHuoDongMapSceneUIClass(Global.GetMapSceneUIClass()) || SceneUIClasses.RebornMap.IsTheScene())
				{
					Super.HintMainText(Global.GetLang("当前不能进行此操作"), 10, 3);
					return true;
				}
				int type = e.Type;
				FriendData friendData = Global.FindFriendData(e.Tag.ToString());
				if (friendData == null)
				{
					GameInstance.Game.SpriteAddFriend(-1, e.Tag.ToString(), type);
				}
				else if (friendData.FriendType != type)
				{
					GameInstance.Game.SpriteAddFriend(friendData.DbID, friendData.OtherRoleName, type);
				}
				else
				{
					string lang = Global.GetLang("好友");
					if (friendData.FriendType == 1)
					{
						lang = Global.GetLang("屏蔽");
					}
					else if (friendData.FriendType == 2)
					{
						lang = Global.GetLang("仇人");
					}
					Super.HintMainText(StringUtil.substitute(Global.GetLang("【{0}】已经在{1}列表中"), new object[]
					{
						friendData.OtherRoleName,
						lang
					}), 10, 3);
				}
			}
			else if (e.ID == 5)
			{
				if (Global.IsKuaFuHuoDongMapSceneUIClass(Global.GetMapSceneUIClass()) || SceneUIClasses.RebornMap.IsTheScene())
				{
					Super.HintMainText(Global.GetLang("当前不能进行此操作"), 10, 3);
				}
				else if (Global.IsInShiLiZhengBaMap())
				{
					Super.HintMainText(Global.GetLang("当前不能进行此操作"), 10, 3);
				}
				else
				{
					if (Global.Data.CurrentTeamData == null)
					{
						GameInstance.Game.SpriteTeam(1, e.GetThingOpt, 0);
					}
					GameInstance.Game.SpriteQueryIDByName(e.Tag.ToString(), 1);
				}
			}
			return true;
		};
		this.OtherAttributeWindow.SetContent(this.OtherAttributeWindow.BodyPresenter, this.otherAttributePart, 0.0, 0.0, true);
		this.OtherAttributeWindow.Top = 9.0;
		if (caching)
		{
			this.OtherAttributeWindow.Visibility = false;
		}
	}

