	protected void ShowSkillWindow(int toSelectSkillID = -1, bool caching = false, bool onlyOnce = false)
	{
		if (!(null != this.SkillWindow))
		{
			this.SkillWindow = U3DUtils.NEW<GChildWindow>();
			this.SkillWindow.Left = (double)(Super.GetChildLeft((int)Global.GlobalMainWindow.ActualWidth, 1000) + 300);
			this.SkillWindow.Top = (double)(Super.GetChildTop((int)Global.GlobalMainWindow.ActualHeight, 600) + 20);
			this.SkillWindow.HeadLeft = 0.0;
			this.SkillWindow.HeadTop = 0.0;
			this.SkillWindow.HeadWidth = 303.0;
			this.SkillWindow.HeadHeight = 64.0;
			this.SkillWindow.BodyLeft = 0.0;
			this.SkillWindow.BodyTop = 64.0;
			this.SkillWindow.BodyWidth = 303.0;
			this.SkillWindow.BodyHeight = 370.0;
			this.SkillWindow.ImgTitle = "NetImages/GameRes/Images/WinTitle/Jinen.png";
			this.InitChildWindow(this.SkillWindow, Global.GetLang("人物技能"));
			this.SkillWindow.ChildWindowClose = delegate(object s, EventArgs e)
			{
				this.CloseSkillWindow();
				return true;
			};
			this.Root.Children.Add(this.SkillWindow);
			this.skillPart = U3DUtils.NEW<SkillPart>();
			this.skillPart.BodyBackgroundURL = new ImageURL(Global.GetGameResImageURL("Images/Plate/jn_bak.png"), false, 0);
			this.skillPart.InitPartSize((int)this.SkillWindow.BodyWidth - 18, (int)this.SkillWindow.BodyHeight - 9);
			this.skillPart.InitPartData();
			if (caching || toSelectSkillID > 0)
			{
			}
			this.SkillWindow.SetContent(this.SkillWindow.BodyPresenter, this.skillPart, 9.0, 0.0, true);
			if (caching)
			{
				this.SkillWindow.Visibility = false;
			}
			return;
		}
		if (this.HideSkillWindowTicks > 0.0)
		{
			return;
		}
		if (this.SkillWindow.Visibility)
		{
			this.CloseSkillWindow();
		}
		else
		{
			this.SkillWindow.Left = (double)(Super.GetChildLeft((int)Global.GlobalMainWindow.ActualWidth, 1000) + 300);
			this.SkillWindow.Top = (double)(Super.GetChildTop((int)Global.GlobalMainWindow.ActualHeight, 600) + 20);
			this.SkillWindow.Visibility = true;
			GChildWindow.ZZ++;
			if ((double)GChildWindow.ZZ > Canvas.GetZIndex(this.SkillWindow))
			{
				Canvas.SetZIndex(this.SkillWindow, (double)GChildWindow.ZZ);
			}
			if (toSelectSkillID > 0)
			{
			}
			this.skillPart.GetNewData(onlyOnce);
		}
	}

	protected void ReShowSkillWindow()
	{
		if (this.HideSkillWindowTicks <= 0.0)
		{
			return;
		}
		if (null == this.SkillWindow)
		{
			return;
		}
		if (this.SkillWindow.Visibility)
		{
			return;
		}
		double num = (double)Global.GetCorrectLocalTime();
		if (num - this.HideSkillWindowTicks < 1000.0)
		{
			return;
		}
		this.HideSkillWindowTicks = 0.0;
		this.SkillWindow.Visibility = true;
	}

