			return;
		}
		if (Global.IsAutoFighting())
		{
			Super.HintEndAutoFight(true);
		}
		this.CloseRelatedToParcelPart();
		if (null != this.PlayerTradingWindow)
		{
			this.ClosePlayerTradingWindow();
			return;
		}
		if (null != this.JingLingPart)
		{
			this.CloseJingLingPartWindow();
		}
