			return true;
		};
		this.Root.Children.Add(this.PlayerTradingWindow);
		this.ptPart = U3DUtils.NEW<PlayerTradingPart>();
		this.ptPart.OtherRoleID = otherRoleID;
		this.ptPart.InitPartData();
		this.ptPart.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
		{
			if (e.ID == 1 && e.IDType == -1)
