	public void ShowActivityWindow(bool huodongWin = false, int showPage = 0, int TabID = -1)
	{
		if (showPage >= 500)
		{
			huodongWin = (showPage >= 300);
		}
		if (null != this.ActivityWindow)
		{
			if (this.ActivityWindow.Visibility)
			{
				if (showPage <= 0)
				{
					this.CloseActivityWindow();
				}
			}
			else
			{
				this.ActivityWindow.Visibility = true;
				GChildWindow.ZZ++;
			}
			if (showPage > 0)
			{
				this._ActivityPart.ShowPage(showPage, 0);
			}
			return;
		}
		this.ActivityWindow = U3DUtils.NEW<GChildWindow>();
		this.ActivityWindow.Modal = true;
		this.ActivityWindow.IsShowModal = true;
		this.ActivityWindow.ChildWindowClose = delegate(object s, EventArgs e)
		{
			this.CloseActivityWindow();
			return true;
		};
		this.InitChildWindow(this.ActivityWindow, Global.GetLang("日常活动"));
		this.Root.Children.Add(this.ActivityWindow);
		ActivityPart activityPart = U3DUtils.NEW<ActivityPart>();
		this.ActivityWindow.SetContent(this.ActivityWindow.BodyPresenter, activityPart, 0.0, 0.0, true);
		activityPart._Close.MouseLeftButtonUp = delegate(object s, MouseEvent e)
		{
			this.CloseActivityWindow();
		};
		this._ActivityPart = activityPart;
		this._ActivityPart.InitPartData((!huodongWin) ? 0 : 1, showPage);
		if (TabID != -1)
		{
			this._ActivityPart.ClickItemBySystem(TabID);
		}
	}

