		tc.SelectionChanged = delegate(object sender, object item)
		{
			GTabControl gtabControl = sender as GTabControl;
			string text = (item as BaseEventArgs).Text;
			if (text != null)
			{
				if (PlayZone.<>f__switch$map8 == null)
				{
					Dictionary<string, int> dictionary = new Dictionary<string, int>(2);
					dictionary.Add("全服通告", 0);
					dictionary.Add("个人信息", 1);
					PlayZone.<>f__switch$map8 = dictionary;
				}
				int num;
				if (PlayZone.<>f__switch$map8.TryGetValue(text, ref num))
				{
					if (num != 0)
					{
						if (num == 1)
						{
							tc.Container.BackgroundURL = new ImageURL(Global.GetGameResImageURL("Images/Plate/gg_bak.png"), false, 0);
							gtabControl.SetBody(this.activityPersonalInfoPart);
							this.activityPersonalInfoPart.GetNewData();
