					else
					{
						tc.Container.BackgroundURL = new ImageURL(Global.GetGameResImageURL("Images/Plate/gg_bak.png"), false, 0);
						gtabControl.SetBody(this.activityServerNoticePart);
						this.activityServerNoticePart.GetNewData();
					}
				}
			}
		};
		if (!caching)
		{
			if (showPage == 0)
			{
				tc.Container.BackgroundURL = new ImageURL(Global.GetGameResImageURL("Images/Plate/gg_bak.png"), false, 0);
				tc.SetBody(this.activityPersonalInfoPart);
				this.activityPersonalInfoPart.GetNewData();
