				tc.SetBody(this.activityServerNoticePart);
				this.activityServerNoticePart.GetNewData();
			}
			tc.SelectItem(new object[]
			{
				showPage
			});
		}
		this.PersonalInfoWindow.SetContent(this.PersonalInfoWindow.BodyPresenter, tc, 9.0, 0.0, true);
		if (caching)
		{
			this.PersonalInfoWindow.Visibility = false;
		}
