		int num2 = (int)this.Container.Height;
		GChildWindow messageBoxWindow = Super.ShowMessageBox(this.Root, 1, Global.GetLang("提示"), message, (int)((this.Width - 253.0) / 2.0), (int)((this.Height - 171.0) / 2.0), (int)this.Width, (int)this.Height, 0.01, default(Vector3), null, null);
		messageBoxWindow.ChildWindowClose = delegate(object s1, EventArgs e1)
		{
			int messageBoxReturn = messageBoxWindow.MessageBoxReturn;
			Super.CloseMessageBox(this.Root, messageBoxWindow);
			if (messageBoxReturn == 0)
			{
				GameInstance.Game.SpriteOpenYangGongBK(false);
			}
			return true;
		};
	}

