	public void ShowLianluWindow(int pageID = 0, int goodType = 0)
	{
		if (this.m_RidePetPart != null)
		{
			this.CloseRidePetPartWindow();
		}
		int trigger = 0;
		int param = 0;
		int param2 = 0;
		if (!GongnengYugaoMgr.IsGongNengOpened(GongNengIDs.LianLu, ref trigger, ref param, ref param2))
		{
			UIHelper.HintGongNengOpenCondition(GongNengIDs.LianLu, trigger, param, param2, true);
			return;
		}
		if (pageID == 9)
		{
			if (!GongnengYugaoMgr.IsGongNengOpened(GongNengIDs.ZaiZao, ref trigger, ref param, ref param2))
			{
				UIHelper.HintGongNengOpenCondition(GongNengIDs.ZaiZao, trigger, param, param2, true);
				return;
			}
		}
		else if (pageID == 7)
		{
			if (!GongnengYugaoMgr.IsGongNengOpened(GongNengIDs.ZhuangBeiPeiYang, ref trigger, ref param, ref param2))
			{
				UIHelper.HintGongNengOpenCondition(GongNengIDs.ZhuangBeiPeiYang, trigger, param, param2, true);
				return;
			}
		}
		else if (pageID == 11 && !GongnengYugaoMgr.IsGongNengOpened(GongNengIDs.ShenQiJuHun, ref trigger, ref param, ref param2))
		{
			UIHelper.HintGongNengOpenCondition(GongNengIDs.ShenQiJuHun, trigger, param, param2, true);
			return;
		}
		if (null != this.LianluWindow)
		{
			if (this.LianluWindow.Visibility)
			{
				this.CloseLianluWindow();
			}
			else
			{
				this.LianluWindow.Visibility = true;
				this.lianluPart.PauseAllEffect(false);
				this.lianluPart.InitPartData(pageID);
			}
			return;
		}
		this.LianluWindow = U3DUtils.NEW<GChildWindow>();
		this.LianluWindow.Modal = true;
		this.LianluWindow.IsShowModal = true;
		this.InitChildWindow(this.LianluWindow, Global.GetLang("炼炉"));
		this.LianluWindow.ChildWindowClose = delegate(object s, EventArgs e)
		{
			this.CloseLianluWindow();
			return true;
		};
		this.Root.Children.Add(this.LianluWindow);
		this.lianluPart = U3DUtils.NEW<LianluPart>();
		this.lianluPart.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
		{
			if (e.IDType == 0 && e.ID == 0)
			{
				this.CloseLianluWindow();
			}
		};
		this.lianluPart.CloseCallBack = delegate(object s, DPSelectedItemEventArgs e)
		{
			this.CloseLianluWindow();
		};
		GameInstance.Game.GetJieriFanbeiInfo();
		this.lianluPart.InitPartGoodType(goodType);
		this.lianluPart.InitPartSize(0, 0);
		this.lianluPart.InitPartData(pageID);
		this.LianluWindow.SetContent(this.LianluWindow.BodyPresenter, this.lianluPart, 0.0, 0.0, true);
	}

