	protected void ShowFamilyWindow(int bhid, bool caching = false)
	{
		if (null != this.FamilyWindow)
		{
			if (this.FamilyWindow.Visibility)
			{
				this.CloseFamilyWindow();
			}
			else
			{
				this.familyPart.GetNewData(bhid);
				this.FamilyWindow.Visibility = true;
			}
			return;
		}
		this.FamilyWindow = U3DUtils.NEW<GChildWindow>();
		this.FamilyWindow.Modal = true;
		this.FamilyWindow.IsShowModal = true;
		this.InitChildWindow(this.FamilyWindow, Global.GetLang("战盟"));
		this.FamilyWindow.ChildWindowClose = delegate(object s, EventArgs e)
		{
			this.CloseFamilyWindow();
			return true;
		};
		this.Root.Children.Add(this.FamilyWindow);
		this.familyPart = U3DUtils.NEW<FamilyPart>();
		this.familyPart.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
		{
			if (e.ID == 0)
			{
				this.ShowFamilyListWindow(false);
			}
			else if (e.ID == 1)
			{
				this.ShowZhengDuoGuizeWindow(e.IDType);
				if (e.ShowFlagUpdate && null != this.familyLingdiPart)
				{
					this.familyLingdiPart.DelayShowFlagUpdateWindow = true;
				}
			}
			else if (e.ID == 2)
			{
				this.CloseFamilyWindow();
				this.ShowGameChatBoxWindow(4, e.Title);
			}
			else if (e.ID == 3)
			{
				this.ShowFamilyHuangChengWindow(false);
			}
			else if (e.ID == -1)
			{
				this.CloseFamilyWindow();
				this.ShowFamilyCreateWindow(false);
			}
			else if (e.ID == 10)
			{
				if (this.familyPart != null && this.familyPart.MyBangHuiDetailData != null)
				{
					this.ShowMuDuiHuanWindow(3, this.familyPart.MyBangHuiDetailData.QiLevel);
				}
				else
				{
					this.ShowMuDuiHuanWindow(3, 0);
				}
			}
			else if (e.ID == 11)
			{
				this.OpenShenDianWindow();
			}
			if (e.ID != 10 && e.ID != 11)
			{
				this.CloseFamilyWindow();
			}
		};
		this.familyPart.InitPartSize((int)this.FamilyWindow.BodyWidth - 18, (int)this.FamilyWindow.BodyHeight - 9);
		this.FamilyWindow.SetContent(this.FamilyWindow.BodyPresenter, this.familyPart, 9.0, 0.0, true);
		if (caching)
		{
			this.FamilyWindow.Visibility = false;
		}
		else
		{
			this.familyPart.GetNewData(bhid);
		}
	}

