	protected void ShowFamilyRequestWindow()
	{
		if (null != this.familyRequestWindow)
		{
			if (this.familyRequestWindow.Visibility)
			{
				this.CloseFamilyRequestWindow();
			}
			else
			{
				this.familyRequestWindow.Visibility = true;
			}
			return;
		}
		this.familyRequestWindow = U3DUtils.NEW<GChildWindow>();
		this.familyRequestWindow.Modal = true;
		this.InitChildWindow1(this.familyRequestWindow, Global.GetLang("加入战盟申请"));
		this.familyRequestWindow.ChildWindowClose = delegate(object s, EventArgs e)
		{
			this.CloseFamilyRequestWindow();
			return true;
		};
		this.Root.Children.Add(this.familyRequestWindow);
		this.family_Part_Request = U3DUtils.NEW<FamilyRequestPart>();
		this.family_Part_Request.InitPartSize((int)this.familyRequestWindow.BodyWidth - 18, (int)this.familyRequestWindow.BodyHeight - 9);
		this.family_Part_Request.InitPartData();
		this.family_Part_Request.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
		{
			BangHuiUIItem bangHuiUIItem = e.Tag as BangHuiUIItem;
			if (e.IDType == 1)
			{
				if (bangHuiUIItem.BangHuiCmd == 1)
				{
					GameInstance.Game.SpriteAddBHMember(bangHuiUIItem.BHID, bangHuiUIItem.OtherRoleID, bangHuiUIItem.OtherRoleName, 0);
				}
				else
				{
					GameInstance.Game.SpriteAgreeToBHMember(bangHuiUIItem.OtherRoleID, bangHuiUIItem.BHID, bangHuiUIItem.BHName, 1);
				}
			}
			if (e.IDType == 2)
			{
				if (bangHuiUIItem.BangHuiCmd == 1)
				{
					GameInstance.Game.SpriteRefuseApplyToBHMember(bangHuiUIItem.BHID, bangHuiUIItem.OtherRoleID);
				}
				else
				{
					GameInstance.Game.SpriteAgreeToBHMember(bangHuiUIItem.OtherRoleID, bangHuiUIItem.BHID, bangHuiUIItem.BHName, 0);
				}
			}
			else if (e.IDType == 10)
			{
				this.CloseChildWindow(this.familyRequestWindow);
				if (this.familyRequestWindow != null)
				{
					this.familyRequestWindow = null;
				}
				if (this.family_Part_Request != null)
				{
					this.family_Part_Request.Destroy();
					this.family_Part_Request = null;
				}
			}
		};
		this.familyRequestWindow.SetContent(this.familyRequestWindow.BodyPresenter, this.family_Part_Request, 9.0, 0.0, true);
	}

	protected void CloseFamilyListWindow()
	{
		if (null != this.FamilyListWindow)
		{
