		this.FamilyListWindow.ChildWindowClose = delegate(object s, EventArgs e)
		{
			this.CloseFamilyListWindow();
			this.ProcessFactionEvent();
			return true;
		};
		this.Root.Children.Add(this.FamilyListWindow);
		this.familylistPart = U3DUtils.NEW<FamilyListPart>();
