		this.FamilyListWindow.SetContent(this.FamilyListWindow.BodyPresenter, this.familylistPart, 9.0, 0.0, true);
		this.familylistPart.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
		{
			if (e.ID == 1)
			{
				this.CloseFamilyListWindow();
				this.ProcessFactionEvent();
			}
			else if (e.ID == 0)
			{
				this.CloseFamilyListWindow();
				this.ShowFamilyWindow(e.IDType, false);
			}
			else if (e.ID == -9)
			{
				this.CloseFamilyListWindow();
				this.ProcessFactionEvent();
			}
			else if (e.ID == -10)
			{
				this.CloseFamilyListWindow();
			}
		};
		this.familylistPart.ShowChatBoxCallback = delegate(object s, DPSelectedItemEventArgs e)
		{
			this.ShowChatBoxInFamilyList(4, e);
		};
		if (caching)
		{
			this.FamilyListWindow.Visibility = false;
		}
		else
		{
			GameInstance.Game.GetLuoLanChengZhuRoleInfo();
		}
	}

