	protected void ShowPortableBagWindow(bool caching = false, bool forceShowNavi = false)
	{
		if (null != this.PortableBagWindow)
		{
			if (this.PortableBagWindow.Visibility)
			{
				this.ClosePortableBagWindow();
			}
			else
			{
				if (null != this.ParcelWindow && this.ParcelWindow.Visibility)
				{
					Super.SetChildCoordinate(0, 0, this.ParcelWindow, this.PortableBagWindow);
				}
				this.PortableBagWindow.Visibility = true;
				GChildWindow.ZZ++;
				if ((double)GChildWindow.ZZ > Canvas.GetZIndex(this.PortableBagWindow))
				{
					Canvas.SetZIndex(this.PortableBagWindow, (double)GChildWindow.ZZ);
				}
				this.portableBagPart.ForceShowNavi = forceShowNavi;
				this.portableBagPart.GetNewData();
				this.portableBagPart.InitPartData();
			}
			return;
		}
		this.PortableBagWindow = U3DUtils.NEW<GChildWindow>();
		this.PortableBagWindow.Modal = true;
		if (null != this.ParcelWindow && this.ParcelWindow.Visibility)
		{
			Super.SetChildCoordinate(0, 0, this.ParcelWindow, this.PortableBagWindow);
		}
		this.InitChildWindow(this.PortableBagWindow, Global.GetLang("随身仓库"));
		this.PortableBagWindow.ChildWindowClose = delegate(object s, EventArgs e)
		{
			this.ClosePortableBagWindow();
			return true;
		};
		this.Root.Children.Add(this.PortableBagWindow);
		this.portableBagPart = U3DUtils.NEW<PortableBagPart>();
		this.portableBagPart.InitPartData();
		this.PortableBagWindow.SetContent(this.PortableBagWindow.BodyPresenter, this.portableBagPart, 0.0, 0.0, true);
		this.portableBagPart.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
		{
			if (e.ID == -1)
			{
				this.ClosePortableBagWindow();
			}
			else if (e.ID == -2)
			{
				if (null == this.saveGetGChildWindow)
				{
					this.saveGetGChildWindow = U3DUtils.NEW<GChildWindow>();
					this.InitChildWindow(this.saveGetGChildWindow, "_TaskWindow");
					this.Container.Children.Add(this.saveGetGChildWindow);
					this.saveGetGChildWindow.ModalType = ChildWindowModalType.TransBak;
					this.saveGetGChildWindow.IsShowModal = true;
					if (null == this.saveGetMoneyPart)
					{
						this.saveGetMoneyPart = U3DUtils.NEW<SaveGetMoneyPart>();
						this.saveGetGChildWindow.SetContent(this.saveGetGChildWindow.BodyPresenter, this.saveGetMoneyPart, 0.0, 0.0, true);
						this.saveGetMoneyPart.close.MouseLeftButtonUp = delegate(object ss, MouseEvent ee)
						{
							this.CloseChildWindow(this.saveGetGChildWindow);
							this.saveGetGChildWindow = null;
							this.saveGetMoneyPart = null;
						};
					}
				}
			}
			else if (e.ID == -3)
			{
				this.ClosePortableBagWindow();
				this.ShowPortableRebornBagWindow();
			}
			return true;
		};
		if (caching)
		{
			this.PortableBagWindow.Visibility = false;
		}
		else
		{
			this.portableBagPart.ForceShowNavi = forceShowNavi;
			this.portableBagPart.GetNewData();
		}
	}

