	public void ShowGamePayerRoleWindow(GamePayerRolePart_PartID type)
	{
		if (null != this.GamePayerRoleWindow)
		{
			if (this.GamePayerRoleWindow.Visibility)
			{
				this.gamePayerRolePart.InitPartData(type);
			}
			else
			{
				this.GamePayerRoleWindow.Visibility = true;
				this.gamePayerRolePart.InitPartData(type);
				this.InitChildWindow(this.GamePayerRoleWindow, Global.GetLang("人物"));
			}
			return;
		}
		this.GamePayerRoleWindow = U3DUtils.NEW<GChildWindow>();
		this.GamePayerRoleWindow.Modal = true;
		this.GamePayerRoleWindow.IsShowModal = true;
		this.InitChildWindow(this.GamePayerRoleWindow, Global.GetLang("人物"));
		this.GamePayerRoleWindow.ChildWindowClose = delegate(object s, EventArgs e)
		{
			this.CloseGamePayerRoleWindow();
			return true;
		};
		this.Root.Children.Add(this.GamePayerRoleWindow);
		this.gamePayerRolePart = U3DUtils.NEW<GamePayerRolePart>();
		this.gamePayerRolePart.InitPartData(type);
		this.gamePayerRolePart.ChildWindowClose = delegate(object s, EventArgs e)
		{
			this.CloseGamePayerRoleWindow();
			return true;
		};
		this.gamePayerRolePart.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
		{
			if (e.ID == -1)
			{
				this.CloseGamePayerRoleWindow();
				if (e.IDType == 1)
				{
					this.ShowSyntesizeWindow(false, 201);
				}
				else if (e.IDType == 2)
				{
					this.ShowMuDuiHuanWindow(0, 0);
				}
				else if (e.IDType == 3)
				{
					this.ShowJingLingPart(jinglingSystemPart.BtnType.JingLing);
				}
				else if (e.IDType == 4)
				{
					this.OpenRidePetPartWindow(RidePetUIType.ZuoQi);
				}
			}
			else if (e.ID == 1)
			{
				bool needToChangeLayer = e.IDType == 1;
				this.ShowShareWindow(needToChangeLayer);
			}
			else if (e.ID == -2)
			{
				this.CloseGamePayerRoleWindow();
				switch (e.IDType)
				{
				case 1:
					this.ShowMallWindow(false, 0, 1);
					break;
				case 2:
					this.ShowNPCSaleWindow(ConfigNPCs.FindNPCIDByName(Global.GetLang("莱雅")), 31);
					break;
				case 3:
					this.ShowMallWindow(false, 0, 3);
					break;
				case 4:
					this.ShowMuDuiHuanWindow(0, 0);
					break;
				case 5:
					this.OpenChengJiuSystem();
					break;
				case 6:
					this.ShowArenaWindow();
					ArenaPart.needToOpenJunxian = true;
					break;
				case 7:
					this.ShowGamePayerRoleWindow(GamePayerRolePart_PartID.GamePayerRolePart_XingHun);
					break;
				case 8:
					this.ShowJingLingPart(jinglingSystemPart.BtnType.JingLing);
					break;
				case 9:
					this.ShowJingLingPart(jinglingSystemPart.BtnType.YuanSuZhiXin);
					break;
				case 10:
					this.ShowLianluWindow(9, 0);
					break;
				case 11:
					this.ShowGuardStatueWindow();
					break;
				case 12:
					this.ShowTianTiJingSaiWindow();
					break;
				case 13:
					this.ShowFluorescentDiamondWindow(FluorescentOpenTypes.DiamondInlay);
					break;
				case 14:
					this.ShowFluorescentDiamondWindow(FluorescentOpenTypes.SoulCometStone);
					break;
				case 15:
					this.OpenShenQiSystemPart();
					break;
				case 16:
					this.OpenTeamCompetePart(false);
					break;
				case 17:
					this.ShowQiFuWindow(false);
					break;
				case 18:
					this.ProcessGuideRequest(new DPSelectedItemEventArgs
					{
						ID = 1535
					});
					break;
				}
			}
			return true;
		};
		this.GamePayerRoleWindow.SetContent(this.GamePayerRoleWindow.BodyPresenter, this.gamePayerRolePart, 0.0, 0.0, true);
	}

	public void CloseGamePayerRoleWindow()
