	protected void ShowRepetitionWindow(int npcID = 0, bool caching = false, ActivityCategorys activityCategorys = ActivityCategorys.JuQingFuBen, int TabID = -1)
	{
		if (null != this.RepetitionWindow)
		{
			if (this.RepetitionWindow.Visibility)
			{
				this.CloseAutoPlayWindow();
			}
			this.RepetitionWindow.Visibility = true;
			this.LimitChildWindowRange(this.RepetitionWindow);
			GChildWindow.ZZ++;
			if ((double)GChildWindow.ZZ > Canvas.GetZIndex(this.RepetitionWindow))
			{
				Canvas.SetZIndex(this.RepetitionWindow, (double)GChildWindow.ZZ);
			}
			this.repetitionPart.NpcID = npcID;
			this.repetitionPart.ResetGetNewData();
			this.repetitionPart.GetNewData();
			if (0 <= TabID)
			{
				this.repetitionPart.ShowRiChangFuBenDetailPart(activityCategorys, TabID);
			}
			return;
		}
		this.RepetitionWindow = U3DUtils.NEW<GChildWindow>();
		this.RepetitionWindow.HeadLeft = 0.0;
		this.RepetitionWindow.HeadTop = 0.0;
		this.RepetitionWindow.HeadWidth = 604.0;
		this.RepetitionWindow.HeadHeight = 64.0;
		this.RepetitionWindow.BodyLeft = 0.0;
		this.RepetitionWindow.BodyTop = 64.0;
		this.RepetitionWindow.BodyWidth = 604.0;
		this.RepetitionWindow.BodyHeight = 261.0;
		this.RepetitionWindow.ImgTitle = "NetImages/GameRes/Images/WinTitle/FubenChuansong.png";
		this.InitChildWindow(this.RepetitionWindow, Global.GetLang("副本传送"));
		this.RepetitionWindow.ChildWindowClose = delegate(object s, EventArgs e)
		{
			this.CloseAutoPlayWindow();
			return true;
		};
		this.Root.Children.Add(this.RepetitionWindow);
		this.repetitionPart = U3DUtils.NEW<RiChangFuBenPart>();
		this.repetitionPart.NpcID = npcID;
		this.repetitionPart.BodyBackgroundURL = new ImageURL(Global.GetGameResImageString("richangHuodongRichangFuben_bak.jpg"), false, 0);
		this.RepetitionWindow.SetContent(this.RepetitionWindow.BodyPresenter, this.repetitionPart, 9.0, 0.0, true);
		if (!caching)
		{
			this.repetitionPart.NpcID = npcID;
		}
		if (caching)
		{
			this.RepetitionWindow.Visibility = false;
		}
		if (0 <= TabID)
		{
			this.repetitionPart.ShowRiChangFuBenDetailPart(activityCategorys, TabID);
		}
	}

