	protected void ShowMingXiangWindow()
	{
		if (null == this.mingXiangPart)
		{
			GChildWindow mingXiangWindow = null;
			this.mingXiangPart = U3DUtils.NEW<MingXiangPart>();
			mingXiangWindow = PlayZone.AddChildWindow(this.mingXiangPart, ChildWindowModalType.Translucent);
			mingXiangWindow.ChildWindowClose = delegate(object s, EventArgs e)
			{
				this.CloseChildWindow(mingXiangWindow);
				return true;
			};
			this.mingXiangPart.InitPartSize();
			GameInstance.Game.CMD_SPR_GET_MEDITATE_GOODS_Request();
			this.mingXiangPart.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
			{
				if (e.ID == 1)
				{
					this.ShowChongZhiWindow();
				}
				else
				{
					this.CloseChildWindow(mingXiangWindow);
					Object.Destroy(mingXiangWindow.gameObject);
					this.mingXiangPart = null;
				}
			};
		}
	}

	protected void ShowAutoPlayWindow(bool caching = false)
	{
		if (Global.Data.GameScene.OnLeaderPreMove())
		{
			return;
		}
		if (this.scene.IsInStalling())
		{
			return;
		}
		if (Global.IsAutoFighting())
		{
		}
		if (null != this.AutoPlayWindow)
		{
			this.AutoPlayWindow.Visibility = true;
			this.autoPart.InitPartSize((int)this.AutoPlayWindow.BodyWidth - 18, (int)this.AutoPlayWindow.BodyHeight - 9);
			return;
		}
		this.AutoPlayWindow = U3DUtils.NEW<GChildWindow>();
		this.InitChildWindow(this.AutoPlayWindow, Global.GetLang("自动挂机"));
		this.AutoPlayWindow.ChildWindowClose = delegate(object s, EventArgs e)
		{
			this.CloseAutoPlayWindow();
			return true;
