						tc.Container.BackgroundURL = new ImageURL(Global.GetGameResImageURL("Images/Plate/jysc_twlb_bak.png"), false, 0);
						gtabControl.SetBody(this.markStallListPart);
						this.markStallListPart.GetNewData(0, string.Empty);
					}
				}
			}
		};
		this.markStallListPart.InitPartData();
		this.markItemListPart.InitPartData();
		if (!caching)
		{
			this.markStallListPart.ResetGetNewData();
			this.markItemListPart.ResetGetNewData();
			if (tabIndex == 0)
			{
				tc.Container.BackgroundURL = new ImageURL(Global.GetGameResImageURL("Images/Plate/jysc_twlb_bak.png"), false, 0);
				tc.SetBody(this.markStallListPart);
				this.markStallListPart.GetNewData(toViewOtherRoleID, toViewOtherRoleName);
			}
			else if (tabIndex == 1)
			{
				tc.Container.BackgroundURL = new ImageURL(Global.GetGameResImageURL("Images/Plate/jysc_wplb_bak.png"), false, 0);
				tc.SetBody(this.markItemListPart);
				this.markItemListPart.GetNewData(-1);
			}
			tc.SelectItem(new object[]
			{
				tabIndex
			});
		}
		this.MarkWindow.SetContent(this.MarkWindow.BodyPresenter, tc, 9.0, 0.0, true);
		if (caching)
		{
			this.MarkWindow.Visibility = false;
		}
	}

