			if (gmenuItem.MenuItemID >= 0)
			{
				if (gmenuItem.MenuItemID == 0)
				{
					this.ShowForgeWindow();
				}
				else if (gmenuItem.MenuItemID == 1)
				{
					this.ShowEnhanceWindow();
				}
				else if (gmenuItem.MenuItemID == 2)
				{
					this.ShowEquipUpgradeWindow();
				}
				else if (gmenuItem.MenuItemID == 3)
				{
					this.ShowSubForgeWindow(-1);
				}
				else if (gmenuItem.MenuItemID == 4)
				{
					this.ShowEnchaseBijouWindow();
				}
				else if (gmenuItem.MenuItemID == 5)
				{
					this.ShowSyntesizeWindow(false, 0);
				}
				else if (gmenuItem.MenuItemID == 6)
				{
					this.ShowTianShengXiLianWindow();
				}
				else if (gmenuItem.MenuItemID == 7)
				{
					this.ShowZhuangBeiChuanChengWindow();
				}
			}
			this.CloseNoBorderWindow(this.QuickItemMenuWindow);
			this.QuickItemMenuWindow = null;
		};
		this.QuickItemMenuWindow.SetContent(this.QuickItemMenuWindow.BodyPresenter, this.menuPart, 2.0, 2.0);
	}

