	public void ShowOtherRolePopupMenuWindow(int x, int y)
	{
		if (null != this.OtherRolePopupMenuWindow)
		{
			this.CloseNoBorderWindow(this.OtherRolePopupMenuWindow);
			this.OtherRolePopupMenuWindow = null;
			this.menuPart = null;
		}
		this.menuPart = U3DUtils.NEW<GMenuPart>();
		string imageFileName = "Images/Plate/menu_item_unselected.png";
		for (int i = 0; i < this.OtherRoleMenuItemIDs.Length; i++)
		{
			if (i != 4 && i != 8)
			{
				if (i != 2 || (Global.Data.CurrentTeamData != null && Global.Data.CurrentTeamData.LeaderRoleID == Global.Data.roleData.RoleID && Global.Data.CurrentTeamData.TeamRoles.Count < 5))
				{
					if (i == 3)
					{
						if (Global.Data.CurrentTeamData != null)
						{
							goto IL_157;
						}
						if (!Global.Data.OtherRoles.ContainsKey(this.objectFaceID))
						{
							goto IL_157;
						}
						RoleData value = Global.Data.OtherRoles.GetValue(this.objectFaceID);
						if (value.TeamID <= 0)
						{
							goto IL_157;
						}
					}
					if ((i != 9 && i != 10) || Global.IsHuangDi(Global.Data.roleData))
					{
						this.menuPart.AddMenuItem(this.OtherRoleMenuItemIDs[i], imageFileName, this.OtherRoleMenuItemNames[i], null);
					}
				}
			}
			IL_157:;
		}
		this.OtherRolePopupMenuWindow = U3DUtils.NEW<NoBorderWindow>();
		this.OtherRolePopupMenuWindow.BodyLeft = 0.0;
		this.OtherRolePopupMenuWindow.BodyTop = 0.0;
		this.OtherRolePopupMenuWindow.BodyWidth = 120.0;
		this.OtherRolePopupMenuWindow.BodyHeight = (double)((this.menuPart.ItemCount + 1) * 21);
		this.OtherRolePopupMenuWindow.BodyBackBrush = new SolidColorBrush(1185560U);
		this.OtherRolePopupMenuWindow.BodyBackOpacity = 0.9;
		this.OtherRolePopupMenuWindow.Left = (double)x;
