	protected void ProcessOtherRoleMenuClick(int menuID)
	{
		switch (menuID)
		{
		case 0:
			if (this.ObjectFaceType == GSpriteTypes.Other)
			{
				GameInstance.Game.SpriteGetOtherAttrib(this.objectFaceID);
			}
			break;
		case 1:
			if (null != this.GameChatBox && this.ObjectFaceType == GSpriteTypes.Other)
			{
				this.GameChatBox.ShowInputBox(StringUtil.substitute("/{0} ", new object[]
				{
					this.ObjectRoleFace.VSName
				}), true);
			}
			break;
		case 2:
			if (this.ObjectFaceType == GSpriteTypes.Other)
			{
				if (this.ObjectRoleFace.TeamMode)
				{
					GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("抱歉，对方已有队伍不能再接受邀请!"), new object[0]), 0, -1, -1, 0);
				}
				else
				{
					GameInstance.Game.SpriteTeam(3, this.objectFaceID, 0);
				}
			}
			break;
		case 3:
			if (this.ObjectFaceType == GSpriteTypes.Other && Global.Data.OtherRoles.ContainsKey(this.objectFaceID))
			{
				RoleData value = Global.Data.OtherRoles.GetValue(this.objectFaceID);
				if (value.TeamID > 0)
				{
					GameInstance.Game.SpriteTeam(4, this.objectFaceID, 0);
					Super.HintMainText(StringUtil.substitute(Global.GetLang("申请入队请求已发出，请等待队长的回复。"), new object[0]), 10, 3);
				}
			}
			break;
		case 4:
			try
			{
				if (Global.Data.OtherRoles.ContainsKey(this.objectFaceID))
				{
					RoleData value2 = Global.Data.OtherRoles.GetValue(this.objectFaceID);
				}
			}
			catch (Exception ex)
			{
				MUDebug.LogException(ex);
				GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("调用系统剪贴板功能出错!"), new object[0]), 0, -1, -1, 0);
			}
			break;
		case 5:
			if (this.ObjectFaceType == GSpriteTypes.Other && this.ObjectRoleFace.Visibility)
			{
				GameInstance.Game.SpriteGoodsExchange(this.objectFaceID, 1, -1);
			}
			break;
		case 6:
			if (this.ObjectFaceType == GSpriteTypes.Other)
			{
				FriendData friendData = Global.FindFriendData(this.ObjectRoleFace.VSName);
				if (friendData == null)
				{
					GameInstance.Game.SpriteAddFriend(-1, this.ObjectRoleFace.VSName, 0);
				}
				else if (friendData.FriendType != 0)
				{
					GameInstance.Game.SpriteAddFriend(friendData.DbID, friendData.OtherRoleName, 0);
				}
				else
				{
					string lang = Global.GetLang("好友");
					if (friendData.FriendType == 1)
					{
						lang = Global.GetLang("屏蔽");
					}
					else if (friendData.FriendType == 2)
					{
						lang = Global.GetLang("仇人");
					}
					GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("【{0}】已经在{1}列表中"), new object[]
					{
						this.ObjectRoleFace.VSName,
						lang
					}), 0, -1, -1, 0);
				}
			}
			break;
		case 7:
			if (this.ObjectFaceType == GSpriteTypes.Other)
			{
				FriendData friendData2 = Global.FindFriendData(this.ObjectRoleFace.VSName);
				if (friendData2 == null)
				{
					GameInstance.Game.SpriteAddFriend(-1, this.ObjectRoleFace.VSName, 1);
				}
				else if (friendData2.FriendType != 1)
				{
					GameInstance.Game.SpriteAddFriend(friendData2.DbID, friendData2.OtherRoleName, 1);
				}
				else
				{
					string lang2 = Global.GetLang("好友");
					if (friendData2.FriendType == 1)
					{
						lang2 = Global.GetLang("屏蔽");
					}
					else if (friendData2.FriendType == 2)
					{
						lang2 = Global.GetLang("仇人");
					}
					GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("【{0}】已经在{1}列表中"), new object[]
					{
						this.ObjectRoleFace.VSName,
						lang2
					}), 0, -1, -1, 0);
				}
			}
			break;
		case 8:
			if (this.ObjectFaceType == GSpriteTypes.Other)
			{
				this.ProcessMarketEvent(0, this.objectFaceID, this.ObjectRoleFace.VSName);
			}
			break;
		case 9:
			if (this.ObjectFaceType == GSpriteTypes.Other && Global.Data.OtherRoles.ContainsKey(this.objectFaceID))
			{
				RoleData value3 = Global.Data.OtherRoles.GetValue(this.objectFaceID);
				if (value3.HuangHou <= 0)
				{
					GameInstance.Game.SpriteAddHuangFei(this.objectFaceID, this.ObjectRoleFace.VSName);
				}
				else
				{
					GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("【{0}】已经是皇妃了"), new object[]
					{
						this.ObjectRoleFace.VSName
					}), 0, -1, -1, 0);
				}
			}
			break;
		case 10:
			if (this.ObjectFaceType == GSpriteTypes.Other)
			{
				GameInstance.Game.SpriteSendToLaoFang(this.objectFaceID, this.ObjectRoleFace.VSName);
			}
			break;
		case 11:
			this.ShowEmailWindow(false, this.ObjectRoleFace.VSName);
			break;
		}
	}

