			{
				return;
			}
			this.CloseNoBorderWindow(this.FormatedRoleMenuWindow);
			this.FormatedRoleMenuWindow = null;
			this.ProcessFormatedRoleMenuClick(gmenuItem.MenuItemID, this.menuPart.Tag as string);
		};
		this.FormatedRoleMenuWindow.SetContent(this.FormatedRoleMenuWindow.BodyPresenter, this.menuPart, 2.0, 2.0);
	}

	protected void ProcessFormatedRoleMenuClick(int menuID, string otherName)
	{
		if (string.IsNullOrEmpty(otherName))
		{
			return;
		}
		switch (menuID)
		{
		case 0:
			GameInstance.Game.SpriteQueryIDByName(otherName, 0);
			break;
		case 1:
			if (null != this.GameChatBox)
			{
				this.GameChatBox.ShowInputBox(StringUtil.substitute("/{0} ", new object[]
				{
					otherName
				}), true);
			}
			break;
		case 2:
			GameInstance.Game.SpriteQueryIDByName(otherName, 1);
			break;
		case 3:
			GameInstance.Game.SpriteQueryIDByName(otherName, 2);
			break;
		case 4:
			try
			{
			}
			catch (Exception ex)
			{
				MUDebug.LogException(ex);
				GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("调用系统剪贴板功能出错!"), new object[0]), 0, -1, -1, 0);
			}
			break;
		case 5:
			GameInstance.Game.SpriteQueryIDByName(otherName, 3);
			break;
		case 6:
		{
			FriendData friendData = Global.FindFriendData(otherName);
			if (friendData == null)
			{
				GameInstance.Game.SpriteAddFriend(-1, otherName, 0);
			}
			else if (friendData.FriendType != 0)
			{
				GameInstance.Game.SpriteAddFriend(friendData.DbID, friendData.OtherRoleName, 0);
			}
			else
			{
				string lang = Global.GetLang("好友");
				if (friendData.FriendType == 1)
				{
					lang = Global.GetLang("屏蔽");
				}
				else if (friendData.FriendType == 2)
				{
					lang = Global.GetLang("仇人");
				}
				GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("【{0}】已经在{1}列表中"), new object[]
				{
					otherName,
					lang
				}), 0, -1, -1, 0);
			}
			break;
		}
		case 7:
		{
			FriendData friendData = Global.FindFriendData(otherName);
			if (friendData == null)
			{
				GameInstance.Game.SpriteAddFriend(-1, otherName, 1);
			}
			else if (friendData.FriendType != 1)
			{
				GameInstance.Game.SpriteAddFriend(friendData.DbID, otherName, 1);
			}
			else
			{
				string lang2 = Global.GetLang("好友");
				if (friendData.FriendType == 1)
				{
					lang2 = Global.GetLang("屏蔽");
				}
				else if (friendData.FriendType == 2)
				{
					lang2 = Global.GetLang("仇人");
				}
				GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("【{0}】已经在{1}列表中"), new object[]
				{
					otherName,
					lang2
				}), 0, -1, -1, 0);
			}
			break;
		}
		case 8:
			GameInstance.Game.SpriteQueryIDByName(otherName, 4);
			break;
		case 9:
			GameInstance.Game.SpriteQueryIDByName(otherName, 5);
			break;
		case 10:
			GameInstance.Game.SpriteQueryIDByName(otherName, 6);
			break;
		case 11:
			this.ShowEmailWindow(false, otherName);
			break;
		}
	}

