	public void ShowSystemHelpWindowWindow(int mode, string hintText = "")
	{
		if (null != this.systemHelpPart)
		{
			this.systemHelpPart.WaittingModes.Add(mode);
			return;
		}
		this.systemHelpPart = U3DUtils.NEW<SystemHelpPart>();
		if (null == this.systemHelpPart)
		{
			return;
		}
		Global.MainStage.Children.Add(this.systemHelpPart);
		this.systemHelpPart.transform.localPosition = new Vector3(0f, 0f, -9900f);
		this.systemHelpPart.HintText = hintText;
		this.systemHelpPart.InitPartSize(350, 20);
		if (!this.systemHelpPart.InitPartData(mode))
		{
			if (null != this.systemHelpPart)
			{
				this.systemHelpPart.Destroy();
				this.Root.Children.Remove(this.systemHelpPart, true);
				this.systemHelpPart = null;
			}
			return;
		}
		this.systemHelpPart.ToClose = delegate(object s, EventArgs e)
		{
			if (null != this.systemHelpPart)
			{
				this.systemHelpPart.Destroy();
				this.Root.Children.Remove(this.systemHelpPart, true);
				this.systemHelpPart = null;
			}
		};
	}

	protected void InitCoodownEvent()
	{
		Global.NotifyAddCoolDown = new EventHandler(this.NotifyAddCoolDown);
		Global.NotifyGoodsAddCoolDown = new EventHandler(this.NotifyAddGoodsCoolDown);
		Global.NotifyEmblemAddCoolDown = new EventHandler(this.NotifyEmblemAddCoolDown);
	}

	private void NotifyEmblemAddCoolDown(object sender, object _e)
	{
		EmblemCoolDownEventArgs emblemCoolDownEventArgs = _e as EmblemCoolDownEventArgs;
		if (null != this.GameCtrlBar && emblemCoolDownEventArgs != null)
		{
			this.GameCtrlBar.RefreshEmblemCoodDown(emblemCoolDownEventArgs.EmblemID, emblemCoolDownEventArgs.CDTicks, emblemCoolDownEventArgs.ContinuedTicks);
		}
	}

	protected void NotifyAddGoodsCoolDown(object sender, object _e)
	{
	}

	protected void NotifyAddCoolDown(object sender, object _e)
	{
		if (_e == EventArgs.Empty)
		{
			MUDebug.LogError<string>(new string[]
			{
				"调用要传参数啊!!!"
			});
			return;
		}
		CoolDownEventArgs coolDownEventArgs = _e as CoolDownEventArgs;
		if (null != this.GameCtrlBar && coolDownEventArgs != null)
		{
			this.GameCtrlBar.RefreshCoolDown(coolDownEventArgs.SkillID, coolDownEventArgs.ToDrawTicks);
		}
		if (null != this.MainQuickBar)
		{
			this.MainQuickBar.RefreshCoolDown(coolDownEventArgs.SkillID, true);
		}
	}

