	protected void ProcessFactionEvent()
	{
		if (Global.IsOperateUnPermitInKuaFuMapCheck(true, false))
		{
			return;
		}
		if (Global.Data.roleData.HideGM > 0)
		{
			if (PlayZone.GlobalPlayZone != null)
			{
				PlayZone.GlobalPlayZone.OpenWolfSoulFieldWorldWindow();
			}
			return;
		}
		if (Super.GData.BangHuiUIItemQueue.Count > 0)
		{
			this.GameMenuIconBoxContainer.StopAnimation(6);
			this.ShowFamilyRequestWindow();
		}
		else if (string.IsNullOrEmpty(Global.Data.roleData.BHName))
		{
			this.ShowFamilyCreateWindow(false);
		}
		else
		{
			this.ShowFamilyWindow(Global.Data.roleData.Faction, false);
		}
	}

	protected void ProcessAutoPlayEvent()
	{
		if (Global.IsAutoFighting())
		{
			Super.HintEndAutoFight(true);
		}
		this.ShowAutoPlayWindow(false);
	}

	protected void ProcessTeamEvent()
	{
		if (Super.GData.TeamUIItemQueue.Count > 0)
