	protected void ShowEquipUpgradeWindow()
	{
		if (!(null != this.EquipUpgradeWindow))
		{
			this.EquipUpgradeWindow = U3DUtils.NEW<GChildWindow>();
			this.EquipUpgradeWindow.Left = (double)(Super.GetChildLeft((int)Global.GlobalMainWindow.ActualWidth, 1000) + 105);
			this.EquipUpgradeWindow.Top = (double)(Super.GetChildTop((int)Global.GlobalMainWindow.ActualHeight, 600) + 50);
			this.EquipUpgradeWindow.HeadLeft = 0.0;
			this.EquipUpgradeWindow.HeadTop = 0.0;
			this.EquipUpgradeWindow.HeadWidth = 358.0;
			this.EquipUpgradeWindow.HeadHeight = 64.0;
			this.EquipUpgradeWindow.BodyLeft = 0.0;
			this.EquipUpgradeWindow.BodyTop = 64.0;
			this.EquipUpgradeWindow.BodyWidth = 358.0;
			this.EquipUpgradeWindow.BodyHeight = 389.0;
			this.InitChildWindow(this.EquipUpgradeWindow, Global.GetLang("装备进阶"));
			this.EquipUpgradeWindow.ChildWindowClose = delegate(object s, EventArgs e)
			{
				this.CloseChildWindow(s as GChildWindow);
				this.EquipUpgradeWindow = null;
				this.equipUpgradePart.Destroy();
				this.equipUpgradePart = null;
				return true;
			};
			this.Root.Children.Add(this.EquipUpgradeWindow);
			this.equipUpgradePart = U3DUtils.NEW<EquipUpgradePart>();
			this.equipUpgradePart.BodyBackgroundURL = new ImageURL(Global.GetGameResImageURL("Images/Plate/zbjj_bak.png"), false, 0);
			this.equipUpgradePart.InitPartSize((int)this.EquipUpgradeWindow.BodyWidth - 18, (int)this.EquipUpgradeWindow.BodyHeight - 9);
			this.equipUpgradePart.InitPartData();
			this.equipUpgradePart.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
			{
				if (e.IDType == 1)
				{
					this.HideEquipUpgradeWindowTicks = (double)Global.GetCorrectLocalTime();
					this.EquipUpgradeWindow.Visibility = false;
				}
			};
			this.EquipUpgradeWindow.SetContent(this.EquipUpgradeWindow.BodyPresenter, this.equipUpgradePart, 9.0, 0.0, true);
			return;
		}
		if (this.HideEquipUpgradeWindowTicks > 0.0)
		{
			return;
		}
	}

	protected void ReShowEquipUpgradeWindow()
	{
		if (this.HideEquipUpgradeWindowTicks <= 0.0)
		{
			return;
		}
		if (null == this.EquipUpgradeWindow)
		{
			return;
		}
		if (this.EquipUpgradeWindow.Visibility)
		{
			return;
		}
		double num = (double)Global.GetCorrectLocalTime();
		if (num - this.HideEquipUpgradeWindowTicks < 1000.0)
		{
			return;
		}
		this.HideEquipUpgradeWindowTicks = 0.0;
		this.EquipUpgradeWindow.Visibility = true;
	}

