	protected void ProcessActivityTipCountInShowTimeCount()
	{
		double num = (double)Global.GetCorrectLocalTime();
		if (num - this.LastActivityTipCountInShowTimeTicks < 5000.0)
		{
			return;
		}
		this.LastActivityTipCountInShowTimeTicks = num;
		ActivityTime activityTime = new ActivityTime();
		int num2;
		string title;
		bool flag;
		int activityTipCountInShowTime = Global.GetActivityTipCountInShowTime(activityTime, out num2, out title, out flag);
		if (!Global.InActivityMap() && num2 == 17)
		{
			ActivityTipItem activityTipItem = ActivityTipManager.GetActivityTipItem(15003);
			if (activityTipItem.IsActive)
			{
				this.ShowActivityHintWindow(num2, title, activityTime);
			}
		}
		else if (!Global.InActivityMap() && num2 >= 0)
		{
			this.ShowActivityHintWindow(num2, title, activityTime);
		}
		else
		{
			this.HideActivityHintWindow();
		}
		ActivityTipManager.OnChangeItemCountValue(1006, activityTipCountInShowTime);
		if (flag)
		{
			ActivityTipManager.OnChangeItemCountValue(1100, 1);
		}
		else
		{
			ActivityTipManager.OnChangeItemCountValue(1100, 0);
		}
	}

	protected void ProcessEquipStrongAndBagCheck()
	{
