			return;
		}
		this.LastEquipStrongCheckTicks = num;
		if (null != this.GameHintQueueIcon)
		{
			this.GameHintQueueIcon.CheckBagItemChange();
			this.GameHintQueueIcon.CheckEquipBroken();
			this.GameHintQueueIcon.CheckEquipInvalid();
		}
