	private void ProcessLifeMagicCheck()
	{
		if (20 > Global.Data.roleData.Level && 0 >= Global.Data.roleData.ChangeLifeCount)
		{
			return;
		}
		float num = 100f * (float)Global.Data.roleData.LifeV / (float)Global.Data.roleData.MaxLifeV;
		float num2 = 100f * (float)Global.Data.roleData.MagicV / (float)Global.Data.roleData.MaxMagicV;
		bool flag = false;
		bool flag2 = false;
		if (Global.Data.AutoFightData != null)
		{
			flag = (num < (float)Global.Data.AutoFightData.LifeLessThanX);
			flag2 = (num2 < (float)Global.Data.AutoFightData.MagicLessThanX);
		}
		if (flag || flag2)
		{
			if (!Global.g_bIsYaoPinTip)
			{
				bool flag3 = false;
				if (flag)
				{
					flag3 = true;
					foreach (int goodsID in ConfigSystemParam.GetSystemParamIntArrayByName("AutoAddLifeVGoodsIDs", ','))
					{
						GoodsData goodsDataByID = Global.GetGoodsDataByID(goodsID);
						if (goodsDataByID != null)
						{
							flag3 = false;
							break;
						}
					}
				}
				bool flag4 = false;
				if (flag2)
				{
					flag4 = true;
					foreach (int goodsID2 in ConfigSystemParam.GetSystemParamIntArrayByName("AutoAddMagicVGoodsIDs", ','))
					{
						GoodsData goodsDataByID2 = Global.GetGoodsDataByID(goodsID2);
						if (goodsDataByID2 != null)
						{
							flag4 = false;
							break;
						}
					}
				}
				if (flag3)
				{
					this.GameHintQueueIcon.RemoveHint(HintQueueIcon.HintTypes.YaoPinTipMaigc, true);
					this.GameHintQueueIcon.AddNewHint(HintQueueIcon.HintTypes.YaoPinTip, new object[0]);
				}
				else if (flag4)
				{
					this.GameHintQueueIcon.RemoveHint(HintQueueIcon.HintTypes.YaoPinTip, true);
					this.GameHintQueueIcon.AddNewHint(HintQueueIcon.HintTypes.YaoPinTipMaigc, new object[0]);
				}
			}
		}
		else
		{
			this.GameHintQueueIcon.RemoveHint(HintQueueIcon.HintTypes.YaoPinTip, true);
			this.GameHintQueueIcon.RemoveHint(HintQueueIcon.HintTypes.YaoPinTipMaigc, true);
			this.GameHintQueueIcon.ProcessHintQueue(true);
		}
	}

	protected void StartUITimer()
	{
		this.UITimer = new DispatcherTimer("PlayZone_GameCtrl_UITimer")
		{
			Interval = TimeSpan.FromMilliseconds(500.0)
		};
		this.UITimer.Tick = new DispatcherTimerEventHandler(this.UITimer_Tick);
		this.UITimer.Start();
	}

	protected void ProcessDailyInfo()
	{
		long correctLocalTime = Global.GetCorrectLocalTime();
		if (correctLocalTime - this.LastCurrentDayOfYearLastTick < 10000L)
		{
			return;
		}
		this.LastCurrentDayOfYearLastTick = correctLocalTime;
		DateTime correctDateTime = Global.GetCorrectDateTime();
		if (this.CurrentDayOfYear < 0L)
		{
			this.CurrentDayOfYear = (long)correctDateTime.Day;
		}
		else if ((long)correctDateTime.Day != this.CurrentDayOfYear)
		{
			Global.Data.roleData.AdorationCount = 0;
		}
	}

	protected void UITimer_Tick(object sender, object e)
	{
		if (this.scene == null)
		{
			return;
		}
		long correctLocalTime = Global.GetCorrectLocalTime();
		this.ProcessActiveHelp(correctLocalTime);
		ActivityTipManager.OnTimer(correctLocalTime);
		SystemHelpMgr.TimerTick(correctLocalTime);
		this.scene.AutoUseSkillManager();
		this.ShowNewTiShiGoodsWizard();
		this.ShowNewEquipGoodsWizard();
		this.ShowGetGoodsHintEx();
		this.ProcessActivityTipCountInShowTimeCount();
		this.ProcessEquipStrongAndBagCheck();
		this.ProcessLifeMagicCheck();
		this.ProcessDailyInfo();
		this.AutoExpandBagGridTime();
		SpecialPromptManager.GetInstance().ProcesspecialPrompt();
		if (null != this.GameHintQueueIcon)
		{
			this.GameHintQueueIcon.OnTimer(correctLocalTime);
			this.GameHintQueueIcon.ProcessHintQueue(false);
		}
		this.UpdateFaceUI(correctLocalTime);
		this.ProcessSendPushMessageID();
		if (!this.scene.IsMoving())
		{
			if (GException.GetExceptionMsgList().Count > 0)
			{
				if (null != this.RadarMap && !this.RadarMap.ExceptionVisible)
				{
					this.RadarMap.ExceptionVisible = true;
				}
			}
			else if (null != this.RadarMap && this.RadarMap.ExceptionVisible)
			{
				this.RadarMap.ExceptionVisible = false;
			}
		}
		if (null != this.LeaderExperience)
		{
			this.LeaderExperience.RefreshTime();
		}
	}

