	private void ProcessCheckActivityTip()
	{
		if (U3DUtils.GetTimer() - this.LastActivityTipCheckTicks < 2000)
		{
			return;
		}
		if (!RightUpIconMgr.Instance().IsShowAll)
		{
			return;
		}
		this.LastActivityTipCheckTicks = U3DUtils.GetTimer();
		List<string> iconCfgWndNameList = Global.GetIconCfgWndNameList();
		for (int i = 0; i < iconCfgWndNameList.Count; i++)
		{
			this.TryShowActivityTipButton(iconCfgWndNameList[i]);
		}
	}

	private void TryShowActivityTipButton(string name)
	{
		int cfgWndIDByName = CfgWndName.GetCfgWndIDByName(name);
		if (cfgWndIDByName >= 0)
		{
			if (Global.IsActivityTipInShowTime(cfgWndIDByName))
			{
				CfgSingleWndMgr.Instance().ShowWindow(name, true, null);
				RightUpIconMgr.Instance().Add(CfgSingleWndMgr.Instance().Get(name));
			}
			else
			{
				CfgSingleWndMgr.Instance().HideWindow(name);
				RightUpIconMgr.Instance().Remove(CfgSingleWndMgr.Instance().Get(name));
			}
		}
	}

	protected void ProcessQueryIDByName(string name, int opCode, int otherRoleID, int olineState)
	{
		if (otherRoleID == -1)
		{
			GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("角色【{0}】已经离线"), new object[]
			{
				name
			}), 0, -1, -1, 0);
			return;
		}
		if (olineState < 0)
		{
			GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("角色【{0}】已经离线"), new object[]
			{
				name
			}), 0, -1, -1, 0);
			return;
		}
		if (olineState > 0)
		{
			GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("角色【{0}】在{1}线上, 无法操作"), new object[]
			{
				name,
				olineState
			}), 0, -1, -1, 0);
			return;
		}
		switch (opCode)
		{
		case 0:
			GameInstance.Game.SpriteGetOtherAttrib(otherRoleID);
			break;
		case 1:
			GameInstance.Game.SpriteTeam(3, otherRoleID, 0);
			break;
		case 2:
			GameInstance.Game.SpriteTeam(4, otherRoleID, 0);
			Super.HintMainText(StringUtil.substitute(Global.GetLang("申请入队请求已发出，请等待队长的回复。"), new object[0]), 10, 3);
			break;
		case 3:
			GameInstance.Game.SpriteGoodsExchange(otherRoleID, 1, -1);
			break;
		case 4:
			this.ProcessMarketEvent(0, otherRoleID, name);
			break;
		case 5:
			GameInstance.Game.SpriteBanChatToWorldMap(otherRoleID, name);
			break;
		case 6:
			GameInstance.Game.SpriteTakeOutLaoFang(otherRoleID, name);
			break;
		}
	}

