	public void ShowNewTaskWizard(int taskID)
	{
		if (!Super.CanShowSystemWizard(1))
		{
			return;
		}
		TaskVO taskXmlNodeByID = ConfigTasks.GetTaskXmlNodeByID(taskID);
		if (taskXmlNodeByID == null)
		{
			return;
		}
		int limitLevel = taskXmlNodeByID.LimitLevel;
		if (limitLevel > 0 && Global.Data.roleData.Level < limitLevel)
		{
			return;
		}
		SystemHintWindow.AddRoleInfoHintText(uint.MaxValue, StringUtil.substitute(Global.GetLang("接受了新任务[{0}]"), new object[]
		{
			taskXmlNodeByID.Title
		}));
		if (base.TriggerTaskPlot(SystemHelpModes.NewTask, taskID, null))
		{
			return;
		}
		this._SystemWizardPart.InitPartData(1);
	}

	public void ShowCompleteTaskWizard(int taskID, bool canShow = false)
	{
		int taskClassByID = Global.GetTaskClassByID(taskID);
		if (taskClassByID >= 3 && taskClassByID <= 8)
		{
			DailyTaskData dailyTaskData = Global.FindDailyTaskDataByTaskClass(taskClassByID);
			int num = 0;
			if (dailyTaskData != null)
			{
				num = dailyTaskData.RecNum;
			}
			int maxDailyTaskNum = Global.GetMaxDailyTaskNum(taskClassByID, dailyTaskData);
			if (num >= maxDailyTaskNum - 1)
			{
				this.scene.CancelAutoFindRoad(true);
			}
		}
		if (!Super.CanShowSystemWizard(2))
		{
			return;
		}
		TaskVO taskXmlNodeByID = ConfigTasks.GetTaskXmlNodeByID(taskID);
		if (taskXmlNodeByID == null)
		{
			return;
		}
		bool flag = false;
		TaskData taskDataByID = Global.GetTaskDataByID(taskID);
		if (taskDataByID == null)
		{
			return;
		}
		if (Super.JugeTaskComplete(taskXmlNodeByID, taskDataByID.DoingTaskVal1, taskDataByID.DoingTaskVal2))
		{
			flag = true;
		}
		if (!flag)
		{
			if (Super.JugeTaskTargetComplete(taskXmlNodeByID, 1, taskDataByID.DoingTaskVal1) && !Super.JugeTaskTargetComplete(taskXmlNodeByID, 2, taskDataByID.DoingTaskVal2) && taskDataByID.DoingTaskVal2 <= 0)
			{
				this.ShowNewTaskWizard(taskID);
			}
			return;
		}
		int num2 = 0;
		int num3 = -1;
		int num4 = 3;
		int num5 = 0;
		int num6 = 0;
		int num7 = -1;
		int num8 = -1;
		int num9 = 0;
		Super.GetTaskDestNPCID(taskXmlNodeByID, ref num3, ref num4, ref num9);
		Super.GetTaskTargetID(taskXmlNodeByID, 1, out num2, out num3, out num6, out num5, out num6, false, out num7, out num8);
		if (num6 == 0 && num9 == num5)
		{
			return;
		}
		Super.GetTaskTargetID(taskXmlNodeByID, 2, out num2, out num3, out num4, out num5, out num6, false, out num7, out num8);
		if (num6 == 0 && num9 == num5)
		{
			return;
		}
		if (!canShow)
		{
			bool flag2 = base.TriggerTaskPlot(SystemHelpModes.TaskOk, taskID, null);
			if (Global.IsAutoFighting() && Global.GetMapSceneUIClass() != SceneUIClasses.TaskCopy)
			{
				Global.Data.GameScene.CancelAutoFight(0, true);
				if (flag2)
				{
					return;
				}
				Super.PrccessAutoTaskFindRoad(taskID, false, true, false, false);
			}
		}
		this._SystemWizardPart.TaskID = taskID;
		this._SystemWizardPart.AllInstantAutoFindRoad = !canShow;
		this._SystemWizardPart.InitPartData(2);
	}

