	private void ShowNewTiShiGoodsWizard()
	{
		long correctLocalTime = Global.GetCorrectLocalTime();
		if (correctLocalTime - this.LastShowNewTiShiGoodsWizardTick < 1000L)
		{
			return;
		}
		this.LastShowNewTiShiGoodsWizardTick = correctLocalTime;
		if (!Super.CanShowSystemWizard(56))
		{
			return;
		}
		if (this.NewTiShiGoodsDbIDList.Count <= 0)
		{
			return;
		}
		int num = this.NewTiShiGoodsDbIDList[0];
		this.NewTiShiGoodsDbIDList.splice(0, 1, new int[0]);
		GoodsData goodsDataByDbID = Global.GetGoodsDataByDbID(num, null);
		if (goodsDataByDbID == null || goodsDataByDbID.Using > 0)
		{
			return;
		}
		List<int> list = new List<int>();
		while (this.NewTiShiGoodsDbIDList.Count > 0)
		{
			GoodsData goodsDataByDbID2 = Global.GetGoodsDataByDbID(this.NewTiShiGoodsDbIDList[0], null);
			if (goodsDataByDbID2 != null && goodsDataByDbID2.Using <= 0)
			{
				if (goodsDataByDbID.GoodsID != goodsDataByDbID2.GoodsID)
				{
					break;
				}
				list.Add(this.NewTiShiGoodsDbIDList[0]);
			}
			this.NewTiShiGoodsDbIDList.splice(0, 1, new int[0]);
		}
		if (list.Count > 0)
		{
			list.splice(0, 0, new int[]
			{
				num
			});
		}
		this._SystemWizardPart.GoodsDbID = num;
		this._SystemWizardPart.InitPartData(56);
	}

