		}
		BufferData bufferData = null;
		if (systemWizardType == 20)
		{
			bufferData = Global.GetBufferDataByID(4);
		}
		else
		{
			if (systemWizardType == 21)
			{
				return;
			}
			if (systemWizardType == 22)
			{
				bufferData = Global.GetBufferDataByID(1);
			}
			else if (systemWizardType == 24)
			{
				bufferData = Global.GetBufferDataByID(2);
			}
		}
		if (bufferData != null && !Global.IsBufferDataOver(bufferData, 0L, false))
		{
			return;
		}
		GoodsData goodsDataByDbID = Global.GetGoodsDataByDbID(goodsDbID, null);
		if (goodsDataByDbID == null || goodsDataByDbID.Using > 0)
		{
			return;
		}
		this._SystemWizardPart.GoodsDbID = goodsDbID;
		this._SystemWizardPart.InitPartData(systemWizardType);
	}

