	public void ExecuteSystemSettings()
	{
		if (Global.Data.SysSetting.CloseGameMusic)
		{
			Global.Data.SysSetting.CloseGameMusic = true;
			Global.BackgroundAudio43D.StopPlay();
		}
		else
		{
			Global.BackgroundAudio43D.PlayAudio(ConfigSettings.GetMapMusicFileByCode(Global.Data.roleData.MapCode, true), true, false);
			Global.Data.SysSetting.CloseGameMusic = false;
		}
		if (Global.Data.SysSetting.GraphicsQuality)
		{
			PerformanceCtrl.PerformanceType = PerformanceTypes.HiUsage;
		}
		else
		{
			PerformanceCtrl.PerformanceType = PerformanceTypes.LowUsage;
		}
	}

	public void ShowRolePropText()
	{
		double lastShowRolePropTextTicks = (double)Global.GetCorrectLocalTime();
		this.LastShowRolePropTextTicks = lastShowRolePropTextTicks;
		if (Super.GData.RoleTextQueue.Count <= 0)
		{
			return;
		}
		ShowTextItem showTextItem = Super.GData.RoleTextQueue.shift<ShowTextItem>();
		if (!string.IsNullOrEmpty(showTextItem.Text))
		{
			if (showTextItem.NumFormat > 0)
			{
				SystemHintWindow.AddPropsHintText((showTextItem.NumType != 0) ? 16711680U : 65280U, StringUtil.substitute("{0} {1}{2}-{3}{4}", new object[]
				{
					showTextItem.Text,
					(showTextItem.NumType != 0) ? string.Empty : string.Empty,
					showTextItem.NumVal2,
					(showTextItem.NumType != 0) ? string.Empty : string.Empty,
					showTextItem.NumVal
				}));
			}
			else
			{
				SystemHintWindow.AddPropsHintText((showTextItem.NumType != 0) ? 16711680U : 65280U, StringUtil.substitute("{0} {1}{2}", new object[]
				{
					showTextItem.Text,
					(showTextItem.NumType != 0) ? string.Empty : string.Empty,
					showTextItem.NumVal
				}));
			}
		}
	}

	protected void DoChangeLine()
	{
		if (GameInstance.Game.IsActiveDisconnect())
		{
			GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("网络已经断开，无法切线，请刷新网页后重新进入游戏"), new object[0]), 0, -1, -1, 0);
			return;
		}
		this.CloseLeaderAttributeWindow(0);
		this.CloseOtherAttributeWindow();
		this.CloseParcelWindow();
		this.CloseTaskManagerWindow();
		this.CloseNPCSaleWindow();
		this.CloseSkillWindow();
		this.CloseFriendsWindow();
		this.CloseGetThingWindow();
		this.CloseWorldNavigationWindow();
		this.CloseMallWindow();
		this.ClosePetsWindow();
		this.CloseAutoPlayWindow();
		this.CloseBiguanWindow();
		this.CloseGiftBagsWindow();
		this.CloseDigTreasureWindow();
		this.CloseRepetitionWindow();
		this.CloseSyntesizeWindow();
		this.CloseTopListWindow();
		this.CloseTeamWindow();
		this.CloseActivityWindow();
		this.CloseYabiaoWindow();
		this.CloseTouBaoWindow();
		this.CloseEnchaseBijouWindow();
		this.CloseEquipUpgradeWindow();
		this.CloseEnhanceWindow();
		this.CloseTianShengXiLianWindow();
		this.CloseForgeWindow();
		this.CancelNPCDialogWindows();
		this.CloseMarketWin();
		this.ClosePlayerTradingWindow();
		this.ClosePortableBagWindow();
		if (null != this.portableBagPart)
		{
			this.portableBagPart.ResetGetNewData();
		}
		this.scene.StopLeaderMoving();
		this.ShowChangingLineWindow();
	}

	protected bool IsChangingLine()
	{
		return Super.GData.IsChangingLine;
	}

	protected void ShowChangingLineWindow()
	{
		Global.Data.CurrentTeamData = null;
		if (null != this.GameTeamGroupBox)
		{
			this.GameTeamGroupBox.UpdateTeamRoleFaces();
		}
		if (null != this.team_Part_MyTeam)
		{
			this.team_Part_MyTeam.RefreshData();
		}
		this.changingLineWindow = U3DUtils.NEW<GNoHitWindow>();
		this.changingLineWindow.TimerCount = 10;
		this.changingLineWindow.TimerHint = Global.GetLang("正在切换线路, 倒计时");
		this.changingLineWindow.BodyWidth = Global.GlobalMainWindow.ActualWidth;
		this.changingLineWindow.BodyHeight = Global.GlobalMainWindow.ActualHeight;
		this.changingLineWindow.TimerCompleted = delegate(object s, EventArgs e)
		{
			Super.GData.IsChangingLine = false;
			Super.GData.StartConnectTicks = (double)Global.GetCorrectLocalTime();
			GameInstance.Game.Connect(Global.CurrentListData.GameServerIP, Global.CurrentListData.GameServerPort, false);
		};
		Canvas.SetZIndex(this.changingLineWindow, 100000.0);
		this.Root.Children.Add(this.changingLineWindow);
		Super.GData.IsChangingLine = true;
		GameInstance.Game.Disconnect();
		this.changingLineWindow.MyStart();
	}

	protected void HideChangingLineWindow()
	{
		if (null == this.changingLineWindow)
		{
			return;
		}
		Super.GData.StartConnectTicks = 0.0;
		this.changingLineWindow.Destroy();
		this.Root.Children.Remove(this.changingLineWindow, true);
		this.changingLineWindow = null;
	}

	protected void JugeChangingLineTimeout()
	{
		if (null == this.changingLineWindow)
		{
			return;
		}
		if (Super.GData.StartConnectTicks <= 0.0)
		{
			return;
		}
		if ((double)Global.GetCorrectLocalTime() - Super.GData.StartConnectTicks < 8000.0)
		{
			return;
		}
		this.HideChangingLineWindow();
		GameInstance.Game.Disconnect();
		Super.ShowMessageBoxEx(Super.MainWindowRoot, 0, Global.GetLang("错误"), Global.GetLang("网络错误, 切线超时，请刷新网页重新进入游戏"), -1, -1, -1, -1, true);
		GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("网络错误, 切线超时，请刷新网页后重新进入游戏"), new object[0]), 0, -1, -1, 0);
	}

