			this.enhancePart.RefreshGoodsCount();
		}
		if (null != this.ForgeWindow && this.ForgeWindow.Visibility && null != this.forgePart)
		{
			this.forgePart.RefreshGoodsCount();
		}
		if (null != this.TiLianWindow && this.TiLianWindow.Visibility && null != this.tiLianPart)
		{
			this.tiLianPart.RefreshGoodsCount();
		}
		if (null != this.ForgeWindow && this.ForgeWindow.Visibility && null != this.forgePart)
		{
			this.forgePart.RefreshGoodsCount();
		}
		if (null != this.EquipUpgradeWindow && this.EquipUpgradeWindow.Visibility && null != this.equipUpgradePart)
		{
			this.equipUpgradePart.RefreshGoodsCount();
		}
		if (!this.IsShowBiguanWindow() || null != this.biguanPart)
		{
		}
		if (this.IsShowLeaderAttributeWindow())
		{
		}
		if (this.IsShowDigTreasureWindow() && null != this.digtrPart)
		{
			this.digtrPart.RefreshGoodsCount();
		}
		this.TryShowNextJingMaiLevelGuangHuan();
		if (this.IsShowLianluWindow() && this.lianluPart != null)
		{
			this.lianluPart.RefreshGetAfter();
		}
	}

