	public bool JugeHintMainTaskWiward(bool ignoreTicks = true)
	{
		if (this.IsShowNPCDialogWindow())
		{
			return false;
		}
		if (this.IsShowNPCDoingTaskWindow())
		{
			return false;
		}
		if (this.IsShowNPCNewTaskWindow())
		{
			return false;
		}
		if (this.IsShowNPCLuaDialogWindowEx(1000004) || this.IsShowNPCLuaDialogWindowEx(1000005))
		{
			return false;
		}
		if (!this.scene.IsStandLongTime(20000.0))
		{
			return false;
		}
		int timer = U3DUtils.GetTimer();
		if (!ignoreTicks && timer - this._LastJugeHintMainTaskTicks <= 30000)
		{
			return false;
		}
		this._LastJugeHintMainTaskTicks = timer;
		int num = -1;
		bool flag = false;
		if (Global.Data.roleData.TaskDataList != null)
		{
			for (int i = 0; i < Global.Data.roleData.TaskDataList.Count; i++)
			{
				int doingTaskID = Global.Data.roleData.TaskDataList[i].DoingTaskID;
				TaskVO taskXmlNodeByID = ConfigTasks.GetTaskXmlNodeByID(doingTaskID);
				if (taskXmlNodeByID != null)
				{
					if (taskXmlNodeByID.TaskClass == 0)
					{
						int limitLevel = taskXmlNodeByID.LimitLevel;
						if (limitLevel <= 0 || Global.Data.roleData.Level >= limitLevel)
						{
							num = doingTaskID;
							flag = Super.JugeTaskComplete(taskXmlNodeByID, Global.Data.roleData.TaskDataList[i].DoingTaskVal1, Global.Data.roleData.TaskDataList[i].DoingTaskVal2);
						}
						break;
					}
				}
			}
		}
		if (num == -1)
		{
			return false;
		}
		if (num == (int)ConfigSystemParam.GetSystemParamIntByName("FirstMainTaskID"))
		{
			return false;
		}
		if (flag)
		{
			this.ShowCompleteTaskWizard(num, true);
		}
		return true;
	}

