	public void ExecuteNPCScriptHint(int npcID, int scriptID, int hint = 0)
	{
		string message = string.Empty;
		if (hint == 0)
		{
			if (MUVoiceManager.GetInstance().IsJunTuanRealTimeMap() || MUVoiceManager.GetInstance().IsZhanMengRealTimeMap())
			{
				MUVoiceManager.GetInstance().ExitRealTimeScene();
			}
			if (Global.IsInZhanMengLianSaiCompetetionMap())
			{
				this.IsShowUIInZhanMengLianSaiCompetition = true;
			}
			if (Global.IsInKuaFuPlunderBattleMap())
			{
				this.IsShowGuaJi = true;
				this.IsShowHintQueueIcon = true;
			}
			if (Global.IsCompetitionGuanKan)
			{
				Global.IsCompetitionGuanKan = false;
			}
			GameInstance.Game.SpriteRunNPCScript(npcID, scriptID);
			return;
		}
		if (hint == 1)
		{
			if (scriptID == 1 || scriptID == 2 || scriptID == 3 || scriptID == 10)
			{
				message = Global.GetLang("活动进行中离开，不会获得任何奖励，确定要离开吗？");
			}
			else
			{
				if (scriptID != 4)
				{
					if (MUVoiceManager.GetInstance().IsJunTuanRealTimeMap() || MUVoiceManager.GetInstance().IsZhanMengRealTimeMap())
					{
						MUVoiceManager.GetInstance().ExitRealTimeScene();
					}
					if (Global.IsInZhanMengLianSaiCompetetionMap())
					{
						this.IsShowUIInZhanMengLianSaiCompetition = true;
					}
					if (Global.IsInKuaFuPlunderBattleMap())
					{
						this.IsShowGuaJi = true;
						this.IsShowHintQueueIcon = true;
					}
					if (Global.IsCompetitionGuanKan)
					{
						Global.IsCompetitionGuanKan = false;
					}
					GameInstance.Game.SpriteRunNPCScript(npcID, scriptID);
					return;
				}
				message = Global.GetLang("您确认要进入副本下一层吗？");
			}
		}
		else if (hint == 2)
		{
			message = Global.GetLang("您确认要离开当前地图吗？");
		}
		else if (hint == 3)
		{
			message = Global.GetLang("阵营战未结束,此时离开后将无法获得奖励,是否确定离开？");
		}
		else if (hint == 4)
		{
			message = Global.GetLang("确定要离开军团领地吗？");
		}
		else if (hint == 5)
		{
			message = Global.GetLang("活动报名入场中，离开战场，确定放弃报名？");
		}
		NoTitleWindow noTitleWindow = Super.ShowDialogBox(this.Root, 1, message, (int)Global.GlobalMainWindow.ActualWidth / 2 - 150, 170, 10000, string.Empty, "确定", "取消");
		noTitleWindow.ChildWindowClose = delegate(object s1, EventArgs e1)
		{
			if ((s1 as NoTitleWindow).DialogBoxReturn == 0)
			{
				if (MUVoiceManager.GetInstance().IsJunTuanRealTimeMap() || MUVoiceManager.GetInstance().IsZhanMengRealTimeMap())
				{
					MUVoiceManager.GetInstance().ExitRealTimeScene();
				}
				if (Global.IsInZhanMengLianSaiCompetetionMap())
				{
					this.IsShowUIInZhanMengLianSaiCompetition = true;
				}
				if (Global.IsCompetitionGuanKan)
				{
					Global.IsCompetitionGuanKan = false;
				}
				if (Global.IsInKuaFuPlunderBattleMap())
				{
					this.IsShowGuaJi = true;
					this.IsShowHintQueueIcon = true;
				}
				GameInstance.Game.SpriteRunNPCScript(npcID, scriptID);
				if (this._KuafuLianshaPart != null)
				{
					this.CloseKuafuLianshaWindow();
					this._KuafuLianshaPart = null;
					this.KuafuLianshaWindow = null;
					Global.listLianShaObject.Clear();
				}
			}
			Super.CloseNoTitleWindow(this.Root, s1 as NoTitleWindow);
			return true;
		};
	}

