	protected void AddSecondTaskHint(int oldLevel, int newLevel)
	{
		XElement gameResXml = Global.GetGameResXml("Config/SecondTaskHints.xml");
		if (gameResXml == null)
		{
			return;
		}
		List<XElement> xelementList = Global.GetXElementList(gameResXml, "Item");
		if (xelementList == null)
		{
			return;
		}
		for (int i = 0; i < xelementList.Count; i++)
		{
			XElement xelement = xelementList[i];
			int xelementAttributeInt = Global.GetXElementAttributeInt(xelement, "Level");
			if (oldLevel < xelementAttributeInt && newLevel >= xelementAttributeInt)
			{
				this.SecondTaskHintList.Add(Global.GetXElementAttributeInt(xelement, "TaskID"));
			}
		}
	}

	protected void JugeSecondTaskHints()
	{
		if (this.SecondTaskHintList.Count <= 0)
		{
			return;
		}
		if (!Super.CanShowSystemWizard(43))
		{
			return;
		}
		int taskID = this.SecondTaskHintList[0];
		this.SecondTaskHintList.splice(0, 1, new int[0]);
		this.ShowHintSecondTaskWizard(taskID);
	}

	protected void RefreshTeamDataLevel(int roleID, int level, int zhuanShengLevel)
	{
		bool flag = false;
		if (Global.Data.CurrentTeamData != null)
		{
			for (int i = 0; i < Global.Data.CurrentTeamData.TeamRoles.Count; i++)
			{
				if (Global.Data.CurrentTeamData.TeamRoles[i].RoleID == roleID)
				{
					flag = true;
					Global.Data.CurrentTeamData.TeamRoles[i].Level = level;
					Global.Data.CurrentTeamData.TeamRoles[i].ChangeLifeLev = zhuanShengLevel;
					break;
				}
			}
		}
		if (!flag)
		{
			return;
		}
		if (null != this.GameTeamGroupBox)
		{
			this.GameTeamGroupBox.UpdateTeamRoleDataLevel(roleID, level, zhuanShengLevel);
		}
		if (null != this.team_Part_MyTeam)
		{
			this.team_Part_MyTeam.RefreshData();
		}
	}

	protected void RefreshTeamDataZhanLi(int roleID, int zhanLi)
	{
		bool flag = false;
		if (Global.Data.CurrentTeamData != null)
		{
			for (int i = 0; i < Global.Data.CurrentTeamData.TeamRoles.Count; i++)
			{
				if (Global.Data.CurrentTeamData.TeamRoles[i].RoleID == roleID)
				{
					flag = true;
					Global.Data.CurrentTeamData.TeamRoles[i].CombatForce = zhanLi;
					break;
				}
			}
		}
		if (!flag)
		{
			return;
		}
		if (null != this.team_Part_MyTeam)
		{
			this.team_Part_MyTeam.RefreshData();
		}
	}

