	public void OnShengXiaoGuessResult(int roleID, string sResult)
	{
		int type = 0;
		int num = 0;
		string[] array = sResult.Split(new char[]
		{
			'|'
		});
		for (int i = 0; i < array.Length; i++)
		{
			string[] array2 = array[i].Split(new char[]
			{
				'_'
			});
			if (array2.Length == 5)
			{
				num += Global.SafeConvertToInt32(array2[3]);
				type = Global.SafeConvertToInt32(array2[2]);
			}
		}
		if (num > 0)
		{
			SystemHintWindow.AddHintText(uint.MaxValue, StringUtil.substitute(Global.GetLang("天降鸿福，恭喜您押中了生肖属相·{0}，获得了{1}商城绑定钻石奖励！"), new object[]
			{
				Global.GetShengXiaoNameByCode(type),
				num
			}), 30.0);
		}
	}

