	public void ServerNotifyOpenWindow(int roleID, int windowType, string extraParam)
	{
		if (Global.Data.RoleID != roleID)
		{
			return;
		}
		switch (windowType)
		{
		case 0:
		{
			int num = Global.SafeConvertToInt32(extraParam);
			int num2 = 2130706432 + num;
			this.ShowchuanSongShiWindow(num2, num, false);
			break;
		}
		case 1:
		{
			int luaFileID = Global.SafeConvertToInt32(extraParam);
			this.ShowDingWeiWindow(luaFileID, false);
			break;
		}
		case 2:
			if (!string.IsNullOrEmpty(extraParam))
			{
				string[] array = extraParam.Split(new char[]
				{
					'$'
				});
				if (array.Length == 3)
				{
					int num3 = Global.SafeConvertToInt32(array[0]);
					int num4 = Global.SafeConvertToInt32(array[1]);
					if (num3 >= 1 && num3 <= 5)
					{
						if (num4 == 1)
						{
							SystemHelpPart.Countdown(num3, null, false);
						}
						else
						{
							SystemHelpPart.Countdown(num3, null, true);
						}
					}
				}
			}
			break;
		}
	}

