	public void OnPataNextIndexEvent()
	{
		int num = Global.Data.roleData.MapCode;
		num++;
		if (num >= Global.GetPataIndexRange()[0] && num <= Global.GetPataIndexRange()[1] && RiChangPaTaPart.DataDict != null)
		{
			RiChangHuoDongData riChangHuoDongData = null;
			if (RiChangPaTaPart.DataDict.TryGetValue(num, ref riChangHuoDongData))
			{
				if (0 != UIHelper.AvalidLevel(riChangHuoDongData.MinLevel, riChangHuoDongData.MaxLevel, riChangHuoDongData.MinZhuanSheng, riChangHuoDongData.MaxZhuanSheng))
				{
					GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("需要达到{0}转{1}级后，才能继续挑战"), new object[]
					{
						riChangHuoDongData.MinZhuanSheng,
						riChangHuoDongData.MinLevel
					}), 0, -1, -1, 0);
				}
				else
				{
					if (Global.CanEnterByTypeID(num) == SceneUIClasses.PaTa)
					{
						int zhanLi = 0;
						int fubenID = num;
						if (!Global.CanEnterFuBenByZhanLi(fubenID, out zhanLi))
						{
							PlayZone.GlobalPlayZone.OpenFuBenTiShiPartWindow(1, zhanLi);
							PlayZone.GlobalPlayZone.m_FuBenTiShiPart.dpsHandler = delegate(object s, DPSelectedItemEventArgs e)
							{
								if (e.ID == 1)
								{
									PlayZone.GlobalPlayZone.CloseFuBenTiShiPartWindow();
									GameInstance.Game.SpriteEnterFuBen(fubenID);
								}
							};
							PlayZone.GlobalPlayZone.m_FuBenTiShiPart.dpsHandlerClose = delegate(object s, DPSelectedItemEventArgs e)
							{
								this.CloseFuBenTiShiPartWindow();
								if (this.GameFubenBoxMini != null)
								{
									this.GameFubenBoxMini.OnLeaveFuBenIconClick(this.GameFubenBoxMini, null);
								}
							};
							return;
						}
					}
					Super.ShowNetWaiting(string.Empty);
					GameInstance.Game.SpriteEnterFuBen(num);
				}
			}
		}
	}

