	protected string FormatLevelUpString(string s, string padString = " ")
	{
		string text = "|" + s;
		int i = 20 - s.Length;
		while (i > 1)
		{
			i--;
			text += padString;
		}
		return text;
	}

	protected void OnClientRoleLevelUp()
	{
		int num = RoleAttributePart.CalcPoint();
		if (num > 0 && Global.Data.roleData.AutoAssignPropertyPoint != 0)
		{
			RoleAttributePart.AutoAddPoint(num);
		}
		this.TryShowNextJingMaiLevelGuangHuan();
		this.TryShowNextWuXueLevelGuangHuan();
		XElement isolateResXml = Global.GetIsolateResXml("Config/Gifts/UpLevelGift.xml");
		if (isolateResXml == null)
		{
			return;
		}
		List<XElement> xelementList = Global.GetXElementList(isolateResXml, "Item");
		for (int i = 0; i < xelementList.Count; i++)
		{
			XElement xelement = xelementList[i];
			int xelementAttributeInt = Global.GetXElementAttributeInt(xelement, "ToLevel");
			int xelementAttributeInt2 = Global.GetXElementAttributeInt(xelement, "BindMoney");
			int xelementAttributeInt3 = Global.GetXElementAttributeInt(xelement, "MoJing");
			if (xelementAttributeInt == Global.Data.roleData.Level)
			{
				SystemHintWindow.AddRoleInfoHintText(4278222848U, this.FormatLevelUpString(string.Empty, "-"));
				SystemHintWindow.AddRoleInfoHintText(4294967040U, this.FormatLevelUpString(StringUtil.substitute(Global.GetLang("恭喜您升到{0}级"), new object[]
				{
					Global.Data.roleData.Level
				}), " "));
				SystemHintWindow.AddRoleInfoHintText(4278222848U, this.FormatLevelUpString(StringUtil.substitute(Global.GetLang("系统自动奖励："), new object[]
				{
					xelementAttributeInt3
				}), " "));
				if (xelementAttributeInt3 > 0)
				{
					SystemHintWindow.AddRoleInfoHintText(4278222848U, this.FormatLevelUpString("  " + StringUtil.substitute(Global.GetLang("魔晶：{0}"), new object[]
					{
						xelementAttributeInt3
					}), " "));
				}
				if (xelementAttributeInt2 > 0)
				{
					SystemHintWindow.AddRoleInfoHintText(4278222848U, this.FormatLevelUpString("  " + StringUtil.substitute(Global.GetLang("绑定金币：{0}"), new object[]
					{
						xelementAttributeInt2
					}), " "));
				}
				if (i + 1 < xelementList.Count)
				{
					int xelementAttributeInt4 = Global.GetXElementAttributeInt(xelementList[i + 1], "ToLevel");
					SystemHintWindow.AddRoleInfoHintText(4278222848U, this.FormatLevelUpString(StringUtil.substitute(Global.GetLang("下次升级奖励：{0}级"), new object[]
					{
						xelementAttributeInt4
					}), " "));
				}
				SystemHintWindow.AddRoleInfoHintText(4278222848U, this.FormatLevelUpString(string.Empty, "-"));
				return;
			}
		}
		SystemHintWindow.AddRoleInfoHintText(4294967040U, StringUtil.substitute(Global.GetLang("恭喜您升到{0}级"), new object[]
		{
			Global.Data.roleData.Level
		}));
	}

	protected void ProcessNpcClickOnStart(SpriteNotifyEventArgs e)
	{
		if (Global.IsInJingLingMap())
		{
			JingLingMap.inst.ProcessNpcClickOnStart(e);
		}
		else
		{
			if (SystemHelpMgr.DisableNpcClick(e.ExtensionID))
			{
				return;
			}
			GameInstance.Game.SpriteClickOnNPC(Global.Data.roleData.MapCode, e.RoleID, e.ExtensionID);
		}
	}

	protected void ProcessNpcClickOnResult(NPCData npcData)
	{
		if (SystemHelpMgr.DisableNpcClick(npcData.ExtensionID))
		{
			return;
		}
		Global.Data.npcData = npcData;
		NPCInfoVO npcvobyID = ConfigNPCs.GetNPCVOByID(npcData.ExtensionID);
		if (npcvobyID != null && !StringUtil.IsNullOrEmpty(npcvobyID.LuaScriptFile))
		{
			this.ShowNPCLuaDialogWindow(npcData.NPCID, npcData.ExtensionID, false);
			return;
		}
		if (npcvobyID.IsGatherNPC)
		{
			this.ProcessGatherNPC(npcData, npcvobyID);
			return;
		}
		bool flag = true;
		int num = -1;
		int taskID = 0;
		if (Global.Data.roleData.TaskDataList != null && Global.Data.roleData.TaskDataList.Count > 0)
		{
			if (npcData.ExtensionID == 119)
			{
				for (int i = 0; i < Global.Data.roleData.TaskDataList.Count; i++)
				{
					TaskVO taskXmlNodeByID = ConfigTasks.GetTaskXmlNodeByID(Global.Data.roleData.TaskDataList[i].DoingTaskID);
					if (taskXmlNodeByID != null)
					{
						if (npcData.ExtensionID == taskXmlNodeByID.DestNPC)
						{
							int taskClass = taskXmlNodeByID.TaskClass;
							if (taskClass == 0)
							{
								num = Global.Data.roleData.TaskDataList[i].DoingTaskID;
								flag = false;
								break;
							}
							int num2;
							int num3;
							if (taskClass == 8 && Global.CanDoPaoHuanTask(taskClass, out num2, out num3))
							{
								int doingTaskID = Global.Data.roleData.TaskDataList[i].DoingTaskID;
								taskID = doingTaskID;
								flag = false;
							}
						}
					}
				}
			}
			else
			{
				for (int j = 0; j < Global.Data.roleData.TaskDataList.Count; j++)
				{
					TaskVO taskXmlNodeByID2 = ConfigTasks.GetTaskXmlNodeByID(Global.Data.roleData.TaskDataList[j].DoingTaskID);
					if (taskXmlNodeByID2 != null)
					{
						if (npcData.ExtensionID == taskXmlNodeByID2.DestNPC)
						{
							int taskClass2 = taskXmlNodeByID2.TaskClass;
							if (taskClass2 == 0)
							{
								num = Global.Data.roleData.TaskDataList[j].DoingTaskID;
								flag = false;
								break;
							}
							int num4;
							int num5;
							if (taskClass2 == 1)
							{
								if (Global.Data.CurrentClickZhiXianTaskID == Global.Data.roleData.TaskDataList[j].DoingTaskID)
								{
									taskID = Global.Data.roleData.TaskDataList[j].DoingTaskID;
									flag = false;
									break;
								}
							}
							else if (taskClass2 == 9 && Global.CanDoPaoHuanTask(taskClass2, out num4, out num5))
							{
								int doingTaskID2 = Global.Data.roleData.TaskDataList[j].DoingTaskID;
								taskID = doingTaskID2;
								flag = false;
							}
						}
					}
				}
			}
			if (num > 0)
			{
				taskID = num;
			}
		}
		TaskData taskDataByID = Global.GetTaskDataByID(taskID);
		if (taskDataByID != null)
		{
			TaskVO taskXmlNodeByID3 = ConfigTasks.GetTaskXmlNodeByID(taskID);
			if (taskXmlNodeByID3 != null && Super.JugeTaskComplete(taskXmlNodeByID3, taskDataByID.DoingTaskVal1, taskDataByID.DoingTaskVal2) && taskXmlNodeByID3.DestNPC == 10000)
