	private void ProcessGatherNPC(NPCData npcData, NPCInfoVO vo)
	{
		string[] array = vo.GatherCondition.Split(new char[]
		{
			','
		});
		if (npcData.GatherTime > 0)
		{
			for (int i = 0; i < Global.Data.roleData.TaskDataList.Count; i++)
			{
				TaskVO taskXmlNodeByID = ConfigTasks.GetTaskXmlNodeByID(Global.Data.roleData.TaskDataList[i].DoingTaskID);
				if (taskXmlNodeByID != null && taskXmlNodeByID.TargetType1 == 8 && int.Parse(array[0]) == taskXmlNodeByID.ID)
				{
					this.StartCaiji(vo.ID, npcData.GatherTime, CaijiTypes.ByTime, true);
					break;
				}
			}
		}
		else if (npcData.GatherTime == -1)
		{
			this.StopCaiji(true);
			int num = int.Parse(array[1]);
			int num2 = int.Parse(array[3]);
			GSprite gsprite = ObjectsManager.FindSprite(npcData.NPCID);
			GDecoration gdecoration = null;
			if (num2 >= 0)
			{
				Global.GetDecoration(num2, GDecorationTypes.AutoRemove, new Point(0, 0), false, null, -1, -1, true, false);
			}
			if (gdecoration != null && gdecoration.The3DGameObject != null)
			{
				FxPlayController component = gdecoration.The3DGameObject.GetComponent<FxPlayController>();
				if (component != null)
				{
					component.autoDestory = true;
				}
			}
			if (gsprite == null)
			{
				return;
			}
			if (num == 0)
			{
				if (gdecoration != null)
				{
					gdecoration.DecorationDestroyNotify = delegate(object s, EventArgs e)
					{
						this.scene.ServerDelNPC(npcData.ExtensionID, Global.Data.roleData.MapCode);
					};
				}
			}
			else if (num != 1)
			{
				if (num == 2)
				{
				}
			}
		}
		else if (npcData.GatherTime == -2)
		{
		}
	}

	public void SafeRegionNotfiy(bool inSafeRegion)
	{
		GameInstance.Game.RegionEvent(0, (!inSafeRegion) ? 0 : 1);
		if (null != this.GameChatBoxMini)
		{
			if (this.GameChatBoxMini.IsShowGuaJiIcon)
			{
				this.GameChatBoxMini.GuajiIcon.gameObject.SetActive(!inSafeRegion && GongnengYugaoMgr.IsGongNengOpened(GongNengIDs.GuaJi));
			}
			else
			{
				this.GameChatBoxMini.GuajiIcon.gameObject.SetActive(false);
			}
		}
		if (null == this.GameCtrlBar)
		{
			return;
		}
		this.GameCtrlBar.IsSafeRegion = inSafeRegion;
		if (!inSafeRegion)
		{
			if (Global.Data.roleData.IsFlashPlayer > 0 && this.FirstLeaveSafeArea)
			{
				if (Global.Data.roleData.CompletedMainTaskID < 101)
				{
					return;
				}
				this.FirstLeaveSafeArea = false;
				if (null != this.GameCtrlBar)
				{
					int num = Global.CalcOriginalOccupationID(Global.Data.roleData.Occupation);
					GongnengYugaoMgr.ReadyFlyingImgAnimation(PlayZone.GlobalPlayZone, 1000 + num * 100);
				}
				SystemHelpMgr.ShowSystemHelp(SystemHelpModes.LeaveSafeArea, 1);
			}
		}
	}

	public void AutoFindRoadDecoNotify(object sender, StateNotifyEventArgs _e)
	{
		if (_e.state == 0)
		{
			this.GameTaskBoxMini.ShowEffect(false);
			if (null != this.autoFindRoad)
			{
				this.autoFindRoad.Visibility = true;
				return;
			}
			this.autoFindRoad = U3DUtils.NEW<CAnimation>("AutoFindDeco");
			this.Root.Children.Add(this.autoFindRoad);
			this.autoFindRoad.transform.localPosition = new Vector2(0f, (float)((int)Super.GetMainUISize().y / 4));
			if (Global.g_bIsYaoQingCeShi)
			{
				this.autoFindRoad._Sprite.gameObject.SetActive(false);
			}
			UIEventListener.Get(this.autoFindRoad.gameObject).onClick = delegate(GameObject s)
			{
				if (Global.IsInShiLiZhengBaMap())
				{
					MUComp mucompById = ShiLiData.GetMUCompById(ShiLiData.GetSelfCompType());
					if (mucompById != null && Global.Data.roleData.MapCode != mucompById.MapCode)
					{
						Super.HintMainText(Global.GetLang("非本势力地图无法使用此功能"), 10, 3);
						return;
					}
				}
				if (Global.GetVIPLeve() >= 2)
				{
					if (Global.Data.AutoRoadItemsList != null)
					{
						RoadItem roadItem = Global.Data.AutoRoadItemsList[Global.Data.AutoRoadItemsList.Count - 1];
						if (roadItem != null)
						{
							GameInstance.Game.SpriteTaskTransport(roadItem.MapID, roadItem.ToPos.X, roadItem.ToPos.Y, 0);
						}
					}
				}
				else
				{
					Super.HintMainText(Global.GetLang("成为VIP2级用户才能快速传送！"), 10, 3);
				}
			};
		}
		else
		{
			if (null != this.autoFindRoad)
			{
				this.autoFindRoad.Visibility = false;
			}
			if (!Global.IsAutoFighting())
			{
				this.GameTaskBoxMini.ShowEffect(true);
			}
			else
			{
				this.GameTaskBoxMini.ShowEffect(false);
			}
		}
	}

	public void AutoFightDecoNotify(object sender, object _e)
	{
		StateNotifyEventArgs stateNotifyEventArgs = _e as StateNotifyEventArgs;
		if (stateNotifyEventArgs.state == 0)
		{
			if (this.autoFightImg == null)
			{
				this.autoFightImg = U3DUtils.NEW<CAnimation>("AutoFightDeco");
				this.Root.Children.Add(this.autoFightImg);
				this.autoFightImg.transform.localPosition = new Vector2(0f, (float)((int)Super.GetMainUISize().y / 4));
				UIEventListener.Get(this.autoFightImg.gameObject).onClick = delegate(GameObject go)
				{
					this.ShowAutoPlayWindow(false);
				};
			}
			else
			{
				NGUITools.SetActive(this.autoFightImg.gameObject, true);
			}
			this.GameTaskBoxMini.ShowEffect(false);
		}
		else
		{
			if (this.autoFightImg != null)
			{
				NGUITools.SetActive(this.autoFightImg.gameObject, false);
			}
			if (this.autoFindRoad != null && this.autoFindRoad.Visibility)
			{
				this.GameTaskBoxMini.ShowEffect(false);
			}
			else
			{
				this.GameTaskBoxMini.ShowEffect(true);
			}
		}
		if (null != this.autoPart)
		{
			this.autoPart.AutoFightNotify(stateNotifyEventArgs.state);
		}
		if (this.GameChatBoxMini != null)
		{
			this.GameChatBoxMini.ResetAutoFightingUI();
		}
	}

