	private void ClickGetThingNotify(ObjectClickEvent evt)
	{
		ClickGetThingEventArgs clickGetThingEventArgs = evt.Tag as ClickGetThingEventArgs;
		if (clickGetThingEventArgs.ClickGetThingType != 15 && clickGetThingEventArgs.ClickGetThingType != 16)
		{
			return;
		}
		if (clickGetThingEventArgs.Cancel)
		{
			return;
		}
		object sender = clickGetThingEventArgs.sender;
		GIcon gicon = sender as GIcon;
		if (null == gicon)
		{
			return;
		}
		GoodsData gd = gicon.ItemObject as GoodsData;
		if (gd != null)
		{
			GoodVO goodsXmlNodeByID = ConfigGoods.GetGoodsXmlNodeByID(gd.GoodsID);
			if (goodsXmlNodeByID != null)
			{
				int categoriy = goodsXmlNodeByID.Categoriy;
				string title = goodsXmlNodeByID.Title;
				if (clickGetThingEventArgs.ClickGetThingType == 15)
				{
					if (categoriy < 0 || categoriy > 25)
					{
						GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, Global.GetLang("只有装备才需要修理"), 0, -1, -1, 0);
					}
					else
					{
						GameInstance.Game.SpriteMendEquipment(gd.Id);
					}
				}
				else if (clickGetThingEventArgs.ClickGetThingType == 16)
				{
					if (gd.Using > 0)
					{
						GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, Global.GetLang("装备在身上的物品不能出售"), 0, -1, -1, 0);
						return;
					}
					if (gd.Site != 0)
					{
						GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, Global.GetLang("背包中的物品才能出售"), 0, -1, -1, 0);
						return;
					}
					if (Super.CanSaleOutGoods(gd))
					{
						if (!Super.CanDirectSaleOutGoods(gd))
						{
							string lang = Global.GetLang("金币");
							if (gd.Binding > 0)
							{
								lang = Global.GetLang("绑定金币");
							}
							string message = StringUtil.substitute(Global.GetLang("您确定售出{0}并得到{1}{2}吗?"), new object[]
							{
								title,
								Global.GetGoodsSaleToNpcPrice(gd),
								lang
							});
							GChildWindow messageBoxWindow = Super.ShowMessageBox(this.parcelPart.Container, 1, Global.GetLang("物品出售提示"), message, Super.GetChildLeft(630, 316), Super.GetChildTop(321, 128), 630, 321, 0.01, default(Vector3), null, null);
							messageBoxWindow.ChildWindowClose = delegate(object s1, EventArgs e1)
							{
								int messageBoxReturn = messageBoxWindow.MessageBoxReturn;
								Super.CloseMessageBox(this.parcelPart.Container, messageBoxWindow);
								if (messageBoxReturn == 0)
								{
									GameInstance.Game.SpriteModGoods(5, gd.Id, gd.GoodsID, gd.Using, gd.Site, gd.GCount, gd.BagIndex, string.Empty);
								}
								return true;
							};
						}
						else
						{
							GameInstance.Game.SpriteModGoods(5, gd.Id, gd.GoodsID, gd.Using, gd.Site, gd.GCount, gd.BagIndex, string.Empty);
						}
					}
					else
					{
						GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("此物品不可出售"), new object[0]), 0, -1, -1, 0);
					}
				}
			}
		}
		clickGetThingEventArgs.NextClick = true;
	}

