	public void OnBuyFromNpcCompleted(int ret)
	{
		if (ret < 0)
		{
			if (ret != -5000)
			{
				if (ret == -1)
				{
					Super.HintMainText(Global.GetLang("绑定金币余额不足,无法购买"), 10, 3);
					Super.ShowGuideWindow(BaodianGuidePart.GuideType.NeedJinbi, null, string.Empty, string.Empty);
				}
				else if (ret == -8)
				{
					Super.ShowGuideWindow(BaodianGuidePart.GuideType.NeedJinbi, null, string.Empty, string.Empty);
				}
				else if (ret == -13)
				{
					Super.ShowGuideWindow(BaodianGuidePart.GuideType.NeedJinbi, null, string.Empty, string.Empty);
				}
				else if (ret == -14)
				{
					Super.ShowGuideWindow(BaodianGuidePart.GuideType.NeedJinbi, null, string.Empty, string.Empty);
				}
				else if (ret == -20)
				{
					Super.ShowGuideWindow(BaodianGuidePart.GuideType.NeedJinbi, null, string.Empty, string.Empty);
				}
				else if (ret == -30)
				{
					Super.ShowGuideWindow(BaodianGuidePart.GuideType.NeedJinbi, null, string.Empty, string.Empty);
				}
				else if (ret == -90)
				{
					Super.ShowGuideWindow(BaodianGuidePart.GuideType.NeedJinbi, null, string.Empty, string.Empty);
				}
				else if (ret == -3)
				{
					Super.HintMainText(Global.GetLang("背包已满，请清理出空格后再购买"), 10, 3);
				}
				else if (ret == -5001)
				{
					Super.HintMainText(Global.GetLang("角色死亡时，无法购买物品"), 10, 3);
				}
				else
				{
					Super.HintMainText(Global.GetLang("购买失败！"), 10, 3);
				}
			}
		}
		else if (null != this.NpcSalePart)
		{
			this.NpcSalePart.UpdateMoneyText();
		}
	}

