	public void OnEnterGame()
	{
		this.TryShowNextWuXueLevelGuangHuan();
		this.TryShowNextJingMaiLevelGuangHuan();
		try
		{
			this.RadarMap.InitTeleport();
			if (!PlatSDKMgr._isEnterGame)
			{
				PlatSDKMgr.EnterGameCallback();
			}
		}
		catch (Exception ex)
		{
			MUDebug.LogException(ex);
		}
		try
		{
			GongnengYugaoMgr.RefreshAllIcons(true);
			this.RefreshStaticMenuTipsIcon();
			if (this.GameCtrlBar != null)
			{
				this.GameCtrlBar.RefershBianShenButton();
			}
		}
		catch (Exception ex2)
		{
			MUDebug.LogException(ex2);
		}
		try
		{
			this.GameTaskBoxMini.RefreshTasks(-1, -1, false);
			ActivityTipManager.OnEnterGame();
			if (Global.Data.AutoFightData.Fighting || Global.GetMapSceneUIClass() == SceneUIClasses.JingYanFuBen)
			{
				Global.Data.AutoFightData.Fighting = false;
				this.scene.StartAutoFight(-1);
			}
		}
		catch (Exception ex3)
		{
			MUDebug.LogException(ex3);
		}
		try
		{
			GameInstance.Game.SpriteStartMeditateCmd(0);
			Global.Data.MeditateState = 0;
			this.CloseMingXiangAwardBar();
		}
		catch (Exception ex4)
		{
			MUDebug.LogException(ex4);
		}
		try
		{
			if (null != this.LeaderRoleFace)
			{
				if (SceneUIClasses.RebornMap.IsTheScene() && Global.Data.roleData.PKMode != 2)
				{
					GameInstance.Game.SpriteUpdatePKMode(0);
				}
				this.LeaderRoleFace.PKMode_v = Global.Data.roleData.PKMode;
			}
		}
		catch (Exception ex5)
		{
			MUDebug.LogException(ex5);
		}
		Super.DestroyLoadingMap();
	}

	public bool InterceptChuangSongShiAndDingWeiFu(int goodsID)
	{
		if ((goodsID == 32030 || goodsID == 32031) && this.IsShowDingWeiWindow())
		{
			this.CloseDingWeiWindow();
			return true;
		}
		if (goodsID == 32000)
		{
			if (this.IsShowNPCLuaDialogWindowEx(1000005))
			{
				this.CloseNPCLuaDialogWindow();
				return true;
			}
			if (this.IsShowchuanSongShiWindow())
			{
				this.ClosechuanSongShiWindow();
				return true;
			}
		}
		if (goodsID == 32003)
		{
			if (this.IsShowNPCLuaDialogWindowEx(1000004))
			{
				this.CloseNPCLuaDialogWindow();
				return true;
			}
			if (this.IsShowchuanSongShiWindow())
			{
				this.ClosechuanSongShiWindow();
				return true;
			}
		}
		return false;
	}

