	{
		if (this.NuZhanLogo != null)
		{
			this.NuZhanLogo = null;
		}
	}

	protected override void CompleteTalk(object sender, EventArgs e)
	{
		base.CompleteTalk(null, null);
		int num = -1;
		bool flag = false;
		if (Global.Data.roleData.TaskDataList != null)
		{
			for (int i = 0; i < Global.Data.roleData.TaskDataList.Count; i++)
			{
				int doingTaskID = Global.Data.roleData.TaskDataList[i].DoingTaskID;
				TaskVO taskXmlNodeByID = ConfigTasks.GetTaskXmlNodeByID(doingTaskID);
				if (taskXmlNodeByID != null)
				{
					if (taskXmlNodeByID.TaskClass == 0)
					{
						int limitLevel = taskXmlNodeByID.LimitLevel;
						if (limitLevel <= 0 || Global.Data.roleData.Level >= limitLevel)
						{
							num = doingTaskID;
							flag = Super.JugeTaskComplete(taskXmlNodeByID, Global.Data.roleData.TaskDataList[i].DoingTaskVal1, Global.Data.roleData.TaskDataList[i].DoingTaskVal2);
						}
						break;
					}
				}
			}
		}
		if (num == -1)
		{
			return;
		}
		if (num == (int)ConfigSystemParam.GetSystemParamIntByName("FirstMainTaskID"))
		{
			return;
		}
		if (!flag)
		{
			this.ShowNewTaskWizard(num);
		}
	}

	private void ExitGame()
	{
		if (PlatSDKMgr.PlatName == "KY")
		{
			Application.Quit();
			PlatSDKMgr.PlatAbort();
		}
		else
		{
			PlatSDKMgr.OnAppQuit();
		}
	}

	public void ShowSystemSettingWindow(int nStartIndex = 0)
	{
		if (Global.IsKuaFuHuoDongMapSceneUIClass(Global.GetMapSceneUIClass()) || Global.GetMapSceneUIClass() == SceneUIClasses.LangHunLingYu)
		{
			Super.HintMainText(Global.GetLang("当前不能进行此操作"), 10, 3);
			return;
		}
		if (null != this.m_SysSettingWindow)
		{
			this.CloseSystemSetting();
			return;
		}
		this.m_SysSettingWindow = U3DUtils.NEW<GChildWindow>();
		this.m_SysSettingWindow.ModalType = ChildWindowModalType.TransBak;
		this.InitChildWindow(this.m_SysSettingWindow, Global.GetLang("SetWindow"));
		this.m_SysSettingWindow.ChildWindowClose = delegate(object s, EventArgs e)
		{
			Global.SaveSystemSettings();
			this.CloseSystemSetting();
			return true;
		};
		this.Root.Children.Add(this.m_SysSettingWindow);
		this.m_SysSettingWindowPanle = U3DUtils.NEW<SystemSettingPart>();
		this.m_SysSettingWindowPanle.SetTabIndex(nStartIndex);
		if (Global.Data.roleData.MapCode == 6090)
		{
			this.m_SysSettingWindowPanle.m_GameObjBtnArr1.gameObject.SetActive(false);
			this.m_SysSettingWindowPanle.m_GameObjBtnArr2.gameObject.SetActive(true);
		}
		else
		{
			this.m_SysSettingWindowPanle.m_GameObjBtnArr1.gameObject.SetActive(true);
			this.m_SysSettingWindowPanle.m_GameObjBtnArr2.gameObject.SetActive(false);
		}
		this.m_SysSettingWindowPanle.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
		{
			if (e.ID == 101)
			{
				VideoSystem.GetInstance().CloseVideoView();
				this.ReLoadGame(0);
				BasePlayZone.alreadyRequestedNotice = false;
				MUVoiceManager.GetInstance().ExitRealTimeSceneWhenChangeSystemSetting();
			}
			if (e.ID == 102)
			{
				this.ShowAutoPlayWindow(false);
			}
			if (e.ID == 103)
			{
				VideoSystem.GetInstance().CloseVideoView();
				this.ReLoadGame(1);
				BasePlayZone.alreadyRequestedNotice = false;
				MUVoiceManager.GetInstance().ExitRealTimeSceneWhenChangeSystemSetting();
			}
			if (e.ID == 104)
			{
				VideoSystem.GetInstance().CloseVideoView();
				this.ReLoadGame(4);
				BasePlayZone.alreadyRequestedNotice = false;
				MUVoiceManager.GetInstance().ExitRealTimeSceneWhenChangeSystemSetting();
			}
			if (e.ID == 105)
			{
				this.ExitGame();
			}
			if (e.ID == 106)
			{
				Global.ApplyScreenSizeSetting();
				Global.SaveSystemSettings();
				this.CloseSystemSetting();
			}
			if (e.ID == 201)
			{
				GCheckBox gcheckBox = s as GCheckBox;
				if (gcheckBox.Check)
				{
					Global.Data.SysSetting.CloseGameMusic = true;
					Global.BackgroundAudio43D.StopPlay();
				}
				else
				{
					Global.BackgroundAudio43D.PlayAudio(ConfigSettings.GetMapMusicFileByCode(Global.Data.roleData.MapCode, false), true, false);
					Global.Data.SysSetting.CloseGameMusic = false;
				}
			}
			if (e.ID == 202)
			{
				GCheckBox gcheckBox2 = s as GCheckBox;
				Global.Data.SysSetting.CloseGameAudio = gcheckBox2.Check;
			}
			if (e.ID == 203)
			{
				GCheckBox gcheckBox3 = s as GCheckBox;
				Global.Data.SysSetting.AutoAcceptTeamApply = !gcheckBox3.Check;
			}
			if (e.ID == 204)
			{
				GCheckBox gcheckBox4 = s as GCheckBox;
				Global.Data.SysSetting.RefuseExchangeRequest = gcheckBox4.Check;
			}
			if (e.ID == 205)
			{
				GCheckBox gcheckBox5 = s as GCheckBox;
				Global.Data.SysSetting.RefusePrivateChat = gcheckBox5.Check;
			}
			if (e.ID == 206)
			{
				GCheckBox gcheckBox6 = s as GCheckBox;
				Global.Data.SysSetting.HideChatPopupWin = gcheckBox6.Check;
			}
			if (e.ID == 207)
			{
				GCheckBox gcheckBox7 = s as GCheckBox;
				Global.Data.SysSetting.HideOtherRoles = gcheckBox7.Check;
				if (null != this.RadarMap)
				{
					this.RadarMap.RefreshHideIcon();
				}
				Global.SaveSystemSettings();
			}
			if (e.ID == 208)
			{
				GCheckBox gcheckBox8 = s as GCheckBox;
				if (gcheckBox8.Check)
				{
					Global.Data.SysSetting.HideGameEffect = true;
				}
				else
				{
					Global.Data.SysSetting.HideGameEffect = false;
				}
			}
			if (e.ID == 301)
			{
				GCheckBox gcheckBox9 = s as GCheckBox;
				if (gcheckBox9.Check)
				{
					Global.Data.SysSetting.GraphicsQuality = true;
					PerformanceCtrl.PerformanceType = PerformanceTypes.HiUsage;
				}
			}
			if (e.ID == 302)
			{
				GCheckBox gcheckBox10 = s as GCheckBox;
				if (gcheckBox10.Check)
				{
					Global.Data.SysSetting.GraphicsQuality = false;
					PerformanceCtrl.PerformanceType = PerformanceTypes.LowUsage;
				}
			}
			if (e.ID == 303)
			{
				GCheckBox gcheckBox11 = s as GCheckBox;
				if (gcheckBox11.Check)
				{
					Global.Data.SysSetting.ScreenLockSize = true;
				}
				else
				{
					Global.Data.SysSetting.ScreenLockSize = false;
				}
			}
			if (e.ID == 304)
			{
				return;
			}
			if (e.ID == 305)
			{
				GCheckBox gcheckBox12 = s as GCheckBox;
				if (gcheckBox12.Check && Global.Data.SysSetting.HideChiBang)
				{
					Global.Data.SysSetting.HideChiBang = false;
					if (null != this.RadarMap)
					{
						this.RadarMap.RefreshHideIcon();
					}
				}
				Global.Data.SysSetting.HideOtherRolesStatus = gcheckBox12.Check;
				Global.Data.SysSetting.HideOtherRolesChiBangStatus = !gcheckBox12.Check;
				Global.SaveSystemSettings();
			}
			if (e.ID == 306)
			{
				GCheckBox gcheckBox13 = s as GCheckBox;
				if (gcheckBox13.Check && Global.Data.SysSetting.HideOtherRoles)
				{
					Global.Data.SysSetting.HideOtherRoles = false;
					if (null != this.RadarMap)
					{
						this.RadarMap.RefreshHideIcon();
					}
				}
				Global.Data.SysSetting.HideOtherRolesChiBangStatus = gcheckBox13.Check;
				Global.Data.SysSetting.HideOtherRolesStatus = !gcheckBox13.Check;
				Global.SaveSystemSettings();
			}
		};
		this.m_SysSettingWindow.SetContent(this.m_SysSettingWindow.BodyPresenter, this.m_SysSettingWindowPanle, 0.0, 0.0, true);
	}

	protected void CloseSystemSetting()
	{
		if (null != this.m_SysSettingWindow)
		{
			this.m_SysSettingWindowPanle.Destroy();
			this.m_SysSettingWindowPanle = null;
			this.m_SysSettingWindow.Visibility = false;
			this.CloseChildWindow(this.m_SysSettingWindow);
			this.Root.Children.Remove(this.m_SysSettingWindow, true);
			this.m_SysSettingWindow = null;
		}
	}

