	private void OpenReconnectionWindow()
	{
		this.CloseReconnectionWindow();
		if (Super.roleCreator)
		{
			Super.CloseRoleCreatorWindow();
		}
		this.m_ReconnectionPart = U3DUtils.NEW<ReconnectionPart>();
		if (5 >= Global.g_nReconnTimes)
		{
			this.m_ReconnectionPart.m_nWindowType = 0;
			this.m_ReconnectionPart.SetWindowState();
		}
		else
		{
			this.m_ReconnectionPart.m_nWindowType = 1;
			this.m_ReconnectionPart.SetWindowState();
		}
		this.m_ReconnectionPart.m_DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
		{
			if (e.ID == 1)
			{
				this.ReLoadGame(3);
			}
			if (e.ID == 2)
			{
				this.ReLoadGame(1);
			}
			this.CloseReconnectionWindow();
			return true;
		};
		NGUITools.AddChild2(Super.MainGameMgr.gameObject, this.m_ReconnectionPart.gameObject);
		this.m_ReconnectionPart.gameObject.transform.localPosition = new Vector3(1f, 1f, -8000f);
	}

	private void CloseReconnectionWindow()
	{
		if (null != this.m_ReconnectionPart)
		{
			Object.Destroy(this.m_ReconnectionPart.gameObject);
			this.m_ReconnectionPart = null;
		}
	}

	public void ReLogin()
	{
		SystemHelpMgr.Reset();
		this.ClearGameData(0);
		this.CloseSocket();
		Global.Data.CurrentTeamData = null;
		string loginMode = Global.GetLoginMode();
		if ("0" != loginMode)
		{
			Super.ShowPlatformUserLogin(Super.MainWindowRoot, true);
		}
		else
		{
			Super.ShowUserLogin(Super.MainWindowRoot);
		}
	}

	private IEnumerator LoadEmptyScene(int nType)
	{
		float depth = Global.UICamera.depth;
		Global.UICamera.depth = 0f;
		yield return 2;
		ObjectsManager.Clear();
		Application.LoadLevel("empty");
		XmlManager.ClearPartXml();
		AsyncOperation async = Resources.UnloadUnusedAssets();
		GC.Collect();
		yield return async;
		Global.UICamera.depth = depth;
		this.ReLoadGameEx(nType);
		yield break;
	}

	private void ReLoadGame(int nType)
	{
		if (this.scene != null)
		{
			if (nType != 5)
			{
				this.scene.CancelAutoFindRoad(true);
			}
			this.scene.CancelAutoFight(0, true);
		}
		if (nType != 3)
		{
			base.StartCoroutine<bool>(this.LoadEmptyScene(nType));
		}
		else
		{
			this.ReLoadGameEx(nType);
		}
	}

	public void ClearDataWhenDownloadFail()
	{
		this.ReLoadGameEx(0);
	}

	private void ReLoadGameEx(int nType)
	{
		SystemHelpMgr.Reset();
		Global.ClearDictByXilian();
		if (nType == 0)
		{
			this.CloseSocket();
			this.ClearGameData(0);
			KuaFuLoginManager.ClearLoginInfo();
			Global.Data.CurrentTeamData = null;
			string loginMode = Global.GetLoginMode();
			if ("0" != loginMode)
			{
				PlatformUserLogin platformUserLogin = Super.ShowPlatformUserLogin(Super.MainWindowRoot, true);
			}
			else
			{
				Super.ShowUserLogin(Super.MainWindowRoot);
			}
		}
		else if (nType == 1)
		{
			Global.g_bReconnRoleManager = true;
			this.CloseSocket();
			this.ClearGameData(0);
			KuaFuLoginManager.ClearLoginInfo();
			Global.Data.CurrentTeamData = null;
			string loginMode2 = Global.GetLoginMode();
			if (loginMode2 == "0" && (string.Empty == Global.g_strUserName || string.Empty == Global.g_strPassWord))
			{
				Global.g_bReconnRoleManager = false;
				Super.ShowUserLogin(Super.MainWindowRoot);
				return;
			}
			Super.ShowRoleManager(Super.MainWindowRoot);
		}
		else if (nType == 3)
		{
			this.CloseReconnectionWindow();
			Super.ShowNetWaiting(Global.GetLang("正在连接游戏服务器..."));
			GameInstance.Game.Disconnect();
			GameInstance.Game.ResetGameClient();
			KuaFuLoginManager.ChangeToOriginalServer();
			GameInstance.Game.Connect(Global.CurrentListData.GameServerIP, Global.CurrentListData.GameServerPort, true);
		}
		else if (nType == 4)
		{
			this.CloseSocket();
			this.ClearGameData(0);
			KuaFuLoginManager.ClearLoginInfo();
			Global.Data.CurrentTeamData = null;
			string loginMode3 = Global.GetLoginMode();
			if ("0" != loginMode3)
			{
				PlatformUserLogin platformUserLogin2 = Super.ShowPlatformUserLogin(Super.MainWindowRoot, true);
				platformUserLogin2.StartCoroutine<bool>(platformUserLogin2.ShowXuanFuFirstPartEx(Super.MainWindowRoot));
			}
			else
			{
				Super.ShowUserLogin(Super.MainWindowRoot);
			}
		}
		else if (nType == 5)
		{
			Global.g_bReconnRoleManager = true;
			this.CloseSocket();
			this.ClearGameData(0);
			Global.Data.CurrentTeamData = null;
			string loginMode4 = Global.GetLoginMode();
			if (loginMode4 == "0" && (string.Empty == Global.g_strUserName || string.Empty == Global.g_strPassWord))
			{
				Global.g_bReconnRoleManager = false;
				Super.ShowUserLogin(Super.MainWindowRoot);
				return;
			}
			Super.ShowRoleManager(Super.MainWindowRoot);
		}
	}

	public void CloseSocket()
	{
		GameInstance.Game.Disconnect();
		GameInstance.Game.SocketFailed -= this.GameSocketFailed;
		GameInstance.Game.SocketSuccess -= this.GameSocketSuccess;
		GameInstance.Game.SocketCommand -= this.GameSocketCommand;
		GameInstance.CreateNewTCPGame();
	}

	private void ClearGameData(int nClearType = 0)
	{
		Global.g_StallStateType = StallStateType.StallNull;
		if (!Global.g_bReconnRoleManager)
		{
			Global.g_strPassWord = string.Empty;
			Global.g_strUserName = string.Empty;
		}
		if (nClearType == 0)
		{
			if (this.UITimer != null)
			{
				this.UITimer.Stop();
				this.UITimer.Dispose();
				this.UITimer = null;
			}
			if (Global.Data.roleData != null && Global.Data.roleData.GoodsDataList != null)
			{
				Global.Data.roleData.GoodsDataList.Clear();
			}
		}
		SystemErrorText.Clear();
		TeamCompeteDataManager.ClearInivteDatas();
		TeamCompeteDataManager.ClearRequestJoinDatas();
		TeamCompeteDataManager.Clear();
		DaTaoShaDataManager.Clear();
		if (Global.Data.CurrentCopyTeamData != null)
		{
			Global.Data.CurrentCopyTeamData = null;
		}
		if (Global.Data.mZhanMengHongBaoTipsData != null)
		{
			Global.Data.mZhanMengHongBaoTipsData.Clear();
		}
		if (Global.Data.mSystemHongBaoTipsDataDict != null)
		{
			Global.Data.mSystemHongBaoTipsDataDict.Clear();
		}
		if (Global.Data.HongBaoFlagDict != null)
		{
			Global.Data.HongBaoFlagDict.Clear();
		}
		if (Global.Data.HongBaoRankDict != null)
		{
			Global.Data.HongBaoRankDict.Clear();
		}
		if (Global.Data.JinDanGoodsDataList != null)
		{
			Global.Data.JinDanGoodsDataList.Clear();
		}
		if (Global.Data.JingLingGoodsDataList != null)
		{
			Global.Data.JingLingGoodsDataList.Clear();
		}
		if (Global.Data.FakeRoles != null)
		{
			Global.Data.FakeRoles.Clear();
		}
		if (Global.Data.OtherRoles != null)
		{
			Global.Data.OtherRoles.Clear();
		}
		if (Super.GData.RoleUsingGoodsDataList != null)
		{
			Super.GData.RoleUsingGoodsDataList.Clear();
		}
		if (null != Global.CurrentMapLoader)
		{
			Global.CurrentMapLoader.Unload(true);
			Global.CurrentMapLoader = null;
		}
		if (null != Global.CurrentMapSettingsLoader)
		{
			Global.CurrentMapSettingsLoader.Unload(true);
			Global.CurrentMapSettingsLoader = null;
		}
		if (null != Global.CurrentTerrainLoader)
		{
			Global.CurrentTerrainLoader.Unload(true);
			Global.CurrentTerrainLoader = null;
		}
		if (null != Global.Login3DBakMapLoader)
		{
			Global.Login3DBakMapLoader.Unload(true);
			Global.Login3DBakMapLoader = null;
		}
		if (null != this.m_FuhuoPanle)
		{
			this.CloseFuhuo();
		}
		this.ClearChatData();
		DispatcherTimerDriver.ClearAll();
		MuAssetManager.Instance.UnLoadAllUnuseResource();
		ZoneLoader.ReleaseSingleton();
		this.ReleaseEvent();
		Object.Destroy(base.gameObject);
		Object.Destroy(Super.MainGameMgr.gameObject);
		this.ClearScene();
		this.CloseNPCDoingTaskWindow();
		U3DUtils.ClearAll3DObjects(true, true);
		if (null != Global.Joystick)
		{
			Global.Joystick.gameObject.SetActive(false);
		}
		if (null != this._NPCDoingTaskPart2)
		{
			Object.Destroy(this._NPCDoingTaskPart2.gameObject);
			this._NPCDoingTaskPart2 = null;
		}
		if (null != PlayGameGuide.singleton)
		{
			PlayGameGuide.singleton.Visibility = false;
		}
		if (ConfigMagics.MagicsNodeDict.Count != 0)
		{
			ConfigMagics.MagicsNodeDict.Clear();
		}
		if (ConfigSystemOpen.GetSystemOpenVODict().Count > 0)
		{
			ConfigSystemOpen.ResetSystemOpenVOs();
		}
		UIHelper.ResetDelayInvokeRunning();
	}

