	public void OpenMarryLoveTockenPart()
	{
		if (Global.IsOperateUnPermitInKuaFuMapCheck(true, false))
		{
			return;
		}
		if (this.m_MarryLoveTockenWindow != null)
		{
			return;
		}
		if (Global.Data.roleData.IsFlashPlayer != 0)
		{
			return;
		}
		this.m_MarryLoveTockenWindow = U3DUtils.NEW<GChildWindow>();
		this.m_MarryLoveTockenWindow.IsShowModal = true;
		this.m_MarryLoveTockenWindow.ModalType = ChildWindowModalType.Translucent2;
		this.InitChildWindow(this.m_MarryLoveTockenWindow, string.Empty);
		this.Root.Children.Add(this.m_MarryLoveTockenWindow);
		this.m_MarryLoveTockenPart = U3DUtils.NEW<MarryLoveTockenPart>();
		this.m_MarryLoveTockenWindow.ChildWindowClose = delegate(object s, EventArgs e)
		{
			this.CloseMarryTockenWindow();
			return true;
		};
		this.m_MarryLoveTockenPart.InitPartData();
		this.m_MarryLoveTockenPart.callback = delegate(object s, DPSelectedItemEventArgs e)
		{
			if (e.ID == 1)
			{
				this.CloseMarryTockenWindow();
				this.ShowGameChatBoxWindow(4, e.Title);
			}
			else if (e.ID == 2)
			{
				this.OpenBuyRingPart(new DPSelectedItemEventHandler(this.m_MarryLoveTockenPart.CloseCallBack));
			}
			else if (e.ID == 3)
			{
				this.OpenHunYanPart(1, 1, null, new DPSelectedItemEventHandler(this.m_MarryLoveTockenPart.CloseCallBack));
			}
			else if (e.ID == 4)
			{
				this.CloseMarryTockenWindow();
				this.OpenLoveFuBenPart();
			}
		};
		this.m_MarryLoveTockenWindow.SetContent(this.m_MarryLoveTockenWindow.BodyPresenter, this.m_MarryLoveTockenPart, 0.0, 0.0, true);
	}

