	public void OpenHunYanPart(int showType = 1, int checkType = 1, MarryPartyData partyData = null, DPSelectedItemEventHandler closeCallBack = null)
	{
		if (this.m_HunYanWindow != null)
		{
			return;
		}
		if (Global.Data.roleData.IsFlashPlayer != 0)
		{
			return;
		}
		this.m_HunYanWindow = U3DUtils.NEW<GChildWindow>();
		this.m_HunYanWindow.Modal = true;
		this.InitChildWindow(this.m_HunYanWindow, string.Empty);
		this.Root.Children.Add(this.m_HunYanWindow);
		this.m_HunYanWindow.ChildWindowClose = delegate(object s, EventArgs e)
		{
			this.CloseHunYanWindow();
			return true;
		};
		this.m_HunYanPart = U3DUtils.NEW<LoveHunYanPart>();
		this.m_HunYanPart.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
		{
			if (e.ID == 1)
			{
				if (closeCallBack != null)
				{
					closeCallBack(this.m_HunYanPart, new DPSelectedItemEventArgs
					{
						ID = 2
					});
				}
				this.CloseHunYanWindow();
			}
			else if (e.ID == 2)
			{
				this.m_HunYanPart.SetDateTime(e.EquipIDs[0], e.EquipIDs[1], e.EquipIDs[2]);
			}
		};
		this.m_HunYanPart.SetShowType(showType, checkType, partyData);
		this.m_HunYanWindow.SetContent(this.m_HunYanWindow.BodyPresenter, this.m_HunYanPart, 0.0, 0.0, true);
	}

