			Super.HintMainText(Global.GetLang("罗兰城主尚未举办庆功"), 10, 3);
			return;
		}
		if (null == this.yanhuiJoinPart)
		{
			this.yanHuiWindow = U3DUtils.NEW<GChildWindow>();
			this.InitChildWindow(this.yanHuiWindow, "YanhuiWindow");
			this.Container.Children.Add(this.yanHuiWindow);
