			this.yanhuiJoinPart.DPSelectedItem = delegate(object sender, DPSelectedItemEventArgs ee)
			{
				if (null != this.yanHuiWindow)
				{
					this.CloseChildWindow(this.yanHuiWindow);
					this.yanHuiWindow = null;
					this.yanhuiJoinPart = null;
				}
			};
			this.yanhuiJoinPart.InitPart(Global.m_HaveYanHuiData[0], Global.m_HaveYanHuiData[1], Global.m_HaveYanHuiData[2]);
