	private void ShowArenaWindowOnGetData(JingJiDetailData data)
	{
		if (data.state != 1)
		{
			string message = string.Empty;
			int state = data.state;
			switch (state + 16)
			{
			case 0:
				message = Global.GetLang("玩家声望值不够！");
				break;
			case 1:
				message = Global.GetLang("当前有军衔BUFF！");
				break;
			case 2:
				message = Global.GetLang("玩家没有军衔！");
				break;
			case 3:
				message = Global.GetLang("排行榜领取奖励未冷却！");
				break;
			case 4:
				message = Global.GetLang("被挑战者正在被其他玩家挑战！");
				break;
			case 5:
				message = Global.GetLang("被挑战者排名已改变，请在刷新后重试！");
				break;
			case 6:
				message = Global.GetLang("被挑战者不存在！");
				break;
			case 7:
				message = Global.GetLang("冷却时间未到！");
				break;
			case 8:
				message = Global.GetLang("无效副本顺序！");
				break;
			case 9:
				message = Global.GetLang("无效地图！");
				break;
			case 10:
				message = Global.GetLang("钻石不足，无法进行操作！");
				break;
			case 11:
				message = Global.GetLang("付费失败！");
				break;
			case 12:
				message = Global.GetLang("vip次数不足，无法进行操作！");
				break;
			case 13:
				message = Global.GetLang("免费次数不足，无法进行操作！");
				break;
			case 14:
				message = Global.GetLang("死亡时不允许打开竞技场界面！");
				break;
			case 15:
				message = Global.GetLang("战斗时不允许打开竞技场界面！");
				break;
			case 16:
				message = Global.GetLang("非法参数！");
				break;
			default:
				message = Global.GetLang("其他错误，错误码[") + data.state + Global.GetLang("]！");
				break;
			}
			string[] buttons = new string[]
			{
				Global.GetLang("确定")
			};
			Super.ShowMessageBoxEx(Global.GetLang("提示"), message, delegate(object s1, DPSelectedItemEventArgs e1)
			{
			}, buttons);
			this.CloseArenaWindow();
		}
		else
		{
			this.m_ArenaWindow = U3DUtils.NEW<GChildWindow>();
			this.m_ArenaWindow.Modal = true;
			this.m_ArenaWindow.IsShowModal = true;
			this.InitChildWindow(this.m_ArenaWindow, string.Empty);
			this.Root.Children.Add(this.m_ArenaWindow);
			this.m_ArenaWindow.ChildWindowClose = delegate(object s, EventArgs e)
			{
				this.CloseArenaWindow();
				return true;
			};
			this.m_ArenaPart = U3DUtils.NEW<ArenaPart>();
			this.m_ArenaPart.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
			{
				if (e.ID == 0)
				{
					this.CloseArenaWindow();
					this.ShowTopListPartWindow(3);
				}
				else if (e.ID == 1)
				{
					this.CloseArenaWindow();
				}
			};
			this.m_ArenaPart.initInfo(data);
			this.m_ArenaWindow.SetContent(this.m_ArenaWindow.BodyPresenter, this.m_ArenaPart, 0.0, 0.0, true);
		}
	}

