	public void OpenNumberKeyboardPart(DPSelectedItemEventHandler DPSelectedItem = null, UILabel label = null, int iWinX = 0, int iWinY = -100)
	{
		this.NumKeyboardWindow = U3DUtils.NEW<GChildWindow>();
		this.NumKeyboardWindow.ModalType = ChildWindowModalType.TransBak;
		this.InitChildWindow(this.NumKeyboardWindow, Global.GetLang("Number Keyboard"));
		this.NumKeyboardWindow.ChildWindowModalBakClick = delegate(object s, EventArgs e)
		{
			this.CloseNumberKeyboardPart();
			return true;
		};
		this.NumKeyboardWindow.ChildWindowClose = delegate(object s, EventArgs e)
		{
			this.CloseNumberKeyboardPart();
			return true;
		};
		if (null == this.NumKeyboardPart)
		{
			this.NumKeyboardPart = U3DUtils.NEW<NumberKeyboardPart>();
			this.NumKeyboardPart.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
			{
				if (e.IDType == 0)
				{
					this.CloseNumberKeyboardPart();
				}
				if (e.IDType == 1)
				{
					if (e.ID != 0)
					{
						if (label != null)
						{
							label.text = e.ID.ToString();
						}
						if (DPSelectedItem != null)
						{
							DPSelectedItem(this.NumKeyboardPart, e);
						}
					}
					this.CloseNumberKeyboardPart();
				}
			};
			if (label != null)
			{
			}
			this.NumKeyboardWindow.SetContent(this.NumKeyboardWindow.BodyPresenter, this.NumKeyboardPart, 0.0, 0.0, true);
			Vector3 localPosition;
			localPosition..ctor((float)iWinX, (float)iWinY, 0f);
			this.NumKeyboardPart.transform.localPosition = localPosition;
			this.Root.Children.Add(this.NumKeyboardWindow);
		}
	}

	private void CloseNumberKeyboardPart()
	{
		if (null != this.NumKeyboardWindow)
		{
			this.CloseChildWindow(this.NumKeyboardWindow);
			this.Root.Children.Remove(this.NumKeyboardWindow, true);
			this.NumKeyboardPart = null;
			this.NumKeyboardWindow = null;
		}
	}

