		{
			this.m_BianQiangPart = U3DUtils.NEW<BianQiangPart>();
			if (null != this.m_BianQiangPart)
			{
				this.m_BianQiangPart.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
				{
					if (e.ID == -1)
					{
						this.CloseBianQiang();
