					{
						this.CloseBianQiang();
						this.ProcessGuideRequest(e);
					}
				};
			}
			this.m_BianQiangWindow.SetContent(this.m_BianQiangWindow.BodyPresenter, this.m_BianQiangPart, 0.0, 0.0, true);
		}
		catch (Exception ex)
