	public void UseTestCodePart(int key, List<string> list = null)
	{
		if (key == 7)
		{
			int count = Global.Data.roleData.SkillDataList.Count;
			if (count < 4)
			{
				this.GameCtrlBar.AddTempSkill(count, 1);
			}
			else
			{
				this.GameCtrlBar.ResetSkillBar();
			}
		}
		else if (key == 403)
		{
			GongnengYugaoMgr.ReadyFlyingImgAnimation(this.Root, list[0].SafeToInt32(0));
		}
		else if (key == 412)
		{
			this.npcID = list[0];
			this.ProcessNpcClickOnStart(new SpriteNotifyEventArgs
			{
				RoleID = this.npcID.SafeToInt32(0) + 2130706432,
				ExtensionID = this.npcID.SafeToInt32(0),
				SpriteType = GSpriteTypes.NPC
			});
		}
		else if (key == 608)
		{
			LuoLanChengZhanResultInfo item = new LuoLanChengZhanResultInfo();
			item.BHName = "xxxx";
			item.ExpAward = 10000L;
			item.ZhanGongAward = 9999;
			PlayZone.GlobalPlayZone.ShowLuolanchengzhanResultWindow(delegate(object s2, EventArgs e2)
			{
				this.m_LuolanchengzhanResultPart.Init(item);
			});
		}
		else if (key == 609)
		{
			LangHunLingYuAwardsData item = new LangHunLingYuAwardsData();
			PlayZone.GlobalPlayZone.ShowLangHunLingYuResultWindow(delegate(object s2, EventArgs e2)
			{
				this.langhunlingyuResult.Init(item);
			});
		}
	}

