		if (null != this.m_StallPart)
		{
			this.m_StallPart.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
			{
				if (e.ID == 0)
				{
					this.CloseBaiTan();
				}
				if (e.ID == 1)
				{
					this.OpenStallLog();
				}
				if (e.ID == 2)
				{
					this.OpenStallOutLine();
				}
				if (e.ID == 3)
				{
				}
				if (e.ID == 502)
				{
					this.OpenWuPinShangJiaWindow(null, 2);
				}
			};
		}
		this.m_StallWindow.SetContent(this.m_StallWindow.BodyPresenter, this.m_StallPart, 0.0, 0.0, true);
	}

	private void CloseBaiTan()
	{
		if (null != this.m_StallWindow)
		{
			if (null != this.m_StallPart.m_GameObjBag)
			{
				Object.Destroy(Super._ParcelPart.gameObject);
				Super._ParcelPart = null;
				Object.Destroy(this.m_StallPart.m_GameObjBag);
				this.m_StallPart.m_GameObjBag = null;
			}
			this.m_StallPart.Destroy();
			this.m_StallPart = null;
			this.m_StallWindow.Visibility = false;
			this.CloseChildWindow(this.m_StallWindow);
			this.Root.Children.Remove(this.m_StallWindow, true);
			this.m_StallWindow = null;
		}
	}

