	public void OpenWuPinShangJiaWindow(GoodsData goodsdata, int nType = 0)
	{
		if (nType == 0)
		{
			GoodVO goodsXmlNodeByID = ConfigGoods.GetGoodsXmlNodeByID(goodsdata.GoodsID);
			if (goodsXmlNodeByID != null)
			{
				int categoriy = goodsXmlNodeByID.Categoriy;
				bool flag = Global.IsRebornEquip(categoriy);
				if (flag && ChongShengData.beContainBaoShi(goodsdata))
				{
					Super.HintMainText(Global.GetLang("装备中镶嵌宝石，不能出售"), 10, 3);
				}
				else
				{
					this.OpenGoodsShangJia(goodsdata, nType);
				}
			}
		}
		if (nType == 1)
		{
			if (goodsdata.GoodsID == 50020)
			{
				this.OpenJinBiShangJia(goodsdata, 1);
			}
			else
			{
				this.OpenGoodsShangJia(goodsdata, 1);
			}
		}
		if (nType == 2)
		{
			this.OpenJinBiShangJia(goodsdata, nType);
		}
	}

	private void OpenGoodsShangJia(GoodsData goodsdata, int nType = 0)
	{
		this.m_StallGoodsShangJiaWindow = U3DUtils.NEW<GChildWindow>();
		this.m_StallGoodsShangJiaWindow.ModalType = ChildWindowModalType.Translucent;
		this.InitChildWindow(this.m_StallGoodsShangJiaWindow, Global.GetLang("ShangJiaWuPin"));
		this.Root.Children.Add(this.m_StallGoodsShangJiaWindow);
		this.m_StallGoodsShangJiaWindow.ChildWindowClose = delegate(object s, EventArgs e)
		{
			this.CloseWuPinShangJiaWindow();
			return true;
		};
		this.m_StallGoodsShangJiaPart = U3DUtils.NEW<StallGoodsShangJiaPart>();
		this.m_StallGoodsShangJiaPart.m_nWindowType = nType;
		this.m_StallGoodsShangJiaPart.goodsdata = goodsdata;
		this.m_StallGoodsShangJiaPart.SetBtnState(nType);
		if (null != this.m_StallGoodsShangJiaPart)
		{
			this.m_StallGoodsShangJiaPart.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
			{
				if (e.ID == 5)
				{
				}
				if (e.ID == 0)
				{
					this.CloseWuPinShangJiaWindow();
					if (null != this.m_StallPart)
					{
					}
				}
				if (e.ID == 3)
				{
					this.CloseWuPinShangJiaWindow();
				}
				if (e.ID == 4)
				{
					if (null != this.m_StallPart)
					{
						this.CloseWuPinShangJiaWindow();
					}
					if (null != this.m_JiaoYiSuoPart && null != this.m_JiaoYiSuoPart.m_StallNewPart)
					{
						this.CloseWuPinShangJiaWindow();
					}
				}
			};
		}
		this.m_StallGoodsShangJiaWindow.SetContent(this.m_StallGoodsShangJiaWindow.BodyPresenter, this.m_StallGoodsShangJiaPart, 0.0, 0.0, true);
	}

