	public void ShowGetGoodsHintEx()
	{
		if (Super.goodsHintDict != null && Super.goodsHintDict.Count > 0)
		{
			if (this.getGoodsHintPart == null)
			{
				Vector3 localPosition;
				localPosition..ctor(0f, 179f, -401f);
				this.getGoodsHintPart = U3DUtils.NEW<GetGoodsHintPart>();
				this.getGoodsHintPart.transform.localPosition = localPosition;
				this.Root.Children.Add(this.getGoodsHintPart);
			}
			string value = string.Empty;
			int num = -1;
			bool flag = true;
			Dictionary<int, Queue<HintTextdata>>.Enumerator enumerator = Super.goodsHintDict.GetEnumerator();
			if (enumerator.MoveNext())
			{
				KeyValuePair<int, Queue<HintTextdata>> keyValuePair = enumerator.Current;
				flag = false;
				Queue<HintTextdata> value2 = keyValuePair.Value;
				HintTextdata hintTextdata = value2.Dequeue();
				value = hintTextdata.Msg;
				if (value2.Count <= 0)
				{
					flag = true;
				}
				num = keyValuePair.Key;
				this.getGoodsHintPart.AddTextItem(num, value);
			}
			if (flag)
			{
				Super.goodsHintDict.Remove(num);
			}
		}
	}

	private void RecordBagGridStartTime()
	{
		DateTime dateTime;
		dateTime..ctor(Global.GetCorrectLocalTime() * 10000L);
		this.loginStartTimeSecBagGrid = dateTime.Ticks / 10000000L - 28800L;
	}

	private void RecordPortableGridStartTime()
	{
		DateTime dateTime;
		dateTime..ctor(Global.GetCorrectLocalTime() * 10000L);
		this.loginStartTimeSecPortableGrid = dateTime.Ticks / 10000000L - 28800L;
	}

	private void AutoExpandBagGridTime()
	{
		DateTime dateTime;
		dateTime..ctor(Global.GetCorrectLocalTime() * 10000L);
		Global.Data.OnLineTimeBagGrid = dateTime.Ticks / 10000000L - 28800L - this.loginStartTimeSecBagGrid;
		Global.Data.OnLineTimePortableGrid = dateTime.Ticks / 10000000L - 28800L - this.loginStartTimeSecPortableGrid;
		TimeSpan timeSpan = TimeSpan.FromMilliseconds(10000.0);
		long ticks = DateTime.Now.Ticks;
		if (ticks - this._LastExpandTicks < timeSpan.Ticks)
		{
			return;
		}
		this._LastExpandTicks = ticks;
		Global.AutoExpandBagGrid();
	}

	public void UICtrlBarNotify(UICtrlBarTypes uiCtrlBarType, int buttonID)
	{
		if (uiCtrlBarType == UICtrlBarTypes.NormalButton)
		{
			if (buttonID == 0)
			{
				if (Global.IsKuaFuHuoDongMapSceneUIClass(Global.GetMapSceneUIClass()))
				{
					Super.HintMainText(Global.GetLang("当前不能进行此操作"), 10, 3);
				}
				else
				{
					this.OpenJiaoYiSuo();
				}
			}
			else if (buttonID == 1)
			{
				if (this.scene != null)
				{
					this.scene.AutoTalk(true, 500, 360.0);
				}
			}
			else if (buttonID == 2)
			{
				this.ShowZaDanWindow(false);
			}
			else if (buttonID == 3)
			{
				this.ShowMeiRiBiZuoWindow(0);
			}
			else if (buttonID == 4)
			{
				this.ShowLianzhiWindow(-1);
			}
			else if (buttonID == 5)
			{
				this.OpenBianQiang();
			}
			else if (buttonID == 6)
			{
				this.OpenXingyunChoujiangWindow();
			}
		}
		else if (uiCtrlBarType == UICtrlBarTypes.SkillButton)
		{
			if (this.scene != null)
			{
				if (buttonID < 0 || buttonID >= Super.GData.MainQuickKeyItems.Length)
				{
					if (0 >= Global.GetRoleHorseSkillData(Global.Data.RoleID).Count || buttonID != 4)
					{
						MUDebug.LogError<string>(new string[]
						{
							Global.GetLang("技能面板按钮索引访问越界") + buttonID
						});
						return;
					}
				}
				int num = -1;
				if (buttonID < Super.GData.MainQuickKeyItems.Length)
				{
					if (Super.GData.MainQuickKeyItems[buttonID] == null)
					{
						return;
					}
					num = Super.GData.MainQuickKeyItems[buttonID].ID;
				}
				else if (buttonID == 4)
				{
					num = Global.Data.RoleUseHorseSkillId;
				}
				if (0 < num)
				{
					if (!Global.IsInHorseRequestRideCD())
					{
						this.scene.ExternalSkillAttack(num, true);
					}
					else
					{
						MUDebug.Log<string>(new string[]
						{
							Global.GetLang("<color=red>角色请求释放技能  被上坐骑CD挡</color>")
						});
					}
				}
				else
				{
					MUDebug.Log<string>(new string[]
					{
						Global.GetLang("<color=red>角色请求释放技能  被上坐骑CD挡</color>")
					});
				}
			}
		}
		else if (uiCtrlBarType == UICtrlBarTypes.BianShenSkillButton)
		{
			if (this.scene != null)
			{
				int num2 = -1;
				List<int> selfBianShenSkill = ShenHunData.GetSelfBianShenSkill();
				if (buttonID < selfBianShenSkill.Count)
				{
					num2 = selfBianShenSkill[buttonID];
				}
				if (0 < num2)
				{
					this.scene.ExternalSkillAttack(num2, true);
				}
			}
		}
		else if (uiCtrlBarType == UICtrlBarTypes.HuiJiButton)
		{
			this.scene.DoEmblem();
		}
		else if (uiCtrlBarType == UICtrlBarTypes.BianShenButton)
		{
			this.scene.DoBianShen();
		}
	}

	private void ProcessSendPushMessageID()
	{
		if (!this.FirstSendPushMessageID)
		{
			return;
		}
		if (string.IsNullOrEmpty(this.PushServerClientID))
		{
			this.PushServerClientID = QMQJJava.GetPushServerClientID();
			if (string.IsNullOrEmpty(this.PushServerClientID))
			{
				return;
			}
		}
		this.FirstSendPushMessageID = false;
		base.InvokeRepeating("RequestPushMessageServer", 1f, 120f);
	}

	public void RequestPushMessageServer()
	{
		ClientPostPushIDData clientPostPushIDData = new ClientPostPushIDData();
		ServerPostPushIDData responseData = null;
		clientPostPushIDData.strPushID = this.PushServerClientID;
		clientPostPushIDData.lTime = Global.GetTimeStamp();
		clientPostPushIDData.strMD5 = MD5Helper.get_md5_string("tmsk_mu_06" + clientPostPushIDData.strPushID + clientPostPushIDData.lTime);
		VoiceRequestParam voiceRequestParam = new VoiceRequestParam();
		string pushServerURL = Global.PushServerURL;
		voiceRequestParam.url = pushServerURL + "PushMessageServer.aspx";
		voiceRequestParam.callback = delegate(WWW w, object obj)
		{
			this.RequestPushMessageServerCount++;
			if (w != null && string.IsNullOrEmpty(w.error))
			{
				byte[] bytes = w.bytes;
				if (bytes != null && bytes.Length > 0)
				{
					responseData = DataHelper.BytesToObject<ServerPostPushIDData>(bytes, 0, bytes.Length);
					if (responseData != null && responseData.iPushIDChatOrder == 1L)
					{
						this.CancelInvoke("RequestPushMessageServer");
					}
				}
			}
			if (this.RequestPushMessageServerCount > 3)
			{
				this.CancelInvoke("RequestPushMessageServer");
			}
		};
		voiceRequestParam.postData = DataHelper.ObjectToBytes<ClientPostPushIDData>(clientPostPushIDData);
		voiceRequestParam.timeout = 20;
		HttpService.Instance.Load(voiceRequestParam.url, voiceRequestParam.callback, voiceRequestParam.postData, voiceRequestParam.param, 0);
	}

	private void ShowCenterScreenPrompt(string msg)
	{
		if (null == this.textAnim)
		{
			this.textAnim = U3DUtils.NEW<TextAnim>();
			Vector3 localPosition;
			localPosition..ctor(0f, 130f, -3f);
			this.textAnim.transform.localPosition = localPosition;
			this.textAnim.GetComponent<TweenAlpha>().delay = 3f;
			base.Children.Add(this.textAnim);
		}
		this.textAnim.m_LblShowInfo.text = msg;
		this.textAnim.GetComponent<TweenAlpha>().Reset();
		this.textAnim.GetComponent<TweenAlpha>().Play(true);
	}

