					if (!GongnengYugaoMgr.IsGongNengOpened(GongNengIDs.MoShenMiBao))
					{
						Super.HintMainText(Global.GetLang("魔神秘宝功能尚未开启，无法使用该道具"), 10, 3);
						return;
					}
					if (!ConfigVersionSystemOpen.IsVersionSystemOpen(100118))
					{
						Super.HintMainText(Global.GetLang("魔神秘宝功能尚未开启，无法使用该道具"), 10, 3);
						return;
					}
					PlayZone.GlobalPlayZone.ProcessGuideRequest(new DPSelectedItemEventArgs
					{
						ID = uiGuanLianType
					});
				}
				else if (uiGuanLianType == 1530)
				{
					if (!UIHelper.IsGongNengOpenedOrHint(GongNengIDs.Armor, true))
					{
						return;
					}
					PlayZone.GlobalPlayZone.ProcessGuideRequest(new DPSelectedItemEventArgs
					{
						ID = uiGuanLianType
					});
				}
			}
		}
	}

