	private void OpenHefuhuodongWindow()
	{
		if (this.m_HefuhuodongWindow != null)
		{
			return;
		}
		this.m_HefuhuodongWindow = U3DUtils.NEW<GChildWindow>();
		this.m_HefuhuodongWindow.Modal = true;
		this.InitChildWindow(this.m_HefuhuodongWindow, Global.GetLang("Hefu"));
		this.Root.Children.Add(this.m_HefuhuodongWindow);
		this.m_HefuhuodongWindow.ChildWindowClose = delegate(object s, EventArgs e)
		{
			this.CloseHefuhuodongWindow();
			return true;
		};
		this.m_HefuhuodongPart = U3DUtils.NEW<HefuhuodongPart>();
		this.m_HefuhuodongPart.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
		{
			if (e.ID == 1)
			{
				this.CloseHefuhuodongWindow();
			}
			if (e.IDType == 0)
			{
				this.CloseHefuhuodongWindow();
