	public void LoadAdendaView(object sender = null, DPSelectedItemEventArgs args = null)
	{
		if (null == this.adendaWindow)
		{
			this.adendaWindow = U3DUtils.NEW<GChildWindow>();
			this.adendaWindow.IsShowModal = true;
			this.InitChildWindow(this.adendaWindow, "_adendaWindow");
			this.adendaWindow.ModalType = ChildWindowModalType.BlackBak;
			this.Root.Children.Add(this.adendaWindow);
			this.adendaWindow.ChildWindowClose = delegate(object s, EventArgs e)
			{
				this.UnloadAdendaView(null, null);
				return true;
			};
			if (null == this.adendaViewController)
			{
				this.adendaViewController = U3DUtils.NEW<Adenda>();
				this.adendaViewController.GetAdendaInfo();
				this.adendaViewController.closeAdendaViewEventHandler = delegate(object s, DPSelectedItemEventArgs e)
				{
					if (e.Type == -10)
					{
						this.UnloadAdendaView(s, e);
					}
				};
				this.adendaWindow.SetContent(this.adendaWindow.BodyPresenter, this.adendaViewController, 0.0, 0.0, true);
			}
		}
	}

	public void UnloadAdendaView(object sender, DPSelectedItemEventArgs args)
	{
		if (null != this.adendaViewController)
		{
			this.adendaViewController.transform.parent = null;
			Object.Destroy(this.adendaViewController.gameObject);
			this.adendaViewController = null;
		}
		if (null != this.adendaWindow)
		{
			this.CloseChildWindow(this.adendaWindow);
			this.Root.Children.Remove(this.adendaWindow, true);
			this.adendaWindow = null;
		}
	}

