	public void OpenMergedActivityWindow(Transform trans)
	{
		if (null != this.mergedActivityWindow)
		{
			if (this.mergedActivityWindow.Visibility)
			{
				this.CloseMergedActivityWindow();
			}
			else
			{
				this.mergedActivityWindow.Visibility = true;
			}
			return;
		}
		this.mergedActivityWindow = U3DUtils.NEW<GChildWindow>();
		this.mergedActivityWindow.ModalType = ChildWindowModalType.TransBak;
		this.InitChildWindow(this.mergedActivityWindow, Global.GetLang("节日活动"));
		this.mergedActivityWindow.ChildWindowModalBakClick = delegate(object s, EventArgs e)
		{
			this.CloseMergedActivityWindow();
			return true;
		};
		this.mergedActivityWindow.ChildWindowClose = delegate(object s, EventArgs e)
		{
			this.CloseMergedActivityWindow();
			return true;
		};
		this.Root.Children.Add(this.mergedActivityWindow);
		this.mergedActivity = U3DUtils.NEW<MergedActivityIcon>();
		this.mergedActivity.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
		{
			this.CloseMergedActivityWindow();
			if (e.ID == 0)
			{
				this.OpenJieRihuodongWindow();
			}
			else if (e.ID == 1)
			{
				if (Global.IsOperateUnPermitInKuaFuMapCheck(true, false))
				{
					return;
				}
				this.OpenWelfareWindow();
			}
			else if (e.ID == 2)
			{
				this.OpenTuiGuangWindow();
			}
			else if (e.ID == 3)
			{
				this.OpenZhuanXiangHuodongWindow();
			}
			else if (e.ID == 4)
			{
				this.OpenOlympicsWindow();
			}
			else if (e.ID == 5)
			{
				if (Global.IsOperateUnPermitInKuaFuMapCheck(true, true))
				{
					return;
				}
				this.OpenAoYunDaTiWindow();
			}
			else if (e.ID == 6)
			{
				this.OpenYiYuanGouPartWindow();
			}
			else if (e.ID == 7)
			{
				this.OpenXingYunYiYuanPartWindow();
			}
			else if (e.ID == 8)
			{
				this.OpenEveryDayHuodongWindow();
			}
			else if (e.ID == 9)
			{
				this.OpenJiYuanHuoDongWindow(0);
			}
			else if (e.ID == 10)
			{
				this.OpenZhuTiFuWindow(1);
			}
			else if (e.ID == 11)
			{
				this.OpenEveryDayFanLiWindow();
			}
			else if (e.ID == 12)
			{
				if (Global.IsOperateUnPermitInKuaFuMapCheck(true, false))
				{
					return;
				}
				this.OpenCaiShuZiWindow();
			}
			else if (e.ID == 13)
			{
				if (Global.IsOperateUnPermitInKuaFuMapCheck(true, false))
				{
					return;
				}
				this.OpenCaiDaXiaoWindow();
			}
			else if (e.ID == 122)
			{
				if (Global.IsOperateUnPermitInKuaFuMapCheck(true, false))
				{
					return;
				}
				this.ShowTeQuanActivityMainPartWind();
			}
			else if (e.ID == 123)
			{
				if (Global.IsOperateUnPermitInKuaFuMapCheck(true, false))
				{
					return;
				}
				this.OpenHuiGuiHuoDongWindow();
			}
			else if (e.ID == 15)
			{
				if (Global.IsOperateUnPermitInKuaFuMapCheck(true, false))
				{
					return;
				}
				this.OpenMengHuanShiBanPartWindow();
			}
		};
		if (null != trans)
		{
			Transform transform = this.mergedActivityWindow.transform;
			transform.position = new Vector3(trans.position.x, trans.position.y, transform.position.z);
			transform.localPosition = new Vector3(transform.localPosition.x, transform.localPosition.y - 120f, transform.localPosition.z);
		}
		this.mergedActivityWindow.SetContent(this.mergedActivityWindow.BodyPresenter, this.mergedActivity, 0.0, 0.0, false);
	}

