	private void OnQiRiKuangHuanActivityIconClicked(DPSelectedItemEventArgs args)
	{
		if (Global.IsOperateUnPermitInKuaFuMapCheck(true, false))
		{
			return;
		}
		if (1 < HuoDongCommonFlag.GetTopIconBoxDownRightIconIsOpen().Count)
		{
			this.QiRiKuangHuanOpenMergedActivityWindow(args.Tag as Transform);
		}
		else
		{
			this.OpenQiRiKuangHuanWindow();
		}
	}

	private void OpenQiRiKuangHuanWindow()
