		this.qirikuanghuanPart = U3DUtils.NEW<MUQiRiHuoDongPart>();
		this.qirikuanghuanPart.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
		{
			if (e.ID == 1)
