	protected void OpenRidePetPartWindow(RidePetUIType page = RidePetUIType.ZuoQi)
	{
		if (!UIHelper.IsGongNengOpenedOrHint(GongNengIDs.Horese, true))
		{
			return;
		}
		this.CloseRidePetPartWindow();
		this.m_RidePetWindow = U3DUtils.NEW<GChildWindow>();
		this.m_RidePetWindow.ModalType = ChildWindowModalType.BlackBak;
		this.m_RidePetWindow.Modal = true;
		this.m_RidePetWindow.IsShowModal = true;
		this.m_RidePetPart = U3DUtils.NEW<RidePetPart>();
		this.InitChildWindow(this.m_RidePetWindow, Global.GetLang("RidePetPart"));
		this.Root.Children.Add(this.m_RidePetWindow);
		this.m_RidePetPart.InitValue(page);
		this.m_RidePetWindow.ChildWindowClose = delegate(object s, EventArgs e)
		{
			this.CloseRidePetPartWindow();
			return true;
		};
		this.m_RidePetPart.Hander = delegate(object e, DPSelectedItemEventArgs s)
		{
			if (s.ID == 10)
			{
				this.ShowJingLingCangKuWindow(false, false, BaoGuoMode.horseCangKu);
			}
			else if (s.ID == 11)
			{
				PlayZone.GlobalPlayZone.ProcessGuideRequest(new DPSelectedItemEventArgs
				{
					ID = 1536
				});
			}
		};
		this.m_RidePetWindow.SetContent(this.m_RidePetWindow.BodyPresenter, this.m_RidePetPart, 0.0, 0.0, true);
	}

