		if (null != this.m_RidePetWindow)
		{
			this.m_RidePetWindow.Visibility = false;
			this.CloseChildWindow(this.m_RidePetWindow);
			this.Root.Children.Remove(this.m_RidePetWindow, true);
			this.m_RidePetWindow = null;
