	public void OpenRidePetLieQuPartWindow(List<int> ActiviteGoodsList)
	{
		this.CloseRidePetLieQuPartWindow();
		this.m_RidePetLieQuWindow = U3DUtils.NEW<GChildWindow>();
		this.m_RidePetLieQuWindow.ModalType = ChildWindowModalType.BlackBak;
		this.m_RidePetLieQuWindow.Modal = true;
		this.m_RidePetLieQuWindow.IsShowModal = true;
		this.m_RidePetLieQuPart = U3DUtils.NEW<LieQuPart>();
		this.m_RidePetLieQuPart.HaveActiviteList = ActiviteGoodsList;
		this.InitChildWindow(this.m_RidePetLieQuWindow, "RidePetLieQuPartWindow");
		this.Root.Children.Add(this.m_RidePetLieQuWindow);
		this.m_RidePetLieQuPart.m_DpsHandler = delegate(object s, DPSelectedItemEventArgs e)
		{
			if (e.Type == 3)
			{
				PlayZone.GlobalPlayZone.ShowMallWindow(false, 0, 2);
			}
			if (e.Type == 2)
			{
				GGoodIcon ggoodIcon = e.Data as GGoodIcon;
				if (null != ggoodIcon)
				{
					GoodsData goodsData = ggoodIcon.ItemObject as GoodsData;
					if (goodsData != null)
					{
						GTipServiceEx.ShowTip(ggoodIcon, TipTypes.GoodsText, GoodsOwnerTypes.SysGifts, goodsData);
						GTipServiceEx.CloseHander = delegate(object t, DPSelectedItemEventArgs g)
						{
							if (g != null && g.Type == 0 && g.ID == 1 && null != this.m_RidePetLieQuPart)
							{
								this.m_RidePetLieQuPart.ActiveAnimation(true);
							}
						};
						this.m_RidePetLieQuPart.ActiveAnimation(false);
					}
				}
			}
			if (e.ID == 1)
			{
				this.ShowJingLingCangKuWindow(false, false, BaoGuoMode.horseCangKu);
			}
			if (e.Type == 0)
			{
				this.CloseRidePetLieQuPartWindow();
			}
		};
		this.m_RidePetLieQuWindow.ChildWindowClose = delegate(object s, EventArgs e)
		{
			this.CloseRidePetLieQuPartWindow();
			return true;
		};
		this.m_RidePetLieQuWindow.SetContent(this.m_RidePetLieQuWindow.BodyPresenter, this.m_RidePetLieQuPart, 0.0, 0.0, true);
	}

	public void CloseRidePetLieQuPartWindow()
	{
		GTipServiceEx.CloseHander = null;
		if (null != this.m_RidePetLieQuPart)
		{
			Object.Destroy(this.m_RidePetLieQuPart.gameObject);
			this.m_RidePetLieQuPart = null;
		}
		if (null != this.m_RidePetLieQuWindow)
		{
			this.m_RidePetLieQuWindow.Visibility = false;
