	public void ShowFashionWardrobePart(int dbid = 0)
	{
		if (Global.IsOperateUnPermitInKuaFuMapCheck(true, true))
		{
			return;
		}
		if (null != this._FashionWardrobePartwindow)
		{
			this._FashionWardrobePartwindow.Visibility = true;
		}
		else
		{
			this._FashionWardrobePartwindow = U3DUtils.NEW<GChildWindow>();
			this._FashionWardrobePartwindow.ModalType = ChildWindowModalType.BlackBak;
			this._FashionWardrobePartwindow.IsShowModal = true;
			this.InitChildWindow(this._FashionWardrobePartwindow, Global.GetLang("FashionWardrobePart"));
			this.Container.Children.Add(this._FashionWardrobePartwindow);
		}
		if (null != this._FashionWardrobePart)
		{
			Object.Destroy(this._FashionWardrobePart.gameObject);
		}
		this._FashionWardrobePart = U3DUtils.NEW<FashionWardrobePart>();
		byte type = 0;
		if (dbid != 0)
		{
			GoodsData goodsDataByDbID = Global.GetGoodsDataByDbID(dbid, null);
			if (goodsDataByDbID != null)
			{
				int categoriyByGoodsID = Global.GetCategoriyByGoodsID(goodsDataByDbID.GoodsID);
				if (categoriyByGoodsID == 8)
				{
					type = 1;
				}
				else if (categoriyByGoodsID == 24)
				{
					type = 0;
				}
				else if (categoriyByGoodsID == 25)
				{
					type = 2;
				}
				else if (categoriyByGoodsID == 26)
				{
					type = 3;
				}
			}
		}
		this._FashionWardrobePart.SetType(type);
		this._FashionWardrobePartwindow.Body.Add(this._FashionWardrobePart);
		this._FashionWardrobePart.Hander = delegate(object e, DPSelectedItemEventArgs s)
		{
			this.CloseFashionWardrobePart();
		};
		this._FashionWardrobePartwindow.ChildWindowClose = delegate(object s, EventArgs e)
		{
			this.CloseFashionWardrobePart();
			return true;
		};
	}

	public void CloseFashionWardrobePart()
	{
		if (null != this._FashionWardrobePart)
		{
			Object.Destroy(this._FashionWardrobePart.gameObject);
			this._FashionWardrobePart = null;
			this._FashionWardrobePartwindow.Visibility = false;
			this.CloseChildWindow(this._FashionWardrobePartwindow);
			this.Root.Children.Remove(this._FashionWardrobePartwindow, true);
			this._FashionWardrobePartwindow = null;
		}
	}

