	public void OpenKuafuMapView(int targetType, int taskID, int npcID, int mapCode, int ToPosX, int ToPosY, bool isWordMap = false, int bossID = 0, int teleportId = 0, bool BAutoFindRode = false, bool BComeFromTTaskBoxMini = false)
	{
		if (Global.Data.CurrentCopyTeamData != null)
		{
			Global.ZuDuiFuBenTeam(delegate(object s2, DPSelectedItemEventArgs e2)
			{
				if (e2.ID == 0)
				{
					GameInstance.Game.SpriteCopyTeam(TeamCmds.Quit, 0L, 0, 0, 0);
					this.NewOpenKuaFuMapView(targetType, taskID, npcID, mapCode, ToPosX, ToPosY, isWordMap, bossID, teleportId, BAutoFindRode, BComeFromTTaskBoxMini);
				}
			}, -1);
		}
		else
		{
			this.NewOpenKuaFuMapView(targetType, taskID, npcID, mapCode, ToPosX, ToPosY, isWordMap, bossID, teleportId, BAutoFindRode, BComeFromTTaskBoxMini);
		}
	}

	private void NewOpenKuaFuMapView(int targetType, int taskID, int npcID, int mapCode, int ToPosX, int ToPosY, bool isWordMap = false, int bossID = 0, int teleportId = 0, bool BAutoFindRode = false, bool BComeFromTTaskBoxMini = false)
	{
		if (null == PlayZone.GlobalPlayZone.kuafuMapWindow)
		{
			PlayZone.GlobalPlayZone.kuafuMapWindow = U3DUtils.NEW<GChildWindow>();
			PlayZone.GlobalPlayZone.kuafuMapWindow.IsShowModal = true;
			Super.InitChildWindow(PlayZone.GlobalPlayZone.kuafuMapWindow, "_kuafuMapWindow");
			PlayZone.GlobalPlayZone.kuafuMapWindow.ModalType = ChildWindowModalType.BlackBak;
			Super.GData.GlobalPlayZone.Children.Add(PlayZone.GlobalPlayZone.kuafuMapWindow);
			this.kuafuMapWindow.ChildWindowClose = delegate(object s, EventArgs e)
			{
				this.CloseKuafuMapView(null, null);
				return true;
			};
			if (null == PlayZone.GlobalPlayZone.kuafuzhuxianMap)
			{
				PlayZone.GlobalPlayZone.kuafuzhuxianMap = U3DUtils.NEW<KuafuzhuxianMap>();
				PlayZone.GlobalPlayZone.kuafuzhuxianMap.BossID = bossID;
				PlayZone.GlobalPlayZone.kuafuzhuxianMap.TeleportID = teleportId;
				PlayZone.GlobalPlayZone.kuafuzhuxianMap.MapLineID = 1;
				PlayZone.GlobalPlayZone.kuafuzhuxianMap.MapCode = mapCode;
				PlayZone.GlobalPlayZone.kuafuzhuxianMap.FindRoad = delegate(object s, DPSelectedItemEventArgs e)
				{
					if (!isWordMap)
					{
						string systemParamByName = ConfigSystemParam.GetSystemParamByName("VIPBossChuanSong", true);
						bool forceTansport = Global.GetVIPLeve() >= Convert.ToInt32(systemParamByName);
						if (PlayZone.GlobalPlayZone.kuafuzhuxianMap.BComeFromTTaskBoxMini && "1" == ConfigSystemParam.GetSystemParamByName("RiChangOpen", true))
						{
							if (targetType == 1)
							{
								this.TansportPoint(2, taskID, npcID, mapCode, ToPosX, ToPosY, forceTansport);
							}
						}
						else
						{
							this.TansportPoint(targetType, taskID, npcID, mapCode, ToPosX, ToPosY, forceTansport);
						}
					}
					PlayZone.GlobalPlayZone.kuafuzhuxianMap.BComeFromTTaskBoxMini = false;
				};
				PlayZone.GlobalPlayZone.kuafuzhuxianMap.DPSelectItem = delegate(object s, DPSelectedItemEventArgs e)
				{
					if (e.Type == -10)
					{
						this.CloseKuafuMapView(s, e);
					}
					if (null != PlayZone.GlobalPlayZone.kuafuzhuxianMap)
					{
						PlayZone.GlobalPlayZone.kuafuzhuxianMap.BComeFromTTaskBoxMini = false;
					}
				};
				PlayZone.GlobalPlayZone.kuafuMapWindow.SetContent(PlayZone.GlobalPlayZone.kuafuMapWindow.BodyPresenter, PlayZone.GlobalPlayZone.kuafuzhuxianMap, 0.0, 0.0, true);
			}
		}
		PlayZone.GlobalPlayZone.kuafuzhuxianMap.BAutoFindOneRode = BAutoFindRode;
		PlayZone.GlobalPlayZone.kuafuzhuxianMap.BComeFromTTaskBoxMini = BComeFromTTaskBoxMini;
	}

	public void CloseKuafuMapView(object sender, DPSelectedItemEventArgs args)
	{
		Global.Data.WaitingForMapChange = false;
		if (null != PlayZone.GlobalPlayZone.kuafuzhuxianMap)
		{
			PlayZone.GlobalPlayZone.kuafuzhuxianMap.transform.parent = null;
			Object.Destroy(PlayZone.GlobalPlayZone.kuafuzhuxianMap.gameObject);
			PlayZone.GlobalPlayZone.kuafuzhuxianMap = null;
		}
		if (null != PlayZone.GlobalPlayZone.kuafuMapWindow)
		{
			Super.CloseChildWindow(base.Children, PlayZone.GlobalPlayZone.kuafuMapWindow);
			Super.GData.GlobalPlayZone.Children.Remove(PlayZone.GlobalPlayZone.kuafuMapWindow, true);
			PlayZone.GlobalPlayZone.kuafuMapWindow = null;
		}
	}

	public bool TansportPoint(int type, int taskID, int npcID, int mapCode, int toPosX, int toPosY, bool forceTansport = false)
	{
		Global.Data.TargetNpcID = npcID;
		Point pos;
		if (type == 2)
		{
			pos = Global.GetMonsterPointByID(mapCode, Global.Data.TargetNpcID);
		}
		else if (type == 3)
		{
			pos = Global.GetNPCPointByID(mapCode, Global.Data.TargetNpcID);
		}
		else
		{
			pos = new Point(toPosX, toPosY);
		}
		if (pos.X == -1 || pos.Y == -1)
		{
			GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("路径信息格式错误 ,无法自动寻路"), new object[0]), 0, -1, -1, 0);
			return true;
		}
		if (type == 2)
		{
			Global.Data.GameScene.AutoFindRoad(mapCode, pos, 0, ExtActionTypes.EXTACTION_KILLMONSTER);
		}
		else if (type == 3)
		{
			Global.Data.GameScene.AutoFindRoad(mapCode, pos, 120, ExtActionTypes.EXTACTION_NPCDLG);
		}
		else
		{
			Global.Data.GameScene.AutoFindRoad(mapCode, pos, 0, ExtActionTypes.EXTACTION_NONE);
		}
		if (forceTansport && Super.CanTransport(mapCode, true, false))
		{
			GameInstance.Game.SpriteTaskTransport(mapCode, pos.X, pos.Y, 0);
		}
		return true;
	}

	public void ShowShiPinPart(int page = 0)
	{
		if (null != this.m_ShiPinPartWindow)
		{
			MUDebug.Log<string>(new string[]
			{
				"enter_ShowShiPinPart()_if (null != m_ShiPinPartWindow)"
			});
			this.m_ShiPinPartWindow.Visibility = true;
		}
		else
		{
			MUDebug.Log<string>(new string[]
			{
				"enter_ShowShiPinPart()_else"
			});
			this.m_ShiPinPartWindow = U3DUtils.NEW<GChildWindow>();
			this.m_ShiPinPartWindow.ModalType = ChildWindowModalType.BlackBak;
			this.m_ShiPinPartWindow.IsShowModal = true;
			this.InitChildWindow(this.m_ShiPinPartWindow, "ShiPinPartWindow");
			this.Container.Children.Add(this.m_ShiPinPartWindow);
			this.m_ShiPinPartWindow.ChildWindowClose = delegate(object s, EventArgs e)
			{
				if (null != this.m_ShiPinPartWindow)
				{
					Object.Destroy(this.m_ShiPinPart);
					this.m_ShiPinPart = null;
					this.CloseChildWindow(this.m_ShiPinPartWindow);
					this.m_ShiPinPartWindow = null;
				}
				return true;
			};
			if (null != this.m_ShiPinPart)
			{
				Object.Destroy(this.m_ShiPinPart);
			}
			this.m_ShiPinPart = U3DUtils.NEW<ShiPinPart>();
			this.m_ShiPinPartWindow.Body.Add(this.m_ShiPinPart);
			this.m_ShiPinPart.ShowPage(page);
			this.m_ShiPinPart.Hander = delegate(object e, DPSelectedItemEventArgs s)
			{
				if (s.IDType == 0)
				{
					this.CloseShiPinPart();
				}
			};
		}
		this.m_ShiPinPartWindow.ChildWindowClose = delegate(object s, EventArgs e)
		{
			this.CloseShiPinPart();
			return true;
		};
	}

