	public void ShowArmyGroupRenwuPart(byte type = 0, int WeekRank = 0, int GongXian = 0, int JunTuanID = 0)
	{
		if (null == this.m_ArmyGroupRenWuPartWind)
		{
			this.m_ArmyGroupRenWuPartWind = U3DUtils.NEW<GChildWindow>();
			this.m_ArmyGroupRenWuPartWind.Modal = true;
			this.m_ArmyGroupRenWuPartWind.ModalType = ChildWindowModalType.BlackBak;
		}
		Super.InitChildWindow(this.m_ArmyGroupRenWuPartWind, "ArmyGroupRenWuPart");
		this.Container.Children.Add(this.m_ArmyGroupRenWuPartWind);
		if (null != this.m_ArmyGroupRenWuPart)
		{
			Object.Destroy(this.m_ArmyGroupRenWuPart);
		}
		this.m_ArmyGroupRenWuPart = U3DUtils.NEW<ArmyGroupRenWuPart>();
		this.m_ArmyGroupRenWuPart.SetUIType(type);
		if (type == 0)
		{
			this.m_ArmyGroupRenWuPart.Rank = WeekRank;
			this.m_ArmyGroupRenWuPart.GongXian = GongXian;
		}
		else if (type == 1)
		{
			Super.ShowNetWaiting(null);
			GameInstance.Game.SendGetRoleArmyGroupBHData(Global.Data.roleData.JunTuanId);
		}
		else if (type == 2)
		{
			Super.ShowNetWaiting(null);
			GameInstance.Game.SendGetRoleArmyGroupBHData(JunTuanID);
		}
		this.m_ArmyGroupRenWuPartWind.Body.Add(this.m_ArmyGroupRenWuPart);
		this.m_ArmyGroupRenWuPart.Hander = delegate(object e, DPSelectedItemEventArgs s)
		{
			if (s.ID == 0)
			{
				this.CloseArmyGroupRenWuPart();
			}
			else if (s.ID == 1)
			{
