	public void LegionsEastLoad(int ids = 1, int ID = 116, string Site = "1111|1115")
	{
		string[] array = Site.Split(new char[]
		{
			'|'
		});
		this.x = float.Parse(array[0]) / 100f;
		this.y = float.Parse(array[2]) / 10f;
		this.z = float.Parse(array[1]) / 100f;
		Vector3 v3 = new Vector3(this.x, this.y, this.z);
		this.monsterNPCResLoaderEast = new MonsterNPCResLoader(new MonsterNPCLoaderData
		{
			resName = ConfigNPCs.GetNPC3DResNameByID(ID),
			spriteType = GSpriteTypes.NPC
		}, delegate(MonsterNPCLoaderData s, GameObject e)
		{
			e.transform.localPosition = v3;
			e.name = string.Format("Role_{0}", 2130706432 + ID + ids * 100);
		});
	}

	public void LegionsWestLoad(int ids, int id, string site)
	{
		string[] array = site.Split(new char[]
		{
			'|'
		});
		this.x = float.Parse(array[0]) / 100f;
		this.y = 49.5f;
		this.z = float.Parse(array[1]) / 100f;
		Vector3 v3 = new Vector3(this.x, this.y, this.z);
		GameObject gameObject = new GameObject("TempLoader");
		if (gameObject != null)
		{
			this.monsterNPCResLoaderWest = new MonsterNPCResLoader(new MonsterNPCLoaderData
			{
				parent = gameObject,
				resName = ConfigMonsters.GetMonster3DResNameByID(id),
				spriteType = GSpriteTypes.Monster
			}, delegate(MonsterNPCLoaderData s, GameObject e)
			{
				e.transform.localPosition = v3;
				e.name = string.Format("Role_{0}", 2130706432 + id + ids * 100);
			});
		}
	}

	public void DestoryLoad(int ID, int ids)
	{
		string text = string.Format("Role_{0}", 2130706432 + ID + ids * 100);
		GameObject gameObject = GameObject.Find(text);
		if (gameObject != null)
		{
			NGUITools.Destroy(gameObject);
		}
	}

	public void TiHuanZiYuan(int ids = 0, int ID1 = 116, int ID2 = 116, string Site = "1111|1115")
	{
		if (Site == null)
		{
			return;
		}
		this.DestoryLoad(ID1, ids);
		if (Global.GetMapSceneUIClass() == SceneUIClasses.AKaLunDong)
		{
			this.LegionsEastLoad(ids, ID2, Site);
		}
		else if (Global.GetMapSceneUIClass() == SceneUIClasses.AKaLunXi)
		{
			this.LegionsWestLoad(ids, ID2, Site);
		}
	}

	public void ReMapPoint()
	{
		if (Global.KarenScorepProvisionalData == null)
		{
			return;
		}
		if (Global.GetMapSceneUIClass() != SceneUIClasses.AKaLunDong)
		{
			return;
		}
		for (int i = 0; i < Global.KarenScorepProvisionalData.Count; i++)
		{
			if (Global.KarenScorepProvisionalData[i].ResourceList != null && Global.KarenScorepProvisionalData[i].ResourceList.Count > 0)
			{
				for (int j = 0; j < Global.KarenScorepProvisionalData[i].ResourceList.Count; j++)
				{
					if (this.GetDicLegionsEast().ContainsKey(Global.KarenScorepProvisionalData[i].ResourceList[j]))
					{
						this.QiZuoSite = this.GetDicLegionsEast()[Global.KarenScorepProvisionalData[i].ResourceList[j]].NPCID;
					}
					if (this.RadarMap)
					{
						GRadarMapPoint point = this.RadarMap.GetPoint(this.QiZuoSite);
						if (point != null)
						{
							point.sprite.transform.localScale = new Vector3(15f, 15f, 1f);
							if (i == Global.Data.roleData.BattleWhichSide - 1)
							{
								point.Img = "mineyaosai";
							}
							else
							{
								point.Img = "direnyaosai";
							}
						}
					}
				}
			}
		}
	}

