	public void ShowGongNeItem(int taskId, bool forceHide = false)
	{
		forceHide = (Global.GetMapSceneUIClass() != SceneUIClasses.Normal);
		if (this.gongNeItem != null && this.gongNeItem.gameObject.activeInHierarchy == forceHide)
		{
			this.gongNeItem.gameObject.SetActive(!forceHide);
		}
		bool newOpen = false;
		if (AnnouncedSetVO.curTaskID < 0 || (AnnouncedSetVO.curTaskID >= 0 && AnnouncedSetVO.curTaskID != taskId) || null == this.gongNeItem)
		{
			AnnouncedSetVO.curTaskID = taskId;
			AnnouncedSetVO vobyID = AnnouncedSetVO.GetVOByID(taskId);
			if (vobyID == null)
			{
				if (this.gongNeItem != null)
				{
					this.Root.Children.Remove(this.gongNeItem.gameObject, true);
					AnnouncedSetVO.Clear();
				}
				return;
			}
			if (null == this.gongNeItem)
			{
				this.gongNeItem = U3DUtils.NEW<GongNeYuGaoItem>();
				this.Root.Children.Add(this.gongNeItem);
			}
			if (this.gongNeItem.setVo != null)
			{
				newOpen = !vobyID.name.Equals(this.gongNeItem.setVo.name);
			}
			this.gongNeItem.UpdateInfo(vobyID, newOpen);
		}
	}

	protected void ShowRecyclePartWind()
	{
		if (null != this.mRecyclePartWind)
		{
			this.CloseRecyclePartWind();
		}
		this.mRecyclePartWind = U3DUtils.NEW<GChildWindow>();
		this.mRecyclePartWind.Modal = false;
		this.mRecyclePartWind.ModalType = ChildWindowModalType.Translucent2;
		base.Children.Add(this.mRecyclePartWind);
		WindowManage.AddWindows(this.mRecyclePartWind, true, null);
		if (null != this.mRecyclePart)
		{
			Object.Destroy(this.mRecyclePart.gameObject);
		}
		this.mRecyclePart = U3DUtils.NEW<RecyclePart>();
		this.mRecyclePart.InitData();
		this.mRecyclePart.Hander = delegate(object e, DPSelectedItemEventArgs s)
		{
			if (s != null)
			{
				if (0 <= s.ID)
				{
					int id = 101;
					if (s.ID == 0)
					{
						id = 10;
					}
					else if (s.ID == 1)
					{
						id = 11;
					}
					else if (s.ID == 2)
					{
						id = 102;
					}
					if (Super._ParcelPart.DPSelectedItem != null)
					{
						Super._ParcelPart.DPSelectedItem(this, new DPSelectedItemEventArgs
						{
							ID = id,
							IDType = 0
						});
					}
				}
				else if (s.ID == -1)
				{
					Super._ParcelPart.Huishou(true);
				}
				if (s.IDType == 0)
				{
					this.CloseRecyclePartWind();
				}
			}
		};
		this.mRecyclePartWind.Body.Add(this.mRecyclePart);
	}

	protected void CloseRecyclePartWind()
	{
		if (null != this.mRecyclePartWind)
		{
			Super.CloseChildWindow(base.Children, this.mRecyclePartWind);
		}
		if (null != this.mRecyclePart)
		{
			Object.Destroy(this.mRecyclePart.gameObject);
		}
	}

