	public void OpenAwardTipsWindow()
	{
		if (this.m_AwardTipsWindow != null || this.AwardTipsDatas.Count == 0)
		{
			return;
		}
		this.m_AwardTipsWindow = U3DUtils.NEW<GChildWindow>();
		this.m_AwardTipsWindow.Modal = true;
		this.m_AwardTipsWindow.ModalType = ChildWindowModalType.TransBak;
		this.InitChildWindow(this.m_AwardTipsWindow, Global.GetLang("AwardTips"));
		this.m_AwardTipsWindow.ChildWindowClose = delegate(object s, EventArgs e)
		{
			this.CloseAwardTipsWindow();
			return true;
		};
		this.Root.Children.Add(this.m_AwardTipsWindow);
		this.m_AwardTipsWindow.transform.localPosition = new Vector3(0f, 0f, -9850f);
		this.m_AwardTipsPart = U3DUtils.NEW<AwardGoodsTips>();
		this.m_AwardTipsWindow.transform.localPosition = new Vector3(0f, 0f, -9850f);
		this.m_AwardTipsWindow.SetContent(this.m_AwardTipsWindow.BodyPresenter, this.m_AwardTipsPart, 0.0, 0.0, true);
		NotifyMsgWithGoodsData notifyMsgWithGoodsData = this.AwardTipsDatas[0];
		this.AwardTipsDatas.RemoveAt(0);
		this.m_AwardTipsPart.ShowGoodsIcon(notifyMsgWithGoodsData.goodsDataList);
		this.m_AwardTipsPart.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
		{
			this.CloseAwardTipsWindow();
		};
	}

	private void CloseAwardTipsWindow()
	{
		if (null != this.m_AwardTipsWindow)
		{
			this.m_AwardTipsPart = null;
			this.m_AwardTipsWindow.Visibility = false;
			this.CloseChildWindow(this.m_AwardTipsWindow);
			this.Root.Children.Remove(this.m_AwardTipsWindow, true);
