	private void ShowArmorPart()
	{
		if (ConfigVersionSystemOpen.VersionSystemOpenHaveTheId(ConfigSystemOpen.GetVersionSystemOpenIDBySystemOpenID(100), 1) && !ConfigVersionSystemOpen.IsVersionSystemOpen(ConfigSystemOpen.GetVersionSystemOpenIDBySystemOpenID(100)))
