	private void ShowShiLiSelectPart()
	{
		if (null != this.mShiLiSelectPartWind)
		{
			this.CloseShiLiSelectPart();
		}
		this.mShiLiSelectPartWind = U3DUtils.NEW<GChildWindow>();
		this.mShiLiSelectPartWind.Modal = true;
		this.mShiLiSelectPartWind.ModalType = ChildWindowModalType.Translucent2;
		base.Children.Add(this.mShiLiSelectPartWind);
		WindowManage.AddWindows(this.mShiLiSelectPartWind, true, null);
		if (null != this.mShiLiSelectPart)
		{
			Object.Destroy(this.mShiLiSelectPart.gameObject);
		}
		this.mShiLiSelectPart = U3DUtils.NEW<ShiLiSelectPart>();
		this.mShiLiSelectPart.Hander = delegate(object e, DPSelectedItemEventArgs s)
		{
			if (s.Type == 0)
			{
				if (s.ID == 0)
				{
					this.CloseShiLiSelectPart();
				}
			}
			else if (s.Type == 2)
			{
				if (s.ID == 1)
				{
					ShiLiData.ShowShiLiZhengDuo();
				}
				else if (s.ID == 2)
				{
					this.ShowShiLiMiDongMainPart();
				}
				if (s.ID != -1)
				{
					this.CloseShiLiSelectPart();
				}
			}
		};
		this.mShiLiSelectPart.InitData();
		this.mShiLiSelectPartWind.Body.Add(this.mShiLiSelectPart);
	}

	protected void CloseShiLiSelectPart()
	{
		if (null != this.mShiLiSelectPartWind)
		{
			Super.CloseChildWindow(base.Children, this.mShiLiSelectPartWind);
		}
		if (null != this.mShiLiSelectPart)
		{
			Object.Destroy(this.mShiLiSelectPart.gameObject);
		}
	}

