			this.CloseChildWindow(this.m_GoogleWindow);
			this.m_GoogleWindow = null;
			this.m_GooglePart = null;
		}
		if (this.m_GooglePart == null && this.m_GoogleWindow == null)
		{
			this.m_GoogleWindow = U3DUtils.NEW<GChildWindow>();
			this.m_GoogleWindow.IsShowModal = true;
			this.InitChildWindow(this.m_GoogleWindow, "google");
			this.Container.Add(this.m_GoogleWindow);
			this.m_GoogleWindow.ChildWindowClose = delegate(object s, EventArgs e)
			{
				this.CloseChildWindow(this.m_GoogleWindow);
				return true;
			};
			this.m_GoogleWindow.ModalType = ChildWindowModalType.Translucent;
			this.m_GooglePart = U3DUtils.NEW<GooglePart>();
			this.m_GooglePart.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
			{
				if (e.ID == 0)
				{
					this.CloseChildWindow(this.m_GoogleWindow);
					this.m_GoogleWindow = null;
					this.m_GooglePart = null;
				}
				if (e.ID == 1)
				{
					AndroidSDKPlugin.showAchievements();
				}
				if (e.ID == 2)
				{
					AndroidSDKPlugin.ShowSubmitScore(1, Global.GetRoleOwnNumByMoneyType(8));
				}
				if (e.ID == 3)
				{
					AndroidSDKPlugin.ShowSubmitScore(2, e.Index);
				}
			};
			this.m_GoogleWindow.SetContent(this.m_GoogleWindow.BodyPresenter, this.m_GooglePart, 0.0, 0.0, true);
		}
	}

	public void CloseMengHuanShiBanWindow()
	{
		if (null != this.m_MengHuanShiBanWindow)
		{
			this.m_MengHuanShiBanPart.Destroy();
			this.m_MengHuanShiBanPart = null;
			this.m_MengHuanShiBanWindow.Visibility = false;
			this.CloseChildWindow(this.m_MengHuanShiBanWindow);
			this.Root.Children.Remove(this.m_MengHuanShiBanWindow, true);
			this.m_MengHuanShiBanWindow = null;
		}
	}

	public void OpenMengHuanShiBanPartWindow()
	{
		if (this.m_MengHuanShiBanWindow)
		{
			return;
		}
		this.m_MengHuanShiBanWindow = U3DUtils.NEW<GChildWindow>();
		this.m_MengHuanShiBanWindow.Modal = true;
		this.m_MengHuanShiBanWindow.ModalType = ChildWindowModalType.BlackBak;
		this.m_MengHuanShiBanWindow.IsShowModal = true;
		this.m_MengHuanShiBanPart = U3DUtils.NEW<MengHuanShiBanPart>();
		this.InitChildWindow(this.m_MengHuanShiBanWindow, Global.GetLang("MengHuanShiBanPart"));
		this.Root.Children.Add(this.m_MengHuanShiBanWindow);
		this.m_MengHuanShiBanWindow.ChildWindowClose = delegate(object s, EventArgs e)
		{
			this.CloseMengHuanShiBanWindow();
			return true;
		};
		this.m_MengHuanShiBanPart.dpsClose = delegate(object s, DPSelectedItemEventArgs e)
		{
			this.CloseMengHuanShiBanWindow();
		};
		this.m_MengHuanShiBanWindow.SetContent(this.m_MengHuanShiBanWindow.BodyPresenter, this.m_MengHuanShiBanPart, 0.0, 0.0, true);
	}

	protected void GameSocketFailed(object sender, MUSocketConnectEventArgs e)
	{
		MainGame.QueueOnMainThread(delegate()
		{
			Super.HideNetWaiting();
			if (!this.IsChangingLine())
			{
				GameInstance.Game.Disconnect();
				if (!Global.g_bReconnRoleManager)
				{
					Global.g_strUserName = string.Empty;
					Global.g_strPassWord = string.Empty;
				}
				if (Global.Data.CurrentTeamData != null)
				{
					Global.Data.CurrentTeamData = null;
				}
				if (this.team_Part_MyTeam != null)
				{
					this.team_Part_MyTeam.RefreshData();
				}
				this.GameTeamGroupBox.UpdateTeamRoleFaces();
				if (e.ShowMsgBox)
				{
				}
				if (Global.Data.CurrentCopyTeamData != null)
				{
					Global.Data.CurrentCopyTeamData = null;
				}
				if (e.ReturnStartPage)
				{
					this.ReLoadGame(0);
				}
				else
				{
					this.OpenReconnectionWindow();
				}
			}
		});
	}

	protected void GameSocketSuccess(object sender, MUSocketConnectEventArgs e)
	{
		MainGame.QueueOnMainThread(delegate()
		{
			Global.g_nReconnTimes = 0;
			Super.HideNetWaiting();
			GameInstance.Game.InitPlayGame();
		});
	}

	protected void GameSocketCommand(object sender, MUSocketConnectEventArgs e)
	{
		if (e.CmdID == 611)
		{
		}
		MainGame.QueueOnMainThread(delegate()
		{
			this.ProcessNetCommandByUI(e);
		});
	}

	protected void ProcessNetCommandByUI(MUSocketConnectEventArgs e)
	{
		int timer = U3DUtils.GetTimer();
		try
		{
			this.ProcessNetCommand(e);
		}
		catch (Exception ex)
		{
			ex.Data.Add("CmdID", e.CmdID);
			MUDebug.LogException(ex);
		}
	}

	protected bool AssertNetworkException(bool result, int length, object msg = null)
	{
		if (result)
		{
			return true;
		}
		StringBuilder stringBuilder = new StringBuilder("AssertException: ");
		stringBuilder.Append(length);
		if (msg != null)
		{
			stringBuilder.Append(Global.GetLang(", 命令: ")).Append(msg.ToString());
		}
		GError.AddErrMsg(Global.GetLang(stringBuilder.ToString()));
		return false;
	}

