	private IEnumerator _resendClientTimeRequest()
	{
		yield return new WaitForSeconds(15f);
		GameInstance.Game.TimeSynchronizationByClient();
		yield break;
	}

	public void OnStrengthenRequestNew(int cmd, byte[] bytesData, int offset, int length)
	{
		switch (cmd)
		{
		case 780:
		case 782:
			Global.OnRequestCallBack_CheckPending();
			break;
		default:
			if (cmd != 660)
			{
				if (cmd != 800)
				{
					if (cmd != 932)
					{
						if (cmd != 981)
						{
							if (cmd != 1035)
							{
								if (cmd != 1816)
								{
									if (cmd == 1896)
									{
										ZuoQiMainData zuoQiMainData = DataHelper.BytesToObject<ZuoQiMainData>(bytesData, 0, bytesData.Length);
										Global.zuoQiLevelByBianQiang = zuoQiMainData.MountLevel;
									}
								}
								else
								{
									ShenQiData data = DataHelper.BytesToObject<ShenQiData>(bytesData, 0, bytesData.Length);
									Global.RecvShenQiData(data);
								}
							}
							else
							{
								UnionPalaceData data2 = DataHelper.BytesToObject<UnionPalaceData>(bytesData, 0, bytesData.Length);
								Global.RecvShenDianData(data2);
							}
						}
						else
						{
							MerlinGrowthSaveDBData data3 = DataHelper.BytesToObject<MerlinGrowthSaveDBData>(bytesData, 0, bytesData.Length);
							Global.GetDataBagMerlinGrowthSaveDBData(data3);
						}
					}
					else
					{
						GuardStatueData data4 = DataHelper.BytesToObject<GuardStatueData>(bytesData, 0, length);
						Global.OnRequestCallBack_GuardStatue(data4);
					}
				}
				else
				{
					List<LingYuData> lingyuList = DataHelper.BytesToObject<List<LingYuData>>(bytesData, 0, bytesData.Length);
					Global.CountLingyuTotalLevel(lingyuList);
				}
			}
			else
			{
				Dictionary<int, int> dic = DataHelper.BytesToObject<Dictionary<int, int>>(bytesData, 0, length);
				Global.OnRequestCallBack_QueryStar(dic);
			}
			break;
		}
	}

	public void OnStrengthenRequestFinished(int cmd, byte[] bytesData, int offset, int length)
	{
		if (null == this.m_BianQiangPart || null == this.m_BianQiangPart.m_TiShengZhanLiPart)
		{
			return;
		}
		switch (cmd)
		{
		case 780:
		case 782:
			this.m_BianQiangPart.m_TiShengZhanLiPart.OnRequestCallBack_CheckPending();
			break;
		default:
			if (cmd != 660)
			{
				if (cmd != 932)
				{
					if (cmd != 981)
					{
						if (cmd != 1035)
						{
							if (cmd != 1816)
							{
								if (cmd == 1896)
								{
									ZuoQiMainData zuoQiMainData = DataHelper.BytesToObject<ZuoQiMainData>(bytesData, 0, bytesData.Length);
									this.m_BianQiangPart.m_TiShengZhanLiPart.RecvZuoQiLevel(zuoQiMainData.MountLevel);
								}
							}
							else
							{
								ShenQiData data = DataHelper.BytesToObject<ShenQiData>(bytesData, 0, bytesData.Length);
								this.m_BianQiangPart.m_TiShengZhanLiPart.RecvShenQiData(data);
							}
						}
						else
						{
							UnionPalaceData data2 = DataHelper.BytesToObject<UnionPalaceData>(bytesData, 0, bytesData.Length);
							this.m_BianQiangPart.m_TiShengZhanLiPart.RecvShenDianData(data2);
						}
					}
					else
					{
						MerlinGrowthSaveDBData dataBag = DataHelper.BytesToObject<MerlinGrowthSaveDBData>(bytesData, 0, bytesData.Length);
						this.m_BianQiangPart.m_TiShengZhanLiPart.OnRequestCallBack_MerLin(dataBag);
					}
				}
				else
				{
					GuardStatueData statueData = DataHelper.BytesToObject<GuardStatueData>(bytesData, 0, length);
					this.m_BianQiangPart.m_TiShengZhanLiPart.OnRequestCallBack_GuardStatue(statueData);
				}
			}
			else
			{
				Dictionary<int, int> dic = DataHelper.BytesToObject<Dictionary<int, int>>(bytesData, 0, length);
				this.m_BianQiangPart.m_TiShengZhanLiPart.OnRequestCallBack_QueryStar(dic);
			}
			break;
		}
	}

	protected void ShowLoadingMap()
	{
		int ticks1 = U3DUtils.GetTimer();
		this.scene.CancelAutoFight(0, true);
		PerformanceCtrl.Fog = RenderSettings.fog;
		MonsterCachingManager.ClearCachingItems();
		Global.ClearOptimizationCache();
		this.CloseYabiaoWindow();
		this.CancelNPCDialogWindows();
		if (Global.Data.GameRadarMap != null && Global.Data.GameRadarMap.MiniMap.Texture != null && Global.Data.GameRadarMap.MiniMap.Texture.mainTexture != null)
		{
			Object.Destroy(Global.Data.GameRadarMap.MiniMap.Texture.mainTexture);
			Global.Data.GameRadarMap.MiniMap.Texture.mainTexture = null;
		}
		LoadingMap loadingMap = U3DUtils.NEW<LoadingMap>();
		Super.DestroyLoadingMap();
		Super.CurrentLoadingMap = loadingMap;
		loadingMap.MapCode = Global.Data.roleData.MapCode;
		loadingMap.WorkFinished = delegate(object s2, EventArgs e2)
		{
			int timer = U3DUtils.GetTimer();
			ticks1 = U3DUtils.GetTimer();
			this.CompleteMapConversion();
			this.Root.Visibility = true;
			timer = U3DUtils.GetTimer();
		};
		loadingMap.LoadType = 0;
		this.Root.Visibility = false;
		Global.MainStage.Children.Add(loadingMap);
		loadingMap.Coordinate = new Point(0, 0);
	}

	protected void CompleteMapConversion()
	{
		int timer = U3DUtils.GetTimer();
		this.LoadScene(Global.Data.roleData.MapCode, Global.Data.roleData.PosX, Global.Data.roleData.PosY, (double)Global.Data.roleData.RoleDirection, false);
		if (this.IsShowWorldNavigationWindow())
		{
			this.worldNavigationPart.RefreshPartialWorld();
			this.worldNavigationPart.RefreshAllWorld();
		}
		else if (null != this.worldNavigationPart)
		{
			this.worldNavigationPart.NeedToRefresh = true;
		}
		SystemHintWindow.AddMapHintText(65290U, ConfigSettings.GetMapNameByCodeEx(Global.Data.roleData.MapCode, false), (double)FontSizeMgr.MapNameFontSize);
		this.StartPlayGame();
		Global.Data.WaitingForMapChange = false;
		Super.HideChangingMapWindow(this.Root);
		SystemHelpMgr.ShowSystemHelp(SystemHelpModes.ToMap, Global.Data.roleData.MapCode);
		base.TriggerTaskPlot(SystemHelpModes.ToMap, 0, null);
		this.ShowMapNamePrompt(Global.Data.roleData.MapCode);
		if (Global.GetMapSceneUIClass() == SceneUIClasses.JingJiChang)
		{
			GameInstance.Game.SpriteJingjiStartFight();
		}
	}

	public void ServerMapConversion(int roleID, int teleportID, int mapCode, int mapX, int mapY, int diection)
	{
		try
		{
			if (Global.Data.RoleID == roleID)
			{
				Global.Data.roleData.MapCode = mapCode;
				Global.Data.roleData.PosX = mapX;
				Global.Data.roleData.PosY = mapY;
				Global.Data.roleData.RoleDirection = diection;
				this.ShowLoadingMap();
			}
		}
		catch (Exception ex)
		{
			MUDebug.LogException(ex);
		}
	}

	public void ShowMapNamePrompt(int mapCode)
	{
		GameObject gameObject = this.Root.FindName("ShowMapPrompt(Clone)");
		if (gameObject)
		{
			Object.Destroy(gameObject);
		}
		this.MapNamePromptPart = Object.Instantiate<GameObject>(U3DUtils.UIResources("ShowMapPrompt"));
		this.MapNamePromptPart.transform.localPosition = new Vector3(0f, -107f, -100f);
		this.Root.Children.Add(this.MapNamePromptPart);
		GameObject gameObject2 = this.MapNamePromptPart.transform.Find("Texture").gameObject;
		ShowNetImage mapName = null;
		if (gameObject2 != null)
		{
			mapName = gameObject2.GetComponent<ShowNetImage>();
			if (mapName != null)
			{
				mapName.URL = "NetImages/GameRes/Images/Plate/" + mapCode + ".png";
				switch (mapCode)
				{
				case 1:
				case 5:
				case 7:
				case 8:
					mapName.gameObject.transform.localScale = new Vector3(355f, 47f, 1f);
					break;
				case 2:
				case 3:
				case 4:
					mapName.gameObject.transform.localScale = new Vector3(318f, 47f, 1f);
					break;
				case 6:
					mapName.gameObject.transform.localScale = new Vector3(389f, 47f, 1f);
					break;
				default:
					mapName.gameObject.transform.localScale = new Vector3(355f, 47f, 1f);
					break;
				}
			}
		}
		TweenAlpha component = gameObject2.GetComponent<TweenAlpha>();
		if (component != null)
		{
			component.onFinished = delegate(UITweener tween)
			{
				if (mapName != null)
				{
					if (mapName.Texture != null && mapName.Texture.mainTexture != null)
					{
						Object.Destroy(mapName.Texture.mainTexture);
						mapName.Texture.mainTexture = null;
					}
					Object.Destroy(mapName);
				}
				Object.Destroy(this.MapNamePromptPart);
				this.MapNamePromptPart = null;
			};
		}
	}

	public void ProcessGoodsExchange(string[] fields)
	{
		try
		{
			int ret = Convert.ToInt32(fields[0]);
			int roleID = Convert.ToInt32(fields[1]);
			int num = Convert.ToInt32(fields[2]);
			int num2 = Convert.ToInt32(fields[3]);
			if (Global.Data.RoleID == roleID)
			{
				if (Global.Data.OtherRoles.ContainsKey(num))
				{
					RoleData roleData = Global.Data.OtherRoles[num];
					if (num2 == 1)
					{
						if (ret < 0)
						{
							if (ret == -1)
							{
								Super.HintMainText(StringUtil.substitute(Global.GetLang("对方已经离线，无法进行交易"), new object[0]), 10, 3);
							}
							else if (ret == -2)
							{
								Super.HintMainText(StringUtil.substitute(Global.GetLang("对方正在和其他人交易，请一会儿再试"), new object[0]), 10, 3);
							}
							else if (ret == -3 || ret == -4)
							{
								Super.HintMainText(StringUtil.substitute(Global.GetLang("对方距离您过远, 请走近再试"), new object[0]), 10, 3);
							}
							else if (ret == -10)
							{
								Super.HintMainText(StringUtil.substitute(Global.GetLang("您已有申请的交易，正在等待对方回复!"), new object[0]), 10, 3);
							}
							else
							{
								Super.HintMainText(StringUtil.substitute(Global.GetLang("请求交易失败: {0}!"), new object[]
								{
									ret
								}), 10, 3);
							}
						}
						else
						{
							Global.Data.ExchangeID = ret;
						}
					}
					else if (num2 != 2)
					{
						if (num2 == 3)
						{
							if (ret < 0)
							{
								if (ret == -1)
								{
									Super.HintMainText(StringUtil.substitute(Global.GetLang("对方已经离线，无法进行交易"), new object[0]), 10, 3);
								}
								else if (ret == -2)
								{
									Super.HintMainText(StringUtil.substitute(Global.GetLang("对方正在和其他人交易，请一会儿再试"), new object[0]), 10, 3);
								}
								else if (ret == -3 || ret == -4)
								{
									Super.HintMainText(StringUtil.substitute(Global.GetLang("对方距离您过远，请走近再试"), new object[0]), 10, 3);
								}
								else
								{
									Super.HintMainText(StringUtil.substitute(Global.GetLang("交易失败: {0}!"), new object[]
									{
										ret
									}), 10, 3);
								}
							}
							else
							{
								this.ShowPlayerTradingWindow(num);
							}
						}
						else if (num2 != 4)
						{
							if (num2 != 5)
							{
								if (num2 != 6)
								{
									if (num2 != 7)
									{
										if (num2 != 9)
										{
											if (num2 == 10)
											{
												Super.HintMainText(StringUtil.substitute(Global.GetLang("您终止了和【{0}】交易!"), new object[]
												{
													Global.FormatRoleName(roleData)
												}), 10, 3);
											}
											else if (num2 == 11)
											{
												if (null != this.PlayerTradingWindow)
