							{
								ret
							}), 10, 3);
						}
					}
					else
					{
						this.ShowPlayerTradingWindow(roleID);
					}
				}
				else if (num2 == 4)
				{
					if (null != this.PlayerTradingWindow)
					{
						this.CloseChildWindow(this.PlayerTradingWindow);
						this.PlayerTradingWindow = null;
						this.ptPart.Destroy();
						this.ptPart = null;
					}
					Global.Data.ExchangeID = -1;
					Global.Data.ExchangeDataItem = null;
					Super.HintMainText(StringUtil.substitute(Global.GetLang("对方取消了和你的交易"), new object[0]), 10, 3);
				}
				else if (num2 != 5)
				{
					if (num2 != 6)
					{
						if (num2 != 7)
						{
							if (num2 != 9)
							{
								if (num2 == 10)
								{
									Super.HintMainText(StringUtil.substitute(Global.GetLang("对方取消了和您的交易"), new object[0]), 10, 3);
								}
								else if (num2 == 11)
								{
