									{
										this.CloseChildWindow(this.PlayerTradingWindow);
										this.PlayerTradingWindow = null;
										this.ptPart.Destroy();
										this.ptPart = null;
									}
									Global.Data.ExchangeID = -1;
									Global.Data.ExchangeDataItem = null;
									if (ret >= 0)
									{
										Super.HintMainText(StringUtil.substitute(Global.GetLang("交易完成!"), new object[0]), 10, 3);
										JueXingNetManager.UpdateJueXingSuiPian(null);
