									else if (ret == -11)
									{
										Super.HintMainText(StringUtil.substitute(Global.GetLang("交易失败，对方的背包已满!"), new object[0]), 10, 3);
									}
									else if (ret == -2)
									{
										Super.HintMainText(StringUtil.substitute(Global.GetLang("交易失败，对方金币余额不足!"), new object[0]), 10, 3);
									}
									else if (ret == -12)
									{
										Super.ShowGuideWindow(BaodianGuidePart.GuideType.NeedJinbi, null, string.Empty, string.Empty);
									}
									else if (ret == -3)
									{
										Super.HintMainText(StringUtil.substitute(Global.GetLang("交易失败，对方的银票数量不足!"), new object[0]), 10, 3);
									}
									else if (ret == -13)
									{
										Super.HintMainText(StringUtil.substitute(Global.GetLang("交易失败，您的银票数量不足!"), new object[0]), 10, 3);
									}
								}
							}
						}
					}
				}
			}
		}
		catch (Exception ex)
		{
			MUDebug.LogException(ex);
		}
	}

	public void ProcessGoodsStall(string[] fields)
	{
		try
		{
			int num = Convert.ToInt32(fields[0]);
			int num2 = Convert.ToInt32(fields[1]);
			int num3 = Convert.ToInt32(fields[2]);
			if (Global.Data.RoleID == num2)
			{
				if (num3 == 1)
				{
					if (num < 0)
					{
						GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("请求摆摊时错误: {0}"), new object[]
						{
							num
						}), 0, -1, -1, 0);
					}
					else if (Global.Data.StallDataItem != null)
					{
					}
				}
				else if (num3 == 2)
				{
					if (num < 0)
					{
						GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("开始摆摊时错误: {0}"), new object[]
						{
							num
						}), 0, -1, -1, 0);
					}
				}
				else if (num3 == 3)
				{
					if (num < 0)
					{
						GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("取消摆摊时错误: {0}"), new object[]
						{
							num
						}), 0, -1, -1, 0);
					}
					Global.Data.StallDataItem = null;
				}
				else if (num3 != 4)
				{
					if (num3 != 5)
					{
						if (num3 != 6)
						{
							if (num3 == 7)
							{
								if (num < 0)
								{
									GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("显示摆摊时错误: {0}"), new object[]
									{
										num
									}), 0, -1, -1, 0);
								}
							}
							else if (num3 == 8 && num < 0)
							{
								if (num <= -11)
								{
									if (num == -13)
									{
										GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("余额不足，无法购买物品"), new object[0]), 0, -1, -1, 0);
