	public void ProcessCopyTeamCmds(string[] fields)
	{
		try
		{
			int num = Convert.ToInt32(fields[0]);
			int num2 = Convert.ToInt32(fields[1]);
			int num3 = Convert.ToInt32(fields[2]);
			long num4 = Convert.ToInt64(fields[3]);
			if (num == 1)
			{
				if (Global.Data.RoleID == num2)
				{
					TeamCmds teamCmds = (TeamCmds)num3;
					switch (teamCmds)
					{
					case TeamCmds.Quit:
						break;
					default:
						switch (teamCmds)
						{
						case TeamCmds.Create:
							this.zuduiFuBenPart.NotifyCreateTeam(num4);
							break;
						}
						break;
					case TeamCmds.QuickJoinTeam:
						this.zuduiFuBenPart.NotifyJoinTeam();
						break;
					case TeamCmds.Start:
						break;
					case TeamCmds.ChangeKickFlag:
						if (this.zuduiFuBenPart != null)
						{
							this.zuduiFuBenPart.SetCheckState(15, num4);
						}
						break;
					case TeamCmds.AutoStart:
						if (this.zuduiFuBenPart != null)
						{
							this.zuduiFuBenPart.SetCheckState(16, num4);
						}
						break;
					}
				}
			}
			else
			{
				ZuduiFubenPart.ProcessErrorCode((ZuduiFubenPart.ZuduiErrCode)num, true);
			}
		}
		catch (Exception ex)
		{
			MUDebug.LogException(ex);
		}
	}

	public void ProcessArenaBattleCmds(string[] fields)
	{
		try
		{
			int num = Convert.ToInt32(fields[0]);
			int num2 = Convert.ToInt32(fields[1]);
			int num3 = Convert.ToInt32(fields[2]);
			int type = Convert.ToInt32(fields[3]);
			int leftSecs = Convert.ToInt32(fields[4]);
			if (num3 == 1)
			{
				if (this.scene.IsInStalling() || Global.GetMapType(Global.Data.roleData.MapCode) != MapTypes.Normal || Global.GetLaoFangMapCode() != Global.Data.roleData.MapCode)
				{
				}
			}
			else if (num3 == 4)
			{
				if (num == -2)
				{
					GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("PK之王活动已经结束，请期待下一场活动的开启"), new object[]
					{
						num
					}), 0, -1, -1, 0);
				}
				else if (num == -22)
				{
					GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("PK之王战斗已经开始，不能再进入，请期待下一场活动的开启"), new object[]
					{
						num
					}), 0, -1, -1, 0);
				}
				else if (num == -3)
				{
					GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("参加PK之王活动的人数已经达到最大限制"), new object[]
					{
						num
					}), 0, -1, -1, 0);
				}
				else if (num == -10)
				{
					GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("您当前的级别不足，无法参加PK之王活动"), new object[]
					{
						num
					}), 0, -1, -1, 0);
				}
				else if (num <= -1000)
				{
					GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("PK之王活动只能在{0}线参加, 请切换到{0}线后，再进入PK之王"), new object[]
					{
						Math.Abs(num) - 1000
					}), 0, -1, -1, 0);
				}
				else if (num < 0)
				{
					GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("进入PK之王时错误: {0}"), new object[]
					{
						num
					}), 0, -1, -1, 0);
				}
				else
				{
					this.CloseArenaBattleHintWindow();
				}
			}
			else if (num3 == 2)
			{
			}
			if (null != this.GameFubenBoxMini)
			{
				this.GameFubenBoxMini.NotifyPKKingTime(type, leftSecs);
				this.GameFubenBoxMini.NotifySceneMsg(type, leftSecs);
			}
		}
		catch (Exception ex)
		{
			MUDebug.LogException(ex);
		}
	}

	public void ProcessBattleCmds(string[] fields)
	{
		try
		{
			int num = Convert.ToInt32(fields[0]);
			int num2 = Convert.ToInt32(fields[1]);
			int num3 = Convert.ToInt32(fields[2]);
			int type = Convert.ToInt32(fields[3]);
			int leftSecs = Convert.ToInt32(fields[4]);
			if (num3 == 1)
			{
				if (this.scene.IsInStalling() || Global.GetMapType(Global.Data.roleData.MapCode) != MapTypes.Normal || Global.GetLaoFangMapCode() != Global.Data.roleData.MapCode)
				{
				}
			}
			else if (num3 == 4)
			{
				if (num == -2)
				{
					GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("当前不在阵营战活动时间内"), new object[]
					{
						num
					}), 0, -1, -1, 0);
				}
				else if (num == -3)
				{
					GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("参加阵营战活动的人数已经达到最大限制"), new object[]
					{
						num
					}), 0, -1, -1, 0);
				}
				else if (num == -10)
				{
					GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("您当前的级别不足，无法参加阵营战活动"), new object[]
					{
						num
					}), 0, -1, -1, 0);
				}
				else if (num <= -1000)
				{
					GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("阵营战活动只能在{0}线参加, 请切换到{0}线后，再进入阵营战"), new object[]
					{
						Math.Abs(num) - 1000
					}), 0, -1, -1, 0);
				}
				else if (num < 0)
				{
					GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("进入阵营战地图时错误: {0}"), new object[]
					{
						num
					}), 0, -1, -1, 0);
				}
				else
				{
					this.CloseBattleHintWindow();
				}
			}
			else if (num3 == 2)
			{
			}
			if (null != this.GameFubenBoxMini)
			{
				this.GameFubenBoxMini.NotifySceneMsg(type, leftSecs);
			}
		}
		catch (Exception ex)
		{
			MUDebug.LogException(ex);
		}
	}

