	public void ProcessMarketBuy(string[] fields)
	{
		int num = Convert.ToInt32(fields[0]);
		int num2 = Convert.ToInt32(fields[1]);
		int num3 = Convert.ToInt32(fields[2]);
		int num4 = Convert.ToInt32(fields[3]);
		string text = fields[4];
		int num5 = Convert.ToInt32(fields[5]);
		int id = Convert.ToInt32(fields[6]);
		string goodsNameByID = Global.GetGoodsNameByID(id, false);
		if (num2 == 0)
		{
			if (num >= 0)
			{
				if (Global.Data.OtherSaleGoodsDataList != null)
				{
					for (int i = 0; i < Global.Data.OtherSaleGoodsDataList.Count; i++)
					{
						if (Global.Data.OtherSaleGoodsDataList[i].Id == num5)
						{
							Global.Data.OtherSaleGoodsDataList.RemoveRange(i, 1);
							break;
						}
					}
					if (null != this.markItemListPart)
					{
						this.markItemListPart.RefreshOtherSaleGoodsDataList();
					}
					if (null != this.markStallListPart)
					{
						this.markStallListPart.RefreshOtherSaleGoodsDataList();
					}
					if (null != this.m_StallOtherPart)
					{
						this.m_StallOtherPart.DeleteStallItem(num5);
					}
				}
				if (null != this.markItemListPart)
				{
					this.markItemListPart.DeleteSaleGoodsData(num5);
				}
			}
			else if (num == -1 || num == -3)
			{
				GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("购买【{0}】失败, 已经被其他人买走或者下架了"), new object[]
				{
					goodsNameByID
				}), 0, -1, -1, 0);
			}
			else if (num == -2)
			{
				GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("购买【{0}】失败, 摊主已经离线"), new object[]
				{
					goodsNameByID
				}), 0, -1, -1, 0);
			}
			else if (num == -5)
			{
				GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("您的背包已经满，请清理出空位后再购买【{0}】"), new object[]
				{
					goodsNameByID
				}), 1, -1, -1, 0);
			}
			else if (num == -10)
			{
				Super.ShowGuideWindow(BaodianGuidePart.GuideType.NeedJinbi, null, string.Empty, string.Empty);
			}
			else if (num == -20)
			{
				Super.ShowGuideWindow(BaodianGuidePart.GuideType.NeedZuanshi, null, string.Empty, string.Empty);
			}
			else if (num == -21)
			{
				GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("购买【{0}】失败, 您的银票数量不足"), new object[]
				{
					goodsNameByID
				}), 0, -1, -1, 0);
			}
			else if (num == -22)
			{
				GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("购买【{0}】失败, 摊主的背包已满，无法得到您的银票"), new object[]
				{
					goodsNameByID
				}), 0, -1, -1, 0);
			}
			else
			{
				GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("购买【{0}】失败, 错误码:{1}"), new object[]
				{
					goodsNameByID,
					num
				}), 0, -1, -1, 0);
			}
		}
		else if (num >= 0)
		{
			GoodsData saleGoodsDataByDbID = Global.GetSaleGoodsDataByDbID(num5);
			Global.RemoveSaleGoodsData(saleGoodsDataByDbID);
			if (null != this.m_StallPart)
			{
				this.m_StallPart.DeleteStallItem(saleGoodsDataByDbID, 0, 0);
			}
			if (null != this.markStallListPart)
			{
			}
			if (null != Super._ParcelPart)
			{
				Super._ParcelPart.RefreshSaleGoodsPart(saleGoodsDataByDbID, false);
			}
			GGameInfocs.AddGameInfoMessage(GameInfoTypeIndexes.Hot, ShowGameInfoTypes.ErrAndBox, StringUtil.substitute(Global.GetLang("【{0}】从您的摊位中购买了{1}"), new object[]
			{
				text,
				goodsNameByID
			}), 0, -1, -1, 0);
		}
	}

