	public void ProcessHuoDongData(HuodongData huodongData)
	{
		if (this.IsShowGiftBagsWindow())
		{
			return;
		}
		int loginGiftState = huodongData.LoginGiftState;
		if (((loginGiftState & 1) != 1 && huodongData.LoginNum >= 2) || ((loginGiftState & 2) != 2 && huodongData.LoginNum >= 4) || ((loginGiftState & 4) != 4 && huodongData.LoginNum >= 7))
		{
			this.ShowLoginTimesGiftWizard();
		}
		int num = 0;
		int num2 = 0;
		int num3 = 0;
		XElement isolateResXml = Global.GetIsolateResXml("Config/Gifts/OnlieTimeGift.xml");
		if (isolateResXml != null)
		{
			List<XElement> xelementList = Global.GetXElementList(isolateResXml, "Item");
			for (int i = 0; i < xelementList.Count; i++)
			{
				XElement xelement = xelementList[i];
				if (i == 0)
				{
					num = Global.GetXElementAttributeInt(xelement, "TimeOl");
				}
				else if (i == 1)
				{
					num2 = Global.GetXElementAttributeInt(xelement, "TimeOl");
				}
				else if (i == 2)
				{
					num3 = Global.GetXElementAttributeInt(xelement, "TimeOl");
				}
			}
		}
		int onlineGiftState = huodongData.OnlineGiftState;
		if (((onlineGiftState & 1) != 1 && huodongData.CurMTime / 3600 >= num) || ((onlineGiftState & 2) != 2 && huodongData.CurMTime / 3600 >= num2) || ((onlineGiftState & 4) != 4 && huodongData.CurMTime / 3600 >= num3))
		{
			this.ShowOnlineTimeGiftWizard();
		}
	}

	protected void ProcessFirstGoods(int dbID, int goodsID, bool firstGoods)
	{
		int timer = U3DUtils.GetTimer();
		if (Global.GetMapSceneUIClass() == SceneUIClasses.BloodCastle && null != this.GameTaskBoxMini && (goodsID == 10000 || goodsID == 10001 || goodsID == 10002))
		{
			this.GameTaskBoxMini.BloodCastleSceneTaskStatus(Global.Data.roleData.MapCode, 6, 1);
		}
		Global.Data.FirstNewGoodsIDList.Add(goodsID);
		this.ShowSystemHelpWindow(4, string.Empty);
		int up = 0;
		if (Super.CanHintEquipGoods(dbID, goodsID, ref up))
		{
			this.NewEquipGoodsDbIDList.Add(new NewEquipGoodsInfo(dbID, up));
		}
		else
		{
			int num = Super.HilightsGoodsPacelIcon(this.BottomMenu, dbID, goodsID);
			if (num == 70)
			{
				this.NewSkillBookGoodsDbIDList.Add(dbID);
			}
			else
			{
				string text = ConfigSystemParam.GetSystemParamByName("TiShiGoodsID", true);
				if (!string.IsNullOrEmpty(text))
				{
					text.Trim();
					text = "," + text + ",";
					if (text.IndexOf(string.Format(",{0},", goodsID)) != -1)
					{
						this.NewTiShiGoodsDbIDList.Add(dbID);
						return;
					}
				}
			}
		}
	}

