	protected void InitNetwork()
	{
		GameInstance.Game.SocketFailed += this.GameSocketFailed;
		GameInstance.Game.SocketSuccess += this.GameSocketSuccess;
		GameInstance.Game.SocketCommand += this.GameSocketCommand;
	}

	protected void ClearNetwork()
	{
		GameInstance.Game.SocketFailed -= this.GameSocketFailed;
		GameInstance.Game.SocketSuccess -= this.GameSocketSuccess;
		GameInstance.Game.SocketCommand -= this.GameSocketCommand;
	}

	protected void CloseNetwork()
	{
		this.ClearNetwork();
		GameInstance.Game.Disconnect();
	}

	public void ClearXmlData()
	{
		if (0 < this.dicLegionsEast.Count)
		{
			this.dicLegionsEast.Clear();
		}
		if (0 < this.dicLegionsWest.Count)
		{
			this.dicLegionsWest.Clear();
		}
	}

	public Dictionary<int, LegionsEast> GetDicLegionsEast()
	{
		if (this.dicLegionsEast.Count > 0)
		{
			return this.dicLegionsEast;
		}
		XElement gameResXml = Global.GetGameResXml("Config/LegionsEast.xml");
		if (gameResXml == null)
		{
			return null;
		}
		List<XElement> xelementList = Global.GetXElementList(gameResXml, "LegionsEast");
		int i = 0;
		int count = xelementList.Count;
		while (i < count)
		{
			LegionsEast legionsEast = new LegionsEast();
			legionsEast.ID = Global.GetXElementAttributeInt(xelementList[i], "ID");
			legionsEast.NPCID = Global.GetXElementAttributeInt(xelementList[i], "NPCID");
			legionsEast.NPCSite = Global.GetXElementAttributeStr(xelementList[i], "NPCSite");
			if (!this.dicLegionsEast.ContainsKey(legionsEast.ID))
			{
				this.dicLegionsEast.Add(legionsEast.ID, legionsEast);
			}
			i++;
		}
		return this.dicLegionsEast;
	}

	public Dictionary<int, LegionsWest> GetDicLegionsWest()
	{
		if (this.dicLegionsWest.Count > 0)
		{
			return this.dicLegionsWest;
		}
		XElement gameResXml = Global.GetGameResXml("Config/LegionsWest.xml");
		if (gameResXml == null)
		{
			return null;
		}
		List<XElement> xelementList = Global.GetXElementList(gameResXml, "LegionsWest");
		int i = 0;
		int count = xelementList.Count;
		while (i < count)
		{
			LegionsWest legionsWest = new LegionsWest();
			legionsWest.ID = Global.GetXElementAttributeInt(xelementList[i], "ID");
			legionsWest.QiZuoID = Global.GetXElementAttributeInt(xelementList[i], "QiZuoID");
			legionsWest.QiZuoSite = Global.GetXElementAttributeStr(xelementList[i], "QiZuoSite");
			if (!this.dicLegionsWest.ContainsKey(legionsWest.ID))
			{
				this.dicLegionsWest.Add(legionsWest.ID, legionsWest);
			}
			i++;
		}
		return this.dicLegionsWest;
	}

	private void DestoryLegionsEastRes()
	{
		Dictionary<int, LegionsEast>.Enumerator enumerator = this.GetDicLegionsEast().GetEnumerator();
		for (int i = 0; i < 5; i++)
		{
		}
		while (enumerator.MoveNext())
		{
			KeyValuePair<int, LegionsEast> keyValuePair = enumerator.Current;
			string npcname = Global.GetNPCName(keyValuePair.Value.NPCID);
			GameObject gameObject = GameObject.Find(npcname);
			if (gameObject != null)
			{
				NGUITools.Destroy(gameObject);
			}
		}
	}

	private void AddLegionsEastRes()
	{
		foreach (KeyValuePair<int, LegionsEast> keyValuePair in this.GetDicLegionsEast())
		{
			int id = keyValuePair.Value.ID;
			Dictionary<int, LegionsEast>.Enumerator enumerator;
			KeyValuePair<int, LegionsEast> keyValuePair2 = enumerator.Current;
			int npcid = keyValuePair2.Value.NPCID;
			KeyValuePair<int, LegionsEast> keyValuePair3 = enumerator.Current;
			this.LegionsEastLoad(id, npcid, keyValuePair3.Value.NPCSite);
		}
	}

	private void ReReLoadLegionsRes()
	{
		string site = null;
		int id = 0;
		if (Global.OldMineResourceList != null && Global.OldMineResourceList.Count > 0)
		{
			for (int i = 0; i < Global.OldMineResourceList.Count; i++)
			{
				if (this.GetDicLegionsEast().ContainsKey(Global.OldMineResourceList[i]))
				{
					id = this.GetDicLegionsEast()[Global.OldMineResourceList[i]].NPCID;
					site = this.GetDicLegionsEast()[Global.OldMineResourceList[i]].NPCSite;
				}
				string text = string.Format("Role_{0}", 2130789436 + this.GetDicLegionsEast()[Global.OldMineResourceList[i]].ID * 100);
				GameObject gameObject = GameObject.Find(text);
				if (gameObject != null)
				{
					this.TiHuanZiYuan(this.GetDicLegionsEast()[Global.OldMineResourceList[i]].ID, 83004, id, site);
				}
			}
		}
	}

	private void ReLoadLegionsRes(List<KarenScoreData> data)
	{
		int num = 0;
		string site = null;
		if (data == null)
		{
			return;
		}
		if (Global.OldMineResourceList != null && Global.OldMineResourceList.Count > 0)
		{
			for (int i = 0; i < data.Count; i++)
			{
				if (i == Global.Data.roleData.BattleWhichSide - 1)
				{
					if (data[i].ResourceList != null && data[i].ResourceList.Count > 0)
					{
						for (int j = 0; j < data[i].ResourceList.Count; j++)
						{
							if (Global.OldMineResourceList.Contains(data[i].ResourceList[j]))
							{
								Global.OldMineResourceList.Remove(data[i].ResourceList[j]);
							}
						}
					}
					this.ReReLoadLegionsRes();
					break;
				}
			}
		}
		for (int k = 0; k < data.Count; k++)
		{
			if (k == Global.Data.roleData.BattleWhichSide - 1 && data[k].ResourceList != null)
			{
				Global.OldMineResourceList.Clear();
				for (int l = 0; l < data[k].ResourceList.Count; l++)
				{
					Global.OldMineResourceList.Add(data[k].ResourceList[l]);
					if (this.GetDicLegionsEast().ContainsKey(data[k].ResourceList[l]))
					{
						num = this.GetDicLegionsEast()[data[k].ResourceList[l]].NPCID;
						site = this.GetDicLegionsEast()[data[k].ResourceList[l]].NPCSite;
					}
					string text = string.Format("Role_{0}", 2130706432 + num + this.GetDicLegionsEast()[data[k].ResourceList[l]].ID * 100);
					GameObject gameObject = GameObject.Find(text);
					if (!(gameObject == null))
					{
						this.TiHuanZiYuan(this.GetDicLegionsEast()[data[k].ResourceList[l]].ID, num, 83004, site);
					}
				}
				break;
			}
		}
	}

	private void ModGoodsFashion(SCModGoods ModGoods)
	{
		if (ModGoods == null)
		{
			return;
		}
		int site = ModGoods.Site;
		if (site == 6000)
		{
			if (null != this.gamePayerRolePart && null != this.gamePayerRolePart.shizhuangPart)
			{
				int modType = ModGoods.ModType;
				if (modType == 4)
				{
					int id = ModGoods.ID;
					this.gamePayerRolePart.shizhuangPart.OnFashionEquipInvalid(id);
				}
			}
			if (ModGoods.ModType == 4)
			{
				Global.RemoveFashionListGoodsDataByDbId(ModGoods.ID);
				if (null != this._FashionWardrobePart)
				{
					this._FashionWardrobePart.RefreshRoleFashionMod(ModGoods);
				}
				else
				{
					Global.CheckRoleGoodsDataList();
				}
				this.scene.ServerChangeCode(null);
				if (Global.Data.fashionAndTitleList != null)
				{
					int i = 0;
					int count = Global.Data.fashionAndTitleList.Count;
					while (i < count)
					{
						if (Global.Data.fashionAndTitleList[i] != null)
						{
							int categoriyByGoodsID = Global.GetCategoriyByGoodsID(Global.Data.fashionAndTitleList[i].GoodsID);
							if (categoriyByGoodsID == 24 || categoriyByGoodsID == 26 || categoriyByGoodsID == 25 || categoriyByGoodsID == 8)
							{
								this.GameMenuIconBoxContainer.RefreshIconByOrder(FashionWardrobePart.FashionWardrobeOrder, 0 < Global.GetRoleFashionList(ItemCategories.Fashion).Count);
								break;
							}
						}
						i++;
					}
				}
			}
			else
			{
				List<GoodsData> fashionAndTitleList = Global.Data.fashionAndTitleList;
				if (fashionAndTitleList != null)
				{
					bool flag = false;
					for (int j = 0; j < fashionAndTitleList.Count; j++)
					{
						GoodsData goodsData = fashionAndTitleList[j];
						if (goodsData.Id == ModGoods.ID)
						{
							goodsData.Using = ModGoods.IsUsing;
							flag = true;
						}
					}
					if (!flag)
					{
						GoodsData goodsDataByDbID = Global.GetGoodsDataByDbID(ModGoods.ID, null);
						if (goodsDataByDbID != null)
						{
							Global.Data.fashionAndTitleList.Add(goodsDataByDbID);
						}
					}
				}
				else
				{
					Global.Data.fashionAndTitleList = new List<GoodsData>();
					GoodsData goodsDataByDbID2 = Global.GetGoodsDataByDbID(ModGoods.ID, null);
					if (goodsDataByDbID2 != null)
					{
						Global.Data.fashionAndTitleList.Add(goodsDataByDbID2);
					}
				}
				Global.CheckRoleGoodsDataList();
				if (null != this._FashionWardrobePart)
				{
					this._FashionWardrobePart.RefreshRoleFashionMod(ModGoods);
				}
				if (null != this.m_RidePetPart)
				{
					this.m_RidePetPart.NoticeWearFashionCallBask(ModGoods);
				}
				ShenHunNetManager.ServerFashionEquip(ModGoods);
				this.scene.ServerChangeCode(null);
			}
		}
	}

