	private void UseGoodsCallBack(int DbId, int Count)
	{
		GoodsData goodsData = Global.GetDiamondGoodsDataByDBID(DbId);
		if (goodsData != null)
		{
			BagModifyType type;
			if (Count > 0)
			{
				goodsData.GCount = Count;
				type = BagModifyType.BagModifyType_Replace;
			}
			else
			{
				type = BagModifyType.BagModifyType_Destroy;
			}
			Global.OnGoodsChangedInDimaondBag(goodsData, type);
			if (null != this.fluorescentDiamond)
			{
				if (null != this.fluorescentDiamond.diamondDig)
				{
					this.fluorescentDiamond.diamondDig.OnDiamondBagChanged(goodsData, type);
				}
				if (null != this.fluorescentDiamond.diamondInlay)
				{
					this.fluorescentDiamond.diamondInlay.RefreshTipsIcons();
				}
			}
			if (null != this.GameMenuIconBoxContainer)
			{
				this.GameMenuIconBoxContainer.CheckFluorescentDiamondIconState();
			}
			return;
		}
		goodsData = Global.GetGoodsDataByDbID(DbId, null);
		if (goodsData != null)
		{
			GoodVO goodsXmlNodeByID = ConfigGoods.GetGoodsXmlNodeByID(goodsData.GoodsID);
			if (Global.GetCategoriyByGoodsID(goodsData.GoodsID) == 704)
			{
				int num = goodsData.GCount - Count;
				if (0 < num)
				{
					Super.HintMainText(StringUtil.substitute(Global.GetLang("您获得了：{0} + {1}"), new object[]
					{
						Global.GetGoodsNameByID(goodsData.GoodsID, true),
						num
					}), 10, 3);
				}
			}
			if (Count > 0)
			{
				goodsData.GCount = Count;
			}
			else
			{
				if (goodsData.Using > 0)
				{
					goodsData.Using = 0;
					if (null != this.gamePayerRolePart && null != this.gamePayerRolePart.zhuangbeiPart)
					{
						this.gamePayerRolePart.zhuangbeiPart.RemoveEquipIcon(goodsData);
					}
				}
				goodsData.GCount = 0;
				Global.RemoveGoodsData(goodsData);
				if (Global.IsRebornGood(goodsXmlNodeByID))
				{
					if (null != Super._ParcelRebornPart)
					{
						Super._ParcelRebornPart.RemoveGoodsRedPointByDelete(goodsData);
					}
				}
				else if (null != Super._ParcelPart)
				{
					Super._ParcelPart.RemoveGoodsRedPointByDelete(goodsData);
				}
			}
			if (Global.GetCategoriyByGoodsID(goodsData.GoodsID) == 330)
			{
				JueXingNetManager.UpdateJueXingSuiPian(goodsData);
			}
			if (goodsData.GoodsID == ShenHunData.GetBianShenGoodsId())
			{
				UICtrlBar.singleton.BianShenIcon.UpdateNumInfo();
			}
			Global.AddGoodsCoolDown(goodsData.GoodsID);
			if (Global.IsRebornGood(goodsXmlNodeByID) && null != Super._ParcelRebornPart)
			{
				Super._ParcelRebornPart.RefreshGoods1(goodsData);
			}
			if (null != Super._ParcelPart)
			{
				Super._ParcelPart.RefreshGoods1(goodsData);
			}
			if (null != this.portableBagPart && null != this.PortableBagWindow && this.PortableBagWindow.Visibility)
			{
				this.portableBagPart.RefreshExtGridNum();
			}
			string goodsSoundByID = Global.GetGoodsSoundByID(goodsData.GoodsID);
			if (!string.IsNullOrEmpty(goodsSoundByID))
			{
			}
		}
		goodsData = Global.GetBagSoulCometStoneGoodsDataByDBID(DbId);
		if (goodsData != null)
		{
			BagModifyType type2;
			if (Count > 0)
			{
				goodsData.GCount = Count;
				type2 = BagModifyType.BagModifyType_Replace;
			}
			else
			{
				type2 = BagModifyType.BagModifyType_Destroy;
			}
			Global.OnGoodsChangedInSoulCometStoneBag(goodsData, type2);
			if (null != this.fluorescentDiamond && null != this.fluorescentDiamond.soulCometStone)
			{
				this.fluorescentDiamond.soulCometStone.OnSoulCometStoneBagChanged(goodsData);
			}
		}
	}

