	public void PaymentVerify()
	{
		Debug.Log("****** Start payment verify In Timer! ********");
		Dictionary<string, OrderIDsStorage.VerifyInfo> allOrderInfo = OrderIDsStorage.GetAllOrderInfo();
		Debug.Log("Traversing the OrderInfo[" + allOrderInfo.Keys.Count + "]......");
		List<string> list = new List<string>();
		foreach (KeyValuePair<string, OrderIDsStorage.VerifyInfo> keyValuePair in allOrderInfo)
		{
			OrderIDsStorage.VerifyInfo verifyInfo = keyValuePair.Value;
			int daysDiffFromOrder = this.GetDaysDiffFromOrder(Global.Data.UserID, keyValuePair.Key);
			if (daysDiffFromOrder > 10)
			{
				AppsIAPPlugin.PostLogInfo("Save OrderInfo in Server [In-Timer]: " + keyValuePair.Key.ToString());
				AppsIAPPlugin.PostLogInfo(string.Concat(new object[]
				{
					"VerifyInfo [In-Timer]: verifyInfo.countryCode = ",
					verifyInfo.countryCode,
					", verifyInfo.currencyCode = ",
					verifyInfo.currencyCode,
					", verifyInfo.money = ",
					verifyInfo.money,
					", verifyInfo.verNum = ",
					verifyInfo.verNum,
					", verifyInfo.TransID = ",
					verifyInfo.TransID
				}));
				list.Add(keyValuePair.Key.ToString());
			}
		}
		foreach (string orderId in list)
		{
			OrderIDsStorage.Del(orderId);
			OrderIDsStorage.Save();
		}
		if (PlayZone.validOrders == null || PlayZone.validOrders.Count <= 0)
		{
			PlayZone.validOrders = OrderIDsStorage.GetValidOrderInfo();
			if (PlayZone.validOrders != null && PlayZone.validOrders.Count > 0)
			{
				string text = PlayZone.validOrders[0];
				PlayZone.validOrders.RemoveAt(0);
				if (!string.IsNullOrEmpty(text))
				{
					OrderIDsStorage.VerifyInfo verifyInfo = OrderIDsStorage.GetOrderInfo(text);
					if (verifyInfo != null)
					{
						MUDebug.Log<string>(new string[]
						{
							string.Concat(new object[]
							{
								"Get info: ",
								text,
								"-",
								verifyInfo.countryCode,
								"-",
								verifyInfo.currencyCode,
								"-",
								verifyInfo.money,
								"-",
								verifyInfo.TransID,
								"-",
								verifyInfo.verifyState
							})
						});
						MUDebug.Log<string>(new string[]
						{
							"Verify Data: " + Convert.ToBase64String(verifyInfo.verifyData)
						});
						this.currentOrderId = text;
						this.DoVerify(text, verifyInfo);
					}
				}
			}
			else
			{
				base.CancelInvoke("PaymentVerify");
			}
		}
	}

	private void DoVerify(string orderid, OrderIDsStorage.VerifyInfo verifyInfo)
	{
		VoiceRequestParam voiceRequestParam = new VoiceRequestParam();
		voiceRequestParam.url = PlatSDKMgr.GetAPPSPaymentVerifyServerURL();
		long timeStamp = Global.GetTimeStamp();
		string userID = Global.Data.UserID;
		ClientExchangeOrderResultData clientExchangeOrderResultData = new ClientExchangeOrderResultData();
		clientExchangeOrderResultData.strPlatform = PlatSDKMgr.m_platName;
		clientExchangeOrderResultData.strUserID = userID;
		clientExchangeOrderResultData.lTime = timeStamp;
		clientExchangeOrderResultData.nMoney = verifyInfo.money;
		clientExchangeOrderResultData.strExchangeOrder = orderid;
		clientExchangeOrderResultData.nServerID = Global.Data.GameServerID;
		clientExchangeOrderResultData.recipent_data = verifyInfo.verifyData;
		clientExchangeOrderResultData.strIOSVer = verifyInfo.verNum;
		clientExchangeOrderResultData.strTransactionId = verifyInfo.TransID;
		clientExchangeOrderResultData.strNSLocaleCountryCode = verifyInfo.countryCode;
		clientExchangeOrderResultData.strNSLocaleCurrencyCode = verifyInfo.currencyCode;
		clientExchangeOrderResultData.VersionCode = "1.3.0";
		int num = 50;
		int num2 = 50;
		string text = Convert.ToBase64String(verifyInfo.verifyData);
		if (text.Length - num < 0)
		{
			Debug.Log("-----------b64VerifyData: " + text);
			Debug.Log("-----------b64VerifyData length: " + text.Length);
			AppsIAPPlugin.PostLogInfo("Illegal Verify Data [In-Timer]:" + text);
		}
		else
		{
			string text2 = string.Concat(new object[]
			{
				string.Empty,
				timeStamp,
				Global.Data.GameServerID,
				text.Substring(text.Length - num, num2)
			});
			clientExchangeOrderResultData.strMD5 = MD5Helper.get_md5_string(string.Concat(new object[]
			{
				text2,
				PlatSDKMgr.m_platName,
				userID,
				verifyInfo.money,
				orderid,
				Global.Data.GameServerID,
				timeStamp,
				verifyInfo.countryCode,
				verifyInfo.currencyCode,
				clientExchangeOrderResultData.VersionCode
			}));
			clientExchangeOrderResultData.FirstId = Global.Data.ServerData.LastServer.nFirstLevelServerID + string.Empty;
			voiceRequestParam.timeout = 10;
			voiceRequestParam.postData = DataHelper.ObjectToBytes<ClientExchangeOrderResultData>(clientExchangeOrderResultData);
			voiceRequestParam.callback = new Action<WWW, object>(this.VerifyCallback);
			HttpService.Instance.Load(voiceRequestParam.url, voiceRequestParam.callback, voiceRequestParam.postData, voiceRequestParam.param, 0);
		}
	}

	private void VerifyCallback(WWW w, object obj)
	{
		try
		{
			if (w != null)
			{
				if (string.IsNullOrEmpty(w.error))
				{
					byte[] bytes = w.bytes;
					if (bytes != null && bytes.Length > 0)
					{
						ServerExchangeOrderResultData serverExchangeOrderResultData = DataHelper.BytesToObject<ServerExchangeOrderResultData>(bytes, 0, bytes.Length);
						if (serverExchangeOrderResultData != null && !string.IsNullOrEmpty(serverExchangeOrderResultData.strState))
						{
							string text = string.Empty;
							string orderId = string.Empty;
							if (serverExchangeOrderResultData.strState.Contains(":"))
							{
								string[] array = serverExchangeOrderResultData.strState.Split(new char[]
								{
									':'
								});
								if (array != null && array.Length >= 2)
								{
									text = array[0].Trim();
									orderId = array[1].Trim();
								}
								else
								{
									text = serverExchangeOrderResultData.strState;
									orderId = this.currentOrderId;
								}
							}
							else
							{
								text = serverExchangeOrderResultData.strState;
								orderId = this.currentOrderId;
							}
							if (text == "0")
							{
								OrderIDsStorage.Del(orderId);
								OrderIDsStorage.Save();
							}
							else if (text == "-3" || text == "-2")
							{
								OrderIDsStorage.Del(orderId);
								OrderIDsStorage.Save();
							}
						}
					}
				}
				else
				{
					AppsIAPPlugin.PostLogInfo("PaymentVerify callback return error [" + w.error + "] [In-Timer]");
				}
			}
			else
			{
				AppsIAPPlugin.PostLogInfo("PaymentVerify callback return error [Request Time out!] [In-Timer]");
			}
		}
		catch (Exception ex)
		{
			AppsIAPPlugin.PostLogInfo("VerifyCallback exception: " + ex.ToString());
		}
		if (PlayZone.validOrders.Count > 0)
		{
			string text2 = PlayZone.validOrders[0];
			PlayZone.validOrders.RemoveAt(0);
			if (!string.IsNullOrEmpty(text2))
			{
				OrderIDsStorage.VerifyInfo orderInfo = OrderIDsStorage.GetOrderInfo(text2);
				if (orderInfo != null)
				{
					MUDebug.Log<string>(new string[]
					{
						string.Concat(new object[]
						{
							"Get info: ",
							text2,
							"-",
							orderInfo.countryCode,
							"-",
							orderInfo.currencyCode,
							"-",
							orderInfo.money,
							"-",
							orderInfo.TransID,
							"-",
							orderInfo.verifyState
						})
					});
					MUDebug.Log<string>(new string[]
					{
						"Verify Data: " + Convert.ToBase64String(orderInfo.verifyData)
					});
					this.currentOrderId = text2;
					this.DoVerify(text2, orderInfo);
				}
			}
		}
	}

	private int GetDaysDiffFromOrder(string uid, string orderId)
	{
		MUDebug.Log<string>(new string[]
		{
			"uid = " + uid + ", orderId = " + orderId
		});
		int result = 0;
		if (orderId.StartsWith(uid))
		{
			string text = orderId.Substring(uid.Length, "yyyyMMddHHmmss".Length);
			MUDebug.Log<string>(new string[]
			{
				"dateStr = " + text
			});
			DateTime dateTime = DateTime.ParseExact(text, "yyyyMMddHHmmss", CultureInfo.CurrentCulture);
			MUDebug.Log<string>(new string[]
			{
				"dateFromStr = " + dateTime
			});
			DateTime now = DateTime.Now;
			result = (now - dateTime).Days;
		}
		return result;
	}

	public void ClearInvalidCache()
	{
		MUDebug.Log<string>(new string[]
		{
			"Enter ClearInvalidCache..."
		});
		long num = DateTime.Now.Ticks / 10000000L;
		List<string> list = new List<string>();
		Dictionary<string, HttpCache.HttpCacheInfo> dictionary = HttpCache.Get();
		foreach (KeyValuePair<string, HttpCache.HttpCacheInfo> keyValuePair in dictionary)
		{
			MUDebug.Log<string>(new string[]
			{
				"******" + keyValuePair.Value.url
			});
			MUDebug.Log<string>(new string[]
			{
				"******" + keyValuePair.Value.postdata
			});
			long num2 = long.Parse(keyValuePair.Key) / 10000000L;
			long num3 = (num - num2) / 3600L;
			if (keyValuePair.Value.url.StartsWith("http://") || num3 > 120L)
			{
				MUDebug.Log<string>(new string[]
				{
					"Url start with: " + keyValuePair.Value.url
				});
				MUDebug.Log<string>(new string[]
				{
					"Diff hour: " + num3
				});
				list.Add(keyValuePair.Key);
			}
		}
		foreach (string text in list)
		{
			MUDebug.Log<string>(new string[]
			{
				"Key will be delete..." + text
			});
			HttpCache.Del(text);
		}
	}

	public void CheckHttpCache()
	{
		MUDebug.Log<string>(new string[]
		{
			"In CheckHttpCache......"
		});
		Dictionary<string, HttpCache.HttpCacheInfo> dictionary = HttpCache.Get();
		foreach (KeyValuePair<string, HttpCache.HttpCacheInfo> keyValuePair in dictionary)
		{
			string theKey = keyValuePair.Key;
			VoiceRequestParam voiceRequestParam = new VoiceRequestParam();
			voiceRequestParam.url = keyValuePair.Value.url;
			voiceRequestParam.callback = delegate(WWW w, object obj)
			{
				if (w != null && string.IsNullOrEmpty(w.error))
				{
					byte[] bytes = w.bytes;
					if (bytes != null && bytes.Length > 0)
					{
						Hashtable hashtable = (Hashtable)MUJson.jsonDecode(Encoding.UTF8.GetString(bytes));
						if (hashtable["ret"].ToString() == "0")
						{
							MUDebug.Log<string>(new string[]
							{
								"In CheckHttpCache send ok [" + theKey + "] ......"
							});
							HttpCache.Del(theKey);
						}
					}
				}
			};
			voiceRequestParam.postData = keyValuePair.Value.postdata;
			voiceRequestParam.timeout = 20;
			MUDebug.Log<string>(new string[]
			{
				"In CheckHttpCache key = " + theKey
			});
			MUDebug.Log<string>(new string[]
			{
				"In CheckHttpCache url = " + voiceRequestParam.url
			});
			MUDebug.Log<string>(new string[]
			{
				"In CheckHttpCache post = " + Encoding.UTF8.GetString(voiceRequestParam.postData)
			});
			HttpService.Instance.Load(voiceRequestParam.url, voiceRequestParam.callback, voiceRequestParam.postData, voiceRequestParam.param, 0);
		}
	}

	public static GChildWindow AddChildWindow(UserControl part, ChildWindowModalType modalType)
	{
		GChildWindow gchildWindow = null;
		if (null != PlayZone.GlobalPlayZone)
		{
			gchildWindow = U3DUtils.NEW<GChildWindow>();
			Super.InitChildWindow(gchildWindow, part.name);
			PlayZone.GlobalPlayZone.Root.Add(gchildWindow);
			gchildWindow.ModalType = modalType;
			gchildWindow.SetContent(gchildWindow.BodyPresenter, part, 0.0, 0.0, true);
			part.ChildWindowClose = new ChildWindowCloseEventHandler(PlayZone.GlobalPlayZone.CloseChildWindow);
		}
		return gchildWindow;
	}

	public bool CloseChildWindow(object sender, EventArgs args)
	{
		UserControl userControl = sender as UserControl;
		if (null != userControl && null != userControl.parent)
		{
			GChildWindow component = userControl.parent.GetComponent<GChildWindow>();
			if (null != component)
			{
				Super.CloseChildWindow(PlayZone.GlobalPlayZone.Children, component);
			}
		}
		return true;
	}

