	public void ShowTaskPart(int npcID = 0, int taskID = 0, int npcExtensionID = 0, int mapCode = 0, bool newTask = false, int type = 0)
	{
		if (null == this.TaskWindow)
		{
			this.TaskWindow = U3DUtils.NEW<GChildWindow>();
			this.InitChildWindow(this.TaskWindow, "_TaskWindow");
			this.TaskWindow.ChildWindowClose = delegate(object sender, EventArgs e)
			{
				this.CloseTaskPart();
				return true;
			};
			this.Container.Children.Add(this.TaskWindow);
			this.TaskWindow.ModalType = ChildWindowModalType.BlackBak;
			this._TaskPart = U3DUtils.NEW<TabWindow>();
			this.TaskWindow.IsShowModal = true;
			this.TaskWindow.SetContent(this.TaskWindow.BodyPresenter, this._TaskPart, 0.0, 0.0, true);
			this._TaskPart.InitPartData(npcID, taskID, npcExtensionID, mapCode, newTask, type);
			this._TaskPart.DPSelectedItem = delegate(object sender, DPSelectedItemEventArgs e)
			{
				this.CloseTaskPart();
			};
		}
		else if (type == 1)
		{
			if (null != this._TaskPart && null != this._TaskPart._riChangTaskPart)
			{
				this._TaskPart._riChangTaskPart.InitPartData(npcID, taskID, npcExtensionID, mapCode, newTask);
			}
		}
		else if (type == 3 && null != this._TaskPart && null != this._TaskPart._taoFaTaskPart)
		{
			this._TaskPart._taoFaTaskPart.ShowTaskPart(npcID, taskID, npcExtensionID, mapCode, newTask);
		}
	}

	public void ShowJingLingPart(jinglingSystemPart.BtnType type = jinglingSystemPart.BtnType.JingLing)
	{
		int trigger = 0;
		int param = 0;
		int param2 = 0;
		if (!GongnengYugaoMgr.IsGongNengOpened(GongNengIDs.JingLingSystem, ref trigger, ref param, ref param2))
		{
			UIHelper.HintGongNengOpenCondition(GongNengIDs.JingLingSystem, trigger, param, param2, true);
			return;
		}
		if (null != this.JingLingWindow && null != this.JingLingPart)
		{
			this.JingLingPart.SetPart((int)type, YuansuBagTypes.Normal);
			return;
		}
		this.JingLingWindow = U3DUtils.NEW<GChildWindow>();
		this.JingLingWindow.IsShowModal = true;
		this.InitChildWindow(this.JingLingWindow, "_TaskWindow");
		this.Container.Children.Add(this.JingLingWindow);
		this.JingLingWindow.ChildWindowClose = delegate(object s, EventArgs e)
		{
			this.CloseJingLingPartWindow();
			return true;
		};
		this.JingLingWindow.ModalType = ChildWindowModalType.BlackBak;
		this.JingLingPart = U3DUtils.NEW<jinglingSystemPart>();
		this.JingLingPart.DPSelectedItem = delegate(object sender, DPSelectedItemEventArgs e)
		{
			if (e.ID == -10)
			{
				this.CloseJingLingPartWindow();
			}
			else if (e.ID == 1)
			{
				this.CloseJingLingPartWindow();
				this.CloseRelatedToParcelPart();
				this.ShowJingLingZhaoHuanWindow(false);
			}
		};
		this.JingLingWindow.SetContent(this.JingLingWindow.BodyPresenter, this.JingLingPart, 0.0, 0.0, true);
		this.JingLingPart.SetPart((int)type, (type != jinglingSystemPart.BtnType.YuanSuZhiXin) ? YuansuBagTypes.Normal : YuansuBagTypes.Getting);
	}

