	public void ShowDaojishi(string btnOKText = null, string btnCancelText = null, string staticText0 = null, string staticText1 = null, bool IsNeedDaojishi = true, DPSelectedItemEventHandler dpSelectItemEventHandler = null)
	{
		if (this.KuafuDaojishiWindow != null)
		{
			this.CloseChildWindow(this.KuafuDaojishiWindow);
			this.KuafuDaojishiWindow = null;
			this._KuafuDaojishiPart = null;
		}
		if (this.KuafuDaojishiWindow == null && this._KuafuDaojishiPart == null)
		{
			this.KuafuDaojishiWindow = U3DUtils.NEW<GChildWindow>();
			this.KuafuDaojishiWindow.IsShowModal = true;
			this.InitChildWindow(this.KuafuDaojishiWindow, "kuafudaojishi");
			this.Container.Add(this.KuafuDaojishiWindow);
			this.KuafuDaojishiWindow.ModalType = ChildWindowModalType.Translucent;
			this._KuafuDaojishiPart = U3DUtils.NEW<KuafuDaojishiPart>();
			if (btnOKText != null && btnCancelText != null && staticText0 != null && staticText1 != null)
			{
				this._KuafuDaojishiPart.SetTextInPrefabs(btnOKText, btnCancelText, staticText0, staticText1, IsNeedDaojishi);
			}
			if (dpSelectItemEventHandler == null)
			{
				this._KuafuDaojishiPart.DPSelectedItem = delegate(object s, DPSelectedItemEventArgs e)
				{
					if (e.ID == 0)
					{
						GameInstance.Game.EnterHuanYing(0);
						this.CloseChildWindow(this.KuafuDaojishiWindow);
						this.KuafuDaojishiWindow = null;
						this._KuafuDaojishiPart = null;
					}
					if (e.ID == 1)
					{
						GameInstance.Game.EnterHuanYing(1);
					}
				};
			}
			else
			{
				this._KuafuDaojishiPart.DPSelectedItem = dpSelectItemEventHandler;
			}
			this.KuafuDaojishiWindow.SetContent(this.KuafuDaojishiWindow.BodyPresenter, this._KuafuDaojishiPart, 0.0, 0.0, true);
		}
	}

	public void CloseDaojishiWindow()
	{
		if (this.KuafuDaojishiWindow != null)
		{
			this.CloseChildWindow(this.KuafuDaojishiWindow);
			this.KuafuDaojishiWindow = null;
			this._KuafuDaojishiPart = null;
		}
	}

