	private void ShowBuildMain(int GoodID = 0)
	{
		if (Global.IsOperateUnPermitInKuaFuMapCheck(true, true))
		{
			return;
		}
		if (null != this.BuildMainwindow)
		{
			this.BuildMainwindow.Visibility = true;
		}
		else
		{
			this.BuildMainwindow = U3DUtils.NEW<GChildWindow>();
			if (!this.BuildMainwindow.Visibility)
			{
				this.BuildMainwindow.Visibility = true;
			}
			this.BuildMainwindow.transform.localScale = new Vector3(1f, 1f, 1f);
			this.BuildMainwindow.Modal = true;
			this.BuildMainwindow.IsShowModal = true;
			this.Root.Children.Add(this.BuildMainwindow);
			this.BuildMainwindow.ChildWindowClose = delegate(object s, EventArgs e)
			{
				this.CloseBuildMain();
				return true;
			};
		}
		this.InitChildWindow(this.BuildMainwindow, "jinglingyaosai");
		if (null != this.buildMain)
		{
			Object.DestroyImmediate(this.buildMain.gameObject);
			this.buildMain = null;
		}
		this.buildMain = U3DUtils.NEW<BuildMainPart>();
		if (GoodID == -1000)
		{
			this.buildMain.PetShowSignGoodsID = 0;
			this.buildMain.InitByOnEnabel = 1;
		}
		else
		{
			this.buildMain.PetShowSignGoodsID = GoodID;
			this.buildMain.InitBuildMain();
		}
		this.buildMain.transform.localPosition = new Vector3(0f, 0f, 0f);
		this.buildMain.transform.SetParent(this.BuildMainwindow.Body.transform, false);
	}

	public void CloseBuildMain()
	{
		if (this.BuildMainwindow != null)
		{
			this.BuildMainwindow.Visibility = false;
			if (null != this.buildMain)
			{
				Object.Destroy(this.buildMain.gameObject);
			}
			this.CloseChildWindow(this.BuildMainwindow);
			this.BuildMainwindow = null;
			this.buildMain = null;
		}
	}

