		{
			this.buildMain.UpDateAwardState(datalist);
		}
	}

	public void Errcode(int Id)
	{
		string msg = string.Empty;
		switch (Id)
		{
		case 1:
			msg = Global.GetLang("总等级奖励已经领过了");
			break;
		case 2:
			msg = Global.GetLang("总等级不够");
			break;
		case 3:
			msg = Global.GetLang("收费建造队列达到上限");
			break;
		case 4:
			Global.GetLang("未找到已完成任务");
			break;
		case 5:
			msg = Global.GetLang("建造队列不足");
			break;
		case 6:
			msg = Global.GetLang("建造中");
			break;
		case 7:
			msg = Global.GetLang("配置错误");
			break;
		case 8:
			msg = Global.GetLang("传来的参数错误");
			break;
		case 9:
			Super.ShowGuideWindow(BaodianGuidePart.GuideType.NeedZuanshi, null, string.Empty, string.Empty);
			break;
		case 10:
			msg = Global.GetLang("数据库出错");
			break;
		case 11:
			msg = Global.GetLang("功能未开放");
			break;
		case 12:
			msg = Global.GetLang("找不到对应的建筑物");
			break;
		case 13:
			msg = Global.GetLang("找不到对应的建造任务");
			break;
		case 14:
			msg = Global.GetLang("背包空间不够");
			break;
		case 15:
			msg = Global.GetLang("道具不足");
			break;
		default:
			msg = Id.ToString();
			break;
		}
		Super.HintMainText(msg, 10, 3);
	}

