	protected void ShowRebirthMianWind()
	{
		if (Global.IsKuaFuMap(Global.Data.roleData.MapCode, true) && !SceneUIClasses.RebornMap.IsTheScene())
		{
			Super.HintMainText(Global.GetLang("当前地图不能使用此功能"), 10, 3);
			return;
		}
		if (this.mRebirthMainPartWind == null)
		{
			this.mRebirthMainPartWind = U3DUtils.NEW<GChildWindow>();
			this.mRebirthMainPartWind.IsShowModal = false;
			this.mRebirthMainPartWind.ModalType = ChildWindowModalType.Translucent;
			Super.InitChildWindow(this.mRebirthMainPartWind, "RebirthMianWind");
			this.Root.Children.Add(this.mRebirthMainPartWind);
		}
		if (this.mRebirthMainPart == null)
		{
			this.mRebirthMainPart = U3DUtils.NEW<RebirthMainPart>();
			this.mRebirthMainPart.Hander = delegate(object s, DPSelectedItemEventArgs e)
			{
				if (e.Type == 1)
				{
					switch (e.ID)
					{
					case 1:
						if (Global.Data.roleData.RebornCount >= IConfigbase<ConfigRebirth>.Instance.GetMaxRebornCount())
						{
							Super.HintMainText(Global.GetLang("已达到最大重生阶数"), 10, 3);
							return;
						}
						this.ShowRebirthFirstPartWind();
						this.CloseRebirthMianWind();
						break;
					case 2:
						this.OpenChongShengYinJiPart();
						break;
					case 3:
						this.OpenChongShengLianLuWindow(ChongShenLianLuTypes.ZhuangBeiDaKong);
						break;
					case 4:
						this.ShowRebirthBossPartWind();
						this.CloseRebirthMianWind();
						break;
					case 5:
						this.ShowRebirthRankPartWind();
						this.CloseRebirthMianWind();
						break;
					case 6:
						this.OpenMoShenMiBaoWindow();
						break;
					}
				}
				if (e.Type == 0)
				{
					this.CloseRebirthMianWind();
				}
			};
		}
		this.mRebirthMainPartWind.SetContent(this.mRebirthMainPartWind.BodyPresenter, this.mRebirthMainPart, 0.0, 0.0, true);
	}

