	public static bool OnPreChangeMap(int mapCode = -1, int hint = 0)
	{
		if (mapCode > 0)
		{
			int num = 0;
			int num2 = 0;
			Global.GetMapMinLevelAndZhuanSheng(mapCode, out num2, out num);
			if (Global.Data.roleData.ChangeLifeCount * 400 + Global.Data.roleData.Level < num * 400 + num2)
			{
				Super.HintMainText(Global.GetLang("等级不足，无法传送！"), 10, 3);
				return true;
			}
		}
		if (Global.IsKuaFuHuoDongMapSceneUIClass(Global.GetMapSceneUIClass()) && hint != 10 && PlayZone.GlobalPlayZone.GameFubenBoxMini != null)
		{
			Super.HideNetWaiting();
			PlayZone.GlobalPlayZone.GameFubenBoxMini.ShowMessageText();
			return true;
		}
		return false;
	}

