	protected void ProcessActiveHelp(long ticks)
	{
	}

	public object DoAction(int id, int param)
	{
		if (id >= 10000 && id < 11000)
		{
			if (null != this.GameTaskBoxMini)
			{
				this.GameTaskBoxMini.ShowHelpAnim(1, 1);
			}
			return this;
		}
		switch (id)
		{
		case 14:
		case 18:
		case 28:
		case 33:
		case 36:
		case 46:
		case 50:
		case 197:
			break;
		case 15:
		case 29:
			goto IL_96B;
		case 16:
			Super.PlayYinDaoSound("qianghua1.mp3", true, false);
			if (null != this.lianluPart)
			{
				this.lianluPart.ShowHelpAnim(1, param);
			}
			return this;
		case 17:
			if (null != this.lianluPart)
			{
				this.lianluPart.ShowHelpAnim(2, param);
			}
			return this;
		case 19:
			if (null != this.GameMenuIconBoxContainer)
			{
				this.GameMenuIconBoxContainer.ShowHelpAnim(1, param);
			}
			return this;
		case 20:
			if (null != this.gamePayerRolePart)
			{
				this.gamePayerRolePart.ShowHelpAnim(0, 1);
			}
			return this;
		case 21:
			if (null != GTipServiceEx.GGoodTipsPart)
			{
				GTipServiceEx.GGoodTipsPart.ShowHelpAnim(0, param);
			}
			return this;
		case 22:
			this.ClickNPC(116, 1);
			return this;
		case 23:
			if (null != this.NpcDialogPart)
			{
				this.NpcDialogPart.ShowHelpAnim(0, param);
			}
			return this;
		case 24:
			if (null != this.zhuanZhiPart)
			{
				this.zhuanZhiPart.ShowHelpAnim(0, param);
			}
			return this;
		case 25:
			if (null != this.RadarMap)
			{
				this.RadarMap.ShowHelpAnim(0, param);
			}
			return this;
		case 26:
		case 27:
			if (null != this.worldNavigationPart)
			{
				this.worldNavigationPart.ShowHelpAnim(id - 26, param);
			}
			return this;
		case 30:
		case 31:
		case 32:
			if (id == 31)
			{
				Super.PlayYinDaoSound("zhuijia1.mp3", true, false);
			}
			if (null != this.lianluPart)
			{
				this.lianluPart.ShowHelpAnim(id - 30, param);
			}
			return this;
		case 34:
		case 37:
		case 47:
		case 51:
			if (null != this.GameMenuIconBoxContainer)
			{
				this.GameMenuIconBoxContainer.ShowHelpAnim(3, param);
			}
			return this;
		case 35:
		case 41:
		case 49:
		case 53:
			if (null != this.synthesizePart)
			{
				this.synthesizePart.ShowHelpAnim(1000, param);
			}
			return this;
		case 38:
			if (null != this.synthesizePart)
			{
				this.synthesizePart.ShowHelpAnim(2, param);
			}
			return this;
		case 39:
			if (null != this.synthesizePart)
			{
				this.synthesizePart.ShowHelpAnim(200, param);
			}
			return this;
		case 40:
			if (null != this.synthesizePart)
			{
				this.synthesizePart.ShowHelpAnim(300, param);
			}
			return this;
		case 42:
			SystemHelpPart.ShowHintTextNoTarget(true, Global.GetLang("请跟随指引完成魔晶回收操作"), 3);
			this.ClickNPC(101, 1);
			return this;
		case 43:
			if (null != this.NpcDialogPart)
			{
				this.NpcDialogPart.ShowHelpAnim(0, param);
			}
			return this;
		case 44:
		case 45:
			if (null != this.jiFenHuiShouPart)
			{
				this.jiFenHuiShouPart.ShowHelpAnim(id - 44, param);
			}
			return this;
		case 48:
			if (null != this.synthesizePart)
			{
				this.synthesizePart.ShowHelpAnim(1, param);
			}
			return this;
		case 52:
			if (null != this.synthesizePart)
			{
				this.synthesizePart.ShowHelpAnim(101, param);
			}
			return this;
		case 54:
			SystemHelpPart.ShowHintTextNoTarget(true, Global.GetLang("请跟随指引了解日常任务"), 3);
			this.SetUIVisible(true);
			if (null != this.GameTaskBoxMini)
			{
				this.GameTaskBoxMini.ShowHelpAnim(0, param);
			}
			return this;
		case 55:
			if (null != this.GameTaskBoxMini)
			{
				this.GameTaskBoxMini.ShowHelpAnim(1000, param);
			}
			return this;
		default:
			switch (id)
			{
			case 700:
			case 710:
