			if (null != this.gamePayerRolePart)
			{
				this.gamePayerRolePart.ShowHelpAnim(10000, 1);
			}
			return this;
		case 210:
			this.ShowActivityWindow(false, 300, -1);
			return this;
		case 211:
			if (null != this._ActivityPart && null != this._ActivityPart._PaTaFuBen)
			{
				SystemHelpPart.SetMask(this._ActivityPart._PaTaFuBen.BtnTiaozhan, default(Vector4));
			}
			return this;
		case 220:
			this.ShowActivityWindow(false, 200, -1);
			return this;
		case 230:
			this.ShowActivityWindow(true, 900, -1);
			return this;
		case 239:
			if (null != this._ActivityPart)
			{
				this._ActivityPart.ShowHelpAnim(1, param);
			}
			return this;
		case 240:
			this.ShowActivityWindow(false, 100, -1);
