		case 241:
			if (null != this._ActivityPart && null != this._ActivityPart._JingYanFuBen)
			{
				this._ActivityPart.ShowHelpAnim(1002, 1);
			}
			return this;
		case 242:
			if (null != this.jingYanFuBenDetailPart)
			{
				this.jingYanFuBenDetailPart.ShowHelpAnim(0, 1);
			}
			return this;
		}
		if (this.uiVisible)
		{
			if (null != this.LeaderRoleFace)
			{
				this.LeaderRoleFace.ShowHelpAnim(0, param);
			}
		}
		else
		{
			SystemHelpMgr.OnAction(UIObjIDs.LeaderRoleFace, HelpStateEvents.Clicked, 1);
		}
		return this;
		IL_68D:
		if (null != this.GameMenuIconBoxContainer)
		{
			this.GameMenuIconBoxContainer.ShowHelpAnim(0, param);
		}
		return this;
		IL_96B:
