	private string GetFormatRoleName(RoleData roleData)
	{
		if (SceneUIClasses.RebornMap.IsTheScene())
		{
			return IConfigbase<ConfigChannelName>.Instance.GetPTNameByPTID(Global.Data.roleData.PTID, true) + Global.FormatRoleNameZoneid(roleData.ZoneID, roleData.RoleName, 0, 0);
		}
		string text;
		int num;
		if (KuaFuLoginManager.LoginKuaFuServer(out text, out num))
		{
			return Global.FormatRoleNameZoneid(roleData.ZoneID, roleData.RoleName, 0, 0);
		}
		return Global.FormatRoleName(roleData);
	}

