	private void AddRole()
	{
		RoleData roleData = (RoleData)Global.Data.roleData.Clone();
		roleData.RoleID = Global.GetMyTimer();
		Random random = new Random();
		roleData.PosX += random.Next(-600, 600);
		roleData.PosY += random.Next(-350, 350);
