		Global.Data.GameScene.ToLoadOtherRole(roleData, (double)roleData.PosX, (double)roleData.PosY, (double)roleData.RoleDirection, false);
	}

	private void AddRoleByConfig()
	{
		int num = 120;
		XElement xelement = XElement.Parse(File.ReadAllText(Application.dataPath + "/UIResources/Test/RoleXml.Xml"));
		int num2 = 0;
		foreach (XElement xelement2 in xelement.Elements("Role"))
		{
			num2++;
			RoleData roleData = (RoleData)Global.Data.roleData.Clone();
			if (roleData.GoodsDataList != null)
			{
				roleData.GoodsDataList.Clear();
			}
			else
			{
				roleData.GoodsDataList = new List<GoodsData>();
			}
			for (int i = 0; i < 21; i++)
			{
				string text = ((ItemCategories)i).ToString();
				XAttribute xattribute = xelement2.Attribute(text);
				if (xattribute != null && xattribute.Value != string.Empty)
				{
					GoodsData goodsData = new GoodsData();
					goodsData.Using = 1;
					goodsData.GoodsID = int.Parse(xattribute.Value);
					roleData.GoodsDataList.Add(goodsData);
				}
			}
			string value = xelement2.Attribute("WuQi_Zuo").Value;
			string value2 = xelement2.Attribute("WuQi_You").Value;
			string value3 = xelement2.Attribute("WingID").Value;
			if (value != string.Empty)
			{
				GoodsData goodsData2 = new GoodsData();
				goodsData2.Using = 1;
				goodsData2.GoodsID = int.Parse(value);
				roleData.GoodsDataList.Add(goodsData2);
			}
			if (value2 != string.Empty)
			{
				GoodsData goodsData3 = new GoodsData();
				goodsData3.Using = 1;
				goodsData3.GoodsID = int.Parse(value2);
				roleData.GoodsDataList.Add(goodsData3);
			}
			if (value3 != string.Empty)
			{
				roleData.MyWingData.WingID = int.Parse(xelement2.Attribute("WingID").Value);
				roleData.MyWingData.Using = 1;
			}
			roleData.Occupation = int.Parse(xelement2.Attribute("Occupation").Value);
			roleData.RoleName = string.Concat(new object[]
			{
				"职业",
				int.Parse(xelement2.Attribute("Occupation").Value),
				"    编号:",
				num2
			});
			roleData.RoleID = Global.GetMyTimer() + Random.Range(1, 100000);
			roleData.PosX += num2 % 10 * num + num2 / 10 * num - 1300;
			roleData.PosY += num2 % 10 * num - 300 - num2 / 10 * num;
			Global.Data.OtherRoles.Add(roleData.RoleID, roleData);
			Global.Data.GameScene.ToLoadOtherRole(roleData, (double)roleData.PosX, (double)roleData.PosY, 0.0, false);
		}
	}

	private void AddRoleByConfig13()
	{
		Action<int, string> action = delegate(int _Occupation, string str)
		{
			int num = 0;
			int k;
			for (k = 0; k <= 21; k++)
			{
				int num2 = Enumerable.Count<KeyValuePair<int, GoodVO>>(Enumerable.ToList<KeyValuePair<int, GoodVO>>(Enumerable.Where<KeyValuePair<int, GoodVO>>(ConfigGoods.GoodsXmlNodeDict, (KeyValuePair<int, GoodVO> s) => s.Value.Categoriy == k)));
				if (num2 > num)
				{
					num = num2;
				}
			}
			for (int i = 0; i < 13; i++)
			{
				RoleData roleData = (RoleData)Global.Data.roleData.Clone();
				roleData.Occupation = _Occupation;
				roleData.RoleName = str + (i + 1);
				if (roleData.GoodsDataList != null)
				{
					roleData.GoodsDataList.Clear();
				}
				else
				{
					roleData.GoodsDataList = new List<GoodsData>();
				}
				int k;
				for (k = 0; k <= 21; k++)
				{
					GoodsData goodsData = new GoodsData();
					goodsData.Using = 1;
					List<KeyValuePair<int, GoodVO>> list;
					if (k >= 11 && k <= 21)
					{
						list = Enumerable.ToList<KeyValuePair<int, GoodVO>>(Enumerable.Where<KeyValuePair<int, GoodVO>>(ConfigGoods.GoodsXmlNodeDict, (KeyValuePair<int, GoodVO> s) => s.Value.Categoriy == k));
					}
					else if (k == 9)
					{
						list = Enumerable.ToList<KeyValuePair<int, GoodVO>>(Enumerable.Where<KeyValuePair<int, GoodVO>>(ConfigGoods.GoodsXmlNodeDict, (KeyValuePair<int, GoodVO> s) => s.Value.Categoriy == k));
					}
					else if (k == 8)
					{
						list = Enumerable.ToList<KeyValuePair<int, GoodVO>>(Enumerable.Where<KeyValuePair<int, GoodVO>>(ConfigGoods.GoodsXmlNodeDict, (KeyValuePair<int, GoodVO> s) => s.Value.Categoriy == k && s.Value.ResName.Contains(str)));
						roleData.MyWingData.WingID = i;
						roleData.MyWingData.Using = 1;
					}
					else
					{
						list = Enumerable.ToList<KeyValuePair<int, GoodVO>>(Enumerable.Where<KeyValuePair<int, GoodVO>>(ConfigGoods.GoodsXmlNodeDict, (KeyValuePair<int, GoodVO> s) => s.Value.Categoriy == k && s.Value.ResName.Contains(str)));
					}
					if (i <= list.Count - 1)
					{
						goodsData.GoodsID = list[i].Key;
						roleData.GoodsDataList.Add(goodsData);
					}
				}
				roleData.RoleID = Global.GetMyTimer() + Random.Range(1, 100000);
				Random random = new Random();
				roleData.PosX += (_Occupation - 1) * 340;
				roleData.PosY += (i - 5) * 100;
				Global.Data.OtherRoles.Add(roleData.RoleID, roleData);
				Global.Data.GameScene.ToLoadOtherRole(roleData, (double)roleData.PosX, (double)roleData.PosY, 0.0, false);
			}
		};
		action.Invoke(0, "ZS_");
		action.Invoke(1, "FS_");
		action.Invoke(2, "GS_");
	}

	protected void OnGUI()
	{
		if (!Context.IsShowGmMenuInMobile && this.ts_flags < 9)
		{
			if (Input.GetKeyDown(27))
			{
				this.ts_key_start = (this.ts_key_hold = (float)(this.ts_flags = 0));
				return;
			}
			if (Input.GetKeyDown(319))
			{
				this.ts_key_start = Time.time;
			}
			else if (Input.GetKeyUp(319) && this.ts_key_start > 0f)
			{
				this.ts_key_hold = Time.time;
				Debug.LogError(string.Concat(new object[]
				{
					"Flag = ",
					this.ts_flags,
					" Time",
					this.ts_key_hold - this.ts_key_start
				}));
				if (this.ts_flags < this.ts_patterns.Length)
				{
					bool flag = this.ts_patterns[this.ts_flags] != 0;
					bool flag2 = this.ts_key_hold - this.ts_key_start > 0.5f;
					if (flag != flag2)
					{
						this.ts_flags = 0;
					}
					else
					{
						this.ts_flags++;
					}
				}
				this.ts_key_start = 0f;
				this.ts_key_hold = 0f;
			}
			if (this.ts_flags < 9)
			{
				return;
			}
		}
		if (this.curentFrameTime != Time.fixedDeltaTime)
		{
			this.curentFrameTime = Time.fixedDeltaTime;
		}
		this.RefreshZuDangCube(TestGUIData.ShowViewRange, TestGUIData.ShowZuDang);
		if (Input.GetKeyDown(319))
		{
			if (this.menuKeyDownTime == 0f)
			{
				this.menuKeyDownTime = Time.time;
			}
			return;
		}
		if (Input.GetKeyUp(319))
		{
			if (this.menuKeyDownTime == 0f)
			{
				return;
			}
			bool flag3 = (double)(Time.time - this.menuKeyDownTime) > 0.5;
			this.menuKeyDownTime = 0f;
			if (this.showMenu)
			{
				this.off();
				return;
			}
			if (!flag3)
			{
				this.OnTestKey(285);
				return;
			}
			this.showMenu = !this.showMenu;
		}
		else if (Input.anyKey)
		{
			if (Input.GetKey(282))
			{
				if (!this.showMenu)
				{
					this.PanelIndex = 11;
				}
				this.OnF1();
				if (this.PanelIndex > 16)
				{
					this.PanelIndex = 10;
				}
			}
			else if (Input.GetKey(284))
			{
				this.PanelIndex = 0;
				this.off();
			}
			else if (Input.GetKey(285))
			{
				this.OnTestKey(285);
			}
			else if (Input.GetKey(286))
			{
				this.OnTestKey(286);
			}
			else if (Input.GetKey(287))
			{
				this.OnTestKey(287);
			}
			else if (Input.GetKey(288))
			{
				this.OnTestKey(288);
			}
			else if (Input.GetKey(289))
			{
				this.OnTestKey(289);
			}
			else if (Input.GetKey(290))
			{
				if (Time.fixedTime - this.lastF12Time[10] < 0.3f)
				{
					return;
				}
				this.lastF12Time[10] = Time.fixedTime;
				string text = string.Format("-recover {0}", this.GetFormatRoleName(Global.Data.roleData));
				this.SendGmMsg(text);
			}
