			}
			else if (Input.GetKey(293))
			{
				if (Time.fixedTime - this.lastF12Time[12] < 1f)
				{
					return;
				}
				this.lastF12Time[12] = Time.fixedTime;
				XElement gameResXml = Global.GetGameResXml("Config/ExtPropIndexes.xml");
				List<XElement> xelementList = Global.GetXElementList(gameResXml, "ExtPropIndexes");
				PlayZone.propertyName = new string[xelementList.Count];
				string text4 = string.Empty;
				for (int i = 0; i < xelementList.Count; i++)
				{
					XElement xelement = xelementList[i];
					text4 = Global.GetXElementAttributeStr(xelement, "Description");
					if (Global.GetXElementAttributeStr(xelement, "Percent").Equals("1"))
					{
						text4 += "%";
					}
					PlayZone.propertyName[i] = text4;
				}
				List<int> roleCommonUseIntPamams = Global.Data.roleData.RoleCommonUseIntPamams;
				for (int j = 5; j < PlayZone.propertyName.Length; j++)
				{
					this.SendGmMsg(string.Format("-testdata 0 {0} {1}", j - 4, 0));
				}
			}
