		this.ActionDict["显示内存"] = delegate(string[] e)
		{
			if (GUILayout.Button("显示内存", new GUILayoutOption[0]))
			{
				object[] array = Resources.FindObjectsOfTypeAll(typeof(Texture));
				double num3 = 0.0;
				foreach (Texture texture in array)
				{
					int runtimeMemorySize = Profiler.GetRuntimeMemorySize(texture);
					num3 += (double)runtimeMemorySize;
					if (runtimeMemorySize / 1024 / 1024 >= 1)
					{
						MUDebug.Log<string>(new string[]
						{
							string.Concat(new object[]
							{
								"Texture object ",
								texture.name,
								" using: ",
								runtimeMemorySize / 1024 / 1024,
								"M"
							})
						});
					}
				}
				MUDebug.Log<string>(new string[]
				{
					"TotalTextureSize:" + num3 / 1024.0 / 1024.0
				});
				object[] array3 = Resources.FindObjectsOfTypeAll<Mesh>();
				double num4 = 0.0;
				foreach (Mesh mesh in array3)
				{
					num4 += (double)Profiler.GetRuntimeMemorySize(mesh);
				}
				MUDebug.Log<string>(new string[]
				{
					"totalMeshSize:" + num4 / 1024.0 / 1024.0
				});
				object[] array5 = Resources.FindObjectsOfTypeAll<AudioClip>();
				double num5 = 0.0;
				foreach (AudioClip audioClip in array5)
				{
					num5 += (double)Profiler.GetRuntimeMemorySize(audioClip);
				}
				MUDebug.Log<string>(new string[]
				{
					"totalAudioSize:" + num5 / 1024.0 / 1024.0
				});
				object[] array7 = Resources.FindObjectsOfTypeAll<Animation>();
				double num6 = 0.0;
				foreach (Animation animation in array7)
				{
					num6 += (double)Profiler.GetRuntimeMemorySize(animation);
				}
				MUDebug.Log<string>(new string[]
				{
					"totalAnimationsSize:" + num6 / 1024.0 / 1024.0
				});
				object[] array9 = Resources.FindObjectsOfTypeAll<Material>();
				double num7 = 0.0;
				foreach (Material material in array9)
				{
					num7 += (double)Profiler.GetRuntimeMemorySize(material);
				}
				MUDebug.Log<string>(new string[]
				{
					"totalMaterialSize:" + num7 / 1024.0 / 1024.0
				});
				GC.Collect();
				Debug.Log("Mono used size" + Profiler.GetMonoUsedSize() / 1024f / 1024f + "M");
				Debug.Log("Allocated Mono heap size" + Profiler.GetMonoHeapSize() / 1024f / 1024f + "M");
			}
		};
