		this.ActionDict["升级到等级"] = delegate(string[] e)
		{
			GUILayout.BeginHorizontal(new GUILayoutOption[0]);
			if (GUILayout.Button("升级到等级", new GUILayoutOption[0]))
			{
				double num3 = 0.0;
				int num4 = ConvertExt.SafeConvertToInt32(this.SetLevelLevel);
				for (int i = Global.Data.roleData.Level; i < num4; i++)
				{
					double num5 = (double)Global.Data.LevelUpExperienceList[i + 1];
					double num6 = 0.0;
					if (Global.Data.LevelUpExpProportionList.TryGetValue(Global.Data.roleData.ChangeLifeCount, ref num6))
					{
						num5 *= num6;
					}
					if (i == Global.Data.roleData.Level)
					{
						num3 = num5 - (double)Global.Data.roleData.Experience;
					}
					else
					{
						num3 += num5;
					}
