	private IEnumerator GetMonsterShaderName()
	{
		Dictionary<int, MonsterVO> monstersDict = ConfigMonsters.MonsterXmlNode;
		List<string> shaderNameList = new List<string>();
		List<string> resNameList = new List<string>();
		foreach (KeyValuePair<int, MonsterVO> pair in monstersDict)
		{
			MonsterVO monsterVO = pair.Value;
			if (!resNameList.Contains(monsterVO.ResName))
			{
				resNameList.Add(monsterVO.ResName);
				string url = PathUtils.WebPath("Monster/" + monsterVO.ResName);
				WWW www = new WWW(url);
				yield return www;
				GameObject obj = null;
				if (www.isDone && string.IsNullOrEmpty(www.error))
				{
					string[] names = www.assetBundle.GetAllAssetNames();
					string name = monsterVO.ResName;
					if (name.EndsWith(".unity3d"))
					{
						name = monsterVO.ResName.Substring(0, name.Length - 8);
					}
					AssetBundleRequest abr = www.assetBundle.LoadAssetAsync(name, typeof(Object));
					yield return abr;
					obj = (Object.Instantiate(abr.asset) as GameObject);
				}
				if (obj != null)
				{
					List<Renderer> renderers = new List<Renderer>();
					Renderer[] renderers2 = obj.GetComponentsInChildren<Renderer>(true);
					renderers.AddRange(renderers2);
					for (int i = 0; i < renderers.Count; i++)
					{
						string shaderName = string.Empty;
						for (int j = 0; j < renderers[i].sharedMaterials.Length; j++)
						{
							shaderName = renderers[i].sharedMaterials[j].shader.name;
							if (!shaderNameList.Contains(shaderName))
							{
								shaderNameList.Add(shaderName);
							}
						}
						for (int k = 0; k < renderers[i].materials.Length; k++)
						{
							shaderName = renderers[i].materials[k].shader.name;
							if (!shaderNameList.Contains(shaderName))
							{
								shaderNameList.Add(shaderName);
							}
						}
					}
				}
			}
		}
		StringBuilder builder = new StringBuilder();
		for (int l = 0; l < shaderNameList.Count; l++)
		{
			builder.Append(shaderNameList[l] + "\n");
		}
		MUDebug.LogError<string>(new string[]
		{
			"all:" + builder.ToString()
		});
		yield break;
	}

	private string _CalNPCIDS(GSpriteTypes type)
	{
		int num = (TestGUIData.NPCID.Split(new char[]
		{
			' '
		}).Length <= 0) ? 0 : TestGUIData.NPCID.Split(new char[]
		{
			' '
		})[0].SafeToInt32(0);
		List<int> list = new List<int>();
		for (int i = 0; i < 10000000; i++)
		{
			int num2 = num + i;
			if (type == GSpriteTypes.Monster)
			{
				if (ConfigMonsters.MonsterXmlNode.ContainsKey(num2))
				{
					list.Add(num2);
					if (list.Count >= 50)
					{
						break;
					}
				}
			}
			else if (type == GSpriteTypes.NPC && ConfigNPCs.NPCVODict.ContainsKey(num2))
			{
				list.Add(num2);
				if (list.Count >= 50)
				{
					break;
				}
			}
		}
		string text = string.Empty;
		foreach (int num3 in list)
		{
			text = text + num3 + " ";
		}
		return text;
	}

