			PlayZone.propertyName = new string[xelementList.Count];
			string text = string.Empty;
			for (int i = 0; i < xelementList.Count; i++)
			{
				XElement xelement = xelementList[i];
				text = Global.GetXElementAttributeStr(xelement, "Description");
				if (Global.GetXElementAttributeStr(xelement, "Percent").Equals("1"))
				{
					text += "%";
				}
				PlayZone.propertyName[i] = text;
			}
			TestGUIData.pkking = this.GetFormatRoleName(Global.Data.roleData) + string.Empty;
			TestGUIData.luolan = Global.Data.roleData.Faction + string.Empty;
