	private void RefreshZuDangCube(bool show, bool zudang)
	{
		if (show)
		{
			if (Time.fixedTime - this.lastF12Time[20] > 2f)
			{
				this.lastF12Time[20] = Time.fixedTime;
				foreach (KeyValuePair<int, object[]> keyValuePair in TestGUIData.ZuDangPoints)
				{
					keyValuePair.Value[0] = false;
				}
				int num = (int)LeaderInfo.LeaderPos.x;
				int num2 = (int)LeaderInfo.LeaderPos.z;
				for (int i = 0; i < 564; i += 2)
				{
					int num3 = (int)TestGUIData.ClientViewGridArray[i] + num;
					int num4 = (int)TestGUIData.ClientViewGridArray[i + 1] + num2;
					int num5 = (num3 << 16) + num4;
					object[] array;
					if (!TestGUIData.ZuDangPoints.TryGetValue(num5, ref array))
					{
						array = new object[2];
						TestGUIData.ZuDangPoints[num5] = array;
					}
					try
					{
						if (zudang)
						{
							array[0] = !ChuanQiUtils.CanMove(Global.Data.GameScene.GetLeader(), num3, num4);
						}
						else
						{
							array[0] = true;
						}
					}
					catch (Exception ex)
					{
					}
					if ((bool)array[0] && array[1] == null)
					{
						GameObject gameObject = Resources.Load("Prefabs/Test/TestCude") as GameObject;
						if (null != gameObject)
						{
							gameObject = (SpawnManager.Instantiate(gameObject) as GameObject);
							gameObject.transform.localPosition = new Vector3((float)num3 * 1f + 0.5f, 51.1f, (float)num4 * 1f + 0.5f);
							TestGUIData.ZuDangPoints[num5] = new object[]
							{
								true,
								gameObject
							};
						}
					}
				}
				foreach (KeyValuePair<int, object[]> keyValuePair2 in TestGUIData.ZuDangPoints)
				{
					if (!(bool)keyValuePair2.Value[0])
					{
						if (keyValuePair2.Value[1] != null)
						{
							Object.Destroy(keyValuePair2.Value[1] as GameObject);
						}
						TestGUIData.ZuDangPoints.Remove(keyValuePair2.Key);
					}
				}
			}
		}
		else if (TestGUIData.ZuDangPoints.Count > 0)
		{
			foreach (object[] array2 in TestGUIData.ZuDangPoints.Values)
			{
				Object.Destroy(array2[1] as GameObject);
			}
			TestGUIData.ZuDangPoints.Clear();
		}
	}

