	public void SetTaskToComplete(int taskID)
	{
		string text = string.Empty;
		TaskData taskDataByID = Global.GetTaskDataByID(taskID);
		TaskVO taskXmlNodeByID = ConfigTasks.GetTaskXmlNodeByID(taskID);
		if (taskXmlNodeByID != null && taskDataByID != null)
		{
			int targetNum = taskXmlNodeByID.TargetNum1;
			if (targetNum > taskDataByID.DoingTaskVal1)
			{
				text = taskXmlNodeByID.Title;
				string text2 = string.Format("-settaskv {0} {1} 1 {2}", this.GetFormatRoleName(Global.Data.roleData), text, targetNum);
