	public bool OnTestCompTask(int taskID)
	{
		if (this.nSetToTaskID <= 0)
		{
			return false;
		}
		if (taskID > this.nSetToTaskID)
		{
			this.nSetToTaskID = -1;
			return false;
		}
		TaskVO taskXmlNodeByID = ConfigTasks.GetTaskXmlNodeByID(taskID);
		if (taskXmlNodeByID != null)
		{
			int nextMainTask = Super.GetNextMainTask(taskID);
			if (nextMainTask > 0)
			{
				this.TestGetNextTask(nextMainTask);
				return true;
			}
		}
		return false;
	}

	public bool OnTestNewTask(int taskID)
	{
		if (this.nSetToTaskID <= 0)
		{
			return false;
		}
		if (taskID >= this.nSetToTaskID)
		{
			GongnengYugaoMgr.RefreshAllIcons(false);
			this.nSetToTaskID = -1;
			return false;
		}
		this.SetTaskToComplete(taskID);
		return true;
	}

	public bool OnTestModTask(int taskID)
	{
		if (this.nSetToTaskID <= 0)
		{
			return false;
		}
		if (taskID > this.nSetToTaskID)
		{
			this.nSetToTaskID = -1;
			return false;
		}
		TaskData taskDataByID = Global.GetTaskDataByID(taskID);
		TaskVO taskXmlNodeByID = ConfigTasks.GetTaskXmlNodeByID(taskID);
		int targetNum = taskXmlNodeByID.TargetNum1;
		if (taskDataByID != null && taskXmlNodeByID != null && targetNum <= taskDataByID.DoingTaskVal1)
		{
			int num = 0;
			int num2 = 0;
			int num3 = 0;
			Super.GetTaskDestNPCID(taskXmlNodeByID, ref num, ref num2, ref num3);
			GameInstance.Game.SpriteCompleteTask(num3, taskID, taskDataByID.DbID, 0);
			return true;
		}
		return false;
	}

	public void ClearDupMainTask()
	{
		if (Global.Data.roleData.TaskDataList != null)
		{
			int num = -1;
			foreach (TaskData taskData in Global.Data.roleData.TaskDataList)
			{
				if (Global.GetTaskClassByID(taskData.DoingTaskID) == 0)
				{
					if (num <= 0)
					{
						num = taskData.DoingTaskID;
					}
					else if (taskData.DoingTaskID > num)
					{
						GameInstance.Game.SpriteAbandonTask(taskData.DbID, num);
						num = taskData.DoingTaskID;
					}
					else
					{
						GameInstance.Game.SpriteAbandonTask(taskData.DbID, taskData.DoingTaskID);
					}
				}
			}
		}
	}

	public void GMGetPackedGoodsByIDs(string goodsIDs, int count, int goodsLevel = 0, int appLev = 0, int luck = 0, int excellence = 0, int offset_x = 0, int offset_y = 0)
	{
		if (string.IsNullOrEmpty(goodsIDs))
		{
			return;
		}
		string[] array = goodsIDs.Split(new char[]
		{
			','
		});
		if (array == null || array.Length <= 0)
		{
			return;
		}
		float num = 6.28318548f / (float)array.Length;
		for (int i = 0; i < array.Length; i++)
		{
			NewGoodsPackData newGoodsPackData = new NewGoodsPackData();
			newGoodsPackData.ownerRoleID = Global.Data.roleData.RoleID;
			newGoodsPackData.ownerRoleName = this.GetFormatRoleName(Global.Data.roleData);
			newGoodsPackData.autoID = ++PlayZone.autoID;
			newGoodsPackData.goodsPackID = ++PlayZone.autoID;
			newGoodsPackData.toX = (int)(100f * LeaderInfo.LeaderPos.x + (float)offset_x * Mathf.Cos(num * (float)(i + 1)));
			newGoodsPackData.toY = (int)(100f * LeaderInfo.LeaderPos.z + (float)offset_y * Mathf.Sin(num * (float)(i + 1)));
			newGoodsPackData.goodsID = Global.SafeConvertToInt32(array[i]);
			newGoodsPackData.goodsNum = count;
			newGoodsPackData.productTicks = Global.GetCorrectLocalTime();
			newGoodsPackData.teamID = -1L;
			newGoodsPackData.teamRoleIDs = string.Empty;
			newGoodsPackData.lucky = luck;
			newGoodsPackData.excellenceInfo = excellence;
			newGoodsPackData.appendPropLev = appLev;
			newGoodsPackData.forge_Level = 1;
			this.scene.ServerNewGoodsPack(newGoodsPackData.ownerRoleID, newGoodsPackData.ownerRoleName, newGoodsPackData.autoID, newGoodsPackData.goodsPackID, newGoodsPackData.toX, newGoodsPackData.toY, newGoodsPackData.goodsID, newGoodsPackData.goodsNum, newGoodsPackData.productTicks, newGoodsPackData.teamID, newGoodsPackData.teamRoleIDs, newGoodsPackData.lucky, newGoodsPackData.excellenceInfo, newGoodsPackData.appendPropLev, newGoodsPackData.forge_Level);
		}
	}

	public void ForceCreateNPCWizard(int npcID, int dir, float offset, string resname = "")
	{
		if (npcID == 0)
		{
			npcID = 100;
		}
		NPCRole npcrole = new NPCRole();
		npcrole.NpcID = npcID;
		npcrole.PosX = (int)(100f * LeaderInfo.LeaderPos.x + offset);
		npcrole.PosY = (int)(100f * LeaderInfo.LeaderPos.z);
		npcrole.MapCode = Global.Data.roleData.MapCode;
		npcrole.Dir = dir;
		string xmlName = "Config/npcs1.Xml";
		XElement gameResXml = Global.GetGameResXml(xmlName);
		if (gameResXml != null)
		{
			XElement xelement = Global.GetXElement(gameResXml, "NPC", "ID", npcID.ToString());
			if (xelement != null)
			{
				npcrole.RoleString = xelement.ToString();
				try
				{
					string roleString = npcrole.RoleString;
					XElement xelement2 = XElement.Parse(roleString);
					if (xelement2 != null)
					{
						this._AddFadeNPC(xelement2, npcrole.PosX, npcrole.PosY, npcrole.MapCode, npcrole.Dir);
					}
				}
				catch (Exception ex)
				{
					MUDebug.LogException(ex);
				}
			}
		}
	}

	private bool _AddFadeNPC(XElement npcXmlNode, int posX, int posY, int mapCode = -1, int dir = 0)
	{
		if (Global.Data.roleData.MapCode != mapCode)
		{
			return false;
		}
		int num = posX / this.scene.CurrentMapData.GridSizeX;
		int num2 = posY / this.scene.CurrentMapData.GridSizeY;
		int xelementAttributeInt = Global.GetXElementAttributeInt(npcXmlNode, "ID");
		NPCInfoVO npcvobyID = ConfigNPCs.GetNPCVOByID(xelementAttributeInt);
		if (npcvobyID.IsSafe > 0)
		{
			Global.SetPartialSafeRegion(new Point(num, num2), 2);
		}
		Global.SetPartialCollideRegion(new Point(num, num2), npcXmlNode);
		return this._AddNewNPCEx(npcXmlNode, (double)posX, (double)posY, dir);
	}

	private bool _AddNewNPCEx(XElement npcXmlNode, double posX, double posY, int dir)
	{
		int num = 2130706432 + Global.GetXElementAttributeInt(npcXmlNode, "ID");
		string name = StringUtil.substitute("Role_{0}", new object[]
		{
			num
		});
		GSprite gsprite = new GSprite();
		gsprite.SpriteType = GSpriteTypes.NPC;
		string sname = Global.GetXElementAttributeStr(npcXmlNode, "SName");
		if (!string.IsNullOrEmpty(Global.GetXElementAttributeStr(npcXmlNode, "Function")))
		{
			sname = StringUtil.substitute("{0}•{1}", new object[]
			{
				Global.GetXElementAttributeStr(npcXmlNode, "Function"),
				Global.GetXElementAttributeStr(npcXmlNode, "SName")
			});
		}
		string text = ConfigNPCs.GetNPCSoundByID(Global.GetXElementAttributeInt(npcXmlNode, "ID"));
		if (text.Length > 0)
		{
			text = StringUtil.substitute("Audio/Npc/{0}", new object[]
			{
				text
			});
			MUDebug.Log<string>(new string[]
			{
				"playSoundURL=" + text
			});
		}
		string npctalkSoundByID = ConfigNPCs.GetNPCTalkSoundByID(Global.GetXElementAttributeInt(npcXmlNode, "ID"));
		if (npctalkSoundByID.Length > 0)
		{
			string[] array = npctalkSoundByID.Split(new char[]
			{
				'|'
			});
			gsprite.PlayNpcTalkSoundURLs = new string[array.Length];
			for (int i = 0; i < array.Length; i++)
			{
				gsprite.PlayNpcTalkSoundURLs[i] = StringUtil.substitute("Audio/Npc/{0}", new object[]
				{
					array[i]
				});
			}
			MUDebug.Log<string>(new string[]
			{
				"talkSoundURL=" + npctalkSoundByID
			});
		}
		gsprite.PlaySoundURL = text;
		this._LoadSprite(gsprite, num, Global.GetXElementAttributeInt(npcXmlNode, "Sex"), name, string.Empty, string.Empty, sname, 0, Global.GetXElementAttributeInt(npcXmlNode, "ID"), 65280U, 65280U, 65280U, 0.0, 0, 0, -1.0, Global.GetXElementAttributeInt(npcXmlNode, "Code"), -1, new Point((int)posX, (int)posY), dir, 0.0, 0.0, 0, true);
		int xelementAttributeInt = Global.GetXElementAttributeInt(npcXmlNode, "ID");
		GSpriteTypes gspriteTypes = (GSpriteTypes)TestGUIData.NPCSType.SafeToInt32(0);
		NPCInfoVO npcvobyID = ConfigNPCs.GetNPCVOByID(xelementAttributeInt);
		string resName = npcvobyID.ResName;
		if (gspriteTypes == GSpriteTypes.Monster)
		{
			gsprite.ExtensionID = npcvobyID.ID;
			gsprite.SpriteType = gspriteTypes;
			npcvobyID.ResName = TestGUIData.U3dName;
		}
		else if (gspriteTypes == GSpriteTypes.NPC && TestGUIData.U3dName.EndsWith(".unity3d"))
		{
			gsprite.ExtensionID = 100;
			gsprite.SpriteType = gspriteTypes;
			npcvobyID.ResName = TestGUIData.U3dName;
		}
		gsprite.Start();
		gsprite.SpriteType = GSpriteTypes.NPC;
		npcvobyID.ResName = resName;
		gsprite.IsOpposition = false;
		Global.CurrentMapData._MapGrid.MoveObject(-1, -1, gsprite.cx, gsprite.cy, gsprite);
		return true;
	}

	private void _LoadSprite(GSprite sprite, int roleID, int roleSex, string name, string faction, string otherName, string sname, int occupation, int extensionID, uint factionColor, uint otherNameColor, uint snameColor, double life, int pkMode, int pkValue, double currentMagic, int equipmentBody, int equipmentWeapon, Point coordinate, int direction, double lifeTotalWidth, double moveSpeed, int factionID, bool addToCanvas)
	{
		sprite.Name = name;
		sprite.RoleID = roleID;
		sprite.RoleSex = roleSex;
		sprite.FactionID = factionID;
		if (!string.IsNullOrEmpty(faction))
		{
			sprite.VFaction = faction;
		}
		if (!string.IsNullOrEmpty(otherName))
		{
			sprite.VOtherName = otherName;
		}
		sprite.VSName = sname;
		sprite.ShowName = Global.FormatShowName(Global.Data.roleData, 0);
		sprite.Occupation = occupation;
		sprite.ExtensionID = extensionID;
		sprite.SNameBrush = new SolidColorBrush(snameColor);
		sprite.VLife = life;
		sprite.PKMode = (GPKModes)pkMode;
		sprite.CurrentMagic = (int)currentMagic;
		sprite.EquipmentBody = equipmentBody;
		sprite.EquipmentWeapon = equipmentWeapon;
		sprite.cx = coordinate.X;
		sprite.cy = coordinate.Y;
		sprite.OrigCoordinate = coordinate;
		sprite.Direction = direction;
		sprite.LifeTotalWidth = lifeTotalWidth;
		sprite.SpriteMoveSpeed = moveSpeed;
		if (addToCanvas)
		{
			ObjectsManager.Add(sprite);
		}
		sprite.Action = GActions.Stand;
	}

	private void CalcViewRegion()
	{
		int num = (int)LeaderInfo.LeaderPos.x;
		int num2 = (int)LeaderInfo.LeaderPos.y;
		List<Point> list = new List<Point>();
		Camera mainCamera = Global.MainCamera;
		if (null != mainCamera)
		{
			for (int i = 0; i < Screen.width; i += 30)
			{
				for (int j = 0; j < Screen.height; j += 30)
				{
					Ray ray = mainCamera.ScreenPointToRay(new Vector3((float)i, (float)j));
					RaycastHit raycastHit;
					if (Physics.Raycast(ray, ref raycastHit, float.PositiveInfinity))
					{
						Point point = new Point((int)raycastHit.point.x - num, (int)raycastHit.point.z - num2);
						if (!list.Contains(point))
						{
							list.Add(point);
						}
					}
				}
			}
			list.Sort((Point x, Point y) => Mathf.Abs(x.X) + Mathf.Abs(x.Y) - Mathf.Abs(y.X) - Mathf.Abs(y.Y));
			StringBuilder stringBuilder = new StringBuilder();
			foreach (Point point2 in list)
			{
				stringBuilder.AppendFormat("{{{0},{1}}},", point2.X, point2.Y);
			}
			Debug.LogError(stringBuilder.ToString());
		}
	}

	private int toint32(string str)
	{
		int result;
		try
		{
			result = Convert.ToInt32(str);
		}
		catch
		{
			result = 0;
		}
		return result;
	}

	private void OneKeyDestoryGoods()
	{
		string text = string.Empty;
		foreach (GoodsData goodsData in Global.Data.roleData.GoodsDataList)
		{
			if (text.Length > 0)
			{
				text += ",";
			}
			text += goodsData.Id;
		}
		GameInstance.Game.SpriteOneKeyQuickSaleOut(2, text);
		GameInstance.Game.SpriteOneKeyQuickSaleOut(1, text);
	}

	protected void StartSendSkillAttack10Per10Timer()
	{
		if (this.SkillAttack10Per10Timer != null)
		{
			return;
		}
		this.SkillAttack10Per10Timer = new DispatcherTimer("SkillAttack10Per10Timer" + Random.Range(0, int.MaxValue));
		this.SkillAttack10Per10Timer.Interval = TimeSpan.FromMilliseconds(0.0);
		this.SkillAttack10Per10Timer.Tick = new DispatcherTimerEventHandler(this.SkillAttack10Per10Timer_Tick);
		this.SkillAttack10Per10Timer.Start();
		this.SkillAttackAmount = 0;
	}

	private void StopSkillAttack10Per10Timer()
	{
		if (this.SkillAttack10Per10Timer != null)
		{
			this.SkillAttack10Per10Timer.Tick = null;
			this.SkillAttack10Per10Timer.Stop();
			this.SkillAttack10Per10Timer = null;
		}
	}

	protected void SkillAttack10Per10Timer_Tick(object sender, object e)
	{
		if (this.SkillAttack10Per10Timer.Interval.Ticks <= 0L)
		{
			this.SkillAttack10Per10Timer.Interval = TimeSpan.FromSeconds(0.1);
		}
		this.SkillAttackAmount++;
		MUDebug.Log(new object[]
		{
			"SkillAttack10Per10Timer:{0}",
			this.SkillAttackAmount
		});
		if (this.skillAttackIdList.Count > 0)
		{
			foreach (object obj in this.skillAttackIdList)
			{
				int num = (int)obj;
				if (ConfigMagicInfos.GetSkillActionType(num) == 0)
				{
					Global.Data.GameScene.DoAttack(false);
				}
				else
				{
					Global.Data.GameScene.DoMagicAttack(num, new Point(-1, -1), null, false, true);
				}
			}
		}
		if (this.SkillAttackAmount >= 100)
		{
			this.StopSkillAttack10Per10Timer();
		}
	}

